class ApiError(Exception):
    def __init__(
        self,
        status_code: int,
        detail: str,
        *,
        hint: str | None = None,
        extra: Dict[str, Any] | None = None,
    ) -> None:
        super().__init__(str(detail))
        self.status_code = int(status_code)
        self.detail = str(detail)
        self.hint = str(hint) if hint else None
        self.extra = dict(extra or {})


def _api_error_payload(
    detail: Any,
    *,
    hint: str | None = None,
    extra: Dict[str, Any] | None = None,
) -> Dict[str, Any]:
    payload: Dict[str, Any] = {
        "error": detail,
        "correlation_id": str(uuid.uuid4()),
        "timestamp": datetime.now(timezone.utc).isoformat(),
    }
    if hint:
        payload["hint"] = str(hint)
    if extra:
        payload.update({str(k): v for k, v in extra.items()})
    return payload


@app.exception_handler(ApiError)
async def api_error_handler(request: Request, exc: ApiError) -> JSONResponse:
    return JSONResponse(
        status_code=int(exc.status_code),
        content=_api_error_payload(exc.detail, hint=exc.hint, extra=exc.extra),
    )


@app.exception_handler(HTTPException)
async def http_exception_handler(request: Request, exc: HTTPException) -> JSONResponse:
    detail = exc.detail if exc.detail is not None else "HTTP error"
    hint = None
    extra: Dict[str, Any] = {}
    if isinstance(detail, dict):
        hint = detail.get("hint")
        extra = {k: v for k, v in detail.items() if k not in {"error", "detail", "hint"}}
        detail = detail.get("error") or detail.get("detail") or "HTTP error"
    return JSONResponse(
        status_code=int(exc.status_code),
        content=_api_error_payload(detail, hint=hint, extra=extra),
    )


def _effective_role(role_codes: List[str]) -> str:
    # Highest privilege wins. Keep this deterministic.
    order = ["ADMIN", "MANAGER", "PLANNER", "APPROVER", "VIEWER"]
    for candidate in order:
        if candidate in role_codes:
            return candidate
    return "VIEWER"


