def _line_scopes_for_public_role(role_code: str) -> List[str]:
    normalized = str(role_code or "VIEWER").upper().strip()
    if normalized in {"ADMIN", "MANAGER"}:
        return list(_ALL_SYSTEM_USER_LINE_SCOPES)
    return list(_DEFAULT_SYSTEM_USER_LINE_SCOPES)


def _to_public_user_record(row: Dict[str, Any]) -> PublicUserRecord:
    role_code = str(row.get("role_code") or "VIEWER").upper().strip()
    display_name = str(row.get("display_name") or "").strip()
    email = str(row.get("email") or "").strip()
    user_id = str(row.get("user_id") or "").strip()
    employee_no = str(row.get("employee_no") or "").strip() or user_id
    auth_subject = str(row.get("auth_subject") or "").strip() or user_id
    normalized_role = role_code if role_code in {"VIEWER", "PLANNER", "APPROVER", "MANAGER", "ADMIN"} else "VIEWER"
    return PublicUserRecord(
        id=user_id,
        name=display_name or (email.split("@")[0] if email else user_id),
        email=email,
        employeeNo=employee_no,
        authSubject=auth_subject,
        role=normalized_role,
        plantScopes=["PLANT_JSNG"],
        lineScopes=_line_scopes_for_public_role(normalized_role),
        isActive=bool(row.get("is_active", True)),
        createdAt=_trim_profile_text(row.get("created_at")) or None,
        lastLoginAt=_trim_profile_text(row.get("last_login_at")) or None,
    )


_MASTER_TYPES = {
    "item",
    "equipment",
    "line",
    "process",
    "bom",
    "worker",
    "spec",
    "defect-code",
}


def _normalize_master_status(value: Any, fallback: str = "ACTIVE") -> str:
    if isinstance(value, str):
        normalized = value.strip().upper()
        if normalized in {"Y", "YES", "TRUE", "1", "ACTIVE"}:
            return "ACTIVE"
        if normalized in {"N", "NO", "FALSE", "0", "INACTIVE"}:
            return "INACTIVE"
    return fallback


def _format_master_timestamp(value: Any) -> str:
    if isinstance(value, datetime):
        return value.isoformat(timespec="minutes")
    if isinstance(value, str):
        text = value.strip()
        if text:
            try:
                return datetime.fromisoformat(text.replace("Z", "+00:00")).isoformat(timespec="minutes")
            except ValueError:
                return text[:16]
    return datetime.now(timezone.utc).isoformat(timespec="minutes")


def _assert_master_identifier(value: str, *, label: str) -> str:
    candidate = str(value or "").strip()
    if not re.match(r"^[A-Za-z_][A-Za-z0-9_]*$", candidate):
        raise HTTPException(status_code=500, detail=f"Invalid {label}: {candidate}")
    return candidate


def _qualify_master_relation(schema_name: str, relation: str) -> str:
    safe_schema = _assert_master_identifier(schema_name, label="schema name")
    safe_relation = _assert_master_identifier(relation, label="relation name")
    return f'"{safe_schema}"."{safe_relation}"'


def _assert_supported_master_type(value: str) -> str:
    normalized = str(value or "").strip()
    if normalized not in _MASTER_TYPES:
        raise HTTPException(status_code=400, detail="지원되지 않는 마스터 타입입니다.")
    return normalized


def _fetch_dict_rows(cur: Any) -> List[Dict[str, Any]]:
    columns = [str(desc[0]) for desc in (cur.description or [])]
    return [dict(zip(columns, row)) for row in (cur.fetchall() or [])]


def _master_relation_exists(registry: RunRegistry, schema_name: str, relation: str) -> bool:
    if not registry.conn:
        return False
    cur = registry.conn.cursor()
    try:
        cur.execute("SELECT to_regclass(%s)", [f"{schema_name}.{relation}"])
        row = cur.fetchone()
        return bool(row and row[0])
    finally:
        try:
            cur.close()
        except Exception:
            pass


def _resolve_latest_master_schema(registry: RunRegistry) -> str | None:
    forced = str(os.getenv("BOHAE_MASTERS_SCHEMA") or "").strip()
    if forced:
        return _assert_master_identifier(forced, label="schema name")
    if not registry.conn:
        return None
    cur = registry.conn.cursor()
    try:
        cur.execute(
            """
            SELECT schema_name
              FROM information_schema.schemata
             WHERE schema_name ~ '^aps_run_[0-9]{4}$'
             ORDER BY schema_name DESC
             LIMIT 1
            """
        )
        row = cur.fetchone()
        if row and row[0]:
            return str(row[0])
        cur.execute(
            """
            SELECT schema_name
              FROM information_schema.schemata
             WHERE schema_name LIKE 'aps_run_%'
             ORDER BY schema_name DESC
             LIMIT 1
            """
        )
        row = cur.fetchone()
        return str(row[0]) if row and row[0] else None
    finally:
        try:
            cur.close()
        except Exception:
            pass


def _map_master_rows(rows: List[Dict[str, Any]], owner_fallback: str) -> List[Dict[str, Any]]:
    out: List[Dict[str, Any]] = []
    for row in rows:
        description = row.get("description")
        out.append(
            {
                "id": str(row.get("id") or row.get("code") or ""),
                "code": str(row.get("code") or row.get("id") or ""),
                "name": str(row.get("name") or row.get("code") or row.get("id") or ""),
                "status": _normalize_master_status(row.get("status")),
                "updatedAt": _format_master_timestamp(row.get("updated_at") or row.get("updatedAt")),
                "owner": str(row.get("owner") or "").strip() or owner_fallback,
                "description": str(description) if isinstance(description, str) else None,
            }
        )
    return out


def _select_master_rows(
    registry: RunRegistry,
    *,
    sql: str,
    params: List[Any],
    owner_fallback: str,
) -> List[Dict[str, Any]]:
    if not registry.conn:
        return []
    cur = registry.conn.cursor()
    try:
        cur.execute(sql, params)
        return _map_master_rows(_fetch_dict_rows(cur), owner_fallback)
    finally:
        try:
            cur.close()
        except Exception:
            pass


def _read_master_rows_from_schema(
    registry: RunRegistry,
    *,
    schema_name: str,
    master_type: str,
    limit: int,
) -> Tuple[List[Dict[str, Any]], str, str | None]:
    if master_type == "item":
        relation = "t_product_master" if _master_relation_exists(registry, schema_name, "t_product_master") else (
            "v_product_master" if _master_relation_exists(registry, schema_name, "v_product_master") else None
        )
        if not relation:
            return [], "db:empty", "product master relation not found"
        rows = _select_master_rows(
            registry,
            sql=f"""
                SELECT
                  product_id AS id,
                  product_id AS code,
                  COALESCE(NULLIF(product_name, ''), product_id) AS name,
                  CASE
                    WHEN UPPER(COALESCE(is_active, 'Y')) IN ('Y','YES','TRUE','1','ACTIVE') THEN 'ACTIVE'
                    ELSE 'INACTIVE'
                  END AS status,
                  '제품마스터' AS owner,
                  NOW() AS updated_at,
                  CONCAT_WS(' · ',
                    NULLIF(cip_group_code, ''),
                    NULLIF(format_sig, ''),
                    NULLIF(liquid_id, ''),
                    NULLIF(pack_style_id, '')
                  ) AS description
                FROM {_qualify_master_relation(schema_name, relation)}
                ORDER BY product_id
                LIMIT %s
            """,
            params=[limit],
            owner_fallback="제품마스터",
        )
        return rows, f"db:{schema_name}.{relation}", None

    if master_type == "line":
        relation = "v_line_master" if _master_relation_exists(registry, schema_name, "v_line_master") else (
            "t_line_master" if _master_relation_exists(registry, schema_name, "t_line_master") else None
        )
        if not relation:
            return [], "db:empty", "line master relation not found"
        rows = _select_master_rows(
            registry,
            sql=f"""
                SELECT
                  line_id AS id,
                  line_id AS code,
                  COALESCE(NULLIF(line_name_ko, ''), NULLIF(line_name, ''), line_id) AS name,
                  CASE
                    WHEN UPPER(COALESCE(is_active, 'Y')) IN ('Y','YES','TRUE','1','ACTIVE') THEN 'ACTIVE'
                    ELSE 'INACTIVE'
                  END AS status,
                  '생산관리팀' AS owner,
                  NOW() AS updated_at,
                  COALESCE(NULLIF(line_name, ''), NULLIF(line_name_ko, ''), '') AS description
                FROM {_qualify_master_relation(schema_name, relation)}
                ORDER BY line_id
                LIMIT %s
            """,
            params=[limit],
            owner_fallback="생산관리팀",
        )
        return rows, f"db:{schema_name}.{relation}", None

    if master_type == "worker":
        relation = "v_staff_master" if _master_relation_exists(registry, schema_name, "v_staff_master") else (
            "t_staff_master" if _master_relation_exists(registry, schema_name, "t_staff_master") else None
        )
        if not relation:
            return [], "db:empty", "staff master relation not found"
        rows = _select_master_rows(
            registry,
            sql=f"""
                SELECT
                  staff_id AS id,
                  staff_id AS code,
                  COALESCE(NULLIF(staff_name, ''), staff_id) AS name,
                  'ACTIVE' AS status,
                  '인사팀' AS owner,
                  NOW() AS updated_at,
                  '' AS description
                FROM {_qualify_master_relation(schema_name, relation)}
                ORDER BY staff_id
                LIMIT %s
            """,
            params=[limit],
            owner_fallback="인사팀",
        )
        return rows, f"db:{schema_name}.{relation}", None

    if master_type == "bom":
        relation = "t_product_master" if _master_relation_exists(registry, schema_name, "t_product_master") else (
            "v_product_master" if _master_relation_exists(registry, schema_name, "v_product_master") else None
        )
        if not relation:
            return [], "db:empty", "bom seed relation not found"
        rows = _select_master_rows(
            registry,
            sql=f"""
                SELECT
                  CONCAT('bom_', LOWER(product_id)) AS id,
                  CONCAT('BOM_', product_id) AS code,
                  CONCAT(COALESCE(NULLIF(product_name, ''), product_id), ' 기본 BOM') AS name,
                  CASE
                    WHEN UPPER(COALESCE(is_active, 'Y')) IN ('Y','YES','TRUE','1','ACTIVE') THEN 'ACTIVE'
                    ELSE 'INACTIVE'
                  END AS status,
                  '생산기술팀' AS owner,
                  NOW() AS updated_at,
                  CONCAT_WS(', ',
                    NULLIF(bottle_id, ''),
                    NULLIF(cap_id, ''),
                    NULLIF(label_id, ''),
                    NULLIF(case_id, '')
                  ) AS description
                FROM {_qualify_master_relation(schema_name, relation)}
                ORDER BY product_id
                LIMIT %s
            """,
            params=[limit],
            owner_fallback="생산기술팀",
        )
        return rows, f"db:{schema_name}.{relation}:bom-derived", None

    if master_type == "equipment":
        relation = "v_line_master" if _master_relation_exists(registry, schema_name, "v_line_master") else None
        if not relation:
            return [], "db:empty", "equipment source relation not found"
        rows = _select_master_rows(
            registry,
            sql=f"""
                SELECT
                  CONCAT('eq_', LOWER(line_id)) AS id,
                  CONCAT('EQ_', line_id) AS code,
                  COALESCE(NULLIF(line_name_ko, ''), NULLIF(line_name, ''), line_id) AS name,
                  CASE
                    WHEN UPPER(COALESCE(is_active, 'Y')) IN ('Y','YES','TRUE','1','ACTIVE') THEN 'ACTIVE'
                    ELSE 'INACTIVE'
                  END AS status,
                  '설비관리팀' AS owner,
                  NOW() AS updated_at,
                  CONCAT('line_proxy=', line_id) AS description
                FROM {_qualify_master_relation(schema_name, relation)}
                ORDER BY line_id
                LIMIT %s
            """,
            params=[limit],
            owner_fallback="설비관리팀",
        )
        return rows, f"db:{schema_name}.{relation}:equipment-proxy", None

    if master_type == "process":
        relation = "v_line_product_capability" if _master_relation_exists(registry, schema_name, "v_line_product_capability") else None
        if not relation:
            return [], "db:empty", "process source relation not found"
        rows = _select_master_rows(
            registry,
            sql=f"""
                SELECT
                  CONCAT('proc_', LOWER(line_id)) AS id,
                  CONCAT('PROC_', line_id) AS code,
                  CONCAT(line_id, ' 공정') AS name,
                  'ACTIVE' AS status,
                  '공정기술팀' AS owner,
                  NOW() AS updated_at,
                  CONCAT('허용 품목수=', COUNT(*)) AS description
                FROM {_qualify_master_relation(schema_name, relation)}
                GROUP BY line_id
                ORDER BY line_id
                LIMIT %s
            """,
            params=[limit],
            owner_fallback="공정기술팀",
        )
        return rows, f"db:{schema_name}.{relation}:process-derived", None

    if master_type == "spec":
        relation = "t_product_master" if _master_relation_exists(registry, schema_name, "t_product_master") else None
        if not relation:
            return [], "db:empty", "spec source relation not found"
        rows = _select_master_rows(
            registry,
            sql=f"""
                SELECT
                  CONCAT('spec_', LOWER(product_id)) AS id,
                  CONCAT('SPEC_', product_id) AS code,
                  CONCAT(product_id, ' 스펙') AS name,
                  'ACTIVE' AS status,
                  '품질관리팀' AS owner,
                  NOW() AS updated_at,
                  CONCAT('volume_ml=', COALESCE(volume_ml::text, '-')) AS description
                FROM {_qualify_master_relation(schema_name, relation)}
                ORDER BY product_id
                LIMIT %s
            """,
            params=[limit],
            owner_fallback="품질관리팀",
        )
        return rows, f"db:{schema_name}.{relation}:spec-derived", None

    if master_type == "defect-code":
        return [], "db:empty", "defect-code source is not provisioned in DB schema"

    return [], "db:empty", "unsupported master type"


def _list_master_rows_payload(
    registry: RunRegistry,
    *,
    master_type: str,
    limit: int = 500,
) -> Dict[str, Any]:
    normalized_type = _assert_supported_master_type(master_type)
    bounded_limit = max(1, min(int(limit or 500), 2000))
    schema_name = _resolve_latest_master_schema(registry)
    if not schema_name:
        return {
            "data": [],
            "type": normalized_type,
            "meta": {
                "source": "db:empty",
                "schema": None,
                "total": 0,
                "note": "run schema not found",
            },
        }

    rows, source, note = _read_master_rows_from_schema(
        registry,
        schema_name=schema_name,
        master_type=normalized_type,
        limit=bounded_limit,
    )
    override_rows = list_factory_master_overrides(registry, master_type=normalized_type)
    merged_rows = apply_factory_master_overrides(rows, override_rows)
    return {
        "data": merged_rows,
        "type": normalized_type,
        "meta": {
            "source": source,
            "schema": schema_name,
            "total": len(merged_rows),
            "note": note,
        },
    }


def _ensure_relations_available(registry: RunRegistry, relations: List[str], *, label: str) -> None:
    if not registry.conn:
        raise HTTPException(status_code=503, detail=f"{label} 중 DB 연결에 실패했습니다.")
    cur = registry.conn.cursor()
    try:
        cur.execute(
            """
            SELECT relation_name,
                   to_regclass(relation_name)
              FROM unnest(%s::text[]) AS relation_name
            """,
            [relations],
        )
        missing = [str(row[0]) for row in (cur.fetchall() or []) if not row[1]]
        if missing:
            raise HTTPException(status_code=503, detail=f"{label} backend unavailable: missing {', '.join(missing)}")
    finally:
        try:
            cur.close()
        except Exception:
            pass


def _as_optional_text(value: Any) -> str | None:
    text = str(value or "").strip()
    return text or None


def _as_text_list(value: Any) -> List[str]:
    if not isinstance(value, list):
        return []
    return [str(item).strip() for item in value if str(item).strip()]


def _coerce_json_object(value: Any) -> Dict[str, Any]:
    if isinstance(value, dict):
        return dict(value)
    if isinstance(value, str):
        try:
            parsed = json.loads(value)
        except Exception:
            return {}
        return dict(parsed) if isinstance(parsed, dict) else {}
    return {}


def _list_scrap_rows_payload(registry: RunRegistry) -> List[Dict[str, Any]]:
    _ensure_relations_available(registry, ["ontology.scrap_record"], label="스크랩 조회")
    cur = registry.conn.cursor()
    try:
        cur.execute(
            """
            SELECT id, lot_id, item_name, reason, qty::float8 AS qty, line_id,
                   operator, created_at::text, status, cancelled_at::text
              FROM ontology.scrap_record
             ORDER BY created_at DESC
            """
        )
        return _fetch_dict_rows(cur)
    finally:
        try:
            cur.close()
        except Exception:
            pass


def _normalize_predictive_alert_source(value: Any) -> str | None:
    normalized = _as_optional_text(value)
    if not normalized:
        return None
    normalized = normalized.upper()
    if normalized == "EAM_PREDICTIVE_ALERT":
        return "PREDICTIVE"
    if normalized == "EAM_SCHEDULE_ALERT":
        return "SCHEDULE"
    return None


def _normalize_predictive_alert_tier(value: Any) -> str:
    normalized = (_as_optional_text(value) or "").upper()
    if normalized in {"CRITICAL", "WARNING", "STABLE"}:
        return normalized
    return "WARNING"


def _list_predictive_alert_rows_payload(registry: RunRegistry, *, limit: int = 50) -> List[Dict[str, Any]]:
    _ensure_relations_available(registry, ["ontology.audit_event", "ontology.alarm_state"], label="예지보전 경고 조회")
    cur = registry.conn.cursor()
    try:
        cur.execute(
            """
            SELECT DISTINCT ON (payload_json ->> 'source', UPPER(COALESCE(payload_json ->> 'equipment_id', '')))
                   actor_user_id,
                   actor_employee_no,
                   actor_auth_subject,
                   actor_role_code,
                   receipt_id,
                   payload_json,
                   created_at::text
              FROM ontology.audit_event
             WHERE payload_json ->> 'domain' = 'ALARM'
               AND payload_json ->> 'source' IN ('EAM_PREDICTIVE_ALERT', 'EAM_SCHEDULE_ALERT')
             ORDER BY payload_json ->> 'source',
                      UPPER(COALESCE(payload_json ->> 'equipment_id', '')),
                      created_at DESC,
                      audit_event_id DESC
             LIMIT %s
            """,
            [max(1, min(int(limit or 50), 500))],
        )
        rows = _fetch_dict_rows(cur)
    finally:
        try:
            cur.close()
        except Exception:
            pass

    out: List[Dict[str, Any]] = []
    for row in rows:
        payload = _coerce_json_object(row.get("payload_json"))
        metadata = _coerce_json_object(payload.get("metadata"))
        source = _normalize_predictive_alert_source(payload.get("source"))
        equipment_id = (_as_optional_text(payload.get("equipment_id")) or "").upper()
        if not source or not equipment_id:
            continue
        risk_score_raw = metadata.get("risk_score")
        try:
            risk_score = int(max(0, min(100, round(float(risk_score_raw)))))
        except Exception:
            risk_score = 0
        out.append(
            {
                "key": f"{source}:{equipment_id}",
                "source": source,
                "equipment_id": equipment_id,
                "last_tier": _normalize_predictive_alert_tier(metadata.get("risk_tier")),
                "last_risk_score": risk_score,
                "last_emitted_at": _as_optional_text(payload.get("created_at")) or _as_optional_text(row.get("created_at")),
                "reasons": _as_text_list(metadata.get("reasons")),
                "alarm_id": _as_optional_text(payload.get("alarm_id")),
                "receipt_id": _as_optional_text(row.get("receipt_id")),
                "actor": {
                    "user_id": _as_optional_text(row.get("actor_user_id")),
                    "employee_no": _as_optional_text(row.get("actor_employee_no")),
                    "auth_subject": _as_optional_text(row.get("actor_auth_subject")),
                    "role_code": _as_optional_text(row.get("actor_role_code")),
                },
            }
        )
    out.sort(key=lambda item: str(item.get("last_emitted_at") or ""), reverse=True)
    return out[: max(1, min(int(limit or 50), 500))]


def _list_alarm_states_by_ids_payload(registry: RunRegistry, alarm_ids: List[str]) -> Dict[str, Dict[str, Any]]:
    normalized = sorted({str(alarm_id or "").strip().upper() for alarm_id in alarm_ids if str(alarm_id or "").strip()})
    if not normalized:
        return {}
    _ensure_relations_available(registry, ["ontology.alarm_state"], label="알람 상태 조회")
    cur = registry.conn.cursor()
    try:
        cur.execute(
            """
            SELECT alarm_id, status, acknowledged_by, acknowledged_at::text,
                   resolved_by, resolved_at::text, updated_by, updated_at::text
              FROM ontology.alarm_state
             WHERE alarm_id = ANY(%s)
            """,
            [normalized],
        )
        rows = _fetch_dict_rows(cur)
    finally:
        try:
            cur.close()
        except Exception:
            pass
    return {str(row.get("alarm_id")): row for row in rows if row.get("alarm_id")}


def _list_alarm_events_since_payload(registry: RunRegistry, cursor_ms: int) -> List[Dict[str, Any]]:
    _ensure_relations_available(registry, ["ontology.audit_event", "ontology.alarm_state"], label="알람 스트림 조회")
    effective_cursor_ms = int(cursor_ms) if int(cursor_ms or 0) > 0 else 0
    cur = registry.conn.cursor()
    try:
        cur.execute(
            """
            SELECT payload_json, created_at::text
              FROM ontology.audit_event
             WHERE payload_json ->> 'domain' = 'ALARM'
               AND created_at > to_timestamp(%s::double precision / 1000.0)
             ORDER BY created_at ASC, audit_event_id ASC
            """,
            [effective_cursor_ms],
        )
        rows = _fetch_dict_rows(cur)
    finally:
        try:
            cur.close()
        except Exception:
            pass

    out: List[Dict[str, Any]] = []
    for row in rows:
        payload = _coerce_json_object(row.get("payload_json"))
        created_at = _as_optional_text(payload.get("created_at")) or _as_optional_text(row.get("created_at")) or datetime.now(timezone.utc).isoformat()
        try:
            emitted_ms = int(payload.get("emitted_ms"))
        except Exception:
            emitted_ms = int(datetime.fromisoformat(created_at.replace("Z", "+00:00")).timestamp() * 1000)
        out.append(
            {
                "id": _as_optional_text(payload.get("alarm_id")) or f"ALARM_{uuid.uuid4().hex[:12].upper()}",
                "severity": _as_optional_text(payload.get("severity")) or "INFO",
                "message": _as_optional_text(payload.get("message")) or "",
                "source": _as_optional_text(payload.get("source")) or "ALARM",
                "ts": created_at,
                "emitted_ms": emitted_ms,
                "line_id": _as_optional_text(payload.get("line_id")),
                "equipment_id": _as_optional_text(payload.get("equipment_id")),
                "linked_run_id": _as_optional_text(payload.get("linked_run_id")),
                "linked_lot_id": _as_optional_text(payload.get("linked_lot_id")),
                "linked_request_id": _as_optional_text(payload.get("linked_request_id")),
                "linked_sample_id": _as_optional_text(payload.get("linked_sample_id")),
            }
        )
    return out


