def _build_lims_approval_queue_payload(snapshot: Dict[str, Any]) -> List[Dict[str, Any]]:
    samples = list(snapshot.get("samples") or [])
    requests = list(snapshot.get("requests") or [])
    results = list(snapshot.get("results") or [])
    decisions = list(snapshot.get("decisions") or [])
    reports = list(snapshot.get("reports") or [])

    by_lot: Dict[str, List[Dict[str, Any]]] = {}
    for sample in samples:
        lot_id = str(sample.get("lot_id") or "")
        if not lot_id:
            continue
        by_lot.setdefault(lot_id, []).append(sample)

    latest_decision_by_lot: Dict[str, Dict[str, Any]] = {}
    for row in decisions:
        lot_id = str(row.get("lot_id") or "")
        if lot_id and lot_id not in latest_decision_by_lot:
            latest_decision_by_lot[lot_id] = row

    latest_report_by_lot: Dict[str, Dict[str, Any]] = {}
    for row in reports:
        lot_id = str(row.get("lot_id") or "")
        if lot_id and lot_id not in latest_report_by_lot:
            latest_report_by_lot[lot_id] = row

    out: List[Dict[str, Any]] = []
    for lot_id, lot_samples in by_lot.items():
        sample_ids = {str(sample.get("sample_id") or "") for sample in lot_samples}
        relevant_requests = [row for row in requests if str(row.get("sample_id") or "") in sample_ids]
        request_ids = {str(row.get("request_id") or "") for row in relevant_requests}
        relevant_results = [row for row in results if str(row.get("request_id") or "") in request_ids]
        latest_collected_at = sorted(
            [str(row.get("collected_at") or "") for row in lot_samples if str(row.get("collected_at") or "")],
            reverse=True,
        )
        inspector_ids = sorted(
            {
                str(row.get("entered_by") or "").strip()
                for row in relevant_results
                if str(row.get("entered_by") or "").strip()
            }
        )
        decision = latest_decision_by_lot.get(lot_id)
        report = latest_report_by_lot.get(lot_id)
        out.append(
            {
                "lot_id": lot_id,
                "sample_count": len(lot_samples),
                "completed_count": len([row for row in relevant_requests if str(row.get("status") or "") == "COMPLETED"]),
                "oos_count": len([row for row in relevant_results if str(row.get("status") or "") == "OOS"]),
                "latest_collected_at": latest_collected_at[0] if latest_collected_at else "",
                "inspector_ids": inspector_ids,
                "approver_id": str((decision or {}).get("decided_by") or "") or None,
                "report_generated": bool(report),
                "report_id": str((report or {}).get("report_id") or "") or None,
                "decision": decision,
            }
        )
    out.sort(key=lambda row: str(row.get("latest_collected_at") or ""), reverse=True)
    return out


def _compute_lims_latest_updated_at(snapshot: Dict[str, Any]) -> str | None:
    candidates: List[str] = []
    for key, field in (
        ("samples", "created_at"),
        ("specs", "updated_at"),
        ("requests", "requested_at"),
        ("results", "created_at"),
        ("decisions", "decided_at"),
        ("reports", "generated_at"),
    ):
        for row in list(snapshot.get(key) or []):
            value = str(row.get(field) or "").strip()
            if value:
                candidates.append(value)
    candidates.sort(reverse=True)
    return candidates[0] if candidates else None


def _load_lims_snapshot_payload(registry: RunRegistry) -> Dict[str, Any]:
    samples = _list_lims_samples_payload(registry)
    specs = _list_lims_specs_payload(registry)
    requests = _list_lims_requests_payload(registry)
    results = _list_lims_results_payload(registry)
    decisions = _list_lims_decisions_payload(registry)
    reports = _list_lims_reports_payload(registry)
    snapshot = {
        "samples": samples,
        "specs": specs,
        "requests": requests,
        "results": results,
        "decisions": decisions,
        "reports": reports,
    }
    snapshot["approvals"] = _build_lims_approval_queue_payload(snapshot)
    snapshot["latestUpdatedAt"] = _compute_lims_latest_updated_at(snapshot)
    return snapshot


def _fetch_lims_report_payload(registry: RunRegistry, report_id: str) -> Dict[str, Any] | None:
    normalized = str(report_id or "").strip()
    if not normalized:
        return None
    rows = _fetch_rows_as_dicts(
        registry,
        """
        SELECT report_id, lot_id, decision_id, decision, generated_by,
               generated_at::text, report_name, report_url
          FROM ontology.lims_report
         WHERE report_id = %s
         LIMIT 1
        """,
        [normalized],
    )
    return rows[0] if rows else None


def _list_released_lots_for_coa_payload(registry: RunRegistry) -> List[Dict[str, Any]]:
    decisions = _list_lims_decisions_payload(registry)
    seen: set[str] = set()
    out: List[Dict[str, Any]] = []
    for row in decisions:
        if str(row.get("decision") or "") != "RELEASE":
            continue
        lot_id = str(row.get("lot_id") or "")
        if not lot_id or lot_id in seen:
            continue
        seen.add(lot_id)
        out.append(
            {
                "lot_id": lot_id,
                "decision_id": str(row.get("decision_id") or ""),
                "decided_at": str(row.get("decided_at") or ""),
                "decided_by": str(row.get("decided_by") or ""),
            }
        )
    return out


def _list_lims_audit_payload(registry: RunRegistry, *, limit: int = 100) -> List[Dict[str, Any]]:
    _ensure_relations_available(registry, _LIMS_REQUIRED_RELATIONS, label="LIMS 감사 조회")
    rows = _fetch_rows_as_dicts(
        registry,
        """
        SELECT audit_event_id, event_type, actor_user_id, payload_json, created_at::text
          FROM ontology.audit_event
         WHERE payload_json ->> 'domain' = 'LIMS'
         ORDER BY created_at DESC, audit_event_id DESC
         LIMIT %s
        """,
        [max(1, min(int(limit or 100), 500))],
    )
    out: List[Dict[str, Any]] = []
    for row in rows:
        payload = _coerce_json_object(row.get("payload_json"))
        metadata = payload.get("metadata")
        out.append(
            {
                "id": str(row.get("audit_event_id") or ""),
                "type": str(payload.get("type") or row.get("event_type") or ""),
                "action_key": str(payload.get("action_key") or ""),
                "actor_id": str(row.get("actor_user_id") or ""),
                "happened_at": str(row.get("created_at") or ""),
                "lot_id": _as_optional_text(payload.get("lot_id")),
                "run_id": _as_optional_text(payload.get("run_id")),
                "sample_id": _as_optional_text(payload.get("sample_id")),
                "request_id": _as_optional_text(payload.get("request_id")),
                "result_id": _as_optional_text(payload.get("result_id")),
                "decision_id": _as_optional_text(payload.get("decision_id")),
                "report_id": _as_optional_text(payload.get("report_id")),
                "metadata": metadata if isinstance(metadata, dict) else None,
            }
        )
    return out


