        plant_id=(str(row.get("plant_id")) if row.get("plant_id") is not None else None),
        line_id=(str(row.get("line_id")) if row.get("line_id") is not None else None),
        equipment_id=(str(row.get("equipment_id")) if row.get("equipment_id") is not None else None),
        run_id=(str(row.get("run_id")) if row.get("run_id") is not None else None),
        due_at=_parse_datetime_value(row.get("due_at")),
