        task_budget_token_amount=_parse_non_negative_int(meta.get("task_budget_token_amount"), field_name="task_budget_token_amount"),
        recognition_points_hint=_parse_non_negative_int(meta.get("recognition_points_hint"), field_name="recognition_points_hint"),
        status=str(row.get("status") or "ASSIGNED").upper(),
