def _ensure_task_budget_account_row(
    cur,
    *,
    user_id: str,
    employee_no: str,
) -> None:
    cur.execute(
        """
        INSERT INTO ontology.task_budget_account (
          user_id,
          employee_no,
          available_balance,
          created_at,
          updated_at
        ) VALUES (%s, %s, 0, now(), now())
        ON CONFLICT (user_id) DO UPDATE SET
          employee_no = EXCLUDED.employee_no,
          updated_at = now()
        """,
        [_trim_profile_text(user_id), _trim_profile_text(employee_no)],
    )


def _fetch_task_budget_account_row(registry: RunRegistry, *, user_id: str) -> Dict[str, Any] | None:
    if not registry.conn:
        raise HTTPException(status_code=503, detail="task token backend unavailable: database error")
    _require_task_token_tables(registry)
    cur = registry.conn.cursor()
    try:
        cur.execute(
            """
            SELECT
              a.user_id,
              a.employee_no,
              COALESCE(u.display_name, '') AS display_name,
              COALESCE(
                (
                  SELECT ura.role_code
                    FROM ontology.app_user_role_assignment ura
                   WHERE ura.user_id = a.user_id
                     AND ura.starts_at <= now()
                     AND (ura.expires_at IS NULL OR ura.expires_at > now())
                     AND ura.revoked_at IS NULL
                   ORDER BY ura.starts_at DESC, ura.assignment_id DESC
                   LIMIT 1
                ),
                (
                  SELECT ur.role_code
                    FROM ontology.app_user_role ur
                   WHERE ur.user_id = a.user_id
                   ORDER BY CASE ur.role_code
                     WHEN 'ADMIN' THEN 1
                     WHEN 'MANAGER' THEN 2
                     WHEN 'APPROVER' THEN 3
                     WHEN 'PLANNER' THEN 4
                     ELSE 5
                   END
                   LIMIT 1
                ),
                'VIEWER'
              ) AS role_code,
              a.available_balance,
              a.updated_at,
              COALESCE((
                SELECT SUM(CASE WHEN l.event_type = 'TREASURY_GRANT' THEN l.delta ELSE 0 END)
                  FROM ontology.task_budget_ledger l
                 WHERE l.user_id = a.user_id
              ), 0) AS granted_total,
              COALESCE((
                SELECT SUM(CASE WHEN l.event_type = 'TASK_PAYOUT' THEN l.delta ELSE 0 END)
                  FROM ontology.task_budget_ledger l
                 WHERE l.user_id = a.user_id
              ), 0) AS paid_total,
              COALESCE((
                SELECT SUM(h.amount)
                  FROM ontology.task_budget_hold h
                 WHERE h.requester_user_id = a.user_id
                   AND h.status = 'LOCKED'
              ), 0) AS locked_total,
              COALESCE((
                SELECT SUM(r.points)
                  FROM ontology.recognition_point_event r
                 WHERE r.user_id = a.user_id
              ), 0) + COALESCE((
                SELECT SUM(s.recognition_points_delta)
                  FROM ontology.task_reward_sanction_event s
                 WHERE s.user_id = a.user_id
              ), 0) AS recognition_points_total
            FROM ontology.task_budget_account a
            LEFT JOIN ontology.app_user u
              ON u.user_id = a.user_id
            WHERE a.user_id = %s
            LIMIT 1
            """,
            [_trim_profile_text(user_id)],
        )
        row = cur.fetchone()
        if row is None:
            return None
        return dict(zip([desc[0] for desc in cur.description], row))
    finally:
        try:
            cur.close()
        except Exception:
            pass


def _list_task_budget_account_rows(registry: RunRegistry, *, limit: int = 1000) -> List[Dict[str, Any]]:
    if not registry.conn:
        raise HTTPException(status_code=503, detail="task token backend unavailable: database error")
    _require_task_token_tables(registry)
    cur = registry.conn.cursor()
    try:
        cur.execute(
            """
            WITH active_users AS (
              SELECT
                u.user_id,
                COALESCE(u.employee_no, '') AS employee_no,
                COALESCE(u.display_name, '') AS display_name,
                COALESCE(
                  (
                    SELECT ura.role_code
                      FROM ontology.app_user_role_assignment ura
                     WHERE ura.user_id = u.user_id
                       AND ura.starts_at <= now()
                       AND (ura.expires_at IS NULL OR ura.expires_at > now())
                       AND ura.revoked_at IS NULL
                     ORDER BY ura.starts_at DESC, ura.assignment_id DESC
                     LIMIT 1
                  ),
                  (
                    SELECT ur.role_code
                      FROM ontology.app_user_role ur
                     WHERE ur.user_id = u.user_id
                     ORDER BY CASE ur.role_code
                       WHEN 'ADMIN' THEN 1
                       WHEN 'MANAGER' THEN 2
                       WHEN 'APPROVER' THEN 3
                       WHEN 'PLANNER' THEN 4
                       ELSE 5
                     END
                     LIMIT 1
                  ),
                  'VIEWER'
                ) AS role_code
              FROM ontology.app_user u
              WHERE u.is_active = true
            ),
            grant_rows AS (
              SELECT user_id, COALESCE(SUM(delta), 0) AS granted_total
                FROM ontology.task_budget_ledger
               WHERE event_type = 'TREASURY_GRANT'
               GROUP BY user_id
            ),
            payout_rows AS (
              SELECT user_id, COALESCE(SUM(delta), 0) AS paid_total
                FROM ontology.task_budget_ledger
               WHERE event_type = 'TASK_PAYOUT'
               GROUP BY user_id
            ),
            lock_rows AS (
              SELECT requester_user_id AS user_id, COALESCE(SUM(amount), 0) AS locked_total
                FROM ontology.task_budget_hold
               WHERE status = 'LOCKED'
               GROUP BY requester_user_id
            ),
            recognition_rows AS (
              SELECT user_id, COALESCE(SUM(points), 0) AS recognition_points_total
                FROM ontology.recognition_point_event
               GROUP BY user_id
            ),
            recognition_adjustment_rows AS (
              SELECT user_id, COALESCE(SUM(recognition_points_delta), 0) AS recognition_points_adjustment_total
                FROM ontology.task_reward_sanction_event
               GROUP BY user_id
            )
            SELECT
              u.user_id,
              u.employee_no,
              u.display_name,
              u.role_code,
              COALESCE(a.available_balance, 0) AS available_balance,
              COALESCE(g.granted_total, 0) AS granted_total,
              COALESCE(l.locked_total, 0) AS locked_total,
              COALESCE(p.paid_total, 0) AS paid_total,
              COALESCE(r.recognition_points_total, 0) + COALESCE(ra.recognition_points_adjustment_total, 0) AS recognition_points_total,
              a.updated_at
            FROM active_users u
            LEFT JOIN ontology.task_budget_account a
              ON a.user_id = u.user_id
            LEFT JOIN grant_rows g
              ON g.user_id = u.user_id
            LEFT JOIN payout_rows p
              ON p.user_id = u.user_id
            LEFT JOIN lock_rows l
              ON l.user_id = u.user_id
            LEFT JOIN recognition_rows r
              ON r.user_id = u.user_id
            LEFT JOIN recognition_adjustment_rows ra
              ON ra.user_id = u.user_id
            ORDER BY
              CASE u.role_code
                WHEN 'ADMIN' THEN 1
                WHEN 'MANAGER' THEN 2
                WHEN 'APPROVER' THEN 3
                WHEN 'PLANNER' THEN 4
                ELSE 5
              END,
              u.employee_no ASC,
              u.user_id ASC
            LIMIT %s
            """,
            [int(max(1, limit))],
        )
        rows = cur.fetchall() or []
        return [dict(zip([desc[0] for desc in cur.description], row)) for row in rows]
    finally:
        try:
            cur.close()
        except Exception:
            pass


def _list_task_budget_ledger_rows(
    registry: RunRegistry,
    *,
    limit: int = 100,
    user_id: str | None = None,
) -> List[Dict[str, Any]]:
    if not registry.conn:
        raise HTTPException(status_code=503, detail="task token backend unavailable: database error")
    _require_task_token_tables(registry)
    cur = registry.conn.cursor()
    try:
        normalized_user_id = _trim_profile_text(user_id) or None
        cur.execute(
            """
            WITH actor_roles AS (
              SELECT
                u.user_id,
                COALESCE(
                  (
                    SELECT ura.role_code
                      FROM ontology.app_user_role_assignment ura
                     WHERE ura.user_id = u.user_id
                       AND ura.starts_at <= now()
                       AND (ura.expires_at IS NULL OR ura.expires_at > now())
                       AND ura.revoked_at IS NULL
                     ORDER BY ura.starts_at DESC, ura.assignment_id DESC
                     LIMIT 1
                  ),
                  (
                    SELECT ur.role_code
                      FROM ontology.app_user_role ur
                     WHERE ur.user_id = u.user_id
                     ORDER BY CASE ur.role_code
                       WHEN 'ADMIN' THEN 1
                       WHEN 'MANAGER' THEN 2
                       WHEN 'APPROVER' THEN 3
                       WHEN 'PLANNER' THEN 4
                       ELSE 5
                     END
                     LIMIT 1
                  ),
                  'VIEWER'
                ) AS role_code
              FROM ontology.app_user u
            )
            SELECT
              l.budget_event_id,
              l.user_id,
              l.employee_no,
              COALESCE(u.display_name, l.user_id) AS display_name,
              COALESCE(ur.role_code, 'VIEWER') AS role_code,
              l.task_id,
              l.event_type,
              l.delta,
              l.balance_after,
              l.counterparty_user_id,
              COALESCE(cp.employee_no, '') AS counterparty_employee_no,
              COALESCE(cp.display_name, '') AS counterparty_display_name,
              COALESCE(cpr.role_code, NULL) AS counterparty_role_code,
              l.receipt_id,
              l.meta_json,
              l.created_at
            FROM ontology.task_budget_ledger l
            LEFT JOIN ontology.app_user u
              ON u.user_id = l.user_id
            LEFT JOIN actor_roles ur
              ON ur.user_id = l.user_id
            LEFT JOIN ontology.app_user cp
              ON cp.user_id = l.counterparty_user_id
            LEFT JOIN actor_roles cpr
              ON cpr.user_id = l.counterparty_user_id
            WHERE (%s IS NULL OR l.user_id = %s OR l.counterparty_user_id = %s)
            ORDER BY l.created_at DESC, l.budget_event_id DESC
            LIMIT %s
            """,
            [normalized_user_id, normalized_user_id, normalized_user_id, int(max(1, limit))],
        )
        rows = cur.fetchall() or []
        return [dict(zip([desc[0] for desc in cur.description], row)) for row in rows]
    finally:
        try:
            cur.close()
        except Exception:
            pass


