def _list_task_budget_hold_rows(
    registry: RunRegistry,
    *,
    limit: int = 100,
    user_id: str | None = None,
) -> List[Dict[str, Any]]:
    if not registry.conn:
        raise HTTPException(status_code=503, detail="task token backend unavailable: database error")
    _require_task_token_tables(registry)
    cur = registry.conn.cursor()
    try:
        normalized_user_id = _trim_profile_text(user_id) or None
        cur.execute(
            """
            SELECT
              h.hold_id,
              h.task_id,
              h.requester_user_id,
              COALESCE(rq.employee_no, '') AS requester_employee_no,
              COALESCE(rq.display_name, h.requester_user_id) AS requester_display_name,
              h.reviewer_user_id,
              COALESCE(rv.employee_no, '') AS reviewer_employee_no,
              COALESCE(rv.display_name, '') AS reviewer_display_name,
              h.assignee_user_id,
              COALESCE(au.employee_no, '') AS assignee_employee_no,
              COALESCE(au.display_name, h.assignee_user_id) AS assignee_display_name,
              h.amount,
              h.status,
              h.lock_event_id,
              h.release_event_id,
              h.payout_event_id,
              h.meta_json,
              h.created_at,
              h.updated_at
            FROM ontology.task_budget_hold h
            LEFT JOIN ontology.app_user rq
              ON rq.user_id = h.requester_user_id
            LEFT JOIN ontology.app_user rv
              ON rv.user_id = h.reviewer_user_id
            LEFT JOIN ontology.app_user au
              ON au.user_id = h.assignee_user_id
            WHERE (
              %s IS NULL
              OR h.requester_user_id = %s
              OR h.assignee_user_id = %s
              OR h.reviewer_user_id = %s
            )
            ORDER BY
              CASE h.status
                WHEN 'LOCKED' THEN 1
                WHEN 'PAID' THEN 2
                WHEN 'RELEASED' THEN 3
                ELSE 4
              END,
              h.updated_at DESC,
              h.hold_id DESC
            LIMIT %s
            """,
            [normalized_user_id, normalized_user_id, normalized_user_id, normalized_user_id, int(max(1, limit))],
        )
        rows = cur.fetchall() or []
        return [dict(zip([desc[0] for desc in cur.description], row)) for row in rows]
    finally:
        try:
            cur.close()
        except Exception:
            pass


