def _insert_task_reward_sanction_event(
    cur,
    *,
    registry: RunRegistry,
    user_id: str,
    employee_no: str,
    approved_by_user_id: str | None,
    approved_by_employee_no: str | None,
    action_type: str,
    budget_token_delta: int = 0,
    recognition_points_delta: int = 0,
    reason: str | None,
    task_id: str | None,
    receipt_id: str | None,
    meta_json: Dict[str, Any] | None = None,
) -> Dict[str, Any]:
    _require_task_token_tables(registry)
    normalized_budget_delta = int(budget_token_delta)
    normalized_recognition_delta = int(recognition_points_delta)
    if normalized_budget_delta == 0 and normalized_recognition_delta == 0:
        raise HTTPException(status_code=400, detail="sanction delta is empty")
    sanction_event_id = f"san_{uuid.uuid4().hex[:12]}"
    cur.execute(
        """
        INSERT INTO ontology.task_reward_sanction_event (
          sanction_event_id,
          user_id,
          employee_no,
          task_id,
          approved_by_user_id,
          approved_by_employee_no,
          action_type,
          budget_token_delta,
          recognition_points_delta,
          reason,
          receipt_id,
          meta_json,
          created_at
        ) VALUES (%s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s::jsonb, now())
        """,
        [
          sanction_event_id,
          _trim_profile_text(user_id),
          _trim_profile_text(employee_no),
          _trim_profile_text(task_id) or None,
          _trim_profile_text(approved_by_user_id) or None,
          _trim_profile_text(approved_by_employee_no) or None,
          _trim_profile_text(action_type).upper() or "COMBINED_ADJUSTMENT",
          normalized_budget_delta,
          normalized_recognition_delta,
          _trim_profile_text(reason) or None,
          _trim_profile_text(receipt_id) or None,
          json.dumps(meta_json or {}, ensure_ascii=False),
        ],
    )
    return {
        "sanction_event_id": sanction_event_id,
        "budget_token_delta": normalized_budget_delta,
        "recognition_points_delta": normalized_recognition_delta,
    }


def _apply_task_reward_sanction_action(
    registry: RunRegistry,
    *,
    actor: Dict[str, Any],
    target_user_id: str,
    budget_token_slash: int,
    recognition_points_slash: int,
    reason: str,
    task_id: str | None = None,
) -> TaskBudgetSanctionResponse:
    _require_task_write_tables(registry)
    _require_task_token_tables(registry)
    if not registry.conn:
        raise HTTPException(status_code=503, detail="task token backend unavailable: database error")
    if _trim_profile_text(actor.get("actor_role")).upper() not in {"ADMIN", "MANAGER"}:
        raise HTTPException(status_code=403, detail="예산/보상 제재는 관리자 또는 매니저만 처리할 수 있습니다.")
    normalized_budget_slash = _parse_non_negative_int(budget_token_slash, field_name="budget_token_slash")
    normalized_recognition_slash = _parse_non_negative_int(
        recognition_points_slash,
        field_name="recognition_points_slash",
    )
    normalized_reason = _trim_profile_text(reason)
    if not normalized_reason:
        raise HTTPException(status_code=400, detail="reason is required")
    if normalized_budget_slash <= 0 and normalized_recognition_slash <= 0:
        raise HTTPException(status_code=400, detail="at least one sanction amount is required")

    target = registry.fetch_app_user_by_id(target_user_id)
    if target is None:
        raise HTTPException(status_code=404, detail="target_user_id not found")

    current_account = _fetch_task_budget_account_row(registry, user_id=_trim_profile_text(target_user_id))
    current_recognition_total = int(current_account.get("recognition_points_total") or 0) if current_account else 0
    if normalized_recognition_slash > current_recognition_total:
        raise HTTPException(status_code=409, detail="인정 포인트 누적보다 큰 제재는 적용할 수 없습니다.")

    request_id = f"REQ_TASK_SANCTION_{uuid.uuid4().hex[:10].upper()}"
    receipt_id = _create_operation_receipt(
        registry,
        action_key="task_reward.sanction",
        entity_type="task_budget_account",
        entity_id=_trim_profile_text(target_user_id),
        request_id=request_id,
        actor=actor,
        status="RUNNING",
    )
    cur = registry.conn.cursor()
    try:
        budget_event = None
        treasury = _fetch_task_budget_treasury_row(registry) or {"treasury_id": "MAIN", "total_supply": 0, "available_balance": 0}
        if normalized_budget_slash > 0:
            budget_event = _adjust_task_budget_account(
                cur,
                registry=registry,
                user_id=_trim_profile_text(target_user_id) or "",
                employee_no=_trim_profile_text(target.get("employee_no")) or "",
                delta=-normalized_budget_slash,
                event_type="ADMIN_SLASH",
                task_id=task_id,
                counterparty_user_id=_trim_profile_text(actor.get("actor_id")) or None,
                receipt_id=receipt_id,
                meta_json={
                    "reason": normalized_reason,
                    "approved_by_user_id": _trim_profile_text(actor.get("actor_id")) or None,
                    "task_id": _trim_profile_text(task_id) or None,
                },
            )
            treasury = _adjust_task_budget_treasury(
                cur,
                delta=normalized_budget_slash,
                meta_json={
                    "action": "ADMIN_SLASH",
                    "target_user_id": _trim_profile_text(target_user_id) or "",
                    "approved_by_user_id": _trim_profile_text(actor.get("actor_id")) or None,
                    "reason": normalized_reason,
                },
            )
        sanction_event = _insert_task_reward_sanction_event(
            cur,
            registry=registry,
            user_id=_trim_profile_text(target_user_id) or "",
            employee_no=_trim_profile_text(target.get("employee_no")) or "",
            approved_by_user_id=_trim_profile_text(actor.get("actor_id")) or None,
            approved_by_employee_no=_trim_profile_text(actor.get("employee_no")) or None,
            action_type=(
                "COMBINED_ADJUSTMENT"
                if normalized_budget_slash > 0 and normalized_recognition_slash > 0
                else "BUDGET_SLASH"
                if normalized_budget_slash > 0
                else "RECOGNITION_SLASH"
            ),
            budget_token_delta=-normalized_budget_slash,
            recognition_points_delta=-normalized_recognition_slash,
            reason=normalized_reason,
            task_id=task_id,
            receipt_id=receipt_id,
            meta_json={
                "approved_by_display_name": _trim_profile_text(actor.get("display_name")) or None,
                "budget_event_id": budget_event["budget_event_id"] if budget_event else None,
            },
        )
        registry.conn.commit()
        treasury_row = _fetch_task_budget_treasury_row(registry) or treasury
        account_row = _fetch_task_budget_account_row(registry, user_id=_trim_profile_text(target_user_id) or "")
        _update_operation_receipt(
            registry,
            receipt_id=receipt_id,
            status="SUCCEEDED",
            meta={
                "request_id": request_id,
                "result_ref": {
                    "entity_id": _trim_profile_text(target_user_id) or "",
                    "sanction_event_id": sanction_event["sanction_event_id"],
                },
            },
            ended=True,
        )
        _insert_audit_event(
            registry,
            receipt_id=receipt_id,
            event_type="TASK_REWARD_SANCTION_APPLIED",
            actor=actor,
            payload_json={
                "domain": "TASK",
                "type": "TASK_REWARD_SANCTION_APPLIED",
                "target_user_id": _trim_profile_text(target_user_id) or "",
                "budget_token_slashed": normalized_budget_slash,
                "recognition_points_slashed": normalized_recognition_slash,
                "reason": normalized_reason,
                "task_id": _trim_profile_text(task_id) or None,
            },
        )
        return TaskBudgetSanctionResponse(
            request_id=request_id,
            receipt_id=receipt_id,
            treasury=_to_task_budget_treasury_record(treasury_row),
            account=_to_task_budget_account_record(account_row or {
                "user_id": _trim_profile_text(target_user_id) or "",
                "employee_no": _trim_profile_text(target.get("employee_no")) or "",
                "display_name": _trim_profile_text(target.get("display_name")) or "",
                "role_code": "VIEWER",
                "available_balance": 0,
                "granted_total": 0,
                "locked_total": 0,
                "paid_total": 0,
                "recognition_points_total": max(0, current_recognition_total - normalized_recognition_slash),
                "updated_at": datetime.utcnow(),
            }),
            budget_token_slashed=normalized_budget_slash,
            recognition_points_slashed=normalized_recognition_slash,
        )
    except HTTPException:
        try:
            registry.conn.rollback()
        except Exception:
            pass
        _update_operation_receipt(
            registry,
            receipt_id=receipt_id,
            status="FAILED",
            error={"message": "task reward sanction rejected"},
            ended=True,
        )
        raise
    except Exception as exc:
        try:
            registry.conn.rollback()
        except Exception:
            pass
        _update_operation_receipt(
            registry,
            receipt_id=receipt_id,
            status="FAILED",
            error={"message": str(exc)},
            ended=True,
        )
        raise HTTPException(status_code=503, detail=f"task reward sanction backend unavailable: {exc}") from exc
    finally:
        try:
            cur.close()
        except Exception:
            pass


def _grant_task_budget_from_treasury_action(
    registry: RunRegistry,
    *,
    actor: Dict[str, Any],
    recipient_user_id: str,
    amount: int,
    note: str | None,
) -> TaskBudgetGrantResponse:
    _require_task_write_tables(registry)
    _require_task_token_tables(registry)
    if not registry.conn:
        raise HTTPException(status_code=503, detail="task token backend unavailable: database error")
    if _trim_profile_text(actor.get("actor_role")).upper() not in {"ADMIN", "MANAGER"}:
        raise HTTPException(status_code=403, detail="예산 토큰 지급은 관리자 또는 매니저만 처리할 수 있습니다.")
    recipient = registry.fetch_app_user_by_id(recipient_user_id)
    if recipient is None:
        raise HTTPException(status_code=404, detail="recipient_user_id not found")
    request_id = f"REQ_TASK_BUDGET_{uuid.uuid4().hex[:10].upper()}"
    receipt_id = _create_operation_receipt(
        registry,
        action_key="task_budget.grant",
        entity_type="task_budget_account",
        entity_id=_trim_profile_text(recipient_user_id),
        request_id=request_id,
        actor=actor,
        status="RUNNING",
    )
    cur = registry.conn.cursor()
    try:
        treasury = _adjust_task_budget_treasury(
            cur,
            delta=-int(amount),
            meta_json={
                "granted_by_user_id": _trim_profile_text(actor.get("actor_id")) or None,
                "recipient_user_id": _trim_profile_text(recipient_user_id),
                "note": _trim_profile_text(note) or None,
                "action": "TREASURY_GRANT",
            },
        )
        ledger_event = _adjust_task_budget_account(
            cur,
            registry=registry,
            user_id=_trim_profile_text(recipient_user_id),
            employee_no=_trim_profile_text(recipient.get("employee_no")) or "",
            delta=int(amount),
            event_type="TREASURY_GRANT",
            task_id=None,
            counterparty_user_id=_trim_profile_text(actor.get("actor_id")) or None,
            receipt_id=receipt_id,
            meta_json={
                "granted_by_user_id": _trim_profile_text(actor.get("actor_id")) or None,
                "granted_by_employee_no": _trim_profile_text(actor.get("employee_no")) or None,
                "note": _trim_profile_text(note) or None,
            },
        )
        registry.conn.commit()
        treasury_row = _fetch_task_budget_treasury_row(registry)
        account_row = _fetch_task_budget_account_row(registry, user_id=_trim_profile_text(recipient_user_id))
        _update_operation_receipt(
            registry,
            receipt_id=receipt_id,
            status="SUCCEEDED",
            meta={
                "request_id": request_id,
                "result_ref": {
                    "entity_id": _trim_profile_text(recipient_user_id),
                    "budget_event_id": ledger_event["budget_event_id"],
                },
            },
            ended=True,
        )
        _insert_audit_event(
            registry,
            receipt_id=receipt_id,
            event_type="TASK_BUDGET_GRANTED",
            actor=actor,
            payload_json={
                "domain": "TASK",
                "type": "TASK_BUDGET_GRANTED",
                "recipient_user_id": _trim_profile_text(recipient_user_id),
                "amount": int(amount),
                "note": _trim_profile_text(note) or None,
                "treasury_available_balance": treasury["available_balance"],
            },
        )
        return TaskBudgetGrantResponse(
            request_id=request_id,
            receipt_id=receipt_id,
            treasury=_to_task_budget_treasury_record(treasury_row or treasury),
            account=_to_task_budget_account_record(account_row or {
                "user_id": _trim_profile_text(recipient_user_id),
                "employee_no": _trim_profile_text(recipient.get("employee_no")) or "",
                "display_name": _trim_profile_text(recipient.get("display_name")) or "",
                "role_code": "VIEWER",
                "available_balance": ledger_event["balance_after"],
                "granted_total": int(amount),
                "locked_total": 0,
                "paid_total": 0,
                "recognition_points_total": 0,
                "updated_at": datetime.utcnow(),
            }),
            granted_amount=int(amount),
        )
    except HTTPException:
        try:
            registry.conn.rollback()
        except Exception:
            pass
        _update_operation_receipt(
            registry,
            receipt_id=receipt_id,
            status="FAILED",
            error={"message": "task budget grant rejected"},
            ended=True,
        )
        raise
    except Exception as exc:
        try:
            registry.conn.rollback()
        except Exception:
            pass
        _update_operation_receipt(
            registry,
            receipt_id=receipt_id,
            status="FAILED",
            error={"message": str(exc)},
            ended=True,
        )
        raise HTTPException(status_code=503, detail=f"task budget grant backend unavailable: {exc}") from exc
    finally:
        try:
            cur.close()
        except Exception:
            pass


def _list_task_budget_accounts_action(
    registry: RunRegistry,
    *,
    actor: Dict[str, Any],
    limit: int = 1000,
) -> TaskBudgetAccountsResponse:
    _require_task_write_tables(registry)
    _require_task_token_tables(registry)
    if not registry.conn:
        raise HTTPException(status_code=503, detail="task token backend unavailable: database error")
    if _trim_profile_text(actor.get("actor_role")).upper() not in {"ADMIN", "MANAGER"}:
        raise HTTPException(status_code=403, detail="예산 토큰 계정은 관리자 또는 매니저만 조회할 수 있습니다.")
    treasury_row = _fetch_task_budget_treasury_row(registry)
    if treasury_row is None:
        raise HTTPException(status_code=503, detail="task budget treasury is not initialized")
    account_rows = _list_task_budget_account_rows(registry, limit=limit)
    return TaskBudgetAccountsResponse(
        treasury=_to_task_budget_treasury_record(treasury_row),
        rows=[_to_task_budget_account_record(row) for row in account_rows],
    )


def _get_task_budget_account_for_actor_action(
    registry: RunRegistry,
    *,
    actor: Dict[str, Any],
) -> TaskBudgetAccountRecord:
    _require_task_write_tables(registry)
    _require_task_token_tables(registry)
    if not registry.conn:
        raise HTTPException(status_code=503, detail="task token backend unavailable: database error")
    actor_user_id = _trim_profile_text(actor.get("actor_id"))
    if not actor_user_id:
        raise HTTPException(status_code=401, detail="actor_id missing")
    actor_user = registry.fetch_app_user_by_id(actor_user_id)
    if actor_user is None:
        raise HTTPException(status_code=404, detail="actor user not found")
    account_row = _fetch_task_budget_account_row(registry, user_id=actor_user_id)
    if account_row is None:
        account_row = {
            "user_id": actor_user_id,
            "employee_no": _trim_profile_text(actor_user.get("employee_no")) or "",
            "display_name": _trim_profile_text(actor_user.get("display_name")) or "",
            "role_code": _trim_profile_text(actor.get("actor_role")).upper() or "VIEWER",
            "available_balance": 0,
            "granted_total": 0,
            "locked_total": 0,
            "paid_total": 0,
            "recognition_points_total": 0,
            "updated_at": datetime.utcnow(),
        }
    return _to_task_budget_account_record(account_row)


def _list_task_budget_history_action(
    registry: RunRegistry,
    *,
    actor: Dict[str, Any],
    limit: int = 100,
    user_id: str | None = None,
) -> TaskBudgetHistoryResponse:
    _require_task_write_tables(registry)
    _require_task_token_tables(registry)
    if not registry.conn:
        raise HTTPException(status_code=503, detail="task token backend unavailable: database error")
    if _trim_profile_text(actor.get("actor_role")).upper() not in {"ADMIN", "MANAGER"}:
        raise HTTPException(status_code=403, detail="예산/보상 감사 내역은 관리자 또는 매니저만 조회할 수 있습니다.")
    treasury_row = _fetch_task_budget_treasury_row(registry)
    if treasury_row is None:
        raise HTTPException(status_code=503, detail="task budget treasury is not initialized")
    ledger_rows = _list_task_budget_ledger_rows(registry, limit=limit, user_id=user_id)
    recognition_rows = _list_recognition_point_event_rows(registry, limit=limit, user_id=user_id)
    sanction_rows = _list_task_reward_sanction_rows(registry, limit=limit, user_id=user_id)
    hold_rows = _list_task_budget_hold_rows(registry, limit=limit, user_id=user_id)
    suspicious_rows = _list_task_reward_suspicious_rows(registry, limit=min(limit, 20))
    return TaskBudgetHistoryResponse(
        treasury=_to_task_budget_treasury_record(treasury_row),
        ledger_rows=[_to_task_budget_ledger_event_record(row) for row in ledger_rows],
        recognition_rows=[_to_recognition_point_event_record(row) for row in recognition_rows],
        sanction_rows=[_to_task_reward_sanction_event_record(row) for row in sanction_rows],
        hold_rows=[_to_task_budget_hold_record(row) for row in hold_rows],
        suspicious_rows=[_to_task_reward_suspicious_case_record(row) for row in suspicious_rows],
        generated_at=datetime.utcnow(),
    )


