def _task_assignment_detail_row_from_inbox_row(row: Dict[str, Any]) -> Dict[str, Any]:
    context = _jsonb_to_obj(row.get("context_json"))
    assigned_user = _trim_profile_text(row.get("assigned_user"))
    assigned_role = _trim_profile_text(row.get("assigned_role"))
    assigned_to_type = "USER" if assigned_user else "ROLE" if assigned_role else "LINE" if _trim_profile_text(context.get("line_id")) else "USER"
    assigned_to_id = assigned_user or assigned_role or _trim_profile_text(context.get("line_id")) or "UNKNOWN"
    task_type = _trim_profile_text(row.get("task_type")) or "ISSUE_EXPLANATION"
    return {
        "task_id": _trim_profile_text(row.get("task_id")),
        "task_type": task_type,
        "title": _trim_profile_text(row.get("note")) or _trim_profile_text(context.get("title")) or task_type,
        "description": _trim_profile_text(context.get("description")) or task_type,
        "created_by_type": "AI",
        "created_by_user_id": _trim_profile_text(context.get("requester_user_id")) or None,
        "assigned_to_type": assigned_to_type,
        "assigned_to_id": assigned_to_id,
        "plant_id": _trim_profile_text(context.get("plant_id")) or None,
        "line_id": _trim_profile_text(context.get("line_id")) or None,
        "equipment_id": _trim_profile_text(context.get("equipment_id")) or None,
        "run_id": _trim_profile_text(context.get("run_id") or context.get("entity_id")) or None,
        "due_at": row.get("due_at"),
        "difficulty": "LOW",
        "evidence_required": bool(context.get("evidence_required")),
        "score_policy_id": _trim_profile_text(context.get("score_policy_id")) or "TASK_DEFAULT",
        "status": "ASSIGNED" if _trim_profile_text(row.get("status")).upper() == "OPEN" else _trim_profile_text(row.get("status")).upper() or "ASSIGNED",
        "request_id": _trim_profile_text(context.get("request_id")) or None,
        "receipt_id": _trim_profile_text(context.get("receipt_id")) or None,
        "meta_json": context,
        "created_at": row.get("created_at"),
        "updated_at": row.get("updated_at"),
    }


