def _fetch_task_assignment_detail_row(registry: RunRegistry, task_id: str) -> Dict[str, Any] | None:
    if not registry.conn:
        raise HTTPException(status_code=503, detail="task detail backend unavailable: database error")
    cur = registry.conn.cursor()
    try:
        cur.execute(
            """
            SELECT
              task_id,
              task_type,
              title,
              description,
              created_by_type,
              created_by_user_id,
              assigned_to_type,
              assigned_to_id,
              plant_id,
              line_id,
              equipment_id,
              run_id,
              due_at,
              difficulty,
              evidence_required,
              score_policy_id,
              status,
              request_id,
              receipt_id,
              meta_json,
              created_at,
              updated_at
            FROM ontology.task_assignment
            WHERE task_id = %s
            LIMIT 1
            """,
            [_trim_profile_text(task_id)],
        )
        row = cur.fetchone()
        if row is None:
            return None
        return dict(zip([desc[0] for desc in cur.description], row))
    finally:
        try:
            cur.close()
        except Exception:
            pass


