def _create_scrap_row(
    registry: RunRegistry,
    *,
    actor: Dict[str, Any],
    receipt_id: str,
    payload: Dict[str, Any],
) -> Dict[str, Any]:
    _ensure_backend_tables(
        registry,
        operation="production scrap",
        tables=["scrap_record", "operation_receipt"],
    )
    if not registry.conn:
        raise HTTPException(status_code=503, detail="production scrap backend unavailable: database error")
    row = {
        "id": _trim_profile_text(payload.get("id")) or f"SCRAP_{uuid.uuid4().hex[:12].upper()}",
        "lot_id": _trim_profile_text(payload.get("lot_id")) or "",
        "item_name": _trim_profile_text(payload.get("item_name")) or "",
        "reason": _trim_profile_text(payload.get("reason")) or "사유 미입력",
        "qty": max(0.0, float(payload.get("qty") or 0.0)),
        "line_id": _trim_profile_text(payload.get("line_id")) or "",
        "operator": _trim_profile_text(payload.get("operator")) or _trim_profile_text(actor.get("employee_no")) or _trim_profile_text(actor.get("actor_id")) or "",
        "created_at": datetime.now(timezone.utc).isoformat(),
        "status": "REQUESTED",
        "cancelled_at": None,
        "receipt_id": receipt_id,
    }
    cur = registry.conn.cursor()
    try:
        cur.execute(
            """
            INSERT INTO ontology.scrap_record
              (id, lot_id, item_name, reason, qty, line_id, operator, created_at, status, cancelled_at)
            VALUES (%s, %s, %s, %s, %s, %s, %s, %s::timestamptz, %s, %s)
            """,
            [
                row["id"],
                row["lot_id"],
                row["item_name"],
                row["reason"],
                row["qty"],
                row["line_id"],
                row["operator"],
                row["created_at"],
                row["status"],
                row["cancelled_at"],
            ],
        )
        registry.conn.commit()
    except Exception as exc:
        try:
            registry.conn.rollback()
        except Exception:
            pass
        raise HTTPException(status_code=503, detail=f"production scrap backend unavailable: {exc}") from exc
    finally:
        try:
            cur.close()
        except Exception:
            pass
    _insert_audit_event(
        registry,
        receipt_id=receipt_id,
        event_type="PRODUCTION_SCRAP_CREATED",
        actor=actor,
        payload_json={
            "domain": "PRODUCTION",
            "type": "SCRAP_CREATED",
            "scrap_id": row["id"],
            "line_id": row["line_id"],
            "lot_id": row["lot_id"],
            "qty": row["qty"],
            "reason": row["reason"],
        },
    )
    return row


def _cancel_scrap_row(
    registry: RunRegistry,
    *,
    actor: Dict[str, Any],
    receipt_id: str,
    scrap_id: str,
) -> Dict[str, Any]:
    _ensure_backend_tables(
        registry,
        operation="production scrap cancel",
        tables=["scrap_record", "operation_receipt"],
    )
    if not registry.conn:
        raise HTTPException(status_code=503, detail="production scrap backend unavailable: database error")
    cur = registry.conn.cursor()
    try:
        cur.execute(
            """
            UPDATE ontology.scrap_record
               SET status = 'CANCELLED',
                   cancelled_at = now()
             WHERE id = %s
         RETURNING id, lot_id, item_name, reason, qty::float8, line_id, operator, created_at, status, cancelled_at
            """,
            [_trim_profile_text(scrap_id)],
        )
        row = cur.fetchone()
        if row is None:
            registry.conn.rollback()
            raise HTTPException(status_code=404, detail="scrap_id not found")
        registry.conn.commit()
        columns = ["id", "lot_id", "item_name", "reason", "qty", "line_id", "operator", "created_at", "status", "cancelled_at"]
        out = dict(zip(columns, row))
    except HTTPException:
        raise
    except Exception as exc:
        try:
            registry.conn.rollback()
        except Exception:
            pass
        raise HTTPException(status_code=503, detail=f"production scrap backend unavailable: {exc}") from exc
    finally:
        try:
            cur.close()
        except Exception:
            pass
    _insert_audit_event(
        registry,
        receipt_id=receipt_id,
        event_type="PRODUCTION_SCRAP_CANCELLED",
        actor=actor,
        payload_json={
            "domain": "PRODUCTION",
            "type": "SCRAP_CANCELLED",
            "scrap_id": out["id"],
            "line_id": out["line_id"],
            "lot_id": out["lot_id"],
        },
    )
    return out


def _next_numeric_id(registry: RunRegistry, *, table: str, column: str, prefix: str) -> str:
    if not registry.conn:
        raise HTTPException(status_code=503, detail="backend unavailable: database error")
    cur = registry.conn.cursor()
    try:
        cur.execute(
            f"""
            SELECT COALESCE(MAX(CAST(SUBSTRING({column} FROM '[0-9]+$') AS integer)), 0) + 1 AS next_seq
              FROM {table}
             WHERE {column} ~ '[0-9]+$'
            """
        )
        row = cur.fetchone()
        next_seq = int((row or [1])[0] or 1)
        return f"{prefix}-{next_seq:04d}"
    finally:
        try:
            cur.close()
        except Exception:
            pass


def _next_opaque_id(prefix: str) -> str:
    return f"{prefix}-{uuid.uuid4().hex[:8].upper()}"


def _normalize_lims_sample_type(value: Any) -> str:
    normalized = str(value or "").strip().upper()
    return normalized if normalized in {"RAW", "WIP", "FG"} else "FG"


def _apply_lims_spec_to_pending_requests(
    registry: RunRegistry,
    *,
    item_id: str,
    sample_type: str,
    analyte: str,
    unit: str,
    min_val: float,
    max_val: float,
) -> None:
    if not registry.conn:
        raise HTTPException(status_code=503, detail="LIMS backend unavailable: database error")
    cur = registry.conn.cursor()
    try:
        cur.execute(
            """
            UPDATE ontology.lims_test_request req
               SET unit = %s,
                   min_val = %s,
                   max_val = %s
              FROM ontology.lims_sample sample
             WHERE req.sample_id = sample.sample_id
               AND req.status <> 'COMPLETED'
               AND sample.item_id = %s
               AND sample.sample_type = %s
               AND upper(trim(req.analyte)) = upper(trim(%s))
            """,
            [unit, min_val, max_val, item_id, sample_type, analyte],
        )
        registry.conn.commit()
    except Exception:
        try:
            registry.conn.rollback()
        except Exception:
            pass
        raise
    finally:
        try:
            cur.close()
        except Exception:
            pass


def _create_lims_sample_records(
    registry: RunRegistry,
    *,
    lot_id: str,
    run_id: str | None,
    item_id: str,
    sample_type: str,
    actor_id: str,
) -> Dict[str, Any]:
    _ensure_backend_tables(
        registry,
        operation="LIMS sample create",
        tables=["lims_sample", "lims_test_request", "lims_spec"],
    )
    if not registry.conn:
        raise HTTPException(status_code=503, detail="LIMS backend unavailable: database error")
    now_iso = datetime.now(timezone.utc).isoformat()
    sample_id = _next_numeric_id(registry, table="ontology.lims_sample", column="sample_id", prefix="SMP")
    sample = {
        "sample_id": sample_id,
        "lot_id": lot_id,
        "run_id": _trim_profile_text(run_id) or "RUN-UNKNOWN",
        "item_id": item_id,
        "sample_type": sample_type,
        "status": "REQUESTED",
        "collected_by": actor_id,
        "collected_at": now_iso,
        "created_at": now_iso,
    }
    cur = registry.conn.cursor()
    try:
        cur.execute(
            """
            INSERT INTO ontology.lims_sample (
              sample_id, lot_id, run_id, item_id, sample_type, status, collected_by, collected_at, created_at
            ) VALUES (%s, %s, %s, %s, %s, %s, %s, %s::timestamptz, %s::timestamptz)
            """,
            [
                sample["sample_id"],
                sample["lot_id"],
                sample["run_id"],
                sample["item_id"],
                sample["sample_type"],
                sample["status"],
                sample["collected_by"],
                sample["collected_at"],
                sample["created_at"],
            ],
        )
        cur.execute(
            """
            SELECT analyte, unit, min_val::float8, max_val::float8
              FROM ontology.lims_spec
             WHERE item_id = %s
               AND sample_type = %s
               AND is_active = true
             ORDER BY analyte ASC, version DESC, updated_at DESC
            """,
            [item_id, sample_type],
        )
        spec_rows = cur.fetchall() or []
        request_rows: List[Dict[str, Any]] = []
        seeds = spec_rows or [("기본 검사", "unit", 0.0, 100.0)]
        for analyte, unit, min_val, max_val in seeds:
            request_id = _next_numeric_id(registry, table="ontology.lims_test_request", column="request_id", prefix="REQ")
            request_row = {
                "request_id": request_id,
                "sample_id": sample_id,
                "lot_id": lot_id,
                "item_id": item_id,
                "analyte": str(analyte or "").strip() or "기본 검사",
                "unit": str(unit or "").strip() or "unit",
                "min_val": float(min_val or 0.0),
                "max_val": float(max_val or 0.0),
                "status": "PENDING",
                "requested_at": now_iso,
                "requested_by": actor_id,
            }
            cur.execute(
                """
                INSERT INTO ontology.lims_test_request (
                  request_id, sample_id, lot_id, item_id, analyte, unit, min_val, max_val, status, requested_at, requested_by
                ) VALUES (%s, %s, %s, %s, %s, %s, %s, %s, %s, %s::timestamptz, %s)
                """,
                [
                    request_row["request_id"],
                    request_row["sample_id"],
                    request_row["lot_id"],
                    request_row["item_id"],
                    request_row["analyte"],
                    request_row["unit"],
                    request_row["min_val"],
                    request_row["max_val"],
                    request_row["status"],
                    request_row["requested_at"],
                    request_row["requested_by"],
                ],
            )
            request_rows.append(request_row)
        registry.conn.commit()
        return {"sample": sample, "requests": request_rows}
    except Exception as exc:
        try:
            registry.conn.rollback()
        except Exception:
            pass
        raise HTTPException(status_code=503, detail=f"LIMS backend unavailable: {exc}") from exc
    finally:
        try:
            cur.close()
        except Exception:
            pass


def _create_lims_sample_action(
    registry: RunRegistry,
    *,
    actor: Dict[str, Any],
    receipt_id: str,
    payload: Dict[str, Any],
) -> Dict[str, Any]:
    actor_id = _trim_profile_text(actor.get("actor_id")) or _trim_profile_text(actor.get("employee_no")) or "UNKNOWN"
    lot_id = _trim_profile_text(payload.get("lot_id"))
    item_id = _trim_profile_text(payload.get("item_id")) or "ITEM-001"
    if not lot_id:
        raise HTTPException(status_code=400, detail="lot_id는 필수입니다.")
    created = _create_lims_sample_records(
        registry,
        lot_id=lot_id,
        run_id=_trim_profile_text(payload.get("run_id")),
        item_id=item_id,
        sample_type=_normalize_lims_sample_type(payload.get("sample_type")),
        actor_id=actor_id,
    )
    _insert_audit_event(
        registry,
        receipt_id=receipt_id,
        event_type="LIMS_SAMPLE_CREATED",
        actor=actor,
        payload_json={
            "domain": "LIMS",
            "type": "SAMPLE_CREATED",
            "sample_id": created["sample"]["sample_id"],
            "lot_id": created["sample"]["lot_id"],
            "run_id": created["sample"]["run_id"],
            "item_id": created["sample"]["item_id"],
            "sample_type": created["sample"]["sample_type"],
            "request_ids": [row["request_id"] for row in created["requests"]],
        },
    )
    return created


def _submit_lims_result_action(
    registry: RunRegistry,
    *,
    actor: Dict[str, Any],
    receipt_id: str,
    payload: Dict[str, Any],
) -> Dict[str, Any]:
    _ensure_backend_tables(
        registry,
        operation="LIMS result submit",
        tables=["lims_test_request", "lims_test_result", "lims_sample"],
    )
    if not registry.conn:
        raise HTTPException(status_code=503, detail="LIMS backend unavailable: database error")
    request_id = _trim_profile_text(payload.get("request_id"))
    measured_value = payload.get("measured_value")
    actor_id = _trim_profile_text(actor.get("actor_id")) or _trim_profile_text(actor.get("employee_no")) or "UNKNOWN"
    if not request_id:
        raise HTTPException(status_code=400, detail="request_id는 필수입니다.")
    try:
        measured_float = float(measured_value)
    except Exception as exc:
        raise HTTPException(status_code=400, detail=f"measured_value가 유효하지 않습니다: {exc}") from exc
    cur = registry.conn.cursor()
    try:
        cur.execute(
            """
            SELECT request_id, sample_id, lot_id, item_id, analyte, unit, min_val::float8, max_val::float8, status, requested_at::text, requested_by
              FROM ontology.lims_test_request
             WHERE request_id = %s
             LIMIT 1
            """,
            [request_id],
        )
        request_row = cur.fetchone()
        if request_row is None:
            raise HTTPException(status_code=404, detail="검사 요청을 찾을 수 없습니다.")
        request_columns = [desc[0] for desc in cur.description]
        request_data = dict(zip(request_columns, request_row))
        result_status = "PASS" if float(request_data["min_val"]) <= measured_float <= float(request_data["max_val"]) else "OOS"
        now_iso = datetime.now(timezone.utc).isoformat()
        result_id = _next_numeric_id(registry, table="ontology.lims_test_result", column="result_id", prefix="RES")
        cur.execute(
            """
            INSERT INTO ontology.lims_test_result (
              result_id, request_id, sample_id, analyte, measured_value, unit, status, entered_by, measured_at, created_at
            ) VALUES (%s, %s, %s, %s, %s, %s, %s, %s, %s::timestamptz, %s::timestamptz)
            """,
            [
                result_id,
                request_id,
                request_data["sample_id"],
                request_data["analyte"],
                measured_float,
                request_data["unit"],
                result_status,
                actor_id,
                now_iso,
                now_iso,
            ],
        )
        cur.execute("UPDATE ontology.lims_test_request SET status = 'COMPLETED' WHERE request_id = %s", [request_id])
        cur.execute(
            """
            SELECT
              COUNT(*)::int AS total_count,
              COUNT(*) FILTER (WHERE req.status = 'COMPLETED')::int AS completed_count,
              COUNT(*) FILTER (WHERE res.status = 'OOS')::int AS oos_count
            FROM ontology.lims_test_request req
            LEFT JOIN ontology.lims_test_result res ON res.request_id = req.request_id
            WHERE req.sample_id = %s
            """,
            [request_data["sample_id"]],
        )
        total_count, completed_count, oos_count = cur.fetchone() or (0, 0, 0)
        sample_status = "TESTING"
        if int(oos_count or 0) > 0:
            sample_status = "OOS"
        elif int(total_count or 0) > 0 and int(total_count or 0) == int(completed_count or 0):
            sample_status = "COMPLETED"
        cur.execute(
            "UPDATE ontology.lims_sample SET status = %s WHERE sample_id = %s RETURNING sample_id, lot_id, run_id, item_id, sample_type, status, collected_by, collected_at::text, created_at::text",
            [sample_status, request_data["sample_id"]],
        )
        sample_row = cur.fetchone()
        sample_columns = [desc[0] for desc in cur.description]
        sample_data = dict(zip(sample_columns, sample_row)) if sample_row else None
        registry.conn.commit()
        result_data = {
            "result_id": result_id,
            "request_id": request_id,
            "sample_id": request_data["sample_id"],
            "analyte": request_data["analyte"],
            "measured_value": measured_float,
            "unit": request_data["unit"],
            "status": result_status,
            "entered_by": actor_id,
            "measured_at": now_iso,
            "created_at": now_iso,
        }
        _insert_audit_event(
            registry,
            receipt_id=receipt_id,
            event_type="LIMS_RESULT_SUBMITTED",
            actor=actor,
            payload_json={
                "domain": "LIMS",
                "type": "RESULT_SUBMITTED",
                "request_id": request_id,
                "sample_id": request_data["sample_id"],
                "lot_id": request_data["lot_id"],
                "result_id": result_id,
                "status": result_status,
            },
        )
        return {
            "request": {**request_data, "status": "COMPLETED"},
            "result": result_data,
            "sample": sample_data,
        }
    except HTTPException:
        try:
            registry.conn.rollback()
        except Exception:
            pass
        raise
    except Exception as exc:
        try:
            registry.conn.rollback()
        except Exception:
            pass
        raise HTTPException(status_code=503, detail=f"LIMS backend unavailable: {exc}") from exc
    finally:
        try:
            cur.close()
        except Exception:
            pass


def _validate_lims_approval_actor(registry: RunRegistry, *, lot_id: str, actor_id: str) -> List[str]:
    if not registry.conn:
        raise HTTPException(status_code=503, detail="LIMS backend unavailable: database error")
    cur = registry.conn.cursor()
    try:
        cur.execute(
            """
            SELECT DISTINCT res.entered_by
              FROM ontology.lims_test_result res
              JOIN ontology.lims_test_request req ON req.request_id = res.request_id
             WHERE req.lot_id = %s
               AND nullif(trim(res.entered_by), '') IS NOT NULL
            """,
            [lot_id],
        )
        inspector_ids = sorted({str((row or [""])[0] or "").strip() for row in (cur.fetchall() or []) if str((row or [""])[0] or "").strip()})
        if actor_id in inspector_ids:
            raise HTTPException(status_code=400, detail="검사자와 승인자는 분리되어야 합니다. 본인이 입력한 LOT는 승인할 수 없습니다.")
        return inspector_ids
    finally:
        try:
            cur.close()
        except Exception:
            pass


def _decide_lims_approval_action(
    registry: RunRegistry,
    *,
    actor: Dict[str, Any],
    receipt_id: str,
    payload: Dict[str, Any],
) -> Dict[str, Any]:
    _ensure_backend_tables(
        registry,
        operation="LIMS approval decide",
        tables=["lims_release_decision", "lims_report", "lims_test_result", "lims_test_request"],
    )
    if not registry.conn:
        raise HTTPException(status_code=503, detail="LIMS backend unavailable: database error")
    lot_id = _trim_profile_text(payload.get("lot_id"))
    decision = _trim_profile_text(payload.get("decision")).upper()
    comment = _trim_profile_text(payload.get("comment")) or ""
    actor_id = _trim_profile_text(actor.get("actor_id")) or _trim_profile_text(actor.get("employee_no")) or "UNKNOWN"
    if not lot_id:
        raise HTTPException(status_code=400, detail="lot_id는 필수입니다.")
    if decision not in {"RELEASE", "HOLD", "REJECT"}:
        raise HTTPException(status_code=400, detail="decision은 RELEASE/HOLD/REJECT 중 하나여야 합니다.")
    inspector_ids = _validate_lims_approval_actor(registry, lot_id=lot_id, actor_id=actor_id)
    cur = registry.conn.cursor()
    try:
        now_iso = datetime.now(timezone.utc).isoformat()
        decision_id = _next_numeric_id(registry, table="ontology.lims_release_decision", column="decision_id", prefix="DEC")
        cur.execute(
            """
            INSERT INTO ontology.lims_release_decision (
              decision_id, lot_id, decision, decided_by, comment, decided_at
            ) VALUES (%s, %s, %s, %s, %s, %s::timestamptz)
            """,
            [decision_id, lot_id, decision, actor_id, comment, now_iso],
        )
        report: Dict[str, Any] | None = None
        if decision == "RELEASE":
            report_id = _next_numeric_id(registry, table="ontology.lims_report", column="report_id", prefix="COA")
            report = {
                "report_id": report_id,
                "lot_id": lot_id,
                "decision_id": decision_id,
                "decision": "RELEASE",
                "generated_by": actor_id,
                "generated_at": now_iso,
                "report_name": f"{report_id}-{lot_id}.pdf",
                "report_url": f"/api/inspection/reports/{report_id}/download",
            }
            cur.execute(
                """
                INSERT INTO ontology.lims_report (
                  report_id, lot_id, decision_id, decision, generated_by, generated_at, report_name, report_url
                ) VALUES (%s, %s, %s, %s, %s, %s::timestamptz, %s, %s)
                """,
                [
                    report["report_id"],
                    report["lot_id"],
                    report["decision_id"],
                    report["decision"],
                    report["generated_by"],
                    report["generated_at"],
                    report["report_name"],
                    report["report_url"],
                ],
            )
        registry.conn.commit()
        decision_row = {
            "decision_id": decision_id,
            "lot_id": lot_id,
            "decision": decision,
            "decided_by": actor_id,
            "comment": comment,
            "decided_at": now_iso,
        }
        _insert_audit_event(
            registry,
            receipt_id=receipt_id,
            event_type="LIMS_APPROVAL_DECIDED",
            actor=actor,
            payload_json={
                "domain": "LIMS",
                "type": "APPROVAL_DECIDED",
                "lot_id": lot_id,
                "decision_id": decision_id,
                "decision": decision,
                "report_id": report.get("report_id") if report else None,
                "inspector_ids": inspector_ids,
            },
        )
        return {"decision": decision_row, "report": report}
    except HTTPException:
        try:
            registry.conn.rollback()
        except Exception:
            pass
        raise
    except Exception as exc:
        try:
            registry.conn.rollback()
        except Exception:
            pass
        raise HTTPException(status_code=503, detail=f"LIMS backend unavailable: {exc}") from exc
    finally:
        try:
            cur.close()
        except Exception:
            pass


def _upsert_lims_spec_action(
    registry: RunRegistry,
    *,
    actor: Dict[str, Any],
    receipt_id: str,
    payload: Dict[str, Any],
) -> Dict[str, Any]:
    _ensure_backend_tables(
        registry,
        operation="LIMS spec upsert",
        tables=["lims_spec", "lims_test_request", "lims_sample"],
    )
    if not registry.conn:
        raise HTTPException(status_code=503, detail="LIMS backend unavailable: database error")
    item_id = _trim_profile_text(payload.get("item_id")) or "ITEM-001"
    sample_type = _normalize_lims_sample_type(payload.get("sample_type"))
    analyte = _trim_profile_text(payload.get("analyte"))
    unit = _trim_profile_text(payload.get("unit"))
    spec_id = _trim_profile_text(payload.get("spec_id"))
    create_new_version = bool(payload.get("create_new_version") is True)
    is_active = bool(payload.get("is_active") is not False)
    try:
        min_val = float(payload.get("min_val"))
        max_val = float(payload.get("max_val"))
        target_val = float(payload.get("target_val"))
    except Exception as exc:
        raise HTTPException(status_code=400, detail=f"규격 수치가 유효하지 않습니다: {exc}") from exc
    if not analyte or not unit:
        raise HTTPException(status_code=400, detail="analyte, unit은 필수입니다.")
    cur = registry.conn.cursor()
    try:
        now_iso = datetime.now(timezone.utc).isoformat()
        created_or_updated: Dict[str, Any]
        if spec_id:
            cur.execute(
                """
                SELECT spec_id, root_spec_id, supersedes_spec_id, version, item_id, sample_type, analyte, unit,
                       min_val::float8, max_val::float8, target_val::float8, is_active, updated_at::text
                  FROM ontology.lims_spec
                 WHERE spec_id = %s
                 LIMIT 1
                """,
                [spec_id],
            )
            row = cur.fetchone()
            columns = [desc[0] for desc in cur.description]
            existing = dict(zip(columns, row)) if row else None
            if existing and create_new_version:
                cur.execute(
                    "UPDATE ontology.lims_spec SET is_active = false, updated_at = %s::timestamptz WHERE spec_id = %s",
                    [now_iso, spec_id],
                )
                created_or_updated = {
                    "spec_id": _next_opaque_id("SPEC"),
                    "root_spec_id": _trim_profile_text(existing.get("root_spec_id")) or spec_id,
                    "supersedes_spec_id": spec_id,
                    "version": int(existing.get("version") or 1) + 1,
                    "item_id": item_id,
                    "sample_type": sample_type,
                    "analyte": analyte,
                    "unit": unit,
                    "min_val": min_val,
                    "max_val": max_val,
                    "target_val": target_val,
                    "is_active": is_active,
                    "updated_at": now_iso,
                }
                cur.execute(
                    """
                    INSERT INTO ontology.lims_spec (
                      spec_id, root_spec_id, supersedes_spec_id, version, item_id, sample_type, analyte, unit,
                      min_val, max_val, target_val, is_active, updated_at
                    ) VALUES (%s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s::timestamptz)
                    """,
                    [
                        created_or_updated["spec_id"],
                        created_or_updated["root_spec_id"],
                        created_or_updated["supersedes_spec_id"],
                        created_or_updated["version"],
                        created_or_updated["item_id"],
                        created_or_updated["sample_type"],
                        created_or_updated["analyte"],
                        created_or_updated["unit"],
                        created_or_updated["min_val"],
                        created_or_updated["max_val"],
                        created_or_updated["target_val"],
                        created_or_updated["is_active"],
                        created_or_updated["updated_at"],
                    ],
                )
            elif existing:
                created_or_updated = {
                    **existing,
                    "item_id": item_id,
                    "sample_type": sample_type,
                    "analyte": analyte,
                    "unit": unit,
                    "min_val": min_val,
                    "max_val": max_val,
                    "target_val": target_val,
                    "is_active": is_active,
                    "updated_at": now_iso,
                }
                cur.execute(
                    """
                    UPDATE ontology.lims_spec
                       SET item_id = %s,
                           sample_type = %s,
                           analyte = %s,
                           unit = %s,
                           min_val = %s,
                           max_val = %s,
                           target_val = %s,
                           is_active = %s,
                           updated_at = %s::timestamptz
                     WHERE spec_id = %s
                    """,
                    [item_id, sample_type, analyte, unit, min_val, max_val, target_val, is_active, now_iso, spec_id],
                )
            else:
                created_or_updated = {
                    "spec_id": spec_id,
                    "root_spec_id": spec_id,
                    "supersedes_spec_id": None,
                    "version": 1,
                    "item_id": item_id,
                    "sample_type": sample_type,
                    "analyte": analyte,
                    "unit": unit,
                    "min_val": min_val,
                    "max_val": max_val,
                    "target_val": target_val,
                    "is_active": is_active,
                    "updated_at": now_iso,
                }
                cur.execute(
                    """
                    INSERT INTO ontology.lims_spec (
                      spec_id, root_spec_id, supersedes_spec_id, version, item_id, sample_type, analyte, unit,
                      min_val, max_val, target_val, is_active, updated_at
                    ) VALUES (%s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s::timestamptz)
                    """,
                    [
                        created_or_updated["spec_id"],
                        created_or_updated["root_spec_id"],
                        created_or_updated["supersedes_spec_id"],
                        created_or_updated["version"],
                        created_or_updated["item_id"],
                        created_or_updated["sample_type"],
                        created_or_updated["analyte"],
                        created_or_updated["unit"],
                        created_or_updated["min_val"],
                        created_or_updated["max_val"],
                        created_or_updated["target_val"],
                        created_or_updated["is_active"],
                        created_or_updated["updated_at"],
                    ],
                )
        else:
            new_spec_id = _next_opaque_id("SPEC")
            created_or_updated = {
                "spec_id": new_spec_id,
                "root_spec_id": new_spec_id,
                "supersedes_spec_id": None,
                "version": 1,
                "item_id": item_id,
                "sample_type": sample_type,
                "analyte": analyte,
                "unit": unit,
                "min_val": min_val,
                "max_val": max_val,
                "target_val": target_val,
                "is_active": is_active,
                "updated_at": now_iso,
            }
            cur.execute(
                """
                INSERT INTO ontology.lims_spec (
                  spec_id, root_spec_id, supersedes_spec_id, version, item_id, sample_type, analyte, unit,
                  min_val, max_val, target_val, is_active, updated_at
                ) VALUES (%s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s::timestamptz)
                """,
                [
                    created_or_updated["spec_id"],
                    created_or_updated["root_spec_id"],
                    created_or_updated["supersedes_spec_id"],
                    created_or_updated["version"],
                    created_or_updated["item_id"],
                    created_or_updated["sample_type"],
                    created_or_updated["analyte"],
                    created_or_updated["unit"],
                    created_or_updated["min_val"],
                    created_or_updated["max_val"],
                    created_or_updated["target_val"],
                    created_or_updated["is_active"],
                    created_or_updated["updated_at"],
                ],
            )
        registry.conn.commit()
        if created_or_updated["is_active"]:
            _apply_lims_spec_to_pending_requests(
                registry,
                item_id=item_id,
                sample_type=sample_type,
                analyte=analyte,
                unit=unit,
                min_val=min_val,
                max_val=max_val,
            )
        _insert_audit_event(
            registry,
            receipt_id=receipt_id,
            event_type="LIMS_SPEC_UPSERTED",
            actor=actor,
            payload_json={
                "domain": "LIMS",
                "type": "SPEC_UPSERTED",
                "spec_id": created_or_updated["spec_id"],
                "root_spec_id": created_or_updated["root_spec_id"],
                "version": created_or_updated["version"],
                "item_id": item_id,
                "sample_type": sample_type,
                "analyte": analyte,
            },
        )
        return created_or_updated
    except HTTPException:
        try:
            registry.conn.rollback()
        except Exception:
            pass
        raise
    except Exception as exc:
        try:
            registry.conn.rollback()
        except Exception:
            pass
        raise HTTPException(status_code=503, detail=f"LIMS backend unavailable: {exc}") from exc
    finally:
        try:
            cur.close()
        except Exception:
            pass


