@app.get("/v1/analytics/oee/summary")
def oee_summary(request: Request) -> dict:
    """Plant-wide OEE summary with per-line breakdown."""
    registry = RunRegistry(Config())
    if not registry.conn:
        raise ApiError("DB_NOT_CONNECTED", "Database connection required", 503)
    cur = registry.conn.cursor()
    cur.execute("""
        SELECT line_id, line_name, status, bpm_target, bpm_actual,
               today_produced, today_target, today_defects, downtime_min_today,
               staff_count, availability, performance, quality, oee_current
        FROM ontology.dt_line_state ORDER BY line_id
    """)
    cols = [d[0] for d in cur.description]
    rows = [dict(zip(cols, r)) for r in cur.fetchall()]

    lines = []
    total_oee = 0.0
    running_count = 0
    for d in rows:
        oee = float(d.get("oee_current") or 0)
        lines.append({
            "line_id": d.get("line_id"),
            "line_name": d.get("line_name"),
            "status": d.get("status"),
            "availability_pct": float(d.get("availability") or 0),
            "performance_pct": float(d.get("performance") or 0),
            "quality_pct": float(d.get("quality") or 0),
            "oee_pct": oee,
            "today_produced": int(d.get("today_produced") or 0),
            "today_target": int(d.get("today_target") or 0),
            "today_defects": int(d.get("today_defects") or 0),
            "downtime_min": int(d.get("downtime_min_today") or 0),
            "staff_count": int(d.get("staff_count") or 0),
            "bpm_actual": float(d.get("bpm_actual") or 0),
            "bpm_target": float(d.get("bpm_target") or 0),
        })
        if d.get("status") == "RUNNING":
            total_oee += oee
            running_count += 1

    return {
        "plant_oee_pct": round(total_oee / max(1, running_count), 1),
        "running_lines": running_count,
        "total_lines": len(rows),
        "lines": lines,
    }


@app.get("/v1/analytics/oee/ranking")
def oee_ranking(request: Request) -> dict:
    """OEE ranking — lines sorted by OEE descending."""
    registry = RunRegistry(Config())
    if not registry.conn:
        raise ApiError("DB_NOT_CONNECTED", "Database connection required", 503)
    cur = registry.conn.cursor()
    cur.execute("""
        SELECT line_id, line_name, status, oee_current, availability, performance, quality
        FROM ontology.dt_line_state
        WHERE status = 'RUNNING' AND oee_current > 0
        ORDER BY oee_current DESC
    """)
    cols = [d[0] for d in cur.description]
    rows = [dict(zip(cols, r)) for r in cur.fetchall()]
    return {
        "ranking": [
            {
                "rank": i + 1,
                "line_id": d["line_id"],
                "line_name": d.get("line_name"),
                "oee_pct": float(d.get("oee_current") or 0),
                "availability_pct": float(d.get("availability") or 0),
                "performance_pct": float(d.get("performance") or 0),
                "quality_pct": float(d.get("quality") or 0),
            }
            for i, d in enumerate(rows)
        ],
        "total_running": len(rows),
    }


