def _measure_db_latency_ms(registry: RunRegistry) -> int | None:
    if not registry.conn:
        return None
    started = time.time()
    cur = registry.conn.cursor()
    try:
        cur.execute("SELECT 1")
        _ = cur.fetchone()
        return int(max(0.0, (time.time() - started) * 1000.0))
    except Exception:
        return None
    finally:
        try:
            cur.close()
        except Exception:
            pass


def _fetch_last_run_info(registry: RunRegistry) -> dict[str, Any]:
    payload: dict[str, Any] = {
        "run_id": None,
        "finished_at": None,
        "status": None,
        "solver_status": None,
        "wall_time_sec": None,
    }
    if not registry.conn:
        return payload

    cur = registry.conn.cursor()
    try:
        table = "solver_run_log" if registry._table_exists("solver_run_log") else "solver_run"
        sql = f"""
        SELECT run_id, finished_at, status, trace_json
        FROM {registry.schema}.{table}
        ORDER BY finished_at DESC NULLS LAST
        LIMIT 1
        """
        cur.execute(sql)
        row = cur.fetchone()
        if row is None:
            return payload
        
        payload["run_id"] = str(row[0]) if row[0] is not None else None
        payload["finished_at"] = row[1].isoformat() if row[1] is not None else None
        payload["status"] = str(row[2]) if row[2] is not None else None
        
        trace = row[3] if len(row) > 3 and row[3] else {}
        if isinstance(trace, str):
            try:
                trace = json.loads(trace)
            except Exception:
                trace = {}
        
        payload["solver_status"] = str(trace.get("solve_status")) if trace.get("solve_status") is not None else None
        
        # Calculate wall_time_sec from started_at_utc and finished_at_utc in trace_json
        start_utc_str = trace.get("started_at_utc")
        finish_utc_str = trace.get("finished_at_utc")
        if start_utc_str and finish_utc_str:
            try:
                from datetime import datetime
                fmt = "%Y-%m-%dT%H:%M:%S"
                start_dt = datetime.fromisoformat(start_utc_str.replace("Z", "+00:00"))
                finish_dt = datetime.fromisoformat(finish_utc_str.replace("Z", "+00:00"))
                payload["wall_time_sec"] = round((finish_dt - start_dt).total_seconds(), 2)
            except Exception:
                pass

        return payload
    except Exception:
        return payload
    finally:
        try:
            cur.close()
        except Exception:
            pass


def _coerce_readyz_timestamp(value: Any, *, fallback_ts: float | None = None) -> datetime | None:
    tzinfo = datetime.now().astimezone().tzinfo or timezone.utc
    text = _clean_text(value)
    if text:
        try:
            dt = datetime.fromisoformat(text.replace("Z", "+00:00"))
            if dt.tzinfo is None:
                dt = dt.replace(tzinfo=tzinfo)
            return dt
        except Exception:
            pass
    if fallback_ts is None:
        return None
    try:
        return datetime.fromtimestamp(float(fallback_ts), tz=tzinfo)
    except Exception:
        return None


def _fetch_latest_bundle_run_info(logs_dir: Path | None = None) -> dict[str, Any]:
    payload: dict[str, Any] = {
        "run_id": None,
        "finished_at": None,
        "status": None,
        "solver_status": None,
        "wall_time_sec": None,
    }
    if logs_dir is None:
        repo_root = Path(__file__).resolve().parents[2]
        logs_dir = repo_root / "out" / "logs"
    if not logs_dir.exists():
        return payload

    manifests = sorted(logs_dir.glob("*_manifest.json"), key=lambda p: p.stat().st_mtime, reverse=True)
    if not manifests:
        return payload

    manifest_path = manifests[0]
    try:
        manifest = json.loads(manifest_path.read_text(encoding="utf-8"))
    except Exception:
        return payload

    solver_meta = manifest.get("solver_meta") if isinstance(manifest.get("solver_meta"), dict) else {}
    pass_stats = solver_meta.get("pass_stats") if isinstance(solver_meta.get("pass_stats"), list) else []
    overall_status = None
    for item in pass_stats:
        if not isinstance(item, dict):
            continue
        if _clean_text(item.get("scope")).upper() == "TOTAL":
            overall_status = _clean_text(item.get("status")) or None
            break

    finished_dt = _coerce_readyz_timestamp(
        manifest.get("created_at_local"),
        fallback_ts=manifest_path.stat().st_mtime,
    )
    raw_exit_code = manifest.get("exit_code", 1)
    try:
        exit_code = int(raw_exit_code) if raw_exit_code is not None else 1
    except Exception:
        exit_code = 1
    payload["run_id"] = _clean_text(manifest.get("run_id")) or None
    payload["finished_at"] = finished_dt.isoformat() if finished_dt is not None else None
    payload["status"] = "SUCCESS" if exit_code == 0 else "FAILED"
    payload["solver_status"] = overall_status
    try:
        wall_time = solver_meta.get("wall_time_sec_total")
        payload["wall_time_sec"] = round(float(wall_time), 2) if wall_time is not None else None
    except Exception:
        payload["wall_time_sec"] = None
    return payload


def _select_readyz_last_run_info(*payloads: dict[str, Any]) -> dict[str, Any]:
    best: dict[str, Any] = {
        "run_id": None,
        "finished_at": None,
        "status": None,
        "solver_status": None,
        "wall_time_sec": None,
    }
    best_finished: datetime | None = None
    for payload in payloads:
        finished_dt = _coerce_readyz_timestamp(payload.get("finished_at"))
        if finished_dt is None:
            if best_finished is None and _clean_text(payload.get("run_id")):
                best = dict(payload)
            continue
        if best_finished is None or finished_dt >= best_finished:
            best = dict(payload)
            best_finished = finished_dt
    return best


