def _refresh_operational_metrics() -> None:
    _METRIC_API_UPTIME_SECONDS.set(max(0.0, time.time() - _APP_STARTED_AT))
    _METRIC_PLAN_CHANGE_ARTIFACT_STORAGE_CONFIGURED.set(1 if _plan_change_gcs_bucket_name() else 0)
    _METRIC_AI_ENABLED.set(1 if _readyz_ai_payload().get("enabled") else 0)
    _METRIC_SENTRY_CONFIGURED.set(1 if _readyz_observability_payload().get("sentry_configured") else 0)
    current_worker_mode = _solver_worker_launch_mode()
    for mode in ("subprocess", "service"):
        _METRIC_SOLVER_WORKER_MODE.labels(mode=mode).set(1 if current_worker_mode == mode else 0)
    db_connected = 0
    registry = None
    try:
        registry = RunRegistry(Config())
        db_connected = 1 if bool(registry.conn) else 0
    except Exception:
        db_connected = 0
    finally:
        try:
            if registry is not None:
                registry.close()
        except Exception:
            pass
    _METRIC_DB_CONNECTED.set(db_connected)


@app.get("/readyz")
def readyz():
    uptime_sec = int(max(0.0, time.time() - _APP_STARTED_AT))
    ssot_path = _find_runtime_ssot_path() or _find_latest_ssot_path()
    ssot_obj = {
        "path": str(ssot_path) if ssot_path is not None else "",
        "exists": bool(ssot_path is not None and ssot_path.exists()),
        "sha256": _sha256_hex_cached(ssot_path) if ssot_path is not None and ssot_path.exists() else "",
    }

    try:
        registry = RunRegistry(Config())
    except ValueError as exc:
        return JSONResponse(
            status_code=503,
            content={
                "status": "not_ready",
                "reason": "invalid_db_config",
                "detail": str(exc),
                "db": {"connected": False, "latency_ms": None},
                "ssot": ssot_obj,
                "artifact_storage": _readyz_artifact_storage_payload(),
                "worker": _readyz_worker_payload(),
                "ai": _readyz_ai_payload(),
                "observability": _readyz_observability_payload(),
                "last_run": {"run_id": None, "finished_at": None, "status": None},
                "solver": {"last_run_wall_time_sec": None, "last_status": None},
                "uptime_sec": uptime_sec,
            },
        )
    try:
        db_connected = bool(registry.conn)
        db_latency_ms = _measure_db_latency_ms(registry)
        last_run = _select_readyz_last_run_info(
            _fetch_last_run_info(registry),
            _fetch_latest_bundle_run_info(),
        )

        payload = {
            "status": "ok" if db_connected else "not_ready",
            "db": {"connected": db_connected, "latency_ms": db_latency_ms},
            "ssot": ssot_obj,
            "artifact_storage": _readyz_artifact_storage_payload(),
            "worker": _readyz_worker_payload(),
            "ai": _readyz_ai_payload(),
            "observability": _readyz_observability_payload(),
            "last_run": {
                "run_id": last_run.get("run_id"),
                "finished_at": last_run.get("finished_at"),
                "status": last_run.get("status")
            },
            "solver": {
                "last_run_wall_time_sec": last_run.get("wall_time_sec"),
                "last_status": last_run.get("solver_status")
            },
            "uptime_sec": uptime_sec,
        }

        if not db_connected:
            return JSONResponse(
                status_code=503,
                content=payload,
            )
        return payload
    finally:
        registry.close()


@app.get("/metrics", include_in_schema=False)
def metrics() -> Response:
    _refresh_operational_metrics()
    return Response(content=generate_latest(), media_type=CONTENT_TYPE_LATEST)


@app.get("/v1/ssot/info")
def get_ssot_info(
    actor_claims: Dict[str, Any] = Depends(get_current_actor),
) -> dict:
    try:
        registry = RunRegistry(Config())
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc
    try:
        _require_authenticated_user(registry, actor_claims)
        _ensure_kiosk_panel_backend_ready(registry)
    finally:
        registry.close()
    ssot_path = _find_latest_ssot_path()
    if ssot_path is None or not ssot_path.exists():
        raise ApiError(404, "SSOT 파일을 찾을 수 없습니다.")
    stat = ssot_path.stat()
    sheet_names: List[str] = []
    workbook = None
    try:
        workbook = load_workbook(filename=str(ssot_path), read_only=True, data_only=True)
        sheet_names = [str(n) for n in list(workbook.sheetnames)]
    finally:
        if workbook is not None:
            try:
                workbook.close()
            except Exception:
                pass

    return {
        "ssot_path": str(ssot_path),
        "file_size_bytes": int(stat.st_size),
        "last_modified": datetime.fromtimestamp(stat.st_mtime).isoformat(),
        "sha256": _sha256_hex(ssot_path),
        "sheet_names": sheet_names,
    }


