def _normalize_plan_change_params(params_json: Any) -> Dict[str, Any]:
    return dict(params_json) if isinstance(params_json, dict) else {}


def _sanitize_plan_change_user_params(params_json: Any) -> Dict[str, Any]:
    raw = _normalize_plan_change_params(params_json)
    return {
        str(key): value
        for key, value in raw.items()
        if isinstance(key, str) and key not in _PLAN_CHANGE_RESERVED_KEYS
    }


def _plan_change_scope_from_params(params_json: Dict[str, Any]) -> Dict[str, Any]:
    raw = params_json.get("__plan_scope")
    if not isinstance(raw, dict):
        raw = {}
    return {
        "plant_id": _trim_profile_text(raw.get("plant_id")) or None,
        "line_id": _trim_profile_text(raw.get("line_id")) or None,
    }


def _plan_change_artifacts_from_params(params_json: Dict[str, Any]) -> Dict[str, Dict[str, Any]]:
    raw = params_json.get("__artifacts")
    if not isinstance(raw, dict):
        return {}
    out: Dict[str, Dict[str, Any]] = {}
    for key, value in raw.items():
        if not isinstance(value, dict):
            continue
        normalized_key = _trim_profile_text(key)
        if not normalized_key:
            continue
        out[normalized_key] = dict(value)
    return out


def _plan_change_artifact_download_url(change_id: str, kind: str) -> str:
    return f"/v1/plan-changes/{change_id}/artifacts/{kind}/download"


def _plan_change_artifacts_for_response(change_id: str, params_json: Dict[str, Any]) -> Dict[str, Dict[str, Any]]:
    artifacts = _plan_change_artifacts_from_params(params_json)
    hydrated: Dict[str, Dict[str, Any]] = {}
    for kind, artifact in artifacts.items():
        hydrated[kind] = {
            **dict(artifact),
            "download_url": _plan_change_artifact_download_url(change_id, kind),
            "downloadable": bool(_trim_profile_text(artifact.get("stored_path"))),
        }
    return hydrated


def _plan_change_simulation_from_params(params_json: Dict[str, Any]) -> Dict[str, Any]:
    raw = params_json.get("__simulation")
    if not isinstance(raw, dict):
        raw = {}
    progress = raw.get("progress_pct")
    try:
        progress_pct = max(0, min(100, int(progress if progress is not None else 0)))
    except Exception:
        progress_pct = 0
    return {
        "status": _trim_profile_text(raw.get("status")) or "IDLE",
        "step": _trim_profile_text(raw.get("step")) or "",
        "progress_pct": progress_pct,
        "preview_only": bool(raw.get("preview_only", True)),
        "receipt_id": _trim_profile_text(raw.get("receipt_id")) or None,
        "result": dict(raw.get("result") or {}) if isinstance(raw.get("result"), dict) else {},
        "error": dict(raw.get("error") or {}) if isinstance(raw.get("error"), dict) else {},
        "updated_at": raw.get("updated_at"),
    }


def _plan_change_overlay_rows_from_params(params_json: Dict[str, Any]) -> Dict[str, List[Dict[str, Any]]]:
    raw = params_json.get("__overlay_rows")
    if not isinstance(raw, dict):
        return {}
    out: Dict[str, List[Dict[str, Any]]] = {}
    for key, value in raw.items():
        normalized_key = _trim_profile_text(key)
        if not normalized_key or not isinstance(value, list):
            continue
        rows: List[Dict[str, Any]] = []
        for item in value:
            if isinstance(item, dict):
                rows.append(dict(item))
        out[normalized_key] = rows
    return out


def _plan_change_public_params(params_json: Dict[str, Any]) -> Dict[str, Any]:
    return {
        str(key): value
        for key, value in params_json.items()
        if isinstance(key, str) and key not in _PLAN_CHANGE_RESERVED_KEYS
    }


def _plan_change_params_with_runtime(
    params_json: Dict[str, Any],
    *,
    plant_id: str | None = None,
    line_id: str | None = None,
    artifacts: Dict[str, Any] | None = None,
    simulation: Dict[str, Any] | None = None,
    overlay_rows: Dict[str, List[Dict[str, Any]]] | None = None,
) -> Dict[str, Any]:
    next_params = _normalize_plan_change_params(params_json)
    scope = _plan_change_scope_from_params(next_params)
    if plant_id is not None:
        scope["plant_id"] = _trim_profile_text(plant_id) or None
    if line_id is not None:
        scope["line_id"] = _trim_profile_text(line_id) or None
    next_params["__plan_scope"] = scope
    if artifacts is not None:
        next_params["__artifacts"] = artifacts
    if simulation is not None:
        next_params["__simulation"] = simulation
    if overlay_rows is not None:
        next_params["__overlay_rows"] = overlay_rows
    return next_params


def _build_plan_change_record(row: Dict[str, Any]) -> PlanChangeRecord:
    params_json = _normalize_plan_change_params(row.get("params_json"))
    scope = _plan_change_scope_from_params(params_json)
    change_id = _trim_profile_text(row.get("change_id"))
    return PlanChangeRecord(
        change_id=change_id,
        base_run_id=_trim_profile_text(row.get("base_run_id")),
        change_type=_trim_profile_text(row.get("change_type")),
        plant_id=scope.get("plant_id"),
        line_id=scope.get("line_id"),
        is_draft=True,
        type="SIMULATION",
        params_json=_plan_change_public_params(params_json),
        status=_trim_profile_text(row.get("status")) or "DRAFT",
        artifacts=_plan_change_artifacts_for_response(change_id, params_json),
        simulation=_plan_change_simulation_from_params(params_json),
        created_by=_trim_profile_text(row.get("created_by")),
        created_at=row.get("created_at"),
        updated_at=row.get("updated_at"),
    )


def _plan_change_issue_details_from_payload(payload: Dict[str, Any]) -> List[PlanChangeIssueDetail]:
    raw_details = payload.get("details")
    if not isinstance(raw_details, list):
        return []
    details: List[PlanChangeIssueDetail] = []
    for item in raw_details:
        if not isinstance(item, dict):
            continue
        row_no_raw = item.get("row_no")
        try:
            row_no = int(row_no_raw) if row_no_raw is not None else None
        except Exception:
            row_no = None
        details.append(
            PlanChangeIssueDetail(
                severity=_trim_profile_text(item.get("severity")) or "ERROR",
                code=_trim_profile_text(item.get("code")),
                sheet=_trim_profile_text(item.get("sheet")) or None,
                row_no=row_no,
                column_name=_trim_profile_text(item.get("column_name")) or None,
                message=_trim_profile_text(item.get("message")),
                value=_trim_profile_text(item.get("value")) or None,
                field=_trim_profile_text(item.get("field")) or None,
                file_name=_trim_profile_text(item.get("file_name")) or None,
                reason=_trim_profile_text(item.get("reason")) or None,
            )
        )
    return details


def _build_plan_change_issues_response(row: Dict[str, Any]) -> PlanChangeIssuesResponse:
    params_json = _normalize_plan_change_params(row.get("params_json"))
    simulation = _plan_change_simulation_from_params(params_json)
    error_payload = simulation.get("error") if isinstance(simulation.get("error"), dict) else {}
    error_code = _trim_profile_text(error_payload.get("error_code")) or ""
    if not error_code and simulation.get("status") == "CONTRACT_FAIL":
        error_code = "CONTRACT_FAIL"
    return PlanChangeIssuesResponse(
        change_id=_trim_profile_text(row.get("change_id")),
        is_draft=True,
        type="SIMULATION",
        status=_trim_profile_text(row.get("status")) or "DRAFT",
        simulation_status=_trim_profile_text(simulation.get("status")) or "IDLE",
        error_code=error_code,
        message=_trim_profile_text(error_payload.get("message")),
        details=_plan_change_issue_details_from_payload(error_payload),
    )


def _build_plan_change_result_response(row: Dict[str, Any]) -> PlanChangeResultResponse:
    params_json = _normalize_plan_change_params(row.get("params_json"))
    simulation = _plan_change_simulation_from_params(params_json)
    change_id = _trim_profile_text(row.get("change_id"))
    return PlanChangeResultResponse(
        change_id=change_id,
        is_draft=True,
        type="SIMULATION",
        status=_trim_profile_text(row.get("status")) or "DRAFT",
        simulation=simulation,
        artifacts=_plan_change_artifacts_for_response(change_id, params_json),
        result=dict(simulation.get("result") or {}) if isinstance(simulation.get("result"), dict) else {},
    )


def _require_plan_change_reader(
    registry: RunRegistry,
    actor_claims: Dict[str, Any],
) -> Dict[str, Any]:
    actor = _require_authenticated_user(registry, actor_claims)
    role = _trim_profile_text(actor.get("actor_role")) or "VIEWER"
    if role not in {"PLANNER", "APPROVER", "MANAGER", "ADMIN"}:
        raise HTTPException(status_code=403, detail="변경 초안은 계획자 이상 권한이 필요합니다.")
    return actor


def _require_plan_change_editor(
    registry: RunRegistry,
    actor_claims: Dict[str, Any],
    *,
    line_id: str | None,
) -> Dict[str, Any]:
    actor = _require_plan_change_reader(registry, actor_claims)
    role = _trim_profile_text(actor.get("actor_role")) or "VIEWER"
    if role not in {"PLANNER", "MANAGER", "ADMIN"}:
        raise HTTPException(status_code=403, detail="변경 초안 생성/시뮬레이션은 계획자 이상 권한이 필요합니다.")
    normalized_line_id = _trim_profile_text(line_id)
    if normalized_line_id and role == "PLANNER" and not _actor_has_line_scope(actor, normalized_line_id):
        raise HTTPException(status_code=403, detail="선택한 라인 범위를 수정할 권한이 없습니다.")
    return actor


def _actor_can_access_plan_change(
    registry: RunRegistry,
    actor: Dict[str, Any],
    row: Dict[str, Any],
) -> bool:
    if _trim_profile_text(actor.get("actor_role")) in {"ADMIN", "MANAGER"}:
        return True
    base_run_id = _trim_profile_text(row.get("base_run_id"))
    if base_run_id:
        run_row = registry.fetch_run(base_run_id)
        if run_row is not None and _actor_can_access_run(actor, run_row):
            return True
    created_by = _trim_profile_text(row.get("created_by"))
    actor_id = _trim_profile_text(actor.get("actor_id"))
    actor_email = _trim_profile_text(actor.get("actor_email"))
    return bool(created_by and (created_by == actor_id or created_by == actor_email))


def _enforce_actor_can_access_plan_change(
    registry: RunRegistry,
    actor: Dict[str, Any],
    row: Dict[str, Any],
) -> None:
    if _actor_can_access_plan_change(registry, actor, row):
        return
    raise HTTPException(status_code=403, detail="해당 변경 초안에 접근할 권한이 없습니다.")


def _ensure_plan_change_mutable(row: Dict[str, Any], *, operation: str) -> None:
    status = _trim_profile_text(row.get("status")) or "DRAFT"
    if status not in _PLAN_CHANGE_MUTABLE_STATUSES:
        raise HTTPException(
            status_code=409,
            detail=f"{operation}은(는) {status} 상태의 변경 초안에서는 허용되지 않습니다.",
        )


def _plan_change_gcs_bucket_name() -> str:
    return (os.getenv("BOHAE_PLAN_CHANGE_GCS_BUCKET") or "").strip()


def _plan_change_gcs_prefix() -> str:
    return (os.getenv("BOHAE_PLAN_CHANGE_GCS_PREFIX") or "plan_changes").strip().strip("/")


@lru_cache(maxsize=1)
def _plan_change_gcs_client() -> Any | None:
    bucket_name = _plan_change_gcs_bucket_name()
    if not bucket_name:
        return None
    try:
        from google.cloud import storage
    except Exception:
        return None
    try:
        return storage.Client()
    except Exception:
        return None


def _plan_change_storage_mode() -> str:
    return "gcs" if _plan_change_gcs_bucket_name() and _plan_change_gcs_client() is not None else "local"


def _plan_change_object_name(change_id: str, stored_name: str) -> str:
    prefix = _plan_change_gcs_prefix()
    if prefix:
        return f"{prefix}/{_trim_profile_text(change_id)}/inputs/{stored_name}"
    return f"{_trim_profile_text(change_id)}/inputs/{stored_name}"


def _store_plan_change_artifact_payload(*, change_id: str, stored_name: str, content: bytes) -> str:
    if _plan_change_storage_mode() == "gcs":
        bucket_name = _plan_change_gcs_bucket_name()
        client = _plan_change_gcs_client()
        if bucket_name and client is not None:
            object_name = _plan_change_object_name(change_id, stored_name)
            bucket = client.bucket(bucket_name)
            blob = bucket.blob(object_name)
            blob.upload_from_string(content, content_type="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet")
            return f"gs://{bucket_name}/{object_name}"
    store_dir = _plan_change_store_root() / _trim_profile_text(change_id) / "inputs"
    store_dir.mkdir(parents=True, exist_ok=True)
    stored_path = store_dir / stored_name
    stored_path.write_bytes(content)
    return str(stored_path)


def _read_plan_change_artifact_bytes(artifact: Dict[str, Any]) -> bytes:
    stored_path = str(artifact.get("stored_path") or "").strip()
    if not stored_path:
        raise FileNotFoundError("stored_path missing")
    if stored_path.startswith("gs://"):
        parsed = urlparse.urlparse(stored_path)
        bucket_name = parsed.netloc
        object_name = parsed.path.lstrip("/")
        client = _plan_change_gcs_client()
        if not bucket_name or not object_name or client is None:
            raise FileNotFoundError("gcs artifact unavailable")
        bucket = client.bucket(bucket_name)
        blob = bucket.blob(object_name)
        if not blob.exists():
            raise FileNotFoundError(stored_path)
        return blob.download_as_bytes()
    path = Path(stored_path).expanduser()
    if not path.exists():
        raise FileNotFoundError(stored_path)
    return path.read_bytes()


def _plan_change_store_root() -> Path:
    raw = str(os.getenv("BOHAE_PLAN_CHANGE_ARTIFACT_ROOT", "out/plan_changes")).strip() or "out/plan_changes"
    return Path(raw)


def _plan_change_error_payload(
    *,
    error_code: str,
    message: str,
    details: List[Dict[str, Any]] | None = None,
) -> Dict[str, Any]:
    payload: Dict[str, Any] = {
        "error_code": _trim_profile_text(error_code) or "FAILED",
        "message": _trim_profile_text(message) or "요청 처리에 실패했습니다.",
    }
    if details:
        payload["details"] = details
    return payload


def _normalize_plan_change_overlay_token(value: Any) -> str:
    text = str(value or "").strip().lower()
    if not text:
        return ""
    text = re.sub(r"[^\w가-힣]+", "_", text)
    return text.strip("_")


def _read_plan_change_sheet_profile(ws: Any) -> Dict[str, Any]:
    header_row_no: int | None = None
    raw_headers: List[str] = []
    normalized_headers: List[str] = []
    max_column = int(getattr(ws, "max_column", 0) or 0)
    for row_index, row in enumerate(ws.iter_rows(values_only=True), start=1):
        values = list(row)
        if not any(str(cell or "").strip() for cell in values):
            continue
        header_row_no = row_index
        raw_headers = [str(cell or "").strip() for cell in values[:max_column]]
        normalized_headers = [_normalize_plan_change_overlay_token(cell) for cell in raw_headers]
        break
    data_row_count = 0
    if header_row_no is not None:
        for row in ws.iter_rows(min_row=header_row_no + 1, values_only=True):
            if any(str(cell or "").strip() for cell in row):
                data_row_count += 1
    return {
        "header_row_no": header_row_no,
        "headers": raw_headers,
        "normalized_headers": normalized_headers,
        "data_row_count": data_row_count,
    }


def _summarize_uploaded_workbook(content: bytes, *, field_name: str, file_name: str) -> Dict[str, Any]:
    try:
        workbook = load_workbook(filename=BytesIO(content), read_only=True, data_only=True)
    except Exception as exc:
        raise HTTPException(
            status_code=422,
            detail=_plan_change_error_payload(
                error_code="ERR_INVALID_EXCEL",
                message=f"{field_name} 파일을 읽지 못했습니다.",
                details=[
                    {
                        "field": field_name,
                        "file_name": file_name,
                        "reason": str(exc),
                    }
                ],
            ),
        ) from exc
    try:
        sheets: List[Dict[str, Any]] = []
        for sheet_name in workbook.sheetnames:
            ws = workbook[sheet_name]
            profile = _read_plan_change_sheet_profile(ws)
            sheets.append(
                {
                    "name": str(sheet_name),
                    "max_row": int(getattr(ws, "max_row", 0) or 0),
                    "max_column": int(getattr(ws, "max_column", 0) or 0),
                    "header_row_no": profile.get("header_row_no"),
                    "headers": profile.get("headers") or [],
                    "data_row_count": int(profile.get("data_row_count") or 0),
                }
            )
        return {
            "sheet_count": len(sheets),
            "sheets": sheets,
        }
    finally:
        workbook.close()


def _analyze_plan_change_overlay_artifact(
    *,
    kind: str,
    artifact: Dict[str, Any],
) -> Tuple[Dict[str, Any], List[Dict[str, Any]]]:
    file_name = _trim_profile_text(artifact.get("file_name")) or kind
    summary: Dict[str, Any] = {
        "kind": kind,
        "file_name": file_name,
        "matched_sheet": None,
        "data_row_count": 0,
        "required_fields": [],
        "matched_columns": {},
    }
    spec = _PLAN_CHANGE_OVERLAY_SPECS.get(kind)
    if spec is None:
        return summary, []
    summary["required_fields"] = sorted(spec["required_fields"].keys())
    try:
        content = _read_plan_change_artifact_bytes(artifact)
    except FileNotFoundError:
        return summary, [
            {
                "severity": "ERROR",
                "code": "ERR_ARTIFACT_NOT_FOUND",
                "message": "시뮬레이션 입력 파일을 찾을 수 없습니다.",
                "field": kind,
                "file_name": file_name,
            }
        ]

    try:
        workbook = load_workbook(filename=BytesIO(content), read_only=True, data_only=True)
    except Exception as exc:
        return summary, [
            {
                "severity": "ERROR",
                "code": "ERR_INVALID_EXCEL",
                "message": "시뮬레이션 입력 파일을 읽지 못했습니다.",
                "field": kind,
                "file_name": file_name,
                "reason": str(exc),
            }
        ]

    try:
        best_candidate: Dict[str, Any] | None = None
        for sheet_name in workbook.sheetnames:
            ws = workbook[sheet_name]
            profile = _read_plan_change_sheet_profile(ws)
            normalized_headers = list(profile.get("normalized_headers") or [])
            matched_columns: Dict[str, int] = {}
            for logical_field, aliases in spec["required_fields"].items():
                for index, header in enumerate(normalized_headers):
                    if header in aliases:
                        matched_columns[logical_field] = index
                        break
            candidate = {
                "sheet_name": str(sheet_name),
                "header_row_no": profile.get("header_row_no"),
                "headers": list(profile.get("headers") or []),
                "normalized_headers": normalized_headers,
                "data_row_count": int(profile.get("data_row_count") or 0),
                "matched_columns": matched_columns,
                "score": len(matched_columns),
            }
            if best_candidate is None or (
                candidate["score"],
                candidate["data_row_count"],
            ) > (
                best_candidate["score"],
                best_candidate["data_row_count"],
            ):
                best_candidate = candidate

        if best_candidate is None:
            return summary, [
                {
                    "severity": "ERROR",
                    "code": "ERR_EMPTY_OVERLAY",
                    "message": "워크북에 읽을 수 있는 시트가 없습니다.",
                    "field": kind,
                    "file_name": file_name,
                }
            ]

        summary["matched_sheet"] = best_candidate["sheet_name"]
        summary["data_row_count"] = best_candidate["data_row_count"]
        summary["matched_columns"] = {
            logical_field: best_candidate["headers"][index]
            for logical_field, index in best_candidate["matched_columns"].items()
            if index < len(best_candidate["headers"])
        }

        details: List[Dict[str, Any]] = []
        missing_fields = [
            logical_field
            for logical_field in spec["required_fields"].keys()
            if logical_field not in best_candidate["matched_columns"]
        ]
        for logical_field in missing_fields:
            alias_hint = ", ".join(sorted(spec["required_fields"][logical_field]))
            details.append(
                {
                    "severity": "ERROR",
                    "code": "ERR_REQUIRED_COLUMN_MISSING",
                    "sheet": best_candidate["sheet_name"],
                    "row_no": int(best_candidate["header_row_no"] or 1),
                    "column_name": logical_field,
                    "message": f"{logical_field} 필수 컬럼이 없습니다.",
                    "field": kind,
                    "file_name": file_name,
                    "reason": alias_hint,
                }
            )

        if details:
            return summary, details

        if int(best_candidate["data_row_count"] or 0) <= 0:
            return summary, [
                {
                    "severity": "ERROR",
                    "code": "ERR_EMPTY_OVERLAY",
                    "sheet": best_candidate["sheet_name"],
                    "row_no": int(best_candidate["header_row_no"] or 1) + 1,
                    "message": "헤더 아래에 데이터 행이 없습니다.",
                    "field": kind,
                    "file_name": file_name,
                }
            ]

        ws = workbook[str(best_candidate["sheet_name"])]
        header_row_no = int(best_candidate["header_row_no"] or 1)
        matched_columns = dict(best_candidate["matched_columns"])
        for row_no, row in enumerate(ws.iter_rows(min_row=header_row_no + 1, values_only=True), start=header_row_no + 1):
            if len(details) >= _PLAN_CHANGE_MAX_VALIDATION_DETAILS:
                break
            values = list(row)
            if not any(str(cell or "").strip() for cell in values):
                continue
            for logical_field, index in matched_columns.items():
                cell_value = values[index] if index < len(values) else None
                if str(cell_value or "").strip():
                    continue
                details.append(
                    {
                        "severity": "ERROR",
                        "code": "ERR_REQUIRED_VALUE_MISSING",
                        "sheet": best_candidate["sheet_name"],
                        "row_no": row_no,
                        "column_name": logical_field,
                        "message": f"{logical_field} 값이 비어 있습니다.",
                        "field": kind,
                        "file_name": file_name,
                    }
                )
                if len(details) >= _PLAN_CHANGE_MAX_VALIDATION_DETAILS:
                    break

        return summary, details
    finally:
        workbook.close()


def _validate_plan_change_overlays(
    *,
    artifacts: Dict[str, Dict[str, Any]],
) -> Tuple[List[Dict[str, Any]], List[Dict[str, Any]]]:
    summaries: List[Dict[str, Any]] = []
    details: List[Dict[str, Any]] = []
    for kind, artifact in artifacts.items():
        summary, artifact_details = _analyze_plan_change_overlay_artifact(kind=kind, artifact=artifact)
        summaries.append(summary)
        if artifact_details:
            details.extend(artifact_details)
        if len(details) >= _PLAN_CHANGE_MAX_VALIDATION_DETAILS:
            return summaries, details[:_PLAN_CHANGE_MAX_VALIDATION_DETAILS]
    return summaries, details


def _parse_plan_change_overlay_date_strict(value: Any) -> date | None:
    if isinstance(value, datetime):
        return value.date()
    if isinstance(value, date):
        return value
    text = str(value or "").strip()
    if not text:
        return None
    for candidate in (text, text[:10], text.replace(".", "-"), text.replace("/", "-")):
        try:
            return date.fromisoformat(candidate)
        except Exception:
            continue
    compact = re.sub(r"[^\d]", "", text)
    if len(compact) == 8:
        try:
            return date(int(compact[:4]), int(compact[4:6]), int(compact[6:8]))
        except Exception:
            return None
    return None


def _parse_plan_change_overlay_quantity(value: Any, *, allow_zero: bool) -> int | None:
    if value is None:
        return None
    if isinstance(value, bool):
        return None
    try:
        if isinstance(value, (int, float)):
            quantity = float(value)
        else:
            quantity = float(str(value).strip().replace(",", ""))
    except Exception:
        return None
    if not quantity.is_integer():
        return None
    quantity_int = int(quantity)
    if quantity_int < 0:
        return None
    if not allow_zero and quantity_int <= 0:
        return None
    return quantity_int


def _find_plan_change_overlay_sheet_candidate(kind: str, workbook: Any) -> Tuple[Dict[str, Any] | None, Dict[str, Any] | None]:
    spec = _PLAN_CHANGE_OVERLAY_SPECS.get(kind)
    if spec is None:
        return None, None
    best_candidate: Dict[str, Any] | None = None
    for sheet_name in workbook.sheetnames:
        ws = workbook[sheet_name]
        profile = _read_plan_change_sheet_profile(ws)
        normalized_headers = list(profile.get("normalized_headers") or [])
        matched_columns: Dict[str, int] = {}
        for logical_field, aliases in spec["required_fields"].items():
            for index, header in enumerate(normalized_headers):
                if header in aliases:
                    matched_columns[logical_field] = index
                    break
        candidate = {
            "sheet_name": str(sheet_name),
            "header_row_no": profile.get("header_row_no"),
            "headers": list(profile.get("headers") or []),
            "normalized_headers": normalized_headers,
            "data_row_count": int(profile.get("data_row_count") or 0),
            "matched_columns": matched_columns,
            "score": len(matched_columns),
        }
        if best_candidate is None or (
            candidate["score"],
            candidate["data_row_count"],
        ) > (
            best_candidate["score"],
            best_candidate["data_row_count"],
        ):
            best_candidate = candidate
    return spec, best_candidate


def _parse_plan_change_overlay_rows(
    *,
    artifacts: Dict[str, Dict[str, Any]],
    requested_start: date,
    requested_end: date,
) -> Tuple[Dict[str, List[Dict[str, Any]]], List[Dict[str, Any]], List[Dict[str, Any]]]:
    overlay_rows: Dict[str, List[Dict[str, Any]]] = {}
    summaries: List[Dict[str, Any]] = []
    details: List[Dict[str, Any]] = []

    for kind, artifact in artifacts.items():
        file_name = _trim_profile_text(artifact.get("file_name")) or kind
        summary: Dict[str, Any] = {
            "kind": kind,
            "file_name": file_name,
            "row_count": 0,
            "total_quantity": 0,
            "preview_rows": [],
        }
        overlay_rows[kind] = []
        try:
            content = _read_plan_change_artifact_bytes(artifact)
        except FileNotFoundError:
            details.append(
                {
                    "severity": "ERROR",
                    "code": "ERR_ARTIFACT_NOT_FOUND",
                    "message": "시뮬레이션 입력 파일을 찾을 수 없습니다.",
                    "field": kind,
                    "file_name": file_name,
                }
            )
            summaries.append(summary)
            continue

        try:
            workbook = load_workbook(filename=BytesIO(content), read_only=True, data_only=True)
        except Exception as exc:
            details.append(
                {
                    "severity": "ERROR",
                    "code": "ERR_INVALID_EXCEL",
                    "message": "시뮬레이션 입력 파일을 읽지 못했습니다.",
                    "field": kind,
                    "file_name": file_name,
                    "reason": str(exc),
                }
            )
            summaries.append(summary)
            continue

        try:
            spec, best_candidate = _find_plan_change_overlay_sheet_candidate(kind, workbook)
            if spec is None or best_candidate is None:
                summaries.append(summary)
                continue
            summary["matched_sheet"] = best_candidate["sheet_name"]
            summary["required_fields"] = sorted(spec["required_fields"].keys())
            summary["matched_columns"] = {
                logical_field: best_candidate["headers"][index]
                for logical_field, index in best_candidate["matched_columns"].items()
                if index < len(best_candidate["headers"])
            }
            ws = workbook[str(best_candidate["sheet_name"])]
            header_row_no = int(best_candidate["header_row_no"] or 1)
            matched_columns = dict(best_candidate["matched_columns"])
            total_quantity = 0
            for row_no, row in enumerate(ws.iter_rows(min_row=header_row_no + 1, values_only=True), start=header_row_no + 1):
                if len(details) >= _PLAN_CHANGE_MAX_VALIDATION_DETAILS:
                    break
                values = list(row)
                if not any(str(cell or "").strip() for cell in values):
                    continue
                product_idx = matched_columns.get("product_id")
                quantity_idx = matched_columns.get("quantity")
                product_id = _trim_profile_text(values[product_idx] if product_idx is not None and product_idx < len(values) else "")
                quantity = _parse_plan_change_overlay_quantity(
                    values[quantity_idx] if quantity_idx is not None and quantity_idx < len(values) else None,
                    allow_zero=(kind == "inventory_file"),
                )
                if not product_id:
                    details.append(
                        {
                            "severity": "ERROR",
                            "code": "ERR_REQUIRED_VALUE_MISSING",
                            "sheet": best_candidate["sheet_name"],
                            "row_no": row_no,
                            "column_name": "product_id",
                            "message": "product_id 값이 비어 있습니다.",
                            "field": kind,
                            "file_name": file_name,
                        }
                    )
                    continue
                if quantity is None:
                    details.append(
                        {
                            "severity": "ERROR",
                            "code": "ERR_INVALID_QUANTITY",
                            "sheet": best_candidate["sheet_name"],
                            "row_no": row_no,
                            "column_name": "quantity",
                            "message": "quantity 값은 0 이상의 정수여야 합니다.",
                            "field": kind,
                            "file_name": file_name,
                            "value": _trim_profile_text(values[quantity_idx] if quantity_idx is not None and quantity_idx < len(values) else None),
                        }
                    )
                    continue

                row_payload: Dict[str, Any] = {
                    "product_id": product_id,
                    "quantity": quantity,
                }
                if kind == "demand_file":
                    date_idx = matched_columns.get("date")
                    overlay_date = _parse_plan_change_overlay_date_strict(
                        values[date_idx] if date_idx is not None and date_idx < len(values) else None
                    )
                    if overlay_date is None:
                        details.append(
                            {
                                "severity": "ERROR",
                                "code": "ERR_INVALID_DATE",
                                "sheet": best_candidate["sheet_name"],
                                "row_no": row_no,
                                "column_name": "date",
                                "message": "date 값은 YYYY-MM-DD 형식이어야 합니다.",
                                "field": kind,
                                "file_name": file_name,
                                "value": _trim_profile_text(values[date_idx] if date_idx is not None and date_idx < len(values) else None),
                            }
                        )
                        continue
                    if overlay_date < requested_start or overlay_date > requested_end:
                        details.append(
                            {
                                "severity": "ERROR",
                                "code": "ERR_DATE_OUT_OF_RANGE",
                                "sheet": best_candidate["sheet_name"],
                                "row_no": row_no,
                                "column_name": "date",
                                "message": "date 값이 base run 기간을 벗어났습니다.",
                                "field": kind,
                                "file_name": file_name,
                                "value": overlay_date.isoformat(),
                            }
                        )
                        continue
                    row_payload["date"] = overlay_date.isoformat()

                overlay_rows[kind].append(row_payload)
                total_quantity += quantity
                preview_rows = summary["preview_rows"]
                if isinstance(preview_rows, list) and len(preview_rows) < 10:
                    preview_rows.append(dict(row_payload))

            summary["row_count"] = len(overlay_rows[kind])
            summary["total_quantity"] = total_quantity
            if kind == "demand_file":
                demand_dates = [row["date"] for row in overlay_rows[kind] if isinstance(row.get("date"), str)]
                if demand_dates:
                    summary["min_date"] = min(demand_dates)
                    summary["max_date"] = max(demand_dates)
        finally:
            workbook.close()

        summaries.append(summary)
        if len(details) >= _PLAN_CHANGE_MAX_VALIDATION_DETAILS:
            return overlay_rows, summaries, details[:_PLAN_CHANGE_MAX_VALIDATION_DETAILS]

    return overlay_rows, summaries, details


def _plan_change_preview_config() -> Config:
    base = Config()
    try:
        preview_limit = int(os.getenv("BOHAE_PLAN_CHANGE_PREVIEW_TIME_LIMIT_SEC", "20") or 20)
    except Exception:
        preview_limit = 20
    try:
        preview_workers_cap = int(os.getenv("BOHAE_PLAN_CHANGE_PREVIEW_MAX_WORKERS", "4") or 4)
    except Exception:
        preview_workers_cap = 4
    return base.with_overrides(
        time_limit_sec=max(1, min(int(base.time_limit_sec), int(preview_limit))),
        workers=max(1, min(int(base.workers), int(preview_workers_cap))),
        log_search_progress=False,
    )


def _plan_change_overlay_key(product_id: str, demand_date: date) -> Tuple[str, str]:
    return (_trim_profile_text(product_id), demand_date.isoformat())


def _build_plan_change_contract_fail_details(errors: List[str]) -> List[Dict[str, Any]]:
    details: List[Dict[str, Any]] = []
    for raw_error in errors[:_PLAN_CHANGE_MAX_VALIDATION_DETAILS]:
        text = _trim_profile_text(raw_error)
        if not text:
            continue
        code, _, remainder = text.partition(":")
        detail: Dict[str, Any] = {
            "severity": "ERROR",
            "code": code or "CONTRACT_FAIL",
            "message": remainder or text,
            "field": "bundle",
            "reason": text,
        }
        match = re.search(r"PRODUCT=([^\s]+)", text)
        if match:
            detail["value"] = match.group(1)
            detail["column_name"] = "product_id"
        details.append(detail)
    return details


def _extract_plan_change_result_metric(result: Dict[str, Any], term: str) -> int | None:
    normalized_term = _trim_profile_text(term).upper()
    for row in result.get("objective_rows") or []:
        if _trim_profile_text((row or {}).get("TERM")).upper() != normalized_term:
            continue
        try:
            return int((row or {}).get("VALUE"))
        except Exception:
            break
    trace = result.get("trace") if isinstance(result.get("trace"), dict) else {}
    candidates = [
        trace.get(f"objective_{normalized_term}"),
        trace.get(normalized_term),
        trace.get(f"objective_breakdown_{normalized_term}"),
    ]
    for candidate in candidates:
        try:
            return int(candidate) if candidate is not None else None
        except Exception:
            continue
    return None


def _apply_plan_change_demand_overlay(
    data: Dict[str, Any],
    *,
    overlay_rows: Dict[str, List[Dict[str, Any]]],
    change_id: str,
) -> Tuple[Dict[str, Any], Dict[str, Any]]:
    from ..models.types import Demand

    next_data = dict(data)
    existing_demands = list(next_data.get("demands") or [])
    demand_overlay_rows = list(overlay_rows.get("demand_file") or [])
    inventory_overlay_rows = list(overlay_rows.get("inventory_file") or [])
    summary: Dict[str, Any] = {
        "source_type": "db",
        "strategy": "DB_DEMAND_OVERLAY",
        "demand_overlay_requested": bool(demand_overlay_rows),
        "inventory_overlay_present": bool(inventory_overlay_rows),
        "inventory_overlay_applied": False,
        "overlay_demand_rows": len(demand_overlay_rows),
        "overlay_inventory_rows": len(inventory_overlay_rows),
        "original_demand_count": len(existing_demands),
        "replaced_existing_demands": 0,
    }
    if not demand_overlay_rows:
        summary["final_demand_count"] = len(existing_demands)
        summary["overlay_demand_keys"] = 0
        return next_data, summary

    start_date = next_data.get("start_date")
    if not isinstance(start_date, date):
        raise RuntimeError("PLAN_CHANGE_PREVIEW_START_DATE_INVALID")

    grouped_overlay: Dict[Tuple[str, str], Dict[str, Any]] = {}
    for raw_row in demand_overlay_rows:
        product_id = _trim_profile_text(raw_row.get("product_id"))
        overlay_date = _parse_date_value(raw_row.get("date"))
        quantity = int(raw_row.get("quantity") or 0)
        key = _plan_change_overlay_key(product_id, overlay_date)
        if key not in grouped_overlay:
            grouped_overlay[key] = {
                "product_id": product_id,
                "date": overlay_date,
                "quantity": 0,
            }
        grouped_overlay[key]["quantity"] = int(grouped_overlay[key]["quantity"]) + quantity

    priority_by_key: Dict[Tuple[str, str], int] = {}
    requested_line_by_key: Dict[Tuple[str, str], str] = {}
    channel_by_key: Dict[Tuple[str, str], str] = {}
    due_time_by_key: Dict[Tuple[str, str], Tuple[int, int]] = {}
    for demand in existing_demands:
        due_dt = getattr(demand, "due_dt", None)
        demand_date = due_dt.date() if isinstance(due_dt, datetime) else None
        if demand_date is None:
            continue
        key = _plan_change_overlay_key(getattr(demand, "product_id", ""), demand_date)
        priority_by_key[key] = max(int(priority_by_key.get(key, 0)), int(getattr(demand, "priority", 0) or 0))
        if key not in requested_line_by_key:
            requested_line_by_key[key] = _trim_profile_text(getattr(demand, "requested_line_id", ""))
        if key not in channel_by_key:
            channel_by_key[key] = _trim_profile_text(getattr(demand, "channel", ""))
        if key not in due_time_by_key and isinstance(due_dt, datetime):
            due_time_by_key[key] = (int(due_dt.hour), int(due_dt.minute))

    replaced_keys = set(grouped_overlay.keys())
    kept_demands: List[Demand] = []
    replaced_existing_demands = 0
    for demand in existing_demands:
        due_dt = getattr(demand, "due_dt", None)
        demand_date = due_dt.date() if isinstance(due_dt, datetime) else None
        if demand_date is None:
            kept_demands.append(demand)
            continue
        key = _plan_change_overlay_key(getattr(demand, "product_id", ""), demand_date)
        if key in replaced_keys:
            replaced_existing_demands += 1
            continue
        kept_demands.append(demand)

    synthetic_demands: List[Demand] = []
    for idx, overlay in enumerate(
        sorted(grouped_overlay.values(), key=lambda item: (item["date"].isoformat(), item["product_id"]))
    ):
        overlay_date = overlay["date"]
        key = _plan_change_overlay_key(str(overlay["product_id"]), overlay_date)
        due_hour, due_minute = due_time_by_key.get(key, (23, 59))
        due_dt = datetime.combine(overlay_date, datetime.min.time()) + timedelta(hours=due_hour, minutes=due_minute)
        due_min = (overlay_date - start_date).days * 24 * 60 + int(due_hour) * 60 + int(due_minute)
        synthetic_demands.append(
            Demand(
                demand_id=(
                    f"OVR_{change_id}_{idx + 1:03d}_"
                    f"{_normalize_plan_change_overlay_token(overlay['product_id']) or 'product'}"
                ),
                product_id=str(overlay["product_id"]),
                order_qty=int(overlay["quantity"]),
                due_dt=due_dt,
                due_min=int(due_min),
                priority=int(priority_by_key.get(key, 0) or 0),
                requested_line_id=requested_line_by_key.get(key, ""),
                hist_machine_id="",
                hist_start_time=None,
                hist_end_time=None,
                is_forced_hist=False,
                channel=channel_by_key.get(key, ""),
            )
        )

    merged_demands = kept_demands + synthetic_demands
    merged_demands.sort(key=lambda demand: (int(demand.due_min), -int(demand.priority), demand.demand_id))
    next_data["demands"] = merged_demands

    data_quality_rows = list(next_data.get("data_quality_rows") or [])
    data_quality_rows.extend(
        [
            {
                "CHECK": "PLAN_CHANGE_DEMAND_OVERLAY_ROWS",
                "VALUE": len(demand_overlay_rows),
                "OK": True,
            },
            {
                "CHECK": "PLAN_CHANGE_DEMAND_OVERLAY_KEYS",
                "VALUE": len(grouped_overlay),
                "OK": True,
            },
            {
                "CHECK": "PLAN_CHANGE_INVENTORY_OVERLAY_ROWS",
                "VALUE": len(inventory_overlay_rows),
                "OK": True,
            },
        ]
    )
    next_data["data_quality_rows"] = data_quality_rows

    summary.update(
        {
            "overlay_demand_keys": len(grouped_overlay),
            "replaced_existing_demands": replaced_existing_demands,
            "final_demand_count": len(merged_demands),
        }
    )
    return next_data, summary


def _build_plan_change_inventory_overlay_preview(
    registry: RunRegistry,
    *,
    overlay_rows: Dict[str, List[Dict[str, Any]]],
) -> Tuple[Dict[str, Any], List[Dict[str, Any]], Dict[str, Any]]:
    inventory_overlay_rows = list(overlay_rows.get("inventory_file") or [])
    preview: Dict[str, Any] = {
        "inventory_overlay_present": bool(inventory_overlay_rows),
        "inventory_overlay_applied": False,
        "overlay_row_count": len(inventory_overlay_rows),
        "matched_product_count": 0,
        "missing_baseline_product_count": 0,
        "items": [],
    }
    if not inventory_overlay_rows:
        return preview, [], {}

    try:
        inventory_rows = _list_scm_inventory_payload(registry)
    except Exception as exc:
        return (
            preview,
            [
                {
                    "code": "INVENTORY_BASELINE_UNAVAILABLE",
                    "message": f"inventory baseline을 읽지 못해 overlay preview를 생략했습니다: {exc}",
                }
            ],
            {
                "inventory_overlay_products": len({_trim_profile_text(row.get('product_id')) for row in inventory_overlay_rows}),
                "inventory_overlay_applied": False,
            },
        )

    baseline_by_item: Dict[str, int] = {}
    for row in inventory_rows:
        item_id = _trim_profile_text(row.get("item_id"))
        if not item_id:
            continue
        try:
            qty = int(float(row.get("quantity") or 0))
        except Exception:
            qty = 0
        baseline_by_item[item_id] = int(baseline_by_item.get(item_id, 0)) + qty

    overlay_by_item: Dict[str, int] = {}
    for row in inventory_overlay_rows:
        product_id = _trim_profile_text(row.get("product_id"))
        if not product_id:
            continue
        overlay_by_item[product_id] = int(row.get("quantity") or 0)

    warnings: List[Dict[str, Any]] = []
    low_stock_products: List[str] = []
    preview_items: List[Dict[str, Any]] = []
    matched_product_count = 0
    missing_baseline_product_count = 0
    for product_id in sorted(overlay_by_item.keys()):
        before_qty = int(baseline_by_item.get(product_id, 0))
        after_qty = int(overlay_by_item[product_id])
        if product_id in baseline_by_item:
            matched_product_count += 1
        else:
            missing_baseline_product_count += 1
        delta_qty = after_qty - before_qty
        if after_qty <= 0:
            low_stock_products.append(product_id)
        preview_items.append(
            {
                "product_id": product_id,
                "before_qty": before_qty,
                "after_qty": after_qty,
                "delta_qty": delta_qty,
                "baseline_found": product_id in baseline_by_item,
            }
        )

    if low_stock_products:
        warnings.append(
            {
                "code": "INVENTORY_LOW_STOCK_AFTER_OVERLAY",
                "message": f"overlay 적용 후 0 이하 재고 품목이 {len(low_stock_products)}건입니다.",
                "products": low_stock_products[:10],
            }
        )
    warnings.append(
        {
            "code": "INVENTORY_OVERLAY_SOLVER_GAP",
            "message": "inventory overlay는 inventory preview에는 반영되었지만 solver 제약에는 아직 미반영입니다.",
        }
    )

    preview.update(
        {
            "inventory_overlay_applied": True,
            "matched_product_count": matched_product_count,
            "missing_baseline_product_count": missing_baseline_product_count,
            "items": preview_items[:20],
        }
    )
    insight_input = {
        "inventory_overlay_products": len(overlay_by_item),
        "inventory_overlay_applied": True,
        "inventory_overlay_low_stock_count": len(low_stock_products),
        "inventory_overlay_matched_product_count": matched_product_count,
        "inventory_overlay_missing_baseline_product_count": missing_baseline_product_count,
    }
    return preview, warnings, insight_input


def _dedupe_plan_change_warnings(warnings: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
    deduped: List[Dict[str, Any]] = []
    seen_keys: set[Tuple[str, str]] = set()
    for warning in warnings:
        if not isinstance(warning, dict):
            continue
        key = (
            _trim_profile_text(warning.get("code")).upper(),
            _trim_profile_text(warning.get("message")),
        )
        if key in seen_keys:
            continue
        seen_keys.add(key)
        deduped.append(dict(warning))
    return deduped


def _run_plan_change_solver_preview(
    *,
    change_id: str,
    scenario_id: str,
    requested_start: date,
    requested_end: date,
    overlay_rows: Dict[str, List[Dict[str, Any]]],
) -> Dict[str, Any]:
    from ..loaders.db_loader import DBLoader
    from ..solver.engine import solve
    from ..validators.contracts import ContractValidator

    config = _plan_change_preview_config()
    loader = DBLoader(config)
    try:
        data = loader.load(scenario_id, requested_start, requested_end)
        merged_data, bundle_assembly = _apply_plan_change_demand_overlay(
            data,
            overlay_rows=overlay_rows,
            change_id=change_id,
        )
        validator = ContractValidator(merged_data, config)
        if not validator.validate():
            raise HTTPException(
                status_code=422,
                detail=_plan_change_error_payload(
                    error_code="CONTRACT_FAIL",
                    message="merged bundle validation failed",
                    details=_build_plan_change_contract_fail_details(validator.errors),
                ),
            )

        result = solve(
            merged_data,
            config,
            previous_plan_path=None,
            run_id=f"SIM_{change_id}_{uuid.uuid4().hex[:8]}",
        )

        plan_rows = list(result.get("plan_rows") or [])
        unscheduled_rows = [row for row in plan_rows if not bool((row or {}).get("IS_SCHEDULED"))]
        scheduled_rows = [row for row in plan_rows if bool((row or {}).get("IS_SCHEDULED"))]
        solve_status = _trim_profile_text((result.get("trace") or {}).get("solve_status")) or _trim_profile_text(
            result.get("status")
        )
        tardiness_total = _extract_plan_change_result_metric(result, "TARDINESS_TOTAL")
        setup_total_min = _extract_plan_change_result_metric(result, "SETUP_TOTAL_MIN")
        unscheduled_count = _extract_plan_change_result_metric(result, "UNSCHEDULED_COUNT")
        preview_summary = {
            "solve_status": solve_status or "UNKNOWN",
            "plan_segment_count": len(result.get("seg_rows") or []),
            "decision_log_rows": len(result.get("decision_log_rows") or []),
            "scheduled_count": len(scheduled_rows),
            "unscheduled_count": int(unscheduled_count if unscheduled_count is not None else len(unscheduled_rows)),
            "tardiness_total_min": int(tardiness_total or 0),
            "setup_total_min": int(setup_total_min or 0),
            "unscheduled_demands_preview": [
                {
                    "demand_id": _trim_profile_text((row or {}).get("DEMAND_ID")),
                    "product_id": _trim_profile_text((row or {}).get("PRODUCT_ID")),
                    "reason": _trim_profile_text((row or {}).get("UNSCHEDULED_REASON")),
                }
                for row in unscheduled_rows[:10]
            ],
        }
        return {
            "engine_mode": "PLAN_CHANGE_SOLVER_PREVIEW",
            "preview_strategy": "REAL_SOLVER_RERUN",
            "preview_config": {
                "time_limit_sec": int(config.time_limit_sec),
                "workers": int(config.workers),
            },
            "bundle_assembly": bundle_assembly,
            "solver_preview": preview_summary,
            "insight_input": {
                "preview_unscheduled_count": preview_summary["unscheduled_count"],
                "preview_tardiness_total_min": preview_summary["tardiness_total_min"],
                "preview_setup_total_min": preview_summary["setup_total_min"],
                "preview_solve_status": preview_summary["solve_status"],
            },
            "warnings": (
                [
                    {
                        "code": "INVENTORY_OVERLAY_SOLVER_GAP",
                        "message": "inventory overlay는 inventory preview에는 반영되지만 solver 제약에는 아직 미반영입니다.",
                    }
                ]
                if bool(overlay_rows.get("inventory_file"))
                else []
            ),
        }
    finally:
        try:
            loader.close()
        except Exception:
            pass


def _generate_plan_change_ai_insight(insight_input: Dict[str, Any]) -> Dict[str, Any]:
    fallback = _build_plan_change_ai_fallback(insight_input)
    try:
        from .vertex_insight import generate_insight

        payload = generate_insight(insight_input)
    except Exception:
        return fallback
    if not isinstance(payload, dict):
        return fallback
    merged = {
        "summary": _trim_profile_text(payload.get("summary")) or fallback.get("summary") or "",
        "tardiness_warnings": list(payload.get("tardiness_warnings") or fallback.get("tardiness_warnings") or []),
        "action_plans": list(payload.get("action_plans") or fallback.get("action_plans") or []),
    }
    return merged


def _build_plan_change_ai_fallback(insight_input: Dict[str, Any]) -> Dict[str, Any]:
    def _metric(name: str) -> int:
        try:
            return int(insight_input.get(name) or 0)
        except Exception:
            return 0

    unscheduled_count = _metric("preview_unscheduled_count") or _metric("base_unscheduled_count")
    tardiness_total_min = _metric("preview_tardiness_total_min")
    setup_total_min = _metric("preview_setup_total_min")
    overlay_total_rows = _metric("overlay_total_rows")
    overlay_total_quantity = _metric("overlay_total_quantity")
    low_stock_count = _metric("inventory_overlay_low_stock_count")
    inventory_product_count = _metric("inventory_overlay_products")
    missing_baseline_count = _metric("inventory_overlay_missing_baseline_product_count")
    solve_status = _trim_profile_text(insight_input.get("preview_solve_status")).upper() or "UNKNOWN"

    summary_parts: List[str] = []
    if unscheduled_count > 0:
        summary_parts.append(f"미배정 {unscheduled_count}건")
    if tardiness_total_min > 0:
        summary_parts.append(f"총 지연 {tardiness_total_min}분")
    if low_stock_count > 0:
        summary_parts.append(f"재고 0 이하 위험 {low_stock_count}건")
    if not summary_parts:
        summary_parts.append(
            f"오버레이 {overlay_total_rows}건({overlay_total_quantity} 수량), solve_status={solve_status}, 치명 경고 없음"
        )
    else:
        summary_parts.append(f"solve_status={solve_status}")

    tardiness_warnings: List[str] = []
    if unscheduled_count > 0:
        tardiness_warnings.append(f"미배정 수요 {unscheduled_count}건이 있어 납기 리스크가 있습니다.")
    if tardiness_total_min > 0:
        tardiness_warnings.append(f"총 지연 시간이 {tardiness_total_min}분으로 집계되었습니다.")
    if low_stock_count > 0:
        tardiness_warnings.append(f"overlay 적용 후 재고 0 이하 품목이 {low_stock_count}건입니다.")
    if missing_baseline_count > 0:
        tardiness_warnings.append(f"inventory baseline 미매치 품목이 {missing_baseline_count}건입니다.")

    action_plans: List[str] = []
    if unscheduled_count > 0 or tardiness_total_min > 0:
        action_plans.append("지연 위험 SKU를 우선순위 재조정 또는 대체 라인 재배치 후보로 검토하십시오.")
    if low_stock_count > 0:
        action_plans.append("재고 0 이하 품목의 현재고와 입고 계획을 확인한 뒤 시뮬레이션을 다시 실행하십시오.")
    if missing_baseline_count > 0:
        action_plans.append("baseline inventory에 없는 품목코드 매핑을 정리한 뒤 inventory overlay를 재업로드하십시오.")
    if setup_total_min > 0:
        action_plans.append("전환 시간이 큰 구간을 묶음 생산 후보로 검토하십시오.")
    if not action_plans:
        action_plans.append("현재 시뮬레이션 결과를 기준안으로 저장하고 추가 오버레이 시나리오를 비교하십시오.")
    if inventory_product_count > 0 and len(action_plans) < 3:
        action_plans.append("재고 overlay 대상 SKU와 생산 demand overlay SKU의 일치 여부를 확인하십시오.")

    return {
        "summary": "; ".join(summary_parts[:3]),
        "tardiness_warnings": tardiness_warnings[:3],
        "action_plans": action_plans[:3],
    }


async def _store_plan_change_artifacts(
    registry: RunRegistry,
    *,
    actor: Dict[str, Any],
    change_id: str,
    demand_file: UploadFile | None,
    inventory_file: UploadFile | None,
) -> PlanChangeRecord:
    row = registry.fetch_plan_change(change_id)
    if row is None:
        raise HTTPException(status_code=404, detail="change_id not found")
    _enforce_actor_can_access_plan_change(registry, actor, row)
    _ensure_plan_change_mutable(row, operation="첨부 파일 업로드")
    incoming_files = {
        "demand_file": demand_file,
        "inventory_file": inventory_file,
    }
    if not any(file is not None for file in incoming_files.values()):
        raise HTTPException(status_code=400, detail="최소 1개의 엑셀 파일이 필요합니다.")

    params_json = _normalize_plan_change_params(row.get("params_json"))
    artifacts = _plan_change_artifacts_from_params(params_json)
    for field_name, upload in incoming_files.items():
        if upload is None:
            continue
        file_name = Path(upload.filename or f"{field_name}.xlsx").name
        suffix = Path(file_name).suffix.lower()
        if suffix not in _PLAN_CHANGE_ALLOWED_SUFFIXES:
            raise HTTPException(
                status_code=422,
                detail=_plan_change_error_payload(
                    error_code="ERR_INVALID_EXCEL",
                    message=f"{field_name}는 .xlsx 파일만 허용됩니다.",
                    details=[{"field": field_name, "file_name": file_name}],
                ),
            )
        content = await upload.read()
        if len(content) > _PLAN_CHANGE_MAX_UPLOAD_BYTES:
            raise HTTPException(
                status_code=413,
                detail=_plan_change_error_payload(
                    error_code="ERR_FILE_TOO_LARGE",
                    message=f"{field_name} 파일 크기가 제한을 초과했습니다.",
                    details=[
                        {
                            "field": field_name,
                            "file_name": file_name,
                            "max_size_bytes": _PLAN_CHANGE_MAX_UPLOAD_BYTES,
                            "received_size_bytes": len(content),
                        }
                    ],
                ),
            )
        workbook = _summarize_uploaded_workbook(content, field_name=field_name, file_name=file_name)
        digest = hashlib.sha256(content).hexdigest()
        stored_name = f"{field_name}_{digest[:12]}{suffix}"
        stored_path = _store_plan_change_artifact_payload(change_id=change_id, stored_name=stored_name, content=content)
        artifacts[field_name] = {
            "kind": field_name,
            "file_name": file_name,
            "mime_type": _trim_profile_text(upload.content_type) or "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
            "size_bytes": len(content),
            "sha256": digest,
            "stored_path": str(stored_path),
            "uploaded_at": datetime.now(timezone.utc).isoformat(),
            "workbook": workbook,
        }
        _METRIC_PLAN_CHANGE_ARTIFACT_UPLOAD_TOTAL.labels(kind=field_name).inc()

    simulation = _plan_change_simulation_from_params(params_json)
    simulation.update(
        {
            "status": "IDLE",
            "step": "ARTIFACTS_ATTACHED",
            "progress_pct": 0,
            "preview_only": True,
            "updated_at": datetime.now(timezone.utc).isoformat(),
            "error": {},
        }
    )
    next_params = _plan_change_params_with_runtime(
        params_json,
        artifacts=artifacts,
        simulation=simulation,
    )
    updated = registry.update_plan_change(change_id=change_id, params_json=next_params)
    if updated is None:
        raise HTTPException(status_code=500, detail="변경 초안 첨부 파일 저장에 실패했습니다.")
    return _build_plan_change_record(updated)


@app.get("/v1/plan-changes", response_model=List[PlanChangeRecord])
def list_plan_changes(
    limit: int = Query(default=50, ge=1, le=200),
    status: PlanChangeStatus | None = Query(default=None),
    actor_claims: Dict[str, Any] = Depends(get_current_actor),
) -> List[PlanChangeRecord]:
    try:
        registry = RunRegistry(Config())
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc
    try:
        if not registry.plan_change_enabled:
            raise HTTPException(
                status_code=503,
                detail="plan_change 테이블이 없습니다. bohae_aps_v20/sql/40_plan_change_v1.sql을 먼저 적용하세요.",
            )
        actor = _require_plan_change_reader(registry, actor_claims)
        rows = registry.list_plan_changes(limit=limit, status=status)
        if _trim_profile_text(actor.get("actor_role")) not in {"ADMIN", "MANAGER"}:
            rows = [row for row in rows if _actor_can_access_plan_change(registry, actor, row)]
        return [_build_plan_change_record(row) for row in rows]
    finally:
        registry.close()


@app.post("/v1/plan-changes", response_model=PlanChangeRecord, status_code=201)
def create_plan_change(
    request: PlanChangeCreateRequest,
    actor_claims: Dict[str, Any] = Depends(get_current_actor),
) -> PlanChangeRecord:
    try:
        registry = RunRegistry(Config())
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc
    try:
        if not registry.plan_change_enabled:
            raise HTTPException(
                status_code=503,
                detail="plan_change 테이블이 없습니다. bohae_aps_v20/sql/40_plan_change_v1.sql을 먼저 적용하세요.",
            )
        base_run_id = request.base_run_id.strip()
        change_type = request.change_type.strip()
        if not base_run_id or not change_type:
            raise HTTPException(status_code=400, detail="base_run_id/change_type 값은 모두 필수입니다.")
        actor = _require_plan_change_editor(registry, actor_claims, line_id=request.line_id)
        run_row = registry.fetch_run(base_run_id)
        if run_row is None:
            _raise_run_not_found(registry, base_run_id)
        _enforce_actor_can_access_run(actor, run_row)

        change_id = f"CHG_{uuid.uuid4().hex[:12]}"
        params_json = _plan_change_params_with_runtime(
            _sanitize_plan_change_user_params(request.params_json),
            plant_id=request.plant_id,
            line_id=request.line_id,
            simulation={
                "status": "IDLE",
                "step": "CREATED",
                "progress_pct": 0,
                "preview_only": True,
                "updated_at": datetime.now(timezone.utc).isoformat(),
                "result": {},
                "error": {},
            },
        )
        row = registry.create_plan_change(
            change_id=change_id,
            base_run_id=base_run_id,
            change_type=change_type,
            params_json=params_json,
            status="DRAFT",
            created_by=str(actor.get("actor_id") or actor.get("actor_email") or ""),
        )
        if row is None:
            raise HTTPException(status_code=500, detail="plan_change 생성에 실패했습니다.")

        return _build_plan_change_record(row)
    finally:
        registry.close()


