@app.get("/v1/plan-changes/{change_id}/artifacts/{kind}/download")
def download_plan_change_artifact(
    change_id: str,
    kind: str,
    actor_claims: Dict[str, Any] = Depends(get_current_actor),
) -> Response:
    try:
        registry = RunRegistry(Config())
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc
    try:
        if not registry.plan_change_enabled:
            raise HTTPException(
                status_code=503,
                detail="plan_change 테이블이 없습니다. bohae_aps_v20/sql/40_plan_change_v1.sql을 먼저 적용하세요.",
            )
        actor = _require_plan_change_reader(registry, actor_claims)
        row = registry.fetch_plan_change(change_id)
        if row is None:
            raise HTTPException(status_code=404, detail="change_id not found")
        _enforce_actor_can_access_plan_change(registry, actor, row)
        params_json = _normalize_plan_change_params(row.get("params_json"))
        artifacts = _plan_change_artifacts_from_params(params_json)
        artifact = artifacts.get(kind)
        if not isinstance(artifact, dict):
            raise HTTPException(status_code=404, detail="artifact kind not found")
        try:
            content = _read_plan_change_artifact_bytes(artifact)
        except FileNotFoundError as exc:
            raise HTTPException(status_code=404, detail=str(exc)) from exc
        file_name = _trim_profile_text(artifact.get("file_name")) or f"{kind}.xlsx"
        media_type = _trim_profile_text(artifact.get("mime_type")) or "application/octet-stream"
        disposition_name = urlparse.quote(file_name)
        _METRIC_PLAN_CHANGE_ARTIFACT_DOWNLOAD_TOTAL.labels(kind=kind).inc()
        return Response(
            content=content,
            media_type=media_type,
            headers={
                "Content-Disposition": f"attachment; filename*=UTF-8''{disposition_name}",
                "Cache-Control": "private, no-store",
            },
        )
    finally:
        registry.close()


