@app.post("/v1/plan-changes/{change_id}/simulate", response_model=PlanChangeSimulateResponse, status_code=202)
def simulate_plan_change(
    change_id: str,
    actor_claims: Dict[str, Any] = Depends(get_current_actor),
) -> PlanChangeSimulateResponse:
    try:
        registry = RunRegistry(Config())
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc
    try:
        if not registry.plan_change_enabled:
            raise HTTPException(
                status_code=503,
                detail="plan_change 테이블이 없습니다. bohae_aps_v20/sql/40_plan_change_v1.sql을 먼저 적용하세요.",
            )
        row = registry.fetch_plan_change(change_id)
        if row is None:
            raise HTTPException(status_code=404, detail="change_id not found")
        params_json = _normalize_plan_change_params(row.get("params_json"))
        scope = _plan_change_scope_from_params(params_json)
        actor = _require_plan_change_editor(registry, actor_claims, line_id=scope.get("line_id"))
        _enforce_actor_can_access_plan_change(registry, actor, row)
        _ensure_plan_change_mutable(row, operation="시뮬레이션")
        base_run = registry.fetch_run(_trim_profile_text(row.get("base_run_id")))
        if base_run is None:
            _raise_run_not_found(registry, _trim_profile_text(row.get("base_run_id")))
        _enforce_actor_can_access_run(actor, base_run)

        request_id = f"req_{uuid.uuid4().hex}"
        receipt_id = _create_operation_receipt(
            registry,
            action_key="plan_change.simulate",
            entity_type="plan_change",
            entity_id=change_id,
            request_id=request_id,
            actor=actor,
            status="RUNNING",
            meta={"base_run_id": _trim_profile_text(row.get("base_run_id"))},
        )
        running_simulation = _plan_change_simulation_from_params(params_json)
        running_simulation.update(
            {
                "status": "RUNNING",
                "step": "VALIDATING_INPUT",
                "progress_pct": 15,
                "preview_only": True,
                "receipt_id": receipt_id,
                "updated_at": datetime.now(timezone.utc).isoformat(),
                "result": {},
                "error": {},
            }
        )
        running_params = _plan_change_params_with_runtime(params_json, simulation=running_simulation)
        row = registry.update_plan_change(change_id=change_id, status="SIMULATING", params_json=running_params) or row
        params_json = _normalize_plan_change_params(row.get("params_json"))
        preview_strategy = "UNSET"

        try:
            artifacts = _plan_change_artifacts_from_params(params_json)
            public_params = _plan_change_public_params(params_json)
            if not artifacts and not public_params:
                raise HTTPException(
                    status_code=422,
                    detail=_plan_change_error_payload(
                        error_code="CONTRACT_FAIL",
                        message="시뮬레이션할 변경 입력이 없습니다.",
                        details=[
                            {
                                "message": "업로드 파일 또는 변경 파라미터가 필요합니다.",
                            }
                        ],
                    ),
                )

            validation_summary, validation_details = _validate_plan_change_overlays(artifacts=artifacts)
            if validation_details:
                raise HTTPException(
                    status_code=422,
                    detail=_plan_change_error_payload(
                        error_code="CONTRACT_FAIL",
                        message="overlay validation failed",
                        details=validation_details,
                    ),
                )

            requested_start = _parse_date_value(base_run.get("requested_start"))
            requested_end = _parse_date_value(base_run.get("requested_end"))
            overlay_rows, overlay_row_summary, overlay_row_details = _parse_plan_change_overlay_rows(
                artifacts=artifacts,
                requested_start=requested_start,
                requested_end=requested_end,
            )
            if overlay_row_details:
                raise HTTPException(
                    status_code=422,
                    detail=_plan_change_error_payload(
                        error_code="CONTRACT_FAIL",
                        message="overlay validation failed",
                        details=overlay_row_details,
                    ),
                )

            artifact_items = []
            for kind, artifact in artifacts.items():
                artifact_items.append(
                    {
                        "kind": kind,
                        "file_name": _trim_profile_text(artifact.get("file_name")),
                        "sheet_count": int((artifact.get("workbook") or {}).get("sheet_count") or 0),
                        "data_row_count": next(
                            (
                                int(summary.get("data_row_count") or 0)
                                for summary in validation_summary
                                if _trim_profile_text(summary.get("kind")) == kind
                            ),
                            0,
                        ),
                    }
                )

            overlay_total_quantity = sum(int(summary.get("total_quantity") or 0) for summary in overlay_row_summary)
            overlay_total_rows = sum(int(summary.get("row_count") or 0) for summary in overlay_row_summary)
            preview_strategy = "STATIC_SUMMARY"
            preview_engine_mode = "PLAN_CHANGE_PREVIEW"
            preview_warnings: List[Dict[str, Any]] = []
            solver_preview_payload: Dict[str, Any] = {}
            inventory_preview_payload: Dict[str, Any] = {}
            source_type = _trim_profile_text(base_run.get("source_type")).lower()
            should_attempt_solver_preview = source_type == "db" and bool(overlay_rows.get("demand_file"))
            if should_attempt_solver_preview:
                running_simulation = _plan_change_simulation_from_params(params_json)
                running_simulation.update(
                    {
                        "status": "RUNNING",
                        "step": "SOLVER_RUNNING",
                        "progress_pct": 65,
                        "preview_only": True,
                        "receipt_id": receipt_id,
                        "updated_at": datetime.now(timezone.utc).isoformat(),
                    }
                )
                preview_running_params = _plan_change_params_with_runtime(
                    params_json,
                    simulation=running_simulation,
                    overlay_rows=overlay_rows,
                )
                updated_row = registry.update_plan_change(
                    change_id=change_id,
                    status="SIMULATING",
                    params_json=preview_running_params,
                )
                if updated_row is not None:
                    row = updated_row
                    params_json = _normalize_plan_change_params(updated_row.get("params_json"))
                try:
                    solver_preview_payload = _run_plan_change_solver_preview(
                        change_id=change_id,
                        scenario_id=_trim_profile_text(base_run.get("scenario_id")),
                        requested_start=requested_start,
                        requested_end=requested_end,
                        overlay_rows=overlay_rows,
                    )
                    preview_strategy = _trim_profile_text(solver_preview_payload.get("preview_strategy")) or "REAL_SOLVER_RERUN"
                    preview_engine_mode = _trim_profile_text(solver_preview_payload.get("engine_mode")) or "PLAN_CHANGE_SOLVER_PREVIEW"
                    preview_warnings.extend(list(solver_preview_payload.get("warnings") or []))
                except HTTPException:
                    raise
                except Exception as exc:
                    preview_strategy = "STATIC_FALLBACK"
                    preview_warnings.append(
                        {
                            "code": "ERR_SOLVER_PREVIEW_FALLBACK",
                            "message": f"real solver preview unavailable, static preview로 대체했습니다: {exc}",
                        }
                    )
            if bool(overlay_rows.get("inventory_file")):
                inventory_preview_payload, inventory_warnings, inventory_insight_input = (
                    _build_plan_change_inventory_overlay_preview(registry, overlay_rows=overlay_rows)
                )
                preview_warnings.extend(inventory_warnings)
                insight_input = {
                    "base_unscheduled_count": int(
                        _as_optional_text((base_run.get("trace_json") or {}).get("UNSCHEDULED_COUNT")) or 0
                    ),
                    "overlay_artifact_count": len(artifact_items),
                    "overlay_total_rows": overlay_total_rows,
                    "overlay_total_quantity": overlay_total_quantity,
                    "overlay_types": [item["kind"] for item in artifact_items],
                    "overlay_row_count": sum(int(item.get("data_row_count") or 0) for item in artifact_items),
                }
                insight_input.update(inventory_insight_input)
            else:
                insight_input = {
                    "base_unscheduled_count": int(
                        _as_optional_text((base_run.get("trace_json") or {}).get("UNSCHEDULED_COUNT")) or 0
                    ),
                    "overlay_artifact_count": len(artifact_items),
                    "overlay_total_rows": overlay_total_rows,
                    "overlay_total_quantity": overlay_total_quantity,
                    "overlay_types": [item["kind"] for item in artifact_items],
                    "overlay_row_count": sum(int(item.get("data_row_count") or 0) for item in artifact_items),
                }

            if isinstance(solver_preview_payload.get("insight_input"), dict):
                insight_input.update(dict(solver_preview_payload.get("insight_input") or {}))
            preview_warnings = _dedupe_plan_change_warnings(preview_warnings)
            ai_insight = _generate_plan_change_ai_insight(insight_input)
            result_payload = {
                "preview_only": True,
                "engine_mode": preview_engine_mode,
                "preview_strategy": preview_strategy,
                "base_run": {
                    "run_id": _trim_profile_text(base_run.get("run_id")),
                    "scenario_id": _trim_profile_text(base_run.get("scenario_id")),
                    "status": _trim_profile_text(base_run.get("status")),
                    "requested_start": str(base_run.get("requested_start") or ""),
                    "requested_end": str(base_run.get("requested_end") or ""),
                },
                "change_summary": {
                    "change_type": _trim_profile_text(row.get("change_type")),
                    "artifact_count": len(artifact_items),
                    "param_keys": sorted(public_params.keys()),
                },
                "artifact_summary": artifact_items,
                "validation_summary": validation_summary,
                "overlay_row_summary": overlay_row_summary,
                "insight_input": insight_input,
                "bundle_assembly": dict(solver_preview_payload.get("bundle_assembly") or {})
                if isinstance(solver_preview_payload.get("bundle_assembly"), dict)
                else {},
                "solver_preview": dict(solver_preview_payload.get("solver_preview") or {})
                if isinstance(solver_preview_payload.get("solver_preview"), dict)
                else {},
                "inventory_preview": inventory_preview_payload,
                "preview_config": dict(solver_preview_payload.get("preview_config") or {})
                if isinstance(solver_preview_payload.get("preview_config"), dict)
                else {},
                "warnings": preview_warnings,
                "ai_insight": ai_insight,
            }

            simulation = _plan_change_simulation_from_params(params_json)
            simulation.update(
                {
                    "status": "SUCCESS",
                    "step": "COMPLETED",
                    "progress_pct": 100,
                    "preview_only": True,
                    "receipt_id": receipt_id,
                    "updated_at": datetime.now(timezone.utc).isoformat(),
                    "result": result_payload,
                    "error": {},
                }
            )
            next_params = _plan_change_params_with_runtime(
                params_json,
                simulation=simulation,
                overlay_rows=overlay_rows,
            )
            updated = registry.update_plan_change(change_id=change_id, status="READY", params_json=next_params)
            if updated is None:
                raise HTTPException(status_code=500, detail="plan_change 시뮬레이션 결과 저장에 실패했습니다.")
            registry.insert_decision_log(
                scenario_id=_trim_profile_text(base_run.get("scenario_id")),
                event_type="PLAN_CHANGE_SIMULATED",
                payload_json={
                    "ENTITY_TYPE": "plan_change",
                    "ENTITY_ID": change_id,
                    "PLAN_CHANGE_ID": change_id,
                    "BASE_RUN_ID": _trim_profile_text(row.get("base_run_id")),
                    "REQUEST_ID": request_id,
                    "RECEIPT_ID": receipt_id,
                    "ARTIFACT_COUNT": len(artifact_items),
                    "PREVIEW_ONLY": True,
                    "PREVIEW_STRATEGY": preview_strategy,
                },
            )
            _update_operation_receipt(
                registry,
                receipt_id=receipt_id,
                status="SUCCEEDED",
                artifacts={"artifact_count": len(artifact_items)},
                meta={
                    "request_id": request_id,
                    "result_ref": {"change_id": change_id},
                    "preview_strategy": preview_strategy,
                },
                ended=True,
            )
            _METRIC_PLAN_CHANGE_SIMULATION_TOTAL.labels(
                status="SUCCESS",
                preview_strategy=preview_strategy,
            ).inc()
            return PlanChangeSimulateResponse(
                plan_change=_build_plan_change_record(updated),
                status="ACCEPTED",
            )
        except HTTPException as exc:
            failed_status = _receipt_status_from_http_exception(exc)
            error_payload = exc.detail if isinstance(exc.detail, dict) else _plan_change_error_payload(
                error_code=failed_status,
                message=_extract_error_message(exc.detail),
            )
            failed_simulation = _plan_change_simulation_from_params(params_json)
            failed_simulation.update(
                {
                    "status": failed_status,
                    "step": "FAILED",
                    "progress_pct": 100,
                    "preview_only": True,
                    "receipt_id": receipt_id,
                    "updated_at": datetime.now(timezone.utc).isoformat(),
                    "result": {},
                    "error": error_payload,
                }
            )
            failure_params = _plan_change_params_with_runtime(params_json, simulation=failed_simulation)
            registry.update_plan_change(change_id=change_id, status="DRAFT", params_json=failure_params)
            _update_operation_receipt(
                registry,
                receipt_id=receipt_id,
                status=failed_status,
                error={
                    "status_code": int(exc.status_code),
                    "message": _extract_error_message(exc.detail),
                },
                meta={"request_id": request_id},
                ended=True,
            )
            _METRIC_PLAN_CHANGE_SIMULATION_TOTAL.labels(
                status=failed_status,
                preview_strategy=preview_strategy,
            ).inc()
            raise
        except Exception as exc:
            error_payload = _plan_change_error_payload(
                error_code="FAILED",
                message="plan_change 시뮬레이션 처리 중 내부 오류가 발생했습니다.",
                details=[{"message": str(exc)}],
            )
            failed_simulation = _plan_change_simulation_from_params(params_json)
            failed_simulation.update(
                {
                    "status": "FAILED",
                    "step": "FAILED",
                    "progress_pct": 100,
                    "preview_only": True,
                    "receipt_id": receipt_id,
                    "updated_at": datetime.now(timezone.utc).isoformat(),
                    "result": {},
                    "error": error_payload,
                }
            )
            failure_params = _plan_change_params_with_runtime(params_json, simulation=failed_simulation)
            registry.update_plan_change(change_id=change_id, status="DRAFT", params_json=failure_params)
            _update_operation_receipt(
                registry,
                receipt_id=receipt_id,
                status="FAILED",
                error={
                    "status_code": 500,
                    "message": str(exc),
                },
                meta={"request_id": request_id},
                ended=True,
            )
            _METRIC_PLAN_CHANGE_SIMULATION_TOTAL.labels(
                status="FAILED",
                preview_strategy=preview_strategy,
            ).inc()
            raise HTTPException(status_code=500, detail=error_payload) from exc
    finally:
        registry.close()


@app.post("/v1/solver/runs", response_model=SolveRunResponse)
def create_solver_run(
    request: SolveRunRequest,
    actor_claims: Dict[str, Any] = Depends(get_current_actor),
    x_idempotency_key: str | None = Header(default=None, alias="Idempotency-Key"),
    x_request_id: str | None = Header(default=None, alias="X-Request-Id"),
) -> SolveRunResponse:
    # Lazy import: solver path pulls heavy modules (ortools/pandas/engine).
    # Kiosk/Ops control-plane endpoints should boot even if solver deps are unavailable.
    from . import service as api_service

    try:
        config = api_service.build_config(request.overrides)
    except Exception as exc:
        raise HTTPException(status_code=400, detail=f"Invalid overrides: {exc}") from exc

    try:
        registry = RunRegistry(config)
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc
    receipt_id: str | None = None
    operation_request_id: str | None = None
    queued_run_id: str | None = None
    try:
        actor = _resolve_authenticated_actor(registry, actor_claims)
        _ensure_operational_command_actor(actor, operation="solver run 생성")
        _ensure_command_kernel(
            registry,
            operation="solver run 생성",
            require_solver_run=True,
            require_idempotency=True,
            require_receipt=True,
        )
        _ensure_solver_worker_queue_contract(registry, operation="solver run 생성")
        _ensure_operational_upstream_truth_ready(registry, operation="solver run 생성")
        idempotency_key = (x_idempotency_key or "").strip() or None
        operation_request_id = (x_request_id or "").strip() or idempotency_key or str(uuid.uuid4())
        idempotency_endpoint = "run.create"
        if idempotency_key:
            cached = registry.fetch_idempotency(idempotency_key, idempotency_endpoint)
            if cached is not None:
                return JSONResponse(
                    status_code=int(cached.get("status_code") or 200),
                    content=cached.get("response") or {},
                )
        request = request.model_copy(
            update={
                "requested_by": str(actor.get("actor_email") or actor.get("actor_id") or ""),
            }
        )
        _ensure_runtime_db_source(request.source, operation="solver run 생성")
        api_service.validate_solve_request(request)
        queued_run_id = api_service.new_run_id()
        queued_at = datetime.now(timezone.utc)
        queued_output_xlsx_path = str(api_service.resolve_output_path(request, queued_run_id))
        effective_writeback = api_service.effective_writeback(request.source, request.writeback)
        worker_timeout_at = _solver_worker_timeout_at(queued_at, time_limit_sec=int(config.time_limit_sec))
        actor_provenance = _build_run_actor_provenance(actor)
        lineage_json = dict(actor_provenance)
        trace_json: Dict[str, Any] = dict(actor_provenance)
        trace_json["queue_state"] = "QUEUED"
        trace_json["worker"] = {
            "launch_mode": "db_lease_subprocess",
            "log_path": str(_solver_worker_log_path(queued_run_id)),
        }
        trace_json["queue_request"] = {
            "queue_mode": "RUN_CREATE",
            "request_id": operation_request_id,
            "receipt_id": None,
            "out_path": request.out_path or queued_output_xlsx_path,
            "writeback": effective_writeback,
            "requested_by": request.requested_by,
            "overrides": _serialize_solver_overrides(request.overrides),
        }
        trace_json["lineage_json"] = dict(lineage_json)

        receipt_id = _create_operation_receipt(
            registry,
            action_key="run.create",
            entity_type="run",
            entity_id=queued_run_id,
            request_id=operation_request_id,
            actor=actor,
            status="RUNNING",
            idempotency_key=idempotency_key,
            meta={
                "endpoint": "/v1/solver/runs",
                "scenario": request.scenario,
                "source_type": request.source,
                "requested_start": str(request.start_date),
                "requested_end": str(request.end_date),
                "run_id": queued_run_id,
            },
        )
        trace_json["queue_request"]["receipt_id"] = receipt_id
        _persist_run_record_or_fail(
            registry,
            run_id=queued_run_id,
            scenario_id=request.scenario,
            source_type=request.source,
            requested_start=request.start_date,
            requested_end=request.end_date,
            status="QUEUED",
            requested_by=request.requested_by,
            output_xlsx_path=queued_output_xlsx_path,
            trace_json=trace_json,
            error_message=None,
            created_at=queued_at,
            started_at=None,
            finished_at=None,
            queued_at=queued_at,
            lease_owner=None,
            lease_expires_at=None,
            last_heartbeat_at=None,
            attempt_count=0,
            timeout_at=worker_timeout_at,
            cancel_requested_at=None,
            payload_json=dict(trace_json["queue_request"]),
            markings=[],
            lineage_json=lineage_json,
        )
        registry.insert_decision_log(
            scenario_id=request.scenario,
            event_type="RUN_REQUESTED",
            payload_json={
                "ENTITY_TYPE": "run",
                "ENTITY_ID": queued_run_id,
                "RUN_ID": queued_run_id,
                "REQUEST_ID": operation_request_id,
                "RECEIPT_ID": receipt_id,
                "ACTOR_ID": actor.get("actor_id"),
                "ACTOR_EMAIL": actor.get("actor_email"),
                "ACTOR_ROLE": actor.get("actor_role"),
                "AFTER": {"status": "QUEUED"},
            },
        )
        try:
            _launch_solver_run_worker_or_fail(queued_run_id)
        except Exception as exc:
            failed_trace = dict(trace_json)
            failed_trace["queue_state"] = "FAILED"
            failed_trace["worker_launch_error"] = str(exc)
            _persist_run_record_or_fail(
                registry,
                run_id=queued_run_id,
                scenario_id=request.scenario,
                source_type=request.source,
                requested_start=request.start_date,
                requested_end=request.end_date,
                status="FAILED",
                requested_by=request.requested_by,
                output_xlsx_path=queued_output_xlsx_path,
                trace_json=failed_trace,
                error_message=str(exc),
                created_at=queued_at,
                started_at=queued_at,
                finished_at=queued_at,
                queued_at=queued_at,
                lease_owner=None,
                lease_expires_at=None,
                last_heartbeat_at=None,
                attempt_count=0,
                timeout_at=worker_timeout_at,
                cancel_requested_at=None,
                payload_json=dict(trace_json["queue_request"]),
                markings=[],
                lineage_json=lineage_json,
            )
            raise
        response = SolveRunResponse(
            run_id=queued_run_id,
            receipt_id=receipt_id,
            status="QUEUED",
            solve_status="QUEUED",
            source=request.source,
            scenario=request.scenario,
            start_date=request.start_date,
            end_date=request.end_date,
            output_xlsx_path=queued_output_xlsx_path,
            writeback=effective_writeback,
            started_at_utc=queued_at,
            finished_at_utc=queued_at,
            plan_segments=0,
            decision_log_rows=0,
            objective={},
        )
        payload = response.model_dump(mode="json") if hasattr(response, "model_dump") else response.dict()  # type: ignore[attr-defined]
        if idempotency_key:
            if isinstance(payload, dict):
                registry.store_idempotency(
                    key=idempotency_key,
                    endpoint=idempotency_endpoint,
                    status_code=202,
                    response_json=payload,
                )
        return JSONResponse(status_code=202, content=payload)
    except HTTPException as exc:
        _update_operation_receipt(
            registry,
            receipt_id=receipt_id,
            status=_receipt_status_from_http_exception(exc),
            error={"status_code": int(exc.status_code), "message": _extract_error_message(exc.detail)},
            meta={"request_id": operation_request_id},
            ended=True,
        )
        raise
    except ValueError as exc:
        _update_operation_receipt(
            registry,
            receipt_id=receipt_id,
            status="FAILED",
            error={"status_code": 400, "message": str(exc)},
            meta={"request_id": operation_request_id},
            ended=True,
        )
        raise HTTPException(status_code=400, detail=str(exc)) from exc
    except Exception as exc:
        _update_operation_receipt(
            registry,
            receipt_id=receipt_id,
            status="FAILED",
            error={"status_code": 500, "message": str(exc)},
            meta={"request_id": operation_request_id},
            ended=True,
        )
        raise ApiError(
            500,
            f"solver run execution failed: {exc}",
            hint="서버 로그를 확인한 뒤 재시도하세요.",
        ) from exc
    finally:
        registry.close()


@app.get("/v1/solver/runs/{run_id}", response_model=SolverRunRecord)
def get_solver_run(
    run_id: str,
    actor_claims: Dict[str, Any] = Depends(get_optional_current_actor),
) -> SolverRunRecord:
    try:
        registry = RunRegistry(Config())
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc
    try:
        _ensure_db_connection(registry, operation="solver run 조회")
        if not registry.enabled:
            raise HTTPException(
                status_code=503,
                detail="Run registry table is not available. Apply bohae_aps_v20/sql/20_app_ops_foundation_v1.sql first.",
            )
        row = registry.fetch_run(run_id)
        if row is None:
            _raise_run_not_found(registry, run_id)
        return SolverRunRecord(**_enrich_run_record_with_engine_meta(row))
    finally:
        registry.close()


