@app.post("/v1/mvp/demo-plan", response_model=MvpDemoPlanResponse)
def create_mvp_demo_plan(
    request: MvpDemoPlanRequest,
    actor_claims: Dict[str, Any] = Depends(get_current_actor),
) -> MvpDemoPlanResponse:
    try:
        registry = RunRegistry(Config())
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc
    try:
        _require_manager_or_admin(registry, actor_claims)
        payload = request.model_dump()
        use_actuals = payload.pop("use_actuals", False)
        if use_actuals:
            result = build_demo_from_actuals(payload)
        else:
            result = build_mvp_demo_plan(payload)
        return MvpDemoPlanResponse(**result)
    except HTTPException:
        raise
    except Exception as exc:
        raise ApiError(
            500,
            f"MVP 데모 계획 생성 실패: {exc}",
            hint="입력 파일 헤더/매핑/캘린더를 확인하고 재시도하세요.",
        ) from exc
    finally:
        registry.close()


@app.get("/v1/dashboard", response_model=DashboardResponse)
def get_dashboard(
    actor_claims: Dict[str, Any] = Depends(get_optional_current_actor),
) -> DashboardResponse:
    try:
        registry = RunRegistry(Config())
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc
    try:
        _ensure_db_connection(registry, operation="대시보드 조회")
        if not registry.enabled:
            raise HTTPException(status_code=503, detail="Registry table is not available.")
            
        rows = registry.list_runs(limit=100)
        
        totalRuns = len(rows)
        runningRuns = sum(1 for r in rows if str(r.get("status", "")).upper() == "RUNNING")
        
        pendingApprovals = 0
        approvedRuns = 0
        rejectedRuns = 0
        sumUnscheduled = 0.0
        countUnscheduled = 0
        
        if registry.approval_enabled:
            approvals = registry.list_approvals(limit=500)
            for a in approvals:
                ast = str(a.get("approval_status", "")).upper()
                if ast == "PENDING":
                    pendingApprovals += 1
                elif ast == "APPROVED":
                    approvedRuns += 1
                elif ast == "REJECTED":
                    rejectedRuns += 1
                    
        for r in rows:
            trace_json = r.get("trace_json", {})
            if isinstance(trace_json, str):
                try:
                    trace_json = json.loads(trace_json)
                except Exception:
                    trace_json = {}
            qty = trace_json.get("unscheduled_qty", None)
            if qty is not None:
                sumUnscheduled += float(qty)
                countUnscheduled += 1
                
        avgUnscheduled = 0.0
        if countUnscheduled > 0:
            avgUnscheduled = round(sumUnscheduled / countUnscheduled, 2)
            
        from bohae_aps_v20.api.schemas import DashboardSummary, DashboardResponse
        summary = DashboardSummary(
            totalRuns=totalRuns,
            runningRuns=runningRuns,
            pendingApprovals=pendingApprovals,
            approvedRuns=approvedRuns,
            rejectedRuns=rejectedRuns,
            avgUnscheduled=avgUnscheduled,
        )
        latest_runs = [SolverRunRecord(**_enrich_run_record_with_engine_meta(row)) for row in rows[:50]]
        return DashboardResponse(summary=summary, latestRuns=latest_runs)
    finally:
        registry.close()


