def _load_public_user_record_by_user_id(registry: RunRegistry, user_id: str) -> PublicUserRecord:
    normalized_user_id = _trim_profile_text(user_id)
    for row in registry.list_app_users(limit=5000, include_inactive=True):
        if _trim_profile_text(row.get("user_id")) == normalized_user_id:
            return _to_public_user_record(row)
    raise HTTPException(status_code=404, detail="사용자를 찾을 수 없습니다.")


def _count_active_admin_users(registry: RunRegistry) -> int:
    return sum(
        1
        for row in registry.list_app_users(limit=5000, include_inactive=True)
        if bool(row.get("is_active", True)) and str(row.get("role_code") or "").upper() == "ADMIN"
    )


def _set_system_user_role(
    registry: RunRegistry,
    support: Dict[str, Any],
    *,
    user_id: str,
    role_code: str,
    actor_user_id: str,
    request_id: str,
    expires_at: datetime | None,
    memo: str | None,
) -> None:
    if not registry.conn:
        raise HTTPException(status_code=503, detail="사용자 권한 저장 중 DB 연결에 실패했습니다.")
    normalized_role = str(role_code or "VIEWER").upper().strip()
    cur = registry.conn.cursor()
    try:
        cur.execute(
            f"DELETE FROM {registry.schema}.app_user_role WHERE user_id = %s",
            [user_id],
        )
        cur.execute(
            f"""
            INSERT INTO {registry.schema}.app_user_role (user_id, role_code)
            VALUES (%s, %s)
            """,
            [user_id, normalized_role],
        )
        if bool(support.get("roleAssignment")):
            cur.execute(
                f"""
                UPDATE {registry.schema}.app_user_role_assignment
                   SET revoked_at = COALESCE(revoked_at, now())
                 WHERE user_id = %s
                   AND revoked_at IS NULL
                """,
                [user_id],
            )
            cur.execute(
                f"""
                INSERT INTO {registry.schema}.app_user_role_assignment (
                    user_id,
                    role_code,
                    granted_by_user_id,
                    assignment_source,
                    request_id,
                    starts_at,
                    expires_at,
                    meta_json
                )
                VALUES (%s, %s, %s, 'SYSTEM_ADMIN', %s, now(), %s, %s::jsonb)
                """,
                [
                    user_id,
                    normalized_role,
                    actor_user_id or None,
                    request_id,
                    expires_at,
                    json.dumps(
                        {
                            "memo": _trim_profile_text(memo) or None,
                            "updated_by": actor_user_id or None,
                        }
                    ),
                ],
            )
    finally:
        try:
            cur.close()
        except Exception:
            pass


def _provision_system_user(
    registry: RunRegistry,
    actor: Dict[str, Any],
    payload: SystemUserInviteRequest,
) -> PublicUserRecord:
    _ensure_db_connection(registry, operation="사용자 프로비저닝")
    support = _get_profile_schema_support(registry)
    normalized_employee_no = _trim_profile_text(payload.employeeNo).replace(" ", "")
    normalized_name = _trim_profile_text(payload.name)
    normalized_email = _trim_profile_text(payload.email).lower()
    if not normalized_employee_no:
        raise HTTPException(status_code=400, detail="사번을 입력해주세요.")
    if normalized_email and "@" not in normalized_email:
        raise HTTPException(status_code=400, detail="이메일 형식을 확인해주세요.")

    existing_user = registry.fetch_app_user_by_identity(employee_no=normalized_employee_no)
    if normalized_email:
        by_email = registry.fetch_app_user_by_email(normalized_email)
        if by_email and _trim_profile_text(by_email.get("user_id")) not in {
            "",
            _trim_profile_text(existing_user.get("user_id")) if existing_user else "",
        }:
            raise HTTPException(status_code=409, detail="같은 이메일을 사용하는 다른 사용자가 이미 존재합니다.")

    profile = _find_employee_verification_profile(registry, normalized_employee_no) or {}
    user_id = (
        _trim_profile_text(existing_user.get("user_id")) if existing_user else ""
    ) or _trim_profile_text(profile.get("userId")) or f"u_emp_{normalized_employee_no}"
    display_name = (
        normalized_name
        or _trim_profile_text(profile.get("displayName"))
        or _trim_profile_text(profile.get("legalName"))
        or (_trim_profile_text(existing_user.get("display_name")) if existing_user else "")
        or normalized_employee_no
    )
    email = (
        normalized_email
        or _trim_profile_text(profile.get("email"))
        or (_trim_profile_text(existing_user.get("email")) if existing_user else "")
        or _build_synthetic_email(normalized_employee_no)
    )
    app_columns = dict(support.get("appUserColumns") or {})
    request_id = f"req_sys_user_{uuid.uuid4().hex}"
    insert_columns = ["user_id", "email", "display_name", "is_active"]
    insert_values: List[Any] = [user_id, email, display_name, True]
    update_assignments = ["email = EXCLUDED.email", "display_name = EXCLUDED.display_name", "is_active = true"]
    if app_columns.get("employeeNo"):
        insert_columns.append("employee_no")
        insert_values.append(normalized_employee_no)
        update_assignments.append("employee_no = COALESCE(app_user.employee_no, EXCLUDED.employee_no)")
    if app_columns.get("authSubject"):
        auth_subject = (_trim_profile_text(existing_user.get("auth_subject")) if existing_user else "") or _trim_profile_text(profile.get("authSubject"))
        insert_columns.append("auth_subject")
        insert_values.append(auth_subject or None)
        update_assignments.append("auth_subject = COALESCE(app_user.auth_subject, EXCLUDED.auth_subject)")
    if app_columns.get("staffId"):
        insert_columns.append("staff_id")
        insert_values.append(_trim_profile_text(profile.get("staffId")) or None)
        update_assignments.append("staff_id = COALESCE(app_user.staff_id, EXCLUDED.staff_id)")
    if app_columns.get("authSource"):
        insert_columns.append("auth_source")
        insert_values.append("FALLBACK")
        update_assignments.append("auth_source = COALESCE(app_user.auth_source, EXCLUDED.auth_source)")
    if app_columns.get("lastIdentitySyncAt"):
        insert_columns.append("last_identity_sync_at")
        insert_values.append(datetime.now(timezone.utc).isoformat())
        update_assignments.append("last_identity_sync_at = now()")
    if app_columns.get("emailIsSynthetic"):
        insert_columns.append("email_is_synthetic")
        insert_values.append(not bool(normalized_email or _trim_profile_text(profile.get("email"))))
        update_assignments.append("email_is_synthetic = EXCLUDED.email_is_synthetic")

    cur = registry.conn.cursor()
    try:
        cur.execute(
            f"""
            INSERT INTO {registry.schema}.app_user ({', '.join(insert_columns)})
            VALUES ({', '.join(['%s'] * len(insert_values))})
            ON CONFLICT (user_id)
            DO UPDATE SET {', '.join(update_assignments)}
            """,
            insert_values,
        )
        _set_system_user_role(
            registry,
            support,
            user_id=user_id,
            role_code=payload.role,
            actor_user_id=_trim_profile_text(actor.get("actor_id")),
            request_id=request_id,
            expires_at=_parse_datetime_value(payload.expiresAt),
            memo=payload.memo,
        )
        registry.conn.commit()
    except HTTPException:
        registry.conn.rollback()
        raise
    except Exception as exc:
        registry.conn.rollback()
        raise HTTPException(status_code=500, detail="사용자 프로비저닝 중 오류가 발생했습니다.") from exc
    finally:
        try:
            cur.close()
        except Exception:
            pass

    return _load_public_user_record_by_user_id(registry, user_id)


def _update_system_user_role(
    registry: RunRegistry,
    actor: Dict[str, Any],
    *,
    user_id: str,
    payload: SystemUserRoleUpdateRequest,
) -> PublicUserRecord:
    _ensure_db_connection(registry, operation="사용자 권한 변경")
    current = _load_public_user_record_by_user_id(registry, user_id)
    next_role = str(payload.role or "VIEWER").upper().strip()
    if current.role == "ADMIN" and next_role != "ADMIN" and current.isActive and _count_active_admin_users(registry) <= 1:
        raise HTTPException(status_code=409, detail="마지막 활성 관리자 권한은 내릴 수 없습니다.")
    support = _get_profile_schema_support(registry)
    try:
        _set_system_user_role(
            registry,
            support,
            user_id=current.id,
            role_code=next_role,
            actor_user_id=_trim_profile_text(actor.get("actor_id")),
            request_id=f"req_sys_role_{uuid.uuid4().hex}",
            expires_at=_parse_datetime_value(payload.expiresAt),
            memo=payload.memo,
        )
        registry.conn.commit()
    except HTTPException:
        registry.conn.rollback()
        raise
    except Exception as exc:
        registry.conn.rollback()
        raise HTTPException(status_code=500, detail="사용자 권한 변경 중 오류가 발생했습니다.") from exc
    return _load_public_user_record_by_user_id(registry, current.id)


def _deactivate_system_user(
    registry: RunRegistry,
    actor: Dict[str, Any],
    *,
    user_id: str,
    payload: SystemUserDeactivateRequest,
) -> PublicUserRecord:
    _ensure_db_connection(registry, operation="사용자 비활성화")
    target = _load_public_user_record_by_user_id(registry, user_id)
    actor_user_id = _trim_profile_text(actor.get("actor_id"))
    if target.id == actor_user_id:
        raise HTTPException(status_code=409, detail="현재 로그인한 본인 계정은 비활성화할 수 없습니다.")
    if target.role == "ADMIN" and target.isActive and _count_active_admin_users(registry) <= 1:
        raise HTTPException(status_code=409, detail="마지막 활성 관리자 계정은 비활성화할 수 없습니다.")
    support = _get_profile_schema_support(registry)
    cur = registry.conn.cursor()
    try:
        cur.execute(
            f"""
            UPDATE {registry.schema}.app_user
               SET is_active = false
             WHERE user_id = %s
            """,
            [target.id],
        )
        if bool(support.get("localCredentialTable")):
            cur.execute(
                f"""
                UPDATE {registry.schema}.auth_local_credential
                   SET is_active = false,
                       updated_at = now()
                 WHERE user_id = %s
                """,
                [target.id],
            )
        if bool(support.get("roleAssignment")):
            cur.execute(
                f"""
                UPDATE {registry.schema}.app_user_role_assignment
                   SET revoked_at = COALESCE(revoked_at, now())
                 WHERE user_id = %s
                   AND revoked_at IS NULL
                """,
                [target.id],
            )
        registry.conn.commit()
    except HTTPException:
        registry.conn.rollback()
        raise
    except Exception as exc:
        registry.conn.rollback()
        raise HTTPException(status_code=500, detail="사용자 비활성화 중 오류가 발생했습니다.") from exc
    finally:
        try:
            cur.close()
        except Exception:
            pass
    return _load_public_user_record_by_user_id(registry, target.id)


