@app.post("/v1/masters/{master_type}")
def create_master_row(
    master_type: str,
    payload: Dict[str, Any] = Body(default={}),
    actor_claims: Dict[str, Any] = Depends(get_current_actor),
) -> Dict[str, Any]:
    try:
        registry = RunRegistry(Config())
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc
    receipt_id: str | None = None
    try:
        _ensure_db_connection(registry, operation="마스터 생성")
        actor = _require_authenticated_user(registry, actor_claims)
        actor_role = str(actor.get("actor_role") or "VIEWER").upper()
        if actor_role not in {"ADMIN", "MANAGER"}:
            raise HTTPException(status_code=403, detail="마스터 생성 권한이 없습니다.")
        ensure_factory_state_schema(registry)
        normalized_type = _assert_supported_master_type(master_type)
        entity_id = _trim_profile_text(payload.get("id")) or _trim_profile_text(payload.get("code")) or f"{normalized_type}_{uuid.uuid4().hex[:8]}"
        request_id = str(uuid.uuid4())
        receipt_id = _create_operation_receipt(
            registry,
            action_key="master.create",
            entity_type="master",
            entity_id=entity_id,
            request_id=request_id,
            actor=actor,
            status="RUNNING",
            meta={"master_type": normalized_type},
        )
        row = upsert_factory_master_override(
            registry,
            actor_id=str(actor.get("actor_id") or actor.get("actor_email") or ""),
            master_type=normalized_type,
            entity_id=entity_id,
            payload=payload,
        )
        registry.insert_decision_log(
            scenario_id="OPS_MASTER",
            event_type="MASTER_CREATED",
            payload_json={
                "ENTITY_TYPE": "master",
                "ENTITY_ID": entity_id,
                "MASTER_TYPE": normalized_type,
                "REQUEST_ID": request_id,
                "RECEIPT_ID": receipt_id,
                "ACTOR_ID": actor.get("actor_id"),
                "ACTOR_ROLE": actor.get("actor_role"),
            },
        )
        _update_operation_receipt(
            registry,
            receipt_id=receipt_id,
            status="SUCCEEDED",
            meta={"request_id": request_id, "result_ref": {"entity_id": entity_id}},
            ended=True,
        )
        return {"data": row, "receipt_id": receipt_id, "status": "SUCCEEDED"}
    except HTTPException as exc:
        _update_operation_receipt(
            registry,
            receipt_id=receipt_id,
            status=_receipt_status_from_http_exception(exc),
            error={"status_code": int(exc.status_code), "message": _extract_error_message(exc.detail)},
            ended=True,
        )
        raise
    finally:
        registry.close()


