        _ensure_db_connection(registry, operation="마스터 일괄 삭제")
        actor = _require_authenticated_user(registry, actor_claims)
        actor_role = str(actor.get("actor_role") or "VIEWER").upper()
        if actor_role not in {"ADMIN", "MANAGER"}:
            raise HTTPException(status_code=403, detail="마스터 일괄 삭제 권한이 없습니다.")
