def _extract_solver_run_line_id(run_row: Dict[str, Any]) -> Optional[str]:
    trace = run_row.get("trace_json")
    if not isinstance(trace, dict):
        return None

    for key in ("LINE_ID", "line_id", "lineId"):
        value = str(trace.get(key) or "").strip().upper()
        if value:
            return value
    return None


def _build_accessible_run_line_index(
    registry: RunRegistry,
    actor: Dict[str, Any],
    *,
    limit: int = 500,
) -> Dict[str, str]:
    rows = registry.list_runs(limit=limit)
    if str(actor.get("actor_role") or "").upper() not in {"ADMIN", "MANAGER"}:
        rows = [row for row in rows if _actor_can_access_run(actor, row)]

    mapping: Dict[str, str] = {}
    for row in rows:
        run_id = str(row.get("run_id") or "").strip().upper()
        line_id = _extract_solver_run_line_id(row)
        if run_id and line_id:
            mapping[run_id] = line_id
    return mapping


def _build_lims_line_summary_payload(
    registry: RunRegistry,
    actor: Dict[str, Any],
    *,
    line_id: str,
) -> Dict[str, Any]:
    normalized_line_id = str(line_id or "").strip().upper()
    if not normalized_line_id:
        raise HTTPException(status_code=400, detail="line_id는 필수입니다.")

    snapshot = _load_lims_snapshot_payload(registry)
    run_id_to_line_id = _build_accessible_run_line_index(registry, actor)
    samples = [
        sample
        for sample in snapshot["samples"]
        if run_id_to_line_id.get(str(sample.get("run_id") or "").strip().upper()) == normalized_line_id
    ]
    sample_ids = {str(row.get("sample_id") or "") for row in samples}
    requests = [row for row in snapshot["requests"] if str(row.get("sample_id") or "") in sample_ids]
    request_ids = {str(row.get("request_id") or "") for row in requests}
    results = [row for row in snapshot["results"] if str(row.get("request_id") or "") in request_ids]
    lot_ids = {str(row.get("lot_id") or "") for row in samples}
    approvals = [row for row in snapshot["approvals"] if str(row.get("lot_id") or "") in lot_ids]

    oos_count = sum(1 for row in results if str(row.get("status") or "").upper() == "OOS")
    pass_count = sum(1 for row in results if str(row.get("status") or "").upper() == "PASS")
    fail_count = sum(1 for row in results if str(row.get("status") or "").upper() == "FAIL")
    pending_count = sum(1 for row in requests if str(row.get("status") or "").upper() != "COMPLETED")
    latest_measured_at = None
    measured_rows = [str(row.get("measured_at") or "").strip() for row in results if str(row.get("measured_at") or "").strip()]
    if measured_rows:
        latest_measured_at = sorted(measured_rows, reverse=True)[0]

    recent_results = sorted(
        list(results),
        key=lambda row: str(row.get("measured_at") or ""),
        reverse=True,
    )[:5]

    return {
        "data": {
            "line_id": normalized_line_id,
            "sample_count": len(samples),
            "request_count": len(requests),
            "pending_count": pending_count,
            "result_count": len(results),
            "pass_count": pass_count,
            "fail_count": fail_count,
            "oos_count": oos_count,
            "approval_pending_count": sum(1 for row in approvals if not str(row.get("decision") or "").strip()),
            "approval_done_count": sum(1 for row in approvals if str(row.get("decision") or "").strip()),
            "latest_measured_at": latest_measured_at,
            "recent_results": [
                {
                    "result_id": str(row.get("result_id") or ""),
                    "sample_id": str(row.get("sample_id") or ""),
                    "analyte": str(row.get("analyte") or ""),
                    "measured_value": row.get("measured_value"),
                    "unit": str(row.get("unit") or ""),
                    "status": str(row.get("status") or ""),
                    "measured_at": str(row.get("measured_at") or ""),
                }
                for row in recent_results
            ],
        },
        "source_mode": _task_source_mode_for_actor(actor),
        "last_updated_at": snapshot.get("latestUpdatedAt"),
    }


def _build_lims_line_summary_map_payload(
    registry: RunRegistry,
    actor: Dict[str, Any],
    *,
    line_ids: List[str],
) -> Dict[str, Any]:
    run_id_to_line_id = _build_accessible_run_line_index(registry, actor)
    all_line_ids = sorted({line_id for line_id in run_id_to_line_id.values() if line_id})
    requested_set = {str(line_id or "").strip().upper() for line_id in line_ids if str(line_id or "").strip()}
    target_line_ids = [line_id for line_id in all_line_ids if not requested_set or line_id in requested_set]
    target_set = set(target_line_ids)

    snapshot = _load_lims_snapshot_payload(registry)
    samples = []
    for sample in snapshot["samples"]:
        run_id = str(sample.get("run_id") or "").strip().upper()
        mapped_line_id = run_id_to_line_id.get(run_id)
        if mapped_line_id and mapped_line_id in target_set:
            samples.append({**sample, "line_id": mapped_line_id})

    sample_id_to_line_id = {str(sample.get("sample_id") or ""): str(sample.get("line_id") or "") for sample in samples}
    requests = [row for row in snapshot["requests"] if str(row.get("sample_id") or "") in sample_id_to_line_id]
    request_id_to_line_id = {
        str(row.get("request_id") or ""): sample_id_to_line_id.get(str(row.get("sample_id") or ""), "")
        for row in requests
    }
    results = [row for row in snapshot["results"] if str(row.get("request_id") or "") in request_id_to_line_id]

    data: Dict[str, Dict[str, int]] = {
        line_id: {
            "sample_count": 0,
            "request_count": 0,
            "pending_count": 0,
            "result_count": 0,
            "pass_count": 0,
            "fail_count": 0,
            "oos_count": 0,
        }
        for line_id in target_line_ids
    }

    for sample in samples:
        line_id = str(sample.get("line_id") or "")
        if line_id in data:
            data[line_id]["sample_count"] += 1

    for request in requests:
        line_id = request_id_to_line_id.get(str(request.get("request_id") or ""), "")
        if line_id not in data:
            continue
        data[line_id]["request_count"] += 1
        if str(request.get("status") or "").upper() != "COMPLETED":
            data[line_id]["pending_count"] += 1

    for result in results:
        line_id = request_id_to_line_id.get(str(result.get("request_id") or ""), "")
        if line_id not in data:
            continue
        data[line_id]["result_count"] += 1
        status = str(result.get("status") or "").upper()
        if status == "PASS":
            data[line_id]["pass_count"] += 1
        elif status == "FAIL":
            data[line_id]["fail_count"] += 1
        elif status == "OOS":
            data[line_id]["oos_count"] += 1

    return {
        "data": data,
        "count": len(data),
        "source_mode": _task_source_mode_for_actor(actor),
        "last_updated_at": snapshot.get("latestUpdatedAt"),
    }


