_ERP_SYNC_RUNTIME: Dict[str, Any] = {
    "status": None,
    "logs": [],
    "scheduler": {
        "active": False,
        "interval_ms": 60 * 60 * 1000,
        "retry_base_ms": 30_000,
        "retry_max_ms": 10 * 60 * 1000,
        "max_retries": 5,
        "retry_count": 0,
        "next_run_at": None,
        "last_run_started_at": None,
        "last_run_finished_at": None,
        "last_result": "IDLE",
        "last_error": None,
    },
    "syncing": False,
}


def _erp_sync_store() -> Dict[str, Any]:
    return _ERP_SYNC_RUNTIME


def _build_local_erp_sync_status(registry: RunRegistry) -> Dict[str, Any]:
    inventory_rows = _list_scm_inventory_payload(registry)
    item_rows = _list_master_rows_payload(registry, master_type="item", limit=2000).get("data") or []
    bom_rows = _list_master_rows_payload(registry, master_type="bom", limit=2000).get("data") or []
    items = sorted({str(row.get("code") or row.get("item_id") or "").strip() for row in list(item_rows) + list(inventory_rows) if str(row.get("code") or row.get("item_id") or "").strip()})
    lots = sorted({str(row.get("lot_id") or "").strip() for row in inventory_rows if str(row.get("lot_id") or "").strip()})
    warehouses = sorted({str(row.get("warehouse_id") or "").strip() for row in inventory_rows if str(row.get("warehouse_id") or "").strip()})
    locations = sorted({str(row.get("location_id") or "").strip() for row in inventory_rows if str(row.get("location_id") or "").strip()})
    warehouse_locations = sorted({
        f"{str(row.get('warehouse_id') or '').strip()}::{str(row.get('location_id') or '').strip()}"
        for row in inventory_rows
        if str(row.get("warehouse_id") or "").strip() and str(row.get("location_id") or "").strip()
    })
    source = "LOCAL_MASTER_DB"
    if os.getenv("BOHAE_UNI_ERP_BASE_URL") or os.getenv("UNI_ERP_BASE_URL") or os.getenv("BOHAE_ERP_BASE_URL"):
        source = "UNI_API"
    state = "OK" if source == "UNI_API" else "STALE"
    message = "UNI ERP 마스터 동기화 준비됨" if source == "UNI_API" else "UNI ERP URL 미설정, 로컬 마스터 기반 동기화"
    now_iso = datetime.now(timezone.utc).isoformat()
    return {
        "state": state,
        "source": source,
        "message": message,
        "last_synced_at": now_iso,
        "updated_at": now_iso,
        "counts": {
            "items": len(items),
            "lots": len(lots),
            "warehouses": len(warehouses),
            "locations": len(locations),
            "boms": len([row for row in bom_rows if str(row.get("code") or "").strip()]),
        },
        "snapshot": {
            "items": items,
            "lots": lots,
            "warehouses": warehouses,
            "locations": locations,
            "warehouse_locations": warehouse_locations,
            "boms": [str(row.get("code") or "").strip() for row in bom_rows if str(row.get("code") or "").strip()],
        },
    }


def _run_erp_sync_cycle(registry: RunRegistry, *, reason: str) -> Dict[str, Any]:
    store = _erp_sync_store()
    started_at = datetime.now(timezone.utc).isoformat()
    store["syncing"] = True
    store["scheduler"]["active"] = True
    store["scheduler"]["last_run_started_at"] = started_at
    store["scheduler"]["last_result"] = "RUNNING"
    store["scheduler"]["last_error"] = None
    try:
        status = _build_local_erp_sync_status(registry)
        finished_at = datetime.now(timezone.utc).isoformat()
        store["status"] = {key: value for key, value in status.items() if key != "snapshot"}
        store["scheduler"]["last_run_finished_at"] = finished_at
        store["scheduler"]["last_result"] = "SUCCESS" if status["state"] != "ERROR" else "ERROR"
        store["scheduler"]["next_run_at"] = (
            datetime.now(timezone.utc) + timedelta(milliseconds=int(store["scheduler"]["interval_ms"]))
        ).isoformat()
        store["logs"] = [
            {
                "log_id": f"ERP_SYNC_{uuid.uuid4().hex[:10].upper()}",
                "reason": reason,
                "started_at": started_at,
                "finished_at": finished_at,
                "duration_ms": max(1, int((datetime.fromisoformat(finished_at) - datetime.fromisoformat(started_at)).total_seconds() * 1000)),
                "state": status["state"],
                "source": status["source"],
                "message": status["message"],
                "counts": status["counts"],
            },
            *list(store.get("logs") or []),
        ][:50]
        return {
            "status": store["status"],
            "syncing": False,
            "logs": store["logs"],
            "scheduler": store["scheduler"],
        }
    finally:
        store["syncing"] = False


@app.get("/v1/system/sync/erp")
def get_system_erp_sync_status(
    limit: int = Query(default=10, ge=1, le=50),
    actor_claims: Dict[str, Any] = Depends(get_current_actor),
) -> Dict[str, Any]:
    try:
        registry = RunRegistry(Config())
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc
    try:
        _ensure_db_connection(registry, operation="ERP sync status")
        actor = _require_authenticated_user(registry, actor_claims)
        if str(actor.get("actor_role") or "").upper() not in {"MANAGER", "ADMIN"}:
            raise HTTPException(status_code=403, detail="ERP 동기화 관리 권한이 없습니다.")
        store = _erp_sync_store()
        if not store.get("status"):
            _run_erp_sync_cycle(registry, reason="AUTO")
        return {
            "data": {
                "status": store.get("status"),
                "syncing": bool(store.get("syncing")),
                "logs": list(store.get("logs") or [])[:limit],
                "scheduler": store.get("scheduler"),
            }
        }
    finally:
        registry.close()


@app.post("/v1/system/sync/erp")
def run_system_erp_sync(
    actor_claims: Dict[str, Any] = Depends(get_current_actor),
) -> Dict[str, Any]:
    try:
        registry = RunRegistry(Config())
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc
    receipt_id: str | None = None
    try:
        _ensure_db_connection(registry, operation="ERP sync run")
        actor = _require_authenticated_user(registry, actor_claims)
        if str(actor.get("actor_role") or "").upper() not in {"MANAGER", "ADMIN"}:
            raise HTTPException(status_code=403, detail="ERP 동기화 관리 권한이 없습니다.")
        request_id = str(uuid.uuid4())
        receipt_id = _create_operation_receipt(
            registry,
            action_key="system.sync.erp.run",
            entity_type="system_sync",
            entity_id="ERP_MASTER",
            request_id=request_id,
            actor=actor,
            status="RUNNING",
        )
        data = _run_erp_sync_cycle(registry, reason="MANUAL")
        _insert_audit_event(
            registry,
            receipt_id=receipt_id,
            event_type="ERP_SYNC_REQUESTED",
            actor=actor,
            payload_json={
                "domain": "SYSTEM",
                "type": "ERP_SYNC_REQUESTED",
                "status": data.get("status"),
            },
        )
        _update_operation_receipt(
            registry,
            receipt_id=receipt_id,
            status="SUCCEEDED",
            meta={"request_id": request_id, "result_ref": {"entity_id": "ERP_MASTER"}},
            ended=True,
        )
        return {"receipt_id": receipt_id, "status": "SUCCEEDED", "data": data}
    except HTTPException as exc:
        _update_operation_receipt(
            registry,
            receipt_id=receipt_id,
            status=_receipt_status_from_http_exception(exc),
            error={"status_code": int(exc.status_code), "message": _extract_error_message(exc.detail)},
            ended=True,
        )
        raise
    finally:
        registry.close()


