@app.post("/v1/eam/predictive-alerts")
def create_eam_predictive_alerts(
    payload: Dict[str, Any] = Body(default={}),
    actor_claims: Dict[str, Any] = Depends(get_current_actor),
) -> Dict[str, Any]:
    try:
        registry = RunRegistry(Config())
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc
    receipt_id: str | None = None
    try:
        _ensure_db_connection(registry, operation="예지보전 경고 발행")
        actor = _require_authenticated_user(registry, actor_claims)
        request_id = str(uuid.uuid4())
        receipt_id = _create_operation_receipt(
            registry,
            action_key="eam.predictive.alert.ack",
            entity_type="alarm",
            entity_id="BATCH",
            request_id=request_id,
            actor=actor,
            status="RUNNING",
        )
        data = _emit_predictive_alert_rows_action(registry, actor=actor, receipt_id=receipt_id, payload=payload)
        _update_operation_receipt(
            registry,
            receipt_id=receipt_id,
            status="SUCCEEDED",
            meta={"request_id": request_id, "result_ref": {"entity_id": "PREDICTIVE_BATCH"}},
            ended=True,
        )
        return {"data": data, "receipt_id": receipt_id, "status": "SUCCEEDED", "emitted_count": data["emitted_count"]}
    except HTTPException as exc:
        _update_operation_receipt(
            registry,
            receipt_id=receipt_id,
            status=_receipt_status_from_http_exception(exc),
            error={"status_code": int(exc.status_code), "message": _extract_error_message(exc.detail)},
            ended=True,
        )
        raise
    finally:
        registry.close()


