@app.get("/v1/alarms/stream")
def stream_alarm_events(
    actor_claims: Dict[str, Any] = Depends(get_current_actor),
) -> StreamingResponse:
    try:
        registry = RunRegistry(Config())
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc
    _ensure_db_connection(registry, operation="알람 스트림 조회")
    _require_authenticated_user(registry, actor_claims)

    def event_stream() -> Any:
        cursor_ms = int(time.time() * 1000)
        try:
            yield f"event: connected\ndata: {json.dumps({'ts': cursor_ms, 'message': '알람 스트림 연결됨'}, ensure_ascii=False)}\n\n"
            while True:
                pending = _list_alarm_events_since_payload(registry, cursor_ms)
                for event in sorted(pending, key=lambda item: int(item.get("emitted_ms") or 0)):
                    yield f"event: alarm\ndata: {json.dumps(event, ensure_ascii=False)}\n\n"
                    cursor_ms = max(cursor_ms, int(event.get("emitted_ms") or cursor_ms))
                yield f"event: heartbeat\ndata: {json.dumps({'ts': int(time.time() * 1000)}, ensure_ascii=False)}\n\n"
                time.sleep(2)
        finally:
            registry.close()

    return StreamingResponse(
        event_stream(),
        media_type="text/event-stream",
        headers={
            "Cache-Control": "no-cache, no-transform",
            "Connection": "keep-alive",
            "X-Accel-Buffering": "no",
        },
    )


