@app.post("/v1/auth/oidc/start", status_code=202)
def post_auth_oidc_start(request: Request, body: Dict[str, Any] = Body(default={})) -> Dict[str, Any]:
    try:
        registry = RunRegistry(Config())
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc
    try:
        context = _get_client_request_context(request)
        support = _get_profile_schema_support(registry)
        employee_no = _trim_profile_text(body.get("employeeNo")).replace(" ", "")
        redirect_path = _trim_profile_text(body.get("redirectPath")) or None
        if registry.conn:
            _record_auth_login_event(
                registry,
                support,
                event_type="OIDC_LOGIN_STARTED",
                result_code="REDIRECT",
                request_id=_trim_profile_text(context.get("requestId")) or f"req_{uuid.uuid4().hex}",
                employee_no=employee_no or None,
                ip_address=context.get("ipAddress"),
                user_agent=context.get("userAgent"),
                meta={"redirect_path": redirect_path},
            )
            registry.conn.commit()
        return {"status": "RECORDED"}
    except Exception:
        if registry.conn:
            registry.conn.rollback()
        raise
    finally:
        registry.close()


@app.post("/v1/auth/oidc/callback/resolve", response_model=AuthOidcCallbackResolveResponse)
def post_auth_oidc_callback_resolve(
    request: Request,
    body: AuthOidcCallbackResolveRequest,
) -> AuthOidcCallbackResolveResponse:
    try:
        registry = RunRegistry(Config())
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc
    try:
        _ensure_db_connection(registry, operation="OIDC callback resolve")
        context = _get_client_request_context(request)
        request_id = _trim_profile_text(context.get("requestId")) or f"req_{uuid.uuid4().hex}"
        resolved_user = _resolve_oidc_public_user_record(
            registry,
            auth_subject=body.sub,
            employee_no=body.employeeNo,
            request_id=request_id,
        )
        support = _get_profile_schema_support(registry)
        _record_auth_login_event(
            registry,
            support,
            event_type="OIDC_LOGIN_SUCCESS",
            result_code="SUCCESS",
            request_id=request_id,
            user_id=resolved_user.id,
            employee_no=resolved_user.employeeNo,
            auth_subject=resolved_user.authSubject,
            ip_address=context.get("ipAddress"),
            user_agent=context.get("userAgent"),
            meta={"redirect_path": body.redirectPath},
        )
        _touch_app_user_last_login(registry, support, resolved_user.id)
        if registry.conn:
            registry.conn.commit()
        return AuthOidcCallbackResolveResponse(
            user=resolved_user,
            employeeNo=resolved_user.employeeNo,
            authSubject=resolved_user.authSubject,
        )
    except HTTPException as exc:
        if registry.conn:
            registry.conn.rollback()
        context = _get_client_request_context(request)
        support = _get_profile_schema_support(registry)
        _record_auth_login_event(
            registry,
            support,
            event_type="OIDC_LOGIN_FAILED",
            result_code="CALLBACK_ERROR",
            request_id=_trim_profile_text(context.get("requestId")) or f"req_{uuid.uuid4().hex}",
            employee_no=_trim_profile_text(body.employeeNo) or None,
            auth_subject=_trim_profile_text(body.sub) or None,
            ip_address=context.get("ipAddress"),
            user_agent=context.get("userAgent"),
            meta={
                "error": str(exc.detail),
                "redirect_path": body.redirectPath,
            },
        )
        if registry.conn:
            registry.conn.commit()
        raise
    finally:
        registry.close()


