@app.get("/v1/approvals", response_model=List[ApprovalRecord])
def list_approvals(
    limit: int = Query(default=50, ge=1, le=500),
    approval_status: ApprovalStatus | None = Query(default=None),
    actor_claims: Dict[str, Any] = Depends(get_current_actor),
) -> List[ApprovalRecord]:
    try:
        registry = RunRegistry(Config())
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc
    try:
        _ensure_db_connection(registry, operation="approval 목록 조회")
        if not registry.approval_enabled or not registry.enabled:
            raise HTTPException(
                status_code=503,
                detail="Approval tables are not available. Apply bohae_aps_v20/sql/20_app_ops_foundation_v1.sql first.",
            )
        actor = _resolve_authenticated_actor(registry, actor_claims)
        rows = registry.list_approvals(limit=limit, approval_status=approval_status)
        if str(actor.get("actor_role") or "").upper() not in {"ADMIN", "MANAGER"}:
            filtered_rows: List[Dict[str, Any]] = []
            for row in rows:
                run_row = registry.fetch_run(str(row.get("run_id") or ""))
                if run_row is not None and _actor_can_access_run(actor, run_row):
                    filtered_rows.append(row)
            rows = filtered_rows
        return [ApprovalRecord(**row) for row in rows]
    finally:
        registry.close()


def _update_approval_impl(
    run_id: str,
    request: ApprovalUpdateRequest,
    *,
    actor: Dict[str, Any],
    x_idempotency_key: str | None,
    x_request_id: str | None,
) -> ApprovalRecord:
    try:
        registry = RunRegistry(Config())
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc
    try:
        _ensure_command_kernel(
            registry,
            operation="approval 변경",
            require_solver_run=True,
            require_approval=True,
            require_idempotency=True,
            require_receipt=True,
        )
        idempotency_key = (
            (x_idempotency_key or "").strip()
            or (request.request_id or "").strip()
            or (x_request_id or "").strip()
            or None
        )
        idempotency_endpoint = f"approval:{run_id}"
        if idempotency_key:
            cached = registry.fetch_idempotency(idempotency_key, idempotency_endpoint)
            if cached is not None:
                return JSONResponse(
                    status_code=int(cached.get("status_code") or 200),
                    content=cached.get("response") or {},
                )

        operation_request_id = idempotency_key or str(uuid.uuid4())
        receipt_id = _create_operation_receipt(
            registry,
            action_key="approval.update",
            entity_type="run",
            entity_id=run_id,
            request_id=operation_request_id,
            actor=actor,
            status="RUNNING",
            meta={
                "endpoint": "/v1/approvals/{run_id}",
                "requested_status": str(request.approval_status or "").upper(),
            },
        )
        resolved_scenario_id = ""

        try:
            run_row = registry.fetch_run(run_id)
            if run_row is None:
                _raise_run_not_found(registry, run_id)
            resolved_scenario_id = str(run_row.get("scenario_id") or "")

            solve_status = str(run_row.get("status") or "").upper()
            if solve_status != "SUCCESS":
                raise HTTPException(
                    status_code=409,
                    detail=f"SUCCESS 상태의 실행만 승인 워크플로우를 진행할 수 있습니다. 현재 상태: {solve_status}",
                )

            current_approval = registry.fetch_approval(run_id)
            current_status = (
                str(current_approval.get("approval_status") or "").upper()
                if current_approval is not None
                else "NONE"
            )

            desired_status = str(request.approval_status or "").upper()
            comment = (request.comment or "").strip()
            actor_role = str(actor.get("actor_role") or "VIEWER").upper()

            if desired_status == "PENDING":
                if actor_role not in ("ADMIN", "MANAGER", "PLANNER"):
                    raise HTTPException(status_code=403, detail="승인 요청은 계획자 이상 권한이 필요합니다.")
                if current_status == "PENDING":
                    raise HTTPException(status_code=409, detail="이미 승인 대기 상태입니다.")
                if current_status in ("APPROVED", "REJECTED"):
                    raise HTTPException(status_code=409, detail="이미 최종 상태로 확정된 실행입니다.")
            elif desired_status == "APPROVED":
                if actor_role not in ("ADMIN", "MANAGER", "APPROVER"):
                    raise HTTPException(status_code=403, detail="승인은 승인자 이상 권한이 필요합니다.")
                if current_status != "PENDING":
                    raise HTTPException(
                        status_code=409,
                        detail=f"PENDING 상태에서만 승인할 수 있습니다. 현재 상태: {current_status}",
                    )
            elif desired_status == "REJECTED":
                if actor_role not in ("ADMIN", "MANAGER", "APPROVER"):
                    raise HTTPException(status_code=403, detail="반려는 승인자 이상 권한이 필요합니다.")
                if current_status != "PENDING":
                    raise HTTPException(
                        status_code=409,
                        detail=f"PENDING 상태에서만 반려할 수 있습니다. 현재 상태: {current_status}",
                    )
                if not comment:
                    raise HTTPException(status_code=400, detail="반려 사유(comment)는 필수입니다.")
            else:
                raise HTTPException(status_code=400, detail=f"유효하지 않은 approval_status 입니다: {desired_status}")

            before_payload = {"solve_status": solve_status, "approval_status": current_status}
            after_payload = {"solve_status": solve_status, "approval_status": desired_status}

            updated = registry.upsert_approval(
                run_id=run_id,
                approval_status=desired_status,
                approved_by=str(actor.get("actor_id") or actor.get("actor_email") or ""),
                comment=comment if comment else None,
            )
            if updated is None:
                raise HTTPException(status_code=500, detail="approval update failed")

            event_type = {
                "PENDING": "RUN_SUBMITTED_FOR_APPROVAL",
                "APPROVED": "RUN_APPROVED",
                "REJECTED": "RUN_REJECTED",
            }.get(desired_status, "RUN_APPROVAL_UPDATED")

            registry.insert_decision_log(
                scenario_id=resolved_scenario_id,
                event_type=event_type,
                payload_json={
                    "ENTITY_TYPE": "run",
                    "ENTITY_ID": run_id,
                    "RUN_ID": run_id,
                    "REQUEST_ID": operation_request_id,
                    "RECEIPT_ID": receipt_id,
                    "ACTOR_ID": actor.get("actor_id"),
                    "ACTOR_EMAIL": actor.get("actor_email"),
                    "ACTOR_ROLE": actor.get("actor_role"),
                    "COMMENT": comment,
                    "BEFORE": before_payload,
                    "AFTER": after_payload,
                },
            )

            target = registry.fetch_approval(run_id)
            if target is None:
                raise HTTPException(status_code=500, detail="approval updated but failed to fetch record")

            target["receipt_id"] = receipt_id
            response = ApprovalRecord(**target)
            _update_operation_receipt(
                registry,
                receipt_id=receipt_id,
                status="SUCCEEDED",
                artifacts={"approval_status": desired_status},
                meta={"request_id": operation_request_id},
                ended=True,
            )

            if idempotency_key:
                payload = response.model_dump(mode="json") if hasattr(response, "model_dump") else response.dict()  # type: ignore[attr-defined]
                if isinstance(payload, dict):
                    registry.store_idempotency(
                        key=idempotency_key,
                        endpoint=idempotency_endpoint,
                        status_code=200,
                        response_json=payload,
                    )
            return response
        except HTTPException as exc:
            failed_status = _receipt_status_from_http_exception(exc)
            _update_operation_receipt(
                registry,
                receipt_id=receipt_id,
                status=failed_status,
                error={
                    "status_code": int(exc.status_code),
                    "message": _extract_error_message(exc.detail),
                },
                meta={"request_id": operation_request_id},
                ended=True,
            )
            if failed_status == "CONTRACT_FAIL":
                _create_contract_fail_task(
                    registry,
                    run_id=run_id,
                    scenario_id=resolved_scenario_id,
                    receipt_id=receipt_id,
                    actor=actor,
                    reason=_extract_error_message(exc.detail),
                )
            raise
    finally:
        registry.close()


@app.post("/v1/approvals/{run_id}", response_model=ApprovalRecord)
def update_approval(
    run_id: str,
    request: ApprovalUpdateRequest,
    actor_claims: Dict[str, Any] = Depends(get_current_actor),
    x_idempotency_key: str | None = Header(default=None, alias="Idempotency-Key"),
    x_request_id: str | None = Header(default=None, alias="X-Request-Id"),
) -> ApprovalRecord:
    registry = RunRegistry(Config())
    try:
        actor = _resolve_authenticated_actor(registry, actor_claims)
    finally:
        registry.close()
    _ensure_operational_command_actor(actor, operation="승인 상태 변경")
    return _update_approval_impl(
        run_id,
        request,
        actor=actor,
        x_idempotency_key=x_idempotency_key,
        x_request_id=x_request_id,
    )


@app.post("/v1/solver/runs/{run_id}/execute", response_model=ExecuteApprovedRunResponse)
def execute_approved_solver_run(
    run_id: str,
    request: ExecuteApprovedRunRequest | None = Body(default=None),
    actor_claims: Dict[str, Any] = Depends(get_current_actor),
    x_idempotency_key: str | None = Header(default=None, alias="Idempotency-Key"),
    x_request_id: str | None = Header(default=None, alias="X-Request-Id"),
) -> ExecuteApprovedRunResponse:
    from . import service as api_service

    execute_request = request or ExecuteApprovedRunRequest()

    try:
        config = api_service.build_config(execute_request.overrides)
    except Exception as exc:
        raise HTTPException(status_code=400, detail=f"Invalid overrides: {exc}") from exc

    try:
        registry = RunRegistry(config)
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc
    try:
        _ensure_command_kernel(
            registry,
            operation="승인 실행",
            require_solver_run=True,
            require_approval=True,
            require_idempotency=True,
            require_receipt=True,
        )

        actor = _resolve_authenticated_actor(registry, actor_claims)
        _ensure_operational_command_actor(actor, operation="승인 실행")
        _ensure_operational_upstream_truth_ready(registry, operation="승인 실행")
        if str(actor.get("actor_role") or "").upper() not in {"ADMIN", "MANAGER"}:
            raise HTTPException(status_code=403, detail="매니저 또는 관리자 권한이 필요합니다.")
        idempotency_key = (x_idempotency_key or "").strip() or None
        correlation_id = (getattr(execute_request, "correlation_id", None) or "").strip() or None
        request_id = (x_request_id or "").strip() or None
        operation_request_id = correlation_id or idempotency_key or request_id or str(uuid.uuid4())
        effective_correlation_id = operation_request_id
        idempotency_endpoint = f"execute:{run_id}"
        resolved_scenario_id = ""

        cached = registry.fetch_idempotency(operation_request_id, idempotency_endpoint)
        if cached is not None:
            return JSONResponse(
                status_code=int(cached.get("status_code") or 200),
                content=cached.get("response") or {},
            )

        receipt_id = _create_operation_receipt(
            registry,
            action_key="run.execute",
            entity_type="run",
            entity_id=run_id,
            request_id=operation_request_id,
            actor=actor,
            status="RUNNING",
            idempotency_key=idempotency_key,
            meta={
                "endpoint": "/v1/solver/runs/{run_id}/execute",
                "correlation_id": effective_correlation_id,
                "idempotency_key": idempotency_key,
            },
        )

        try:
            if not registry.try_advisory_lock_execute(run_id):
                raise HTTPException(
                    status_code=409,
                    detail=f"run_id={run_id}에 대한 execute가 이미 진행 중입니다 (concurrent request blocked).",
                )

            already_executed_run_id = registry.check_already_executed(run_id)
            if already_executed_run_id:
                raise HTTPException(
                    status_code=409,
                    detail=f"run_id={run_id}는 이미 실행되었습니다 (executed_run_id={already_executed_run_id}).",
                )
            source_run = registry.fetch_run(run_id)
            if source_run is None:
                _raise_run_not_found(registry, run_id)

            solve_status = str(source_run.get("status") or "").upper()
            if solve_status != "SUCCESS":
                raise HTTPException(
                    status_code=409,
                    detail=f"SUCCESS 상태의 실행만 배포 실행할 수 있습니다. 현재 상태: {solve_status}",
                )

            approval_row = registry.fetch_approval(run_id)
            approval_status = (
                str(approval_row.get("approval_status") or "NONE").upper()
                if approval_row is not None
                else "NONE"
            )
            if approval_status != "APPROVED":
                raise HTTPException(
                    status_code=409,
                    detail=f"APPROVED 상태에서만 배포 실행할 수 있습니다. 현재 승인 상태: {approval_status}",
                )

            scenario_id = str(source_run.get("scenario_id") or "").strip()
            resolved_scenario_id = scenario_id
            requested_start = _parse_date_value(source_run.get("requested_start"))
            requested_end = _parse_date_value(source_run.get("requested_end"))
            if not scenario_id or requested_start is None or requested_end is None:
                raise HTTPException(status_code=500, detail="원본 실행의 시나리오/기간 정보가 유효하지 않습니다.")

            source_type = str(
                execute_request.source
                or os.getenv("BOHAE_APPROVED_EXECUTE_SOURCE")
                or source_run.get("source_type")
                or "db"
            ).strip().lower()
            _ensure_runtime_db_source(source_type, operation="승인 실행")
            _ensure_solver_worker_queue_contract(registry, operation="승인 실행")

            before_payload = {
                "source_run_status": solve_status,
                "approval_status": approval_status,
            }
            queued_run_id = api_service.new_run_id()
            queued_at = datetime.now(timezone.utc)
            queued_writeback = (
                bool(execute_request.writeback)
                if execute_request.writeback is not None
                else True
            )
            execute_config = api_service.build_config(execute_request.overrides)
            worker_timeout_at = _solver_worker_timeout_at(
                queued_at,
                time_limit_sec=int(execute_config.time_limit_sec),
            )
            source_run_green_gate: Dict[str, Any] | None = None
            if queued_writeback:
                source_run_green_gate = _ensure_writeback_green_gate_or_fail(
                    registry,
                    source_run=source_run,
                    actor=actor,
                )
            queued_output_xlsx_path = str(
                api_service.resolve_output_path(
                    SolveRunRequest(
                        source=source_type,
                        scenario=scenario_id,
                        start_date=requested_start,
                        end_date=requested_end,
                        out_path=execute_request.out_path,
                        previous_plan_path=None,
                        writeback=queued_writeback,
                        requested_by=str(actor.get("actor_email") or actor.get("actor_id") or ""),
                        overrides=execute_request.overrides,
                    ),
                    queued_run_id,
                )
            )
            actor_provenance = _build_run_actor_provenance(actor)
            lineage_json = dict(actor_provenance)
            lineage_json["executed_from_run_id"] = run_id
            lineage_json["execution_source"] = "APPROVED_RUN"
            trace_json: Dict[str, Any] = dict(actor_provenance)
            trace_json["executed_from_run_id"] = run_id
            trace_json["queue_state"] = "QUEUED"
            trace_json["worker"] = {
                "launch_mode": "db_lease_subprocess",
                "log_path": str(_solver_worker_log_path(queued_run_id)),
            }
            trace_json["queue_request"] = {
                "queue_mode": "APPROVED_EXECUTE",
                "request_id": operation_request_id,
                "correlation_id": effective_correlation_id,
                "receipt_id": receipt_id,
                "out_path": execute_request.out_path or queued_output_xlsx_path,
                "writeback": queued_writeback,
                "requested_by": str(actor.get("actor_email") or actor.get("actor_id") or ""),
                "executed_from_run_id": run_id,
                "overrides": _serialize_solver_overrides(execute_request.overrides),
            }
            if source_run_green_gate is not None:
                trace_json["source_run_green_gate"] = _json_safe(source_run_green_gate)
            trace_json["lineage_json"] = dict(lineage_json)

            registry.insert_decision_log(
                scenario_id=scenario_id,
                event_type="RUN_EXECUTE_REQUESTED",
                payload_json={
                    "ENTITY_TYPE": "run",
                    "ENTITY_ID": run_id,
                    "RUN_ID": run_id,
                    "REQUEST_ID": operation_request_id,
                    "RECEIPT_ID": receipt_id,
                    "CORRELATION_ID": effective_correlation_id,
                    "IDEMPOTENCY_KEY": idempotency_key,
                    "ACTOR_ID": actor.get("actor_id"),
                    "ACTOR_EMAIL": actor.get("actor_email"),
                    "ACTOR_ROLE": actor.get("actor_role"),
                    "SOURCE_TYPE": source_type,
                    "WRITEBACK_GREEN_GATE": _json_safe(source_run_green_gate) if source_run_green_gate is not None else None,
                    "BEFORE": before_payload,
                    "AFTER": {
                        "source_run_status": solve_status,
                        "approval_status": approval_status,
                        "execute_status": "QUEUED",
                        "executed_run_id": queued_run_id,
                    },
                },
            )
            _persist_run_record_or_fail(
                registry,
                run_id=queued_run_id,
                scenario_id=scenario_id,
                source_type=source_type,
                requested_start=requested_start,
                requested_end=requested_end,
                status="QUEUED",
                requested_by=str(actor.get("actor_email") or actor.get("actor_id") or ""),
                output_xlsx_path=queued_output_xlsx_path,
                trace_json=trace_json,
                error_message=None,
                created_at=queued_at,
                started_at=None,
                finished_at=None,
                queued_at=queued_at,
                lease_owner=None,
                lease_expires_at=None,
                last_heartbeat_at=None,
                attempt_count=0,
                timeout_at=worker_timeout_at,
                cancel_requested_at=None,
                payload_json=dict(trace_json["queue_request"]),
                markings=[],
                lineage_json=lineage_json,
            )
            try:
                _launch_solver_run_worker_or_fail(queued_run_id)
            except Exception as exc:
                failed_trace = dict(trace_json)
                failed_trace["queue_state"] = "FAILED"
                failed_trace["worker_launch_error"] = str(exc)
                _persist_run_record_or_fail(
                    registry,
                    run_id=queued_run_id,
                    scenario_id=scenario_id,
                    source_type=source_type,
                    requested_start=requested_start,
                    requested_end=requested_end,
                    status="FAILED",
                    requested_by=str(actor.get("actor_email") or actor.get("actor_id") or ""),
                    output_xlsx_path=queued_output_xlsx_path,
                    trace_json=failed_trace,
                    error_message=str(exc),
                    created_at=queued_at,
                    started_at=queued_at,
                    finished_at=queued_at,
                    queued_at=queued_at,
                    lease_owner=None,
                    lease_expires_at=None,
                    last_heartbeat_at=None,
                    attempt_count=0,
                    timeout_at=worker_timeout_at,
                    cancel_requested_at=None,
                    payload_json=dict(trace_json["queue_request"]),
                    markings=[],
                    lineage_json=lineage_json,
                )
                raise

            response = ExecuteApprovedRunResponse(
                requested_run_id=run_id,
                executed_run_id=queued_run_id,
                receipt_id=receipt_id,
                status="QUEUED",
                solve_status="QUEUED",
                source=source_type,
                scenario=scenario_id,
                start_date=requested_start,
                end_date=requested_end,
                output_xlsx_path=queued_output_xlsx_path,
                writeback=queued_writeback,
                started_at_utc=queued_at,
                finished_at_utc=queued_at,
                plan_segments=0,
                decision_log_rows=0,
                objective={},
            )

            payload = response.model_dump(mode="json") if hasattr(response, "model_dump") else response.dict()  # type: ignore[attr-defined]
            if isinstance(payload, dict):
                registry.store_idempotency(
                    key=operation_request_id,
                    endpoint=idempotency_endpoint,
                    status_code=202,
                    response_json=payload,
                )

            return JSONResponse(status_code=202, content=payload)
        except HTTPException as exc:
            failed_status = _receipt_status_from_http_exception(exc)
            _update_operation_receipt(
                registry,
                receipt_id=receipt_id,
                status=failed_status,
                error={
                    "status_code": int(exc.status_code),
                    "message": _extract_error_message(exc.detail),
                },
                meta={"request_id": operation_request_id},
                ended=True,
            )
            if failed_status == "CONTRACT_FAIL":
                _create_contract_fail_task(
                    registry,
                    run_id=run_id,
                    scenario_id=resolved_scenario_id,
                    receipt_id=receipt_id,
                    actor=actor,
                    reason=_extract_error_message(exc.detail),
                )
            raise
    finally:
        registry.close()


@app.get("/v1/decision-log")
def list_decision_log(
    run_id: str | None = Query(default=None),
    limit: int = Query(default=200, ge=1, le=1000),
    actor_claims: Dict[str, Any] = Depends(get_current_actor),
) -> list[dict]:
    try:
        registry = RunRegistry(Config())
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc
    try:
        if not registry.decision_log_enabled:
            raise HTTPException(
                status_code=503,
                detail="decision_log 테이블이 없습니다. bohae_aps_v20/sql/20_app_ops_foundation_v1.sql을 먼저 적용하세요.",
            )
        actor = _resolve_authenticated_actor(registry, actor_claims)
        actor_role = str(actor.get("actor_role") or "").upper()
        if run_id:
            run_row = registry.fetch_run(run_id)
            if run_row is None:
                _raise_run_not_found(registry, run_id)
            _enforce_actor_can_access_run(actor, run_row)
        elif actor_role not in {"ADMIN", "MANAGER"}:
            raise HTTPException(status_code=403, detail="decision log 전체 조회는 매니저 또는 관리자 권한이 필요합니다.")
        return registry.list_decision_log(limit=limit, run_id=run_id)
    finally:
        registry.close()


