@app.get("/v1/tasks/inbox", response_model=List[TaskInboxRecord])
def list_task_inbox(
    limit: int = Query(default=100, ge=1, le=500),
    status: str | None = Query(default=None),
    assigned_role: str | None = Query(default=None),
    assigned_user: str | None = Query(default=None),
    scope: str = Query(default="mine"),
    actor_claims: Dict[str, Any] = Depends(get_current_actor),
) -> List[TaskInboxRecord]:
    try:
        registry = RunRegistry(Config())
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc
    try:
        _ensure_db_connection(registry, operation="task inbox 조회")
        if not registry.task_inbox_enabled:
            raise HTTPException(
                status_code=503,
                detail="task_inbox 테이블이 없습니다. bohae_aps_v20/sql/44_operation_kernel_v1.sql을 먼저 적용하세요.",
            )
        actor = _require_authenticated_user(registry, actor_claims)
        role = str(actor.get("actor_role") or "VIEWER").upper()
        role_filter = assigned_role
        user_filter = assigned_user
        scope_normalized = str(scope or "mine").strip().lower()
        if role in {"ADMIN", "MANAGER"}:
            if not user_filter and scope_normalized != "all":
                user_filter = str(actor.get("actor_id") or "")
        else:
            role_filter = role_filter or role
            user_filter = user_filter or str(actor.get("actor_id") or "")
        rows = registry.list_task_inbox(
            limit=limit,
            status=status,
            assigned_role=role_filter,
            assigned_user=user_filter,
        )
        return [_to_task_inbox_record(row) for row in rows]
    finally:
        registry.close()


