@app.get("/v1/tasks/leaderboard", response_model=TaskLeaderboardResponse)
def get_task_leaderboard(
    period: str = Query(default="WEEK"),
    role: str = Query(default="ALL"),
    actor_claims: Dict[str, Any] = Depends(get_current_actor),
) -> TaskLeaderboardResponse:
    try:
        registry = RunRegistry(Config())
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc
    try:
        _ensure_db_connection(registry, operation="task leaderboard 조회")
        if not registry.task_leaderboard_enabled:
            raise HTTPException(
                status_code=503,
                detail="task leaderboard 테이블(score_event/founding_credit/role_normalization_policy)이 준비되지 않았습니다.",
            )
        actor = _require_authenticated_user(registry, actor_claims)
        normalized_period = str(period or "WEEK").upper().strip()
        if normalized_period not in {"WEEK", "MONTH", "ALL"}:
            raise HTTPException(status_code=400, detail="period must be WEEK, MONTH, or ALL")
        normalized_role = str(role or "ALL").upper().strip()
        if normalized_role not in {"ALL", "PLANNER", "APPROVER", "MANAGER", "ADMIN", "VIEWER"}:
            raise HTTPException(status_code=400, detail="role must be ALL or a supported role code")
        source_mode = _task_source_mode_for_actor(actor)
        rows = registry.list_task_leaderboard_rows(
            period=normalized_period,
            role_filter=None if normalized_role == "ALL" else normalized_role,
            limit=20,
        )
        official_score_enabled = source_mode == "LIVE"
        return TaskLeaderboardResponse(
            period=normalized_period,
            source_mode=source_mode,
            official_score_enabled=official_score_enabled,
            ranking_mode="OFFICIAL" if official_score_enabled else "PENDING",
            official_score_label=_task_official_score_label(source_mode),
            pending_score_label=_task_pending_score_label(source_mode),
            rows=[_to_task_leaderboard_row_record(row, source_mode=source_mode) for row in rows],
        )
    finally:
        registry.close()


@app.get("/v1/tasks/{task_id}", response_model=TaskDetailResponse)
def get_task_detail(
    task_id: str,
    actor_claims: Dict[str, Any] = Depends(get_current_actor),
) -> TaskDetailResponse:
    try:
        registry = RunRegistry(Config())
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc
    try:
        _ensure_db_connection(registry, operation="task detail 조회")
        if not registry.task_inbox_enabled:
            raise HTTPException(
                status_code=503,
                detail="task_inbox 테이블이 없습니다. bohae_aps_v20/sql/44_operation_kernel_v1.sql을 먼저 적용하세요.",
            )
        actor = _require_authenticated_user(registry, actor_claims)
        inbox_row = registry.fetch_task_inbox(task_id)
        if inbox_row is None:
            raise HTTPException(status_code=404, detail="task_id not found")
        if not _actor_can_access_task_inbox_row(actor, inbox_row):
            raise HTTPException(status_code=403, detail="작업 상세를 볼 권한이 없습니다.")

        task_row = _fetch_task_assignment_detail_row(registry, task_id) or _task_assignment_detail_row_from_inbox_row(inbox_row)

        actor_user_id = _trim_profile_text(actor.get("actor_id"))
        session_row = _fetch_task_session_row(registry, task_id=task_id, actor_user_id=actor_user_id) if actor_user_id else None
        session_record = None
        if session_row is not None:
            turn_rows = _fetch_task_turn_rows(
                registry,
                task_chat_session_id=_trim_profile_text(session_row.get("task_chat_session_id")),
            )
            session_record = _to_task_conversation_session_record(
                session_row,
                turns=[_to_task_conversation_turn_record(row) for row in turn_rows],
            )

        latest_submission_row = _fetch_latest_task_submission_row(registry, task_id=task_id)
        latest_submission_record = (
            _to_task_submission_record(latest_submission_row)
            if latest_submission_row is not None
            else None
        )
        latest_review_row = (
            _fetch_latest_task_review_row(
                registry,
                submission_id=_trim_profile_text(latest_submission_row.get("submission_id")),
            )
            if latest_submission_row is not None
            else None
        )

        return TaskDetailResponse(
            task=_to_task_assignment_detail_record(task_row),
            session=session_record,
            latest_submission=latest_submission_record,
            latest_review=_to_task_review_record(latest_review_row) if latest_review_row is not None else None,
            assistant_mode=_task_assistant_mode(),
            live_assistant_enabled=_task_live_assistant_enabled(),
        )
    finally:
        registry.close()


