@app.post("/v1/tasks/{task_id}/complete", response_model=TaskInboxRecord)
def complete_task_inbox(
    task_id: str,
    request: TaskCompleteRequest,
    actor_claims: Dict[str, Any] = Depends(get_current_actor),
) -> TaskInboxRecord:
    try:
        registry = RunRegistry(Config())
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc
    try:
        _ensure_db_connection(registry, operation="task complete")
        if not registry.task_inbox_enabled:
            raise HTTPException(
                status_code=503,
                detail="task_inbox 테이블이 없습니다. bohae_aps_v20/sql/44_operation_kernel_v1.sql을 먼저 적용하세요.",
            )
        actor = _require_authenticated_user(registry, actor_claims)
        task_row = None
        try:
            task_row = _fetch_task_assignment_detail_row(registry, task_id)
        except Exception:
            task_row = None
        if task_row is None:
            inbox_row = registry.fetch_task_inbox(task_id)
            if inbox_row is not None:
                task_row = _task_assignment_detail_row_from_inbox_row(inbox_row)
        if task_row is None:
            raise HTTPException(status_code=404, detail="task_id not found")
        if not _task_actor_can_finalize_or_review(actor, task_row):
            raise HTTPException(status_code=403, detail="요청자 또는 지정 검토자만 완료 확정을 처리할 수 있습니다.")
        completed_by = str(actor.get("actor_id") or actor.get("actor_email") or "SYSTEM")
        row = registry.complete_task_inbox(
            task_id=task_id,
            completed_by=completed_by,
            note=(request.note or "").strip() or None,
        )
        if row is None:
            raise HTTPException(status_code=404, detail="task_id not found")
        registry.insert_decision_log(
            scenario_id="OPS_TASK",
            event_type="TASK_COMPLETED",
            payload_json={
                "ENTITY_TYPE": "task",
                "ENTITY_ID": task_id,
                "RUN_ID": _jsonb_to_obj(row.get("context_json")).get("entity_id", ""),
                "ACTOR_ID": actor.get("actor_id"),
                "ACTOR_EMAIL": actor.get("actor_email"),
                "ACTOR_ROLE": actor.get("actor_role"),
                "NOTE": (request.note or "").strip(),
            },
        )
        return _to_task_inbox_record(row)
    finally:
        registry.close()


