@app.get("/v1/tasks/{task_id}/attachments/{attachment_id}")
def get_task_attachment(
    task_id: str,
    attachment_id: str,
    actor_claims: Dict[str, Any] = Depends(get_current_actor),
) -> Response:
    try:
        registry = RunRegistry(Config())
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc
    try:
        _ensure_db_connection(registry, operation="task attachment 조회")
        if not registry.task_inbox_enabled:
            raise HTTPException(
                status_code=503,
                detail="task_inbox 테이블이 없습니다. bohae_aps_v20/sql/44_operation_kernel_v1.sql을 먼저 적용하세요.",
            )
        actor = _require_authenticated_user(registry, actor_claims)
        row = registry.fetch_task_inbox(task_id)
        if row is None:
            raise HTTPException(status_code=404, detail="task_id not found")
        if not _actor_can_access_task_inbox_row(actor, row):
            raise HTTPException(status_code=403, detail="첨부 파일을 볼 권한이 없습니다.")
        attachment = _read_task_attachment_entry(task_id, attachment_id)
        if attachment is None:
            raise HTTPException(status_code=404, detail="첨부 파일을 찾을 수 없습니다.")
        response = FileResponse(
            attachment["filePath"],
            media_type=attachment["mimeType"],
            filename=attachment["fileName"],
        )
        response.headers["Cache-Control"] = "no-store"
        response.headers["Content-Length"] = str(attachment["sizeBytes"])
        response.headers["Content-Disposition"] = (
            f"inline; filename*=UTF-8''{urlparse.quote(_trim_profile_text(attachment['fileName']))}"
        )
        return response
    finally:
        registry.close()


