def _sensor_latest_record_from_row(row: Dict[str, Any]) -> SensorLatestRecord:
    return SensorLatestRecord(
        line_id=str(row.get("line_id") or ""),
        ts_ms=int(row.get("ts_ms") or 0),
        updated_at=row.get("updated_at"),
        current_qty=int(row.get("current_qty") or 0),
        target_qty=int(row.get("target_qty") or 0),
        rate_per_sec=float(row.get("rate_per_sec") or 0.0),
        status=str(row.get("status") or "UNKNOWN"),
        runtime_state=str(row.get("runtime_state") or row.get("status") or "UNKNOWN"),
        temp_c=float(row["temp_c"]) if row.get("temp_c") is not None else None,
        vibration_mm_s=float(row["vibration_mm_s"]) if row.get("vibration_mm_s") is not None else None,
        power_kw=float(row["power_kw"]) if row.get("power_kw") is not None else None,
        latest_device_id=str(row.get("latest_device_id") or "") or None,
        counter_device_id=str(row.get("counter_device_id") or "") or None,
        temp_device_id=str(row.get("temp_device_id") or "") or None,
        vibration_device_id=str(row.get("vibration_device_id") or "") or None,
        power_device_id=str(row.get("power_device_id") or "") or None,
    )


def _sensor_device_record_from_row(row: Dict[str, Any]) -> SensorDeviceRecord:
    return SensorDeviceRecord(
        device_id=str(row.get("device_id") or ""),
        line_id=str(row.get("line_id") or "") or None,
        sensor_kind=str(row.get("sensor_kind") or "COUNTER"),
        last_boot_id=str(row.get("last_boot_id") or ""),
        last_seq=int(row.get("last_seq") or 0),
        last_event_ts=row.get("last_event_ts"),
        last_event_ts_ms=int(row.get("last_event_ts_ms") or 0),
        last_quality=str(row.get("last_quality") or "OK"),
        last_status=str(row.get("last_status") or "UNKNOWN"),
        meta_json=_jsonb_to_obj(row.get("meta_json")),
        created_at=row.get("created_at"),
        updated_at=row.get("updated_at"),
    )


def _sensor_reading_record_from_row(row: Dict[str, Any]) -> SensorReadingRecord:
    return SensorReadingRecord(
        event_id=int(row.get("event_id") or 0),
        device_id=str(row.get("device_id") or ""),
        boot_id=str(row.get("boot_id") or ""),
        seq=int(row.get("seq") or 0),
        topic=str(row.get("topic") or ""),
        line_id=str(row.get("line_id") or "") or None,
        sensor_kind=str(row.get("sensor_kind") or "COUNTER"),
        ts=row.get("ts"),
        ts_ms=int(row.get("ts_ms") or 0),
        window_ms=int(row.get("window_ms")) if row.get("window_ms") is not None else None,
        pulse_count=int(row.get("pulse_count")) if row.get("pulse_count") is not None else None,
        total_count=int(row.get("total_count")) if row.get("total_count") is not None else None,
        metric_value=float(row.get("metric_value")) if row.get("metric_value") is not None else None,
        unit=str(row.get("unit") or "") or None,
        quality=str(row.get("quality") or "OK"),
        payload=_jsonb_to_obj(row.get("payload")),
        ingested_at=row.get("ingested_at"),
    )


@app.get("/v1/sensors/latest", response_model=List[SensorLatestRecord])
def list_sensor_latest(
    limit: int = Query(default=200, ge=1, le=1000),
    actor_claims: Dict[str, Any] = Depends(get_current_actor),
) -> List[SensorLatestRecord]:
    try:
        registry = RunRegistry(Config())
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc
    try:
        _require_authenticated_user(registry, actor_claims)
        _ensure_sensor_backend_ready(registry)
        rows = registry.list_state_sensors(limit=limit)
        return [_sensor_latest_record_from_row(row) for row in rows]
    finally:
        registry.close()


