@app.get("/v1/kiosk/line/{line_id}/counter", response_model=KioskCounterRecord)
def get_kiosk_counter(line_id: str, response: Response) -> KioskCounterRecord:
    if not line_id.strip():
        raise HTTPException(status_code=400, detail="line_id is required")
    try:
        registry = RunRegistry(Config())
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc
    try:
        _ensure_sensor_backend_ready(registry)
        row = registry.fetch_state_sensor(line_id)
        if row is None:
            raise HTTPException(status_code=404, detail="line_id not found")
        payload = KioskCounterRecord(
            ts_ms=int(row.get("ts_ms") or 0),
            period_ms=int(row.get("period_ms") or 0),
            current_qty=int(row.get("current_qty") or 0),
            target_qty=int(row.get("target_qty") or 0),
            rate_per_sec=float(row.get("rate_per_sec") or 0.0),
            status=str(row.get("status") or "UNKNOWN"),
            runtime_state=str(row.get("runtime_state") or row.get("status") or "UNKNOWN"),
            temp_c=float(row["temp_c"]) if row.get("temp_c") is not None else None,
            vibration_mm_s=float(row["vibration_mm_s"]) if row.get("vibration_mm_s") is not None else None,
            power_kw=float(row["power_kw"]) if row.get("power_kw") is not None else None,
            latest_device_id=str(row.get("latest_device_id") or "") or None,
        )
        _apply_source_headers(response, int(payload.ts_ms))
        return payload
    finally:
        registry.close()


def _now_ms() -> int:
    return int(time.time() * 1000)


def _apply_source_headers(response: Response, source_ts_ms: int) -> None:
    now_ms = _now_ms()
    source_ms = int(max(0, int(source_ts_ms or 0)))
    age_ms = int(max(0, now_ms - source_ms)) if source_ms > 0 else int(now_ms)
    response.headers["x-bohae-correlation-id"] = str(uuid.uuid4())
    response.headers["x-bohae-source-ts"] = str(source_ms)
    response.headers["x-bohae-age-ms"] = str(age_ms)


def _jsonb_to_obj(value: object) -> dict:
    if value is None:
        return {}
    if isinstance(value, dict):
        return value
    if isinstance(value, str):
        try:
            parsed = json.loads(value)
            return parsed if isinstance(parsed, dict) else {"_raw": value}
        except Exception:
            return {"_raw": value}
    return {"_raw": str(value)}


def _json_safe(value: object) -> object:
    if isinstance(value, (datetime, date)):
        return value.isoformat()
    if isinstance(value, dict):
        out = {}
        for key, val in value.items():
            out[str(key)] = _json_safe(val)
        return out
    if isinstance(value, (list, tuple)):
        return [_json_safe(v) for v in value]
    return value


def _parse_date_value(value: object) -> date:
    if isinstance(value, datetime):
        return value.date()
    if isinstance(value, date):
        return value
    if isinstance(value, str) and value.strip():
        raw = value.strip()
        try:
            return date.fromisoformat(raw[:10])
        except Exception:
            pass
    return date.today()


def _parse_datetime_value(value: object) -> datetime | None:
    if isinstance(value, datetime):
        return value
    if isinstance(value, str) and value.strip():
        raw = value.strip()
        try:
            return datetime.fromisoformat(raw.replace("Z", "+00:00"))
        except Exception:
            return None
    return None


def _is_true_env(name: str, default: bool) -> bool:
    raw = os.getenv(name)
    if raw is None:
        return default
    normalized = raw.strip().lower()
    if normalized in {"1", "true", "yes", "y", "on"}:
        return True
    if normalized in {"0", "false", "no", "n", "off"}:
        return False
    return default


def _insert_kiosk_sync_skip_decision(
    registry: RunRegistry,
    *,
    run_id: str,
    scenario_id: str,
    actor: dict,
    reason: str,
    details: dict,
    event_type: str = "KIOSK_SYNC_SKIPPED",
) -> None:
    registry.insert_decision_log(
        scenario_id=scenario_id,
        event_type=event_type,
        payload_json={
            "ENTITY_TYPE": "KIOSK_LINE_CONFIG",
            "ENTITY_ID": str(details.get("line_id_target") or ""),
            "RUN_ID": run_id,
            "ACTOR_EMAIL": actor.get("actor_email"),
            "ACTOR_ROLE": actor.get("actor_role"),
            "REASON": reason,
            "DETAILS": _json_safe(details),
        },
    )


def _auto_sync_kiosk_config_from_approved_run(
    registry: RunRegistry,
    run_row: dict,
    actor: dict,
    *,
    source_event: str = "RUN_EXECUTED",
) -> Dict[str, Any]:
    run_id = str(run_row.get("run_id") or "").strip()
    scenario_id = str(run_row.get("scenario_id") or "").strip() or "OPS_KIOSK"
    source_event_label = str(source_event or "RUN_EXECUTED").strip().upper()
    summary: Dict[str, Any] = {
        "run_id": run_id,
        "source_event": source_event_label,
        "matched_lines": [],
        "updated_lines": [],
        "skipped_locked_lines": [],
        "missing_mapping_lines": [],
        "warnings": [],
    }
    if source_event_label == "RUN_APPROVED":
        if not _is_true_env("BOHAE_KIOSK_AUTO_SYNC_ON_APPROVE", True):
            if run_id:
                _insert_kiosk_sync_skip_decision(
                    registry,
                    run_id=run_id,
                    scenario_id=scenario_id,
                    actor=actor,
                    reason="AUTO_SYNC_DISABLED",
                    details={
                        "run_id": run_id,
                        "source_event": source_event_label,
                        "env_name": "BOHAE_KIOSK_AUTO_SYNC_ON_APPROVE",
                    },
                )
            summary["warnings"].append("AUTO_SYNC_DISABLED")
            return summary
    else:
        if not _is_true_env("BOHAE_KIOSK_AUTO_SYNC_ON_EXECUTED", True):
            if run_id:
                _insert_kiosk_sync_skip_decision(
                    registry,
                    run_id=run_id,
                    scenario_id=scenario_id,
                    actor=actor,
                    reason="AUTO_SYNC_DISABLED",
                    details={
                        "run_id": run_id,
                        "source_event": source_event_label,
                        "env_name": "BOHAE_KIOSK_AUTO_SYNC_ON_EXECUTED",
                    },
                )
            summary["warnings"].append("AUTO_SYNC_DISABLED")
            return summary
    if not registry.kiosk_line_config_enabled:
        if run_id:
            _insert_kiosk_sync_skip_decision(
                registry,
                run_id=run_id,
                scenario_id=scenario_id,
                actor=actor,
                reason="KIOSK_CONFIG_TABLE_NOT_AVAILABLE",
                details={"run_id": run_id},
            )
        summary["warnings"].append("KIOSK_CONFIG_TABLE_NOT_AVAILABLE")
        return summary

    configured_line_id = str(os.getenv("BOHAE_KIOSK_APPROVAL_SYNC_LINE_ID") or "").strip()
    fallback_line_id = str(os.getenv("BOHAE_KIOSK_APPROVAL_FALLBACK_LINE_ID") or "").strip()
    source_system = str(os.getenv("BOHAE_KIOSK_APPROVAL_SYNC_SOURCE_SYSTEM") or "SOLVER").strip() or "SOLVER"
    if not run_id:
        summary["warnings"].append("RUN_ID_EMPTY")
        return summary

    plan_metrics_all = _load_run_plan_line_metrics_from_run_row(run_row)
    renderpack_entries_by_line: Dict[str, Dict[str, Any]] = {}
    try:
        output_xlsx_path_bulk = _try_resolve_output_xlsx_path(run_row)
        if output_xlsx_path_bulk:
            renderpack = build_renderpack_from_snapshot(
                run_id=run_id,
                scenario_id=scenario_id,
                requested_start=_parse_date_value(run_row.get("requested_start")),
                requested_end=_parse_date_value(run_row.get("requested_end")),
                solve_status=str(run_row.get("status") or "UNKNOWN"),
                approval_status="APPROVED",
                started_at=_parse_datetime_value(run_row.get("started_at")),
                finished_at=_parse_datetime_value(run_row.get("finished_at")),
                output_xlsx_path=str(output_xlsx_path_bulk),
                output_download_url=f"/v1/solver/runs/{run_id}/artifacts/output-xlsx",
            )
            for row in renderpack.gantt_rows:
                source_line_id = str(row.line_id or "").strip()
                if not source_line_id:
                    continue
                resolved_line_id = registry.resolve_kiosk_line_id(source_line_id, source_system=source_system) or source_line_id
                product_name = str(row.product_name_ko or row.product_id or "").strip()
                if not product_name:
                    continue
                start_rank = _parse_datetime_value(row.start_ts) or datetime.max
                current = renderpack_entries_by_line.get(resolved_line_id)
                candidate = {
                    "line_id_target": resolved_line_id,
                    "renderpack_line_id": source_line_id,
                    "renderpack_line_resolved": resolved_line_id,
                    "product_name": product_name,
                    "start_rank": start_rank,
                    "dur_min": int(row.dur_min or 0),
                }
                if current is None:
                    renderpack_entries_by_line[resolved_line_id] = candidate
                    continue
                if candidate["start_rank"] < current["start_rank"]:
                    renderpack_entries_by_line[resolved_line_id] = candidate
                    continue
                if candidate["start_rank"] == current["start_rank"] and candidate["dur_min"] > current["dur_min"]:
                    renderpack_entries_by_line[resolved_line_id] = candidate
        else:
            summary["warnings"].append("RENDERPACK_SNAPSHOT_UNAVAILABLE")
    except Exception as exc:
        summary["warnings"].append(f"RENDERPACK_BUILD_ERROR:{exc}")
        if not plan_metrics_all:
            # Auto-sync helper must never break approval workflow.
            _insert_kiosk_sync_skip_decision(
                registry,
                run_id=run_id,
                scenario_id=scenario_id,
                actor=actor,
                reason="RENDERPACK_BUILD_ERROR",
                details={
                    "run_id": run_id,
                    "source_event": source_event_label,
                    "error": str(exc),
                },
            )
            return summary

    if not renderpack_entries_by_line and plan_metrics_all:
        for line_id, metrics in sorted(plan_metrics_all.items(), key=lambda item: item[0]):
            product_name = str(metrics.get("product_name") or "").strip()
            first_start_ts = _parse_datetime_value(metrics.get("first_start_ts"))
            renderpack_entries_by_line[line_id] = {
                "line_id_target": line_id,
                "renderpack_line_id": line_id,
                "renderpack_line_resolved": line_id,
                "product_name": product_name,
                "start_rank": first_start_ts or datetime.max,
                "dur_min": 0,
            }

    configured_line_resolved = (
        registry.resolve_kiosk_line_id(configured_line_id, source_system=source_system)
        if configured_line_id
        else ""
    )
    fallback_line_resolved = (
        registry.resolve_kiosk_line_id(fallback_line_id, source_system=source_system)
        if fallback_line_id
        else ""
    )

    strict_sync = _is_true_env("BOHAE_KIOSK_APPROVAL_SYNC_STRICT", True)
    if configured_line_id:
        configured_target = configured_line_resolved or configured_line_id
        filtered_entries = {
            line_id: entry
            for line_id, entry in renderpack_entries_by_line.items()
            if line_id == configured_target
        }
        if strict_sync and not filtered_entries:
            _insert_kiosk_sync_skip_decision(
                registry,
                run_id=run_id,
                scenario_id=scenario_id,
                actor=actor,
                reason="CONFIGURED_LINE_NOT_PRESENT",
                details={
                    "run_id": run_id,
                    "configured_line": configured_line_id,
                    "configured_line_resolved": configured_line_resolved,
                    "source_system": source_system,
                },
            )
            summary["warnings"].append("CONFIGURED_LINE_NOT_PRESENT")
            summary["missing_mapping_lines"].append(configured_target)
            return summary
        if filtered_entries:
            renderpack_entries_by_line = filtered_entries

    if not renderpack_entries_by_line and fallback_line_id:
        fallback_target = fallback_line_resolved or fallback_line_id
        renderpack_entries_by_line[fallback_target] = {
            "line_id_target": fallback_target,
            "renderpack_line_id": fallback_line_id,
            "renderpack_line_resolved": fallback_target,
            "product_name": "",
            "start_rank": datetime.max,
            "dur_min": 0,
        }

    if not renderpack_entries_by_line:
        _insert_kiosk_sync_skip_decision(
            registry,
            run_id=run_id,
            scenario_id=scenario_id,
            actor=actor,
            reason="NO_LINE_ID_RESOLVED",
            details={
                "run_id": run_id,
                "source_system": source_system,
            },
        )
        summary["warnings"].append("NO_LINE_ID_RESOLVED")
        return summary

    updated_rows: List[Dict[str, Any]] = []
    skipped_rows: List[Dict[str, Any]] = []
    matched_line_ids = sorted(renderpack_entries_by_line.keys())
    summary["matched_lines"] = matched_line_ids
    actor_id = str(actor.get("actor_id") or actor.get("actor_email") or "ops")
    cfg_rows = registry.list_kiosk_line_configs_by_line_ids(line_ids=matched_line_ids) if registry.kiosk_line_config_enabled else []
    telem_rows = registry.list_state_sensor_rows(line_ids=matched_line_ids) if registry.state_sensor_enabled else []
    cfg_by_line = {str(row.get("line_id") or "").strip(): row for row in cfg_rows if str(row.get("line_id") or "").strip()}
    telem_by_line = {str(row.get("line_id") or "").strip(): row for row in telem_rows if str(row.get("line_id") or "").strip()}
    plan_metrics_by_line = {line_id: dict(plan_metrics_all.get(line_id) or {}) for line_id in matched_line_ids if plan_metrics_all.get(line_id)}

    for line_id, entry in sorted(renderpack_entries_by_line.items(), key=lambda item: item[0]):
        cfg_before = dict(cfg_by_line.get(line_id) or {})
        if bool(cfg_before.get("config_lock")):
            details = {
                "run_id": run_id,
                "line_id_target": line_id,
                "source_event": source_event_label,
                "reason": "config_lock=true",
                "renderpack_line": entry.get("renderpack_line_id"),
                "renderpack_line_resolved": entry.get("renderpack_line_resolved"),
            }
            skipped_rows.append(details)
            _insert_kiosk_sync_skip_decision(
                registry,
                run_id=run_id,
                scenario_id=scenario_id,
                actor=actor,
                reason="LOCKED_MANUAL_OVERRIDE",
                details=details,
            )
            summary["skipped_locked_lines"].append(line_id)
            continue

        telem = telem_by_line.get(line_id)
        plan_metrics = dict(plan_metrics_by_line.get(line_id) or {})
        product_name = (
            str(plan_metrics.get("product_name") or "").strip()
            or str(entry.get("product_name") or "").strip()
            or str(cfg_before.get("product_name") or "").strip()
            or "제품A"
        )
        unit_label = str(cfg_before.get("unit_label") or os.getenv("BOHAE_KIOSK_DEFAULT_UNIT_LABEL") or "병").strip() or "병"
        target_qty = int(plan_metrics.get("target_qty") or 0)
        if target_qty <= 0:
            target_qty = int(cfg_before.get("target_qty") or 0)
        if target_qty <= 0 and telem is not None:
            target_qty = int(telem.get("target_qty") or 0)
        if target_qty <= 0:
            target_qty = int(os.getenv("BOHAE_KIOSK_DEFAULT_TARGET_QTY", "0") or 0)

        bpm_target = int(plan_metrics.get("bpm_target") or 0)
        if bpm_target <= 0:
            bpm_target = int(cfg_before.get("bpm_target") or 0)
        if bpm_target <= 0 and telem is not None:
            try:
                bpm_target = int(round(float(telem.get("rate_per_sec") or 0.0) * 60.0))
            except Exception:
                bpm_target = 0

        note = (
            f"auto-sync from {source_event_label} ({run_id}); "
            f"renderpack_line={entry.get('renderpack_line_id')}; resolved_line={line_id}; bulk=true; "
            f"target_source={str(plan_metrics.get('source') or 'CONFIG_OR_SENSOR_FALLBACK')}"
        )
        line_label_ko = _clean_text(cfg_before.get("line_label_ko")) or _resolve_kiosk_line_label_ko(line_id)
        after = registry.upsert_kiosk_line_config(
            line_id=line_id,
            line_label_ko=line_label_ko,
            product_name=product_name,
            target_qty=target_qty,
            unit_label=unit_label,
            bpm_target=bpm_target,
            source=source_event_label,
            source_ref=run_id,
            config_lock=bool(cfg_before.get("config_lock")),
            target_qty_source=str(plan_metrics.get("target_qty_source") or plan_metrics.get("source") or ""),
            bpm_target_source=str(plan_metrics.get("bpm_target_source") or plan_metrics.get("source") or ""),
            product_count=int(plan_metrics.get("product_count") or 1),
            product_name_detail=str(plan_metrics.get("product_name_detail") or "") or None,
            product_semantics=str(plan_metrics.get("product_semantics") or ""),
            approved_run_snapshot_at=datetime.now(timezone.utc),
            note=note,
            updated_by=actor_id,
        )
        if after is None:
            details = {
                "run_id": run_id,
                "line_id_target": line_id,
                "source_event": source_event_label,
                "renderpack_line": entry.get("renderpack_line_id"),
                "renderpack_line_resolved": entry.get("renderpack_line_resolved"),
            }
            skipped_rows.append(details)
            _insert_kiosk_sync_skip_decision(
                registry,
                run_id=run_id,
                scenario_id=scenario_id,
                actor=actor,
                reason="UPSERT_RETURNED_NONE",
                details=details,
            )
            summary["warnings"].append(f"UPSERT_RETURNED_NONE:{line_id}")
            continue

        updated_rows.append(
            {
                "line_id_target": line_id,
                "renderpack_line_id": entry.get("renderpack_line_id"),
                "renderpack_line_resolved": entry.get("renderpack_line_resolved"),
                "product_name": product_name,
            }
        )
        registry.insert_decision_log(
            scenario_id=scenario_id,
            event_type="KIOSK_LINE_CONFIG_UPSERT",
            payload_json={
                "ENTITY_TYPE": "KIOSK_LINE_CONFIG",
                "ENTITY_ID": line_id,
                "ACTOR_EMAIL": actor.get("actor_email"),
                "ACTOR_ROLE": actor.get("actor_role"),
                "SOURCE": source_event_label,
                "SOURCE_REF": run_id,
                "RUN_ID": run_id,
                "LINE_ID_TARGET": line_id,
                "RENDERPACK_LINE_ID": entry.get("renderpack_line_id"),
                "RENDERPACK_LINE_RESOLVED": entry.get("renderpack_line_resolved"),
                "NOTE": note,
                "BEFORE": _json_safe(cfg_before),
                "AFTER": _json_safe(after),
            },
        )

    registry.insert_decision_log(
        scenario_id=scenario_id,
        event_type="KIOSK_CONFIG_BULK_SYNC",
        payload_json={
            "ENTITY_TYPE": "KIOSK_LINE_CONFIG",
            "RUN_ID": run_id,
            "SOURCE": source_event_label,
            "SOURCE_REF": run_id,
            "ACTOR_EMAIL": actor.get("actor_email"),
            "ACTOR_ROLE": actor.get("actor_role"),
            "UPDATED_COUNT": len(updated_rows),
            "SKIPPED_COUNT": len(skipped_rows),
            "UPDATED_ROWS": _json_safe(updated_rows),
            "SKIPPED_ROWS": _json_safe(skipped_rows),
        },
    )
    summary["updated_lines"] = [str(row.get("line_id_target") or "") for row in updated_rows if str(row.get("line_id_target") or "")]
    summary["updated_count"] = len(summary["updated_lines"])
    summary["skipped_locked_count"] = len(summary["skipped_locked_lines"])
    summary["missing_mapping_count"] = len(summary["missing_mapping_lines"])
    return summary


def _coerce_kiosk_datetime(value: Any) -> datetime | None:
    if isinstance(value, datetime):
        return value
    raw = str(value or "").strip()
    if not raw:
        return None
    try:
        return datetime.fromisoformat(raw.replace("Z", "+00:00"))
    except Exception:
        return None


def _timestamp_ms_to_datetime(value: Any) -> datetime | None:
    try:
        ts_ms = int(value or 0)
    except Exception:
        return None
    if ts_ms <= 0:
        return None
    return datetime.fromtimestamp(ts_ms / 1000, timezone.utc)


def _normalize_notice_line_ids(value: Any) -> List[str]:
    if not isinstance(value, list):
        return []
    out: List[str] = []
    seen: set[str] = set()
    for entry in value:
        line_id = str(entry or "").strip()
        if not line_id or line_id in seen:
            continue
        seen.add(line_id)
        out.append(line_id)
    return out


def _to_kiosk_announcement_record(row: Dict[str, Any]) -> KioskAnnouncementRecord:
    target_scope = str(row.get("target_scope") or "GLOBAL").strip().upper() or "GLOBAL"
    return KioskAnnouncementRecord(
        id=str(row.get("notice_id") or row.get("id") or ""),
        title=str(row.get("title") or "제목 없음"),
        message=str(row.get("message") or row.get("title") or "내용 없음"),
        importance="HIGH" if str(row.get("importance") or "").upper() == "HIGH" else "NORMAL",
        priority=int(row.get("priority") or 0),
        display_seconds=max(1, int(row.get("display_seconds") or 8)),
        posted_at=_coerce_kiosk_datetime(row.get("created_at")) or _coerce_kiosk_datetime(row.get("updated_at")) or datetime.utcnow(),
        starts_at=_coerce_kiosk_datetime(row.get("starts_at")),
        ends_at=_coerce_kiosk_datetime(row.get("ends_at")),
        target_scope=target_scope,
        line_ids=_normalize_notice_line_ids(row.get("line_ids")) if target_scope == "LINE" else [],
        active=bool(row.get("is_active", True)),
        posted_by=str(row.get("updated_by") or "SYSTEM"),
        updated_at=_coerce_kiosk_datetime(row.get("updated_at")),
    )


def _load_kiosk_announcements(registry: RunRegistry, line_ids: List[str]) -> List[KioskAnnouncementRecord]:
    rows = registry.list_kiosk_notices(line_ids=line_ids, include_inactive=False, now_at=datetime.utcnow())
    return [_to_kiosk_announcement_record(row) for row in rows]


def _resolve_kiosk_read_access_policy() -> str:
    if KIOSK_READ_SHARED_SECRET:
        return f"SHARED_SECRET_HEADER:{KIOSK_READ_TOKEN_HEADER}"
    return KIOSK_PUBLIC_PANEL_ACCESS_POLICY


def _require_kiosk_read_access(x_kiosk_token: str | None) -> None:
    expected = KIOSK_READ_SHARED_SECRET
    if not expected:
        return
    presented = str(x_kiosk_token or "").strip()
    if not presented or not hmac.compare_digest(presented, expected):
        raise HTTPException(status_code=401, detail=f"{KIOSK_READ_TOKEN_HEADER} header is required")


def _dedupe_kiosk_announcements(records: List[KioskAnnouncementRecord]) -> List[KioskAnnouncementRecord]:
    deduped: List[KioskAnnouncementRecord] = []
    seen: set[str] = set()
    for record in records:
        notice_id = str(getattr(record, "id", "") or "")
        dedupe_key = notice_id or f"{record.target_scope}:{record.title}:{record.message}"
        if dedupe_key in seen:
            continue
        seen.add(dedupe_key)
        deduped.append(record)
    return deduped


def _load_kiosk_announcement_bundle(
    registry: RunRegistry,
    line_ids: List[str],
) -> Tuple[List[KioskAnnouncementRecord], Dict[str, List[KioskAnnouncementRecord]]]:
    normalized_line_ids = _normalize_kiosk_device_line_ids(line_ids)
    records = _load_kiosk_announcements(registry, normalized_line_ids)
    by_line: Dict[str, List[KioskAnnouncementRecord]] = {line_id: [] for line_id in normalized_line_ids}
    global_records: List[KioskAnnouncementRecord] = []
    panel_records: List[KioskAnnouncementRecord] = []
    for record in records:
        scope = str(record.target_scope or "GLOBAL").strip().upper()
        if scope == "GLOBAL":
            global_records.append(record)
            panel_records.append(record)
            continue
        matched = False
        for line_id in record.line_ids:
            cleaned = str(line_id or "").strip()
            if cleaned and cleaned in by_line:
                by_line[cleaned].append(record)
                matched = True
        if matched:
            panel_records.append(record)

    global_records = _dedupe_kiosk_announcements(global_records)
    panel_records = _dedupe_kiosk_announcements(panel_records)
    for line_id in list(by_line.keys()):
        by_line[line_id] = _dedupe_kiosk_announcements(global_records + by_line[line_id])
    return panel_records, by_line


def _has_material_kiosk_config(cfg: Dict[str, Any] | None) -> bool:
    if not cfg:
        return False
    if _clean_text(cfg.get("product_name")):
        return True
    if int(cfg.get("target_qty") or 0) > 0:
        return True
    if int(cfg.get("bpm_target") or 0) > 0:
        return True
    return False


def _has_sensor_fallback(telem: Dict[str, Any] | None) -> bool:
    if not telem:
        return False
    if int(telem.get("target_qty") or 0) > 0:
        return True
    if int(telem.get("current_qty") or 0) > 0:
        return True
    if int(telem.get("ts_ms") or 0) > 0:
        return True
    try:
        return float(telem.get("rate_per_sec") or 0.0) > 0.0
    except Exception:
        return False


def _resolve_kiosk_config_source(cfg: Dict[str, Any] | None, telem: Dict[str, Any] | None) -> str:
    if _has_material_kiosk_config(cfg):
        source = str((cfg or {}).get("source") or "MANUAL").strip().upper() or "MANUAL"
        if source in {"RUN_APPROVED", "RUN_EXECUTED", "APPROVED_RUN"}:
            return "APPROVED_RUN"
        return "MANUAL"
    if _has_sensor_fallback(telem):
        return "SENSOR_FALLBACK"
    return "NONE"


def _resolve_kiosk_config_status(
    *,
    config_source: str,
) -> str:
    source_key = str(config_source or "NONE").strip().upper()
    if source_key in {"MANUAL", "APPROVED_RUN"}:
        return "CONFIGURED"
    if source_key == "SENSOR_FALLBACK":
        return "FALLBACK"
    return "UNCONFIGURED"


def _resolve_kiosk_config_source_ref(
    *,
    config_source: str,
    cfg: Dict[str, Any] | None,
    telem: Dict[str, Any] | None,
    line_id: str,
) -> str:
    source_key = str(config_source or "NONE").strip().upper()
    if source_key in {"MANUAL", "APPROVED_RUN"}:
        return str((cfg or {}).get("source_ref") or "").strip()
    if source_key == "SENSOR_FALLBACK":
        return str((telem or {}).get("latest_device_id") or line_id).strip()
    return ""


def _resolve_kiosk_config_updated_at(
    *,
    config_source: str,
    cfg: Dict[str, Any] | None,
    telem: Dict[str, Any] | None,
) -> datetime | None:
    source_key = str(config_source or "NONE").strip().upper()
    if source_key in {"MANUAL", "APPROVED_RUN"}:
        return (cfg or {}).get("updated_at") if cfg else None
    if source_key == "SENSOR_FALLBACK":
        return _coerce_kiosk_datetime((telem or {}).get("updated_at"))
    return None


def _load_kiosk_run_plan_metrics_by_line(
    registry: RunRegistry,
    cfg_rows: List[Dict[str, Any]],
) -> Dict[str, Dict[str, Any]]:
    out: Dict[str, Dict[str, Any]] = {}
    for cfg in cfg_rows:
        line_id = str(cfg.get("line_id") or "").strip()
        source = str(cfg.get("source") or "").strip().upper()
        run_id = str(cfg.get("source_ref") or "").strip()
        if not line_id or source not in {"APPROVED_RUN", "RUN_APPROVED", "RUN_EXECUTED"} or not run_id:
            continue
        target_qty_source = str(cfg.get("target_qty_source") or "").strip()
        bpm_target_source = str(cfg.get("bpm_target_source") or "").strip()
        if target_qty_source == "APPROVED_RUN_PLAN_SNAPSHOT" or bpm_target_source == "APPROVED_RUN_PLAN_SNAPSHOT":
            out[line_id] = {
                "product_name": _clean_text(cfg.get("product_name")),
                "product_name_detail": _clean_text(cfg.get("product_name_detail")) or None,
                "product_id": "",
                "product_count": max(1, int(cfg.get("product_count") or 1)),
                "product_semantics": str(cfg.get("product_semantics") or "SINGLE_PRODUCT").strip() or "SINGLE_PRODUCT",
                "target_qty": max(0, int(cfg.get("target_qty") or 0)),
                "bpm_target": max(0, int(cfg.get("bpm_target") or 0)),
                "segment_count": 0,
                "first_start_ts": None,
                "target_qty_source": target_qty_source or "APPROVED_RUN_PLAN_SNAPSHOT",
                "bpm_target_source": bpm_target_source or target_qty_source or "APPROVED_RUN_PLAN_SNAPSHOT",
                "source": target_qty_source or "APPROVED_RUN_PLAN_SNAPSHOT",
                "approved_run_snapshot_at": cfg.get("approved_run_snapshot_at"),
            }
            continue
        out[line_id] = {
            "product_name": _clean_text(cfg.get("product_name")),
            "product_name_detail": _clean_text(cfg.get("product_name_detail")) or None,
            "product_id": "",
            "product_count": max(1, int(cfg.get("product_count") or 1)),
            "product_semantics": str(cfg.get("product_semantics") or "SINGLE_PRODUCT").strip() or "SINGLE_PRODUCT",
            "target_qty": max(0, int(cfg.get("target_qty") or 0)),
            "bpm_target": max(0, int(cfg.get("bpm_target") or 0)),
            "segment_count": 0,
            "first_start_ts": None,
            "target_qty_source": target_qty_source or "APPROVED_RUN_CONFIG_FALLBACK",
            "bpm_target_source": bpm_target_source or target_qty_source or "APPROVED_RUN_CONFIG_FALLBACK",
            "source": target_qty_source or "APPROVED_RUN_CONFIG_FALLBACK",
            "approved_run_snapshot_at": cfg.get("approved_run_snapshot_at"),
        }
    return out


def _aggregate_kiosk_live_production_by_line(rows: List[Dict[str, Any]]) -> Dict[str, Dict[str, Any]]:
    aggregated: Dict[str, Dict[str, Any]] = {}
    for row in rows:
        line_id = str(row.get("line_id") or "").strip()
        if not line_id:
            continue
        current = aggregated.setdefault(
            line_id,
            {
                "line_id": line_id,
                "target_qty": 0,
                "current_qty": 0,
                "work_order_ids": [],
                "lot_ids": [],
                "run_ids": [],
                "product_ids": [],
            },
        )
        current["target_qty"] += max(0, int(round(float(row.get("planned_qty") or 0))))
        current["current_qty"] += max(0, int(round(float(row.get("actual_qty") or 0))))
        work_order_id = str(row.get("work_order_id") or "").strip()
        lot_id = str(row.get("lot_id") or "").strip()
        run_id = str(row.get("run_id") or "").strip()
        product_id = str(row.get("product_id") or "").strip()
        if work_order_id and work_order_id not in current["work_order_ids"]:
            current["work_order_ids"].append(work_order_id)
        if lot_id and lot_id not in current["lot_ids"]:
            current["lot_ids"].append(lot_id)
        if run_id and run_id not in current["run_ids"]:
            current["run_ids"].append(run_id)
        if product_id and product_id not in current["product_ids"]:
            current["product_ids"].append(product_id)

    for current in aggregated.values():
        work_order_ids = list(current.pop("work_order_ids"))
        lot_ids = list(current.pop("lot_ids"))
        run_ids = list(current.pop("run_ids"))
        product_ids = list(current.pop("product_ids"))
        current["work_order_count"] = len(work_order_ids)
        current["lot_count"] = len(lot_ids)
        current["product_count"] = len(product_ids)
        current["work_order_id"] = work_order_ids[0] if len(work_order_ids) == 1 else None
        current["lot_id"] = lot_ids[0] if len(lot_ids) == 1 else None
        current["run_id"] = run_ids[0] if len(run_ids) == 1 else None
        current["product_id"] = product_ids[0] if len(product_ids) == 1 else None
        current["product_name_detail"] = " / ".join(product_ids) if product_ids else None
        current["current_run_label"] = (
            work_order_ids[0]
            if len(work_order_ids) == 1
            else f"WO {len(work_order_ids)}건 집계"
            if len(work_order_ids) > 1
            else lot_ids[0]
            if len(lot_ids) == 1
            else f"LOT {len(lot_ids)}건 집계"
            if len(lot_ids) > 1
            else None
        )
    return aggregated


def _normalize_kiosk_runtime_state(telem: Dict[str, Any] | None, status: str) -> str:
    runtime_state = str((telem or {}).get("runtime_state") or status or "UNKNOWN").strip().upper()
    if runtime_state == "OK":
        return "RUNNING"
    if runtime_state in {"RUNNING", "DOWN", "ERROR", "STOP", "IDLE", "NO_DATA", "UNKNOWN"}:
        return runtime_state
    return status.strip().upper() or "UNKNOWN"


def _coerce_kiosk_int(value: object, default: int = 0) -> int:
    try:
        if value is None or isinstance(value, bool):
            return int(default)
        if isinstance(value, (int, float)):
            return int(value)
        text = str(value).strip()
        if not text:
            return int(default)
        return int(float(text))
    except Exception:
        return int(default)


def _resolve_kiosk_health_state(*, status: str, runtime_state: str, source_ts_ms: int, stale: bool) -> str:
    status_key = str(status or "UNKNOWN").strip().upper()
    runtime_key = str(runtime_state or status_key or "UNKNOWN").strip().upper()
    if source_ts_ms <= 0 or status_key == "NO_DATA":
        return "NO_DATA"
    if stale:
        return "STALE"
    if status_key == "ERROR" or runtime_key == "ERROR":
        return "ERROR"
    return "LIVE"


def _resolve_stop_window(
    *,
    telem: Dict[str, Any] | None,
    runtime_state: str,
    stale: bool,
    now_ms: int,
    last_count_at_ms: int = 0,
    open_event: Dict[str, Any] | None = None,
) -> Tuple[int, datetime | None, int | None, bool, str | None]:
    runtime_state_since_ts_ms = int((telem or {}).get("runtime_ts_ms") or 0) if telem else 0
    open_started_at: datetime | None = None
    open_started_at_ms = 0
    if open_event:
        payload = open_event.get("payload_json")
        payload_dict = payload if isinstance(payload, dict) else {}
        open_started_at = (
            _coerce_kiosk_datetime(payload_dict.get("opened_at"))
            or _coerce_kiosk_datetime((payload_dict.get("metadata") or {}).get("started_at") if isinstance(payload_dict.get("metadata"), dict) else None)
            or _coerce_kiosk_datetime(open_event.get("created_at"))
        )
        if open_started_at is not None:
            open_started_at_ms = int(open_started_at.timestamp() * 1000)

    if runtime_state == "NO_DATA":
        return runtime_state_since_ts_ms, None, None, False, "NO_DATA"
    if stale:
        return runtime_state_since_ts_ms, None, None, False, "STALE"
    if runtime_state == "RUNNING":
        return runtime_state_since_ts_ms, None, None, False, "RUNNING"

    candidate_ms = [value for value in (runtime_state_since_ts_ms, open_started_at_ms) if value > 0]
    if candidate_ms:
        # Prefer the moment the runtime actually entered a non-running state.
        # This avoids a false "always transient" state when IDLE frames keep arriving
        # but the counter itself is no longer increasing.
        stop_started_at_ms = min(candidate_ms)
    elif int(last_count_at_ms or 0) > 0:
        stop_started_at_ms = int(last_count_at_ms)
    else:
        return runtime_state_since_ts_ms, None, None, False, "STOP_START_UNKNOWN"
    stop_started_at = _timestamp_ms_to_datetime(stop_started_at_ms)
    stop_duration_sec = max(0, int((now_ms - stop_started_at_ms) // 1000))
    return runtime_state_since_ts_ms, stop_started_at, stop_duration_sec, True, None


def _resolve_kiosk_production_state(
    *,
    health_state: str,
    status: str,
    runtime_state: str,
    stop_duration_sec: int | None,
) -> str:
    health_key = str(health_state or "UNKNOWN").strip().upper()
    status_key = str(status or "UNKNOWN").strip().upper()
    runtime_key = str(runtime_state or status_key or "UNKNOWN").strip().upper()
    if health_key in {"STALE", "NO_DATA"}:
        return "UNKNOWN"
    if status_key == "NO_DATA" or runtime_key == "NO_DATA":
        return "UNKNOWN"
    if runtime_key == "RUNNING":
        return "RUNNING"
    if runtime_key in {"DOWN", "ERROR", "STOP", "IDLE", "UNKNOWN"} or status_key in {"DOWN", "ERROR", "STOP", "IDLE"}:
        return "STOPPED" if int(stop_duration_sec or 0) >= KIOSK_TRANSIENT_STOP_SEC else "TRANSIENT_STOP"
    return "UNKNOWN"


def _resolve_kiosk_display_state(*, health_state: str, production_state: str) -> str:
    if health_state in {"STALE", "NO_DATA", "ERROR"}:
        return health_state
    return production_state


def _resolve_kiosk_display_state_reason(
    *,
    health_state: str,
    production_state: str,
    stop_duration_sec: int | None,
) -> str:
    if health_state == "STALE":
        return "SOURCE_TS_EXPIRED"
    if health_state == "NO_DATA":
        return "NO_DATA"
    if health_state == "ERROR":
        return "SENSOR_RUNTIME_ERROR"
    if production_state == "RUNNING":
        return "RUNNING"
    if production_state == "STOPPED" and int(stop_duration_sec or 0) >= KIOSK_TRANSIENT_STOP_SEC:
        return "STOP_THRESHOLD_REACHED"
    if production_state == "TRANSIENT_STOP":
        return "STOP_THRESHOLD_PENDING"
    return "UNKNOWN"


def _resolve_kiosk_stop_label_ko(display_state: str) -> str | None:
    state_key = str(display_state or "").strip().upper()
    if state_key == "CHANGEOVER":
        return "라인교체중"
    if state_key == "TRANSIENT_STOP":
        return "일시 정지"
    if state_key == "STOPPED":
        return "라인 정지"
    if state_key == "BREAK":
        return "쉬는시간"
    if state_key == "ENDED":
        return "라인 종료"
    if state_key == "STALE":
        return "데이터 지연"
    return None


def _normalize_kiosk_theme(value: object, default: str = "light") -> str:
    normalized = str(value or "").strip().lower()
    aliases = {
        "white": "light",
        "black": "dark",
        "high-contrast": "contrast",
        "high_contrast": "contrast",
    }
    normalized = aliases.get(normalized, normalized)
    if normalized in ALLOWED_KIOSK_THEMES:
        return normalized
    return default


def _normalize_kiosk_status_override(value: object, default: str = "AUTO") -> str:
    normalized = str(value or "").strip().upper()
    if normalized in ALLOWED_KIOSK_STATUS_OVERRIDES:
        return normalized
    return default


def _resolve_kiosk_status_action_override(action: object) -> str:
    action_key = str(action or "").strip().upper()
    mapping = {
        "START": "AUTO",
        "STOP": "ENDED",
        "PAUSE": "STOPPED",
        "CHANGEOVER_START": "CHANGEOVER",
        "CHANGEOVER_END": "AUTO",
        "BREAK_START": "BREAK",
        "BREAK_END": "AUTO",
        "AUTO": "AUTO",
    }
    normalized = mapping.get(action_key)
    if not normalized:
        allowed = ", ".join(sorted(mapping))
        raise HTTPException(status_code=400, detail=f"지원하지 않는 kiosk status action 입니다. allowed={allowed}")
    return normalized


def _resolve_kiosk_display_status(
    *,
    production_state: str,
    health_state: str,
    status_override: str,
    status_reason_code: str = "",
) -> Tuple[str, str, str]:
    override_key = _normalize_kiosk_status_override(status_override, default="AUTO")
    reason_key = _normalize_kiosk_reason_code(status_reason_code)
    production_key = str(production_state or "UNKNOWN").strip().upper()
    health_key = str(health_state or "UNKNOWN").strip().upper()
    if override_key == "CHANGEOVER" or reason_key == "CHANGEOVER":
        return "CHANGEOVER", "라인교체중", "yellow"
    if override_key == "BREAK":
        return "BREAK", "쉬는시간", "yellow"
    if override_key == "ENDED":
        return "ENDED", "라인 종료", "gray"
    if override_key == "RUNNING" and health_key not in {"STALE", "NO_DATA"} and production_key in {"RUNNING", "TRANSIENT_STOP"}:
        return "RUNNING", "생산중", "green"
    if override_key == "STOPPED":
        return "STOPPED", "라인 정지", "red"

    if production_key == "RUNNING":
        return "RUNNING", "생산중", "green"
    if production_key == "TRANSIENT_STOP":
        return "STOPPED", "라인 정지", "red"
    if production_key == "STOPPED":
        return "STOPPED", "라인 정지", "red"
    if production_key == "BREAK":
        return "BREAK", "쉬는시간", "yellow"
    if production_key == "ENDED":
        return "ENDED", "라인 종료", "gray"
    if health_key == "STALE":
        return "STOPPED", "라인 정지", "red"
    return "ENDED", "라인 종료", "gray"


def _resolve_kiosk_operator_message_and_hint(
    *,
    config_status: str,
    health_state: str,
    production_state: str,
    status_override: str = "AUTO",
    status_reason_code: str = "",
) -> Tuple[str, str | None]:
    config_key = str(config_status or "UNCONFIGURED").strip().upper()
    health_key = str(health_state or "UNKNOWN").strip().upper()
    production_key = str(production_state or "UNKNOWN").strip().upper()
    override_key = _normalize_kiosk_status_override(status_override, default="AUTO")
    reason_key = _normalize_kiosk_reason_code(status_reason_code)
    if config_key == "UNCONFIGURED":
        return "품목/목표 미설정", "운영자 화면에서 품목과 목표를 먼저 설정하세요."
    if override_key == "CHANGEOVER" or reason_key == "CHANGEOVER":
        return "라인교체중입니다", "교체가 끝나면 다음 품목을 시작하거나 자동 판단으로 되돌리세요."
    if override_key == "BREAK":
        return "쉬는시간", "관리 화면에서 작업 재개 시 자동 판단으로 되돌리세요."
    if override_key == "ENDED":
        return "라인 종료", "다음 작업 전 품목/목표를 다시 확인하세요."
    if health_key == "NO_DATA":
        return "데이터 없음", "센서 연결과 전원 상태를 확인하세요."
    if health_key == "STALE":
        return "데이터 지연", "수집기 또는 네트워크 상태를 확인하세요."
    if health_key == "ERROR":
        return "설비 오류 감지", "현장 설비 상태와 센서 오류를 점검하세요."
    if production_key == "RUNNING":
        return "정상 가동", None
    if production_key == "TRANSIENT_STOP":
        return "일시 정지 감지", "20초 이상 지속되면 라인 정지로 전환됩니다."
    if production_key == "STOPPED":
        return "라인 정지", "현장 확인 후 재가동 또는 장애 조치를 진행하세요."
    return "상태 확인 필요", None


def _normalize_kiosk_layout_mode(value: object, default: str = "grid_2x2") -> str:
    normalized = str(value or "").strip().lower()
    if normalized == "single":
        normalized = "grid_1x1"
    if normalized in ALLOWED_KIOSK_LAYOUT_MODES:
        return normalized
    return default


def _normalize_kiosk_layout_mode_or_400(layout_mode: str) -> str:
    normalized = _normalize_kiosk_layout_mode(layout_mode, default="")
    if not normalized:
        allowed = ", ".join(sorted(ALLOWED_KIOSK_LAYOUT_MODES))
        raise HTTPException(status_code=400, detail=f"지원하지 않는 layout_mode 입니다. allowed={allowed}")
    return normalized


def _normalize_kiosk_theme_or_400(theme: str) -> str:
    normalized = _normalize_kiosk_theme(theme, default="")
    if not normalized:
        raise HTTPException(status_code=400, detail="지원하지 않는 theme 입니다. allowed=dark, light, contrast")
    return normalized


def _normalize_kiosk_profile_kind(value: object, default: str = "DEVICE_BOARD") -> str:
    normalized = str(value or "").strip().upper()
    if normalized in {"DEVICE_BOARD", "LINE_FOCUS"}:
        return normalized
    return default


def _normalize_kiosk_profile_scope(value: object, default: str = "PRIVATE") -> str:
    normalized = str(value or "").strip().upper()
    if normalized in {"PRIVATE", "SHARED"}:
        return normalized
    return default


def _normalize_kiosk_area_filter(value: object, default: str = "all") -> str:
    normalized = str(value or "").strip().lower()
    if normalized in {"all", "b1", "b2", "b3", "b4", "manual"}:
        return normalized
    return default


def _normalize_kiosk_profile_line_ids_or_400(registry: RunRegistry, line_ids: List[str]) -> List[str]:
    cleaned = _normalize_kiosk_device_line_ids(line_ids)
    if not cleaned:
        return []
    existing_line_ids = set(registry.list_existing_kiosk_line_ids(cleaned))
    invalid_line_ids = [line_id for line_id in cleaned if line_id not in existing_line_ids]
    if invalid_line_ids:
        raise HTTPException(
            status_code=400,
            detail=f"unknown kiosk line ids: {', '.join(sorted(invalid_line_ids))}",
        )
    return cleaned


def _actor_can_edit_kiosk_profile(actor: Dict[str, Any], row: Dict[str, Any] | None) -> bool:
    role = str(actor.get("actor_role") or "VIEWER").upper().strip()
    if role in {"ADMIN", "MANAGER"}:
        return True
    if not row:
        return True
    return _clean_text(row.get("owner_user_id")) == _clean_text(actor.get("actor_id"))


def _actor_can_view_kiosk_profile(actor: Dict[str, Any], row: Dict[str, Any]) -> bool:
    role = str(actor.get("actor_role") or "VIEWER").upper().strip()
    if role in {"ADMIN", "MANAGER"}:
        return True
    scope = _normalize_kiosk_profile_scope(row.get("profile_scope"), default="PRIVATE")
    if scope == "SHARED":
        return True
    return _clean_text(row.get("owner_user_id")) == _clean_text(actor.get("actor_id"))


def _to_kiosk_view_profile_record(actor: Dict[str, Any], row: Dict[str, Any]) -> KioskViewProfileRecord:
    return KioskViewProfileRecord(
        profile_id=_clean_text(row.get("profile_id")),
        title=_clean_text(row.get("title")),
        profile_kind=_normalize_kiosk_profile_kind(row.get("profile_kind")),
        profile_scope=_normalize_kiosk_profile_scope(row.get("profile_scope")),
        owner_user_id=_clean_text(row.get("owner_user_id")),
        owner_employee_no=_clean_text(row.get("owner_employee_no")) or None,
        target_device_id=_clean_text(row.get("target_device_id")) or None,
        target_line_id=_clean_text(row.get("target_line_id")) or None,
        layout_mode=_normalize_kiosk_layout_mode(row.get("layout_mode") or "grid_4x3"),
        theme=_normalize_kiosk_theme(row.get("theme") or "dark"),
        viewer_mode=str(row.get("viewer_mode") or "ACTIVE_LINES_BOARD").strip().upper() or "ACTIVE_LINES_BOARD",
        active_lines_only=bool(row.get("active_lines_only")),
        area_filter=_normalize_kiosk_area_filter(row.get("area_filter")),
        line_ids=[str(value).strip() for value in (row.get("line_ids") or []) if str(value).strip()],
        viewer_profile_json=dict(row.get("viewer_profile_json") or {}) if isinstance(row.get("viewer_profile_json"), dict) else {},
        note=_clean_text(row.get("note")),
        updated_by=_clean_text(row.get("updated_by")),
        updated_at=_coerce_kiosk_datetime(row.get("updated_at")) or datetime.now(timezone.utc),
        editable=_actor_can_edit_kiosk_profile(actor, row),
    )


def _resolve_published_kiosk_device_assignment(
    registry: RunRegistry,
    assignment: Dict[str, Any] | None,
) -> Dict[str, Any] | None:
    if assignment is None:
        return None
    base = dict(assignment)
    viewer_profile_json = dict(base.get("viewer_profile_json") or {}) if isinstance(base.get("viewer_profile_json"), dict) else {}
    published_profile_id = _clean_text(viewer_profile_json.get("published_profile_id"))
    if not published_profile_id or not registry.kiosk_view_profile_enabled:
        return base
    profile_row = registry.fetch_kiosk_view_profile(published_profile_id)
    if profile_row is None:
        return base
    if _normalize_kiosk_profile_scope(profile_row.get("profile_scope"), default="PRIVATE") != "SHARED":
        return base
    if _normalize_kiosk_profile_kind(profile_row.get("profile_kind"), default="DEVICE_BOARD") != "DEVICE_BOARD":
        return base

    merged_viewer_profile_json = dict(viewer_profile_json)
    profile_viewer_profile_json = (
        dict(profile_row.get("viewer_profile_json") or {})
        if isinstance(profile_row.get("viewer_profile_json"), dict)
        else {}
    )
    merged_viewer_profile_json.update(profile_viewer_profile_json)
    merged_viewer_profile_json["published_profile_id"] = published_profile_id
    merged_viewer_profile_json["published_profile_title"] = _clean_text(profile_row.get("title"))
    merged_viewer_profile_json["area_filter"] = _normalize_kiosk_area_filter(profile_row.get("area_filter"), default="all")

    merged = dict(base)
    layout_mode = _clean_text(profile_row.get("layout_mode"))
    if layout_mode:
        merged["layout_mode"] = layout_mode
    merged["theme"] = _normalize_kiosk_theme(profile_row.get("theme") or base.get("theme") or "", default="")
    merged["viewer_mode"] = _clean_text(profile_row.get("viewer_mode")) or _clean_text(base.get("viewer_mode")) or "ACTIVE_LINES_BOARD"
    merged["active_lines_only"] = bool(profile_row.get("active_lines_only"))
    profile_line_ids = [str(value).strip() for value in (profile_row.get("line_ids") or []) if str(value).strip()]
    if profile_line_ids:
        merged["line_ids"] = profile_line_ids
    merged["viewer_profile_json"] = merged_viewer_profile_json
    return merged


def _kiosk_layout_capacity(layout_mode: str) -> int:
    return int(KIOSK_LAYOUT_CAPACITY.get(_normalize_kiosk_layout_mode(layout_mode), 0))


def _normalize_kiosk_device_line_ids(line_ids: List[str]) -> List[str]:
    deduped: List[str] = []
    seen: set[str] = set()
    for value in line_ids or []:
        line_id = str(value or "").strip()
        if not line_id or line_id in seen:
            continue
        seen.add(line_id)
        deduped.append(line_id)
    return deduped


def _guess_kiosk_public_zone_label(device_id: str) -> str:
    normalized = _clean_text(device_id).upper()
    if normalized.startswith("KIOSK_HALL_"):
        return "현장 홀"
    if normalized.startswith("KIOSK_PROOF_PANEL_"):
        return "검수 존"
    if normalized.startswith("KIOSK_"):
        return "현장 존"
    return "현장 존"


def _guess_kiosk_public_sort_order(device_id: str) -> int:
    normalized = _clean_text(device_id).upper()
    suffix = normalized.split("_")[-1] if normalized else ""
    try:
        parsed = int(suffix)
        return max(0, parsed)
    except Exception:
        return 999


def _resolve_kiosk_device_label(device_id: str) -> str:
    normalized = _clean_text(device_id).upper()
    if normalized == "KIOSK_HALL_01":
        return "메인 전광판"
    if normalized == "KIOSK_HALL_02":
        return "서브 전광판"
    if normalized.startswith("KIOSK_HALL_"):
        suffix = normalized.split("_")[-1] if normalized else ""
        return f"전광판 {suffix}" if suffix else "현장 전광판"
    if normalized.startswith("KIOSK_PROOF_PANEL_"):
        suffix = normalized.split("_")[-1] if normalized else ""
        return f"검수 패널 {suffix}" if suffix else "검수 패널"
    if normalized.startswith("KIOSK_PROOF_"):
        return "검수 패널"
    if normalized.startswith("KIOSK_"):
        return "현장 전광판"
    return _clean_text(device_id) or "현장 전광판"


def _trim_kiosk_public_zone_suffix(label: str) -> str:
    normalized = re.sub(r"\s+", " ", _clean_text(label)).strip()
    normalized = re.sub(r"\s+(메인\s*전광판|전광판)$", "", normalized)
    normalized = re.sub(r"\s+\d+호(?:\s*라인)?$", "", normalized)
    normalized = re.sub(r"\s+라인\s*\d+$", "", normalized)
    normalized = re.sub(r"\s+패널\s*\d+$", "", normalized)
    return normalized.strip()


def _derive_kiosk_public_zone_from_line_label(line_label: str) -> str:
    normalized = re.sub(r"\s+", " ", _clean_text(line_label)).strip()
    hall_match = re.match(r"^(.+?\d동)\s+\d+호(?:\s*라인)?$", normalized)
    if hall_match and hall_match.group(1):
        return hall_match.group(1).strip()
    proof_match = re.match(r"^(.+?)\s+라인\s*\d+$", normalized)
    if proof_match and proof_match.group(1):
        return proof_match.group(1).strip()
    return ""


def _should_derive_kiosk_public_zone(zone_label: str) -> bool:
    normalized = re.sub(r"\s+", " ", _clean_text(zone_label)).strip()
    return normalized in {"", "현장 존", "현장 홀"}


def _should_prefix_kiosk_public_label(label: str) -> bool:
    normalized = re.sub(r"\s+", " ", _clean_text(label)).strip()
    return normalized in {"메인 전광판", "전광판"}


def _normalize_kiosk_public_surface_meta(
    *,
    assignment: Dict[str, Any],
    line_labels: List[str] | None = None,
) -> Dict[str, Any]:
    device_id = _clean_text(assignment.get("device_id"))
    line_ids = _normalize_kiosk_device_line_ids(list(assignment.get("line_ids") or []))
    viewer_profile_json = (
        dict(assignment.get("viewer_profile_json") or {})
        if isinstance(assignment.get("viewer_profile_json"), dict)
        else {}
    )
    public_surface = (
        dict(viewer_profile_json.get("public_surface") or {})
        if isinstance(viewer_profile_json.get("public_surface"), dict)
        else {}
    )

    raw_label = _clean_text(public_surface.get("label"))
    raw_zone_label = _clean_text(public_surface.get("zone_label"))
    normalized_line_labels = [_clean_text(label) for label in (line_labels or []) if _clean_text(label)]
    derived_zone_from_label = _trim_kiosk_public_zone_suffix(raw_label)
    derived_zone_from_line = next(
        (
            zone
            for zone in (_derive_kiosk_public_zone_from_line_label(label) for label in normalized_line_labels)
            if zone
        ),
        "",
    )

    zone_label = raw_zone_label
    if _should_derive_kiosk_public_zone(zone_label):
        if derived_zone_from_line:
            zone_label = derived_zone_from_line
        elif derived_zone_from_label and derived_zone_from_label != raw_label:
            zone_label = derived_zone_from_label
        else:
            zone_label = _guess_kiosk_public_zone_label(device_id)

    public_label = raw_label or _resolve_kiosk_device_label(device_id)
    if _should_prefix_kiosk_public_label(public_label) and zone_label:
        public_label = f"{zone_label} {public_label}".strip()

    sort_order = _coerce_kiosk_int(public_surface.get("sort_order"), default=_guess_kiosk_public_sort_order(device_id))
    is_public_visible = bool(public_surface.get("visible", True))
    default_target_type = "line" if _clean_text(public_surface.get("target_type")).lower() == "line" else "device"
    default_target_id = _clean_text(
        public_surface.get("target_id")
    ) or (line_ids[0] if default_target_type == "line" and line_ids else device_id)
    if default_target_type == "line" and not line_ids:
        default_target_type = "device"
        default_target_id = device_id

    return {
        "public_label": public_label or _resolve_kiosk_device_label(device_id),
        "zone_label": zone_label or _guess_kiosk_public_zone_label(device_id),
        "sort_order": max(0, sort_order),
        "is_public_visible": is_public_visible,
        "default_target_type": default_target_type,
        "default_target_id": default_target_id or device_id,
    }


def _build_kiosk_public_target_path(*, device_id: str, target_type: str, target_id: str) -> str:
    if str(target_type or "").strip().lower() == "line" and _clean_text(target_id):
        return f"/line/{urlparse.quote(_clean_text(target_id))}"
    return f"/device/{urlparse.quote(_clean_text(device_id))}"


def _extract_kiosk_day_plan_active_segment_label(viewer_profile_json: Dict[str, Any] | None) -> str:
    viewer_profile = viewer_profile_json if isinstance(viewer_profile_json, dict) else {}
    day_plan = viewer_profile.get("day_plan")
    if not isinstance(day_plan, dict):
        return ""
    active_segment_id = _clean_text(day_plan.get("active_segment_id"))
    if not active_segment_id:
        return ""
    segments = day_plan.get("segments")
    if not isinstance(segments, list):
        return active_segment_id
    for raw_segment in segments:
        if not isinstance(raw_segment, dict):
            continue
        segment_id = _clean_text(raw_segment.get("segment_id"))
        if segment_id != active_segment_id:
            continue
        return _clean_text(raw_segment.get("display_product_name")) or active_segment_id
    return active_segment_id


def _extract_kiosk_count_reset_hhmm_from_profile(viewer_profile_json: Dict[str, Any] | None) -> str:
    viewer_profile = viewer_profile_json if isinstance(viewer_profile_json, dict) else {}
    return _clean_text(viewer_profile.get("count_reset_hhmm"))


def _evaluate_kiosk_reset_required(
    *,
    current_qty: int,
    active_segment_label: str,
    viewer_profile_json: Dict[str, Any] | None,
    now_ms: int,
) -> Tuple[bool, str | None, str | None]:
    qty = max(0, int(current_qty or 0))
    if qty <= 0:
        return False, None, None

    config_segment_label = _extract_kiosk_day_plan_active_segment_label(viewer_profile_json)
    if active_segment_label and config_segment_label and _clean_text(active_segment_label) != _clean_text(config_segment_label):
        return (
            True,
            f"품목이 전환되었습니다 ({config_segment_label} → {active_segment_label}). 수량을 초기화해 주세요.",
            "SEGMENT_TRANSITION",
        )

    count_reset_hhmm = _extract_kiosk_count_reset_hhmm_from_profile(viewer_profile_json)
    parsed = _parse_hhmm_to_minutes(count_reset_hhmm)
    if parsed is not None:
        tz = ZoneInfo(KIOSK_PANEL_TIMEZONE)
        now_dt = datetime.fromtimestamp(now_ms / 1000, tz)
        current_min = now_dt.hour * 60 + now_dt.minute
        minutes_since_reset = current_min - int(parsed)
        if 0 <= minutes_since_reset <= 30:
            return (
                True,
                f"카운트 리셋 시각({count_reset_hhmm})이 지났지만 수량이 0으로 리셋되지 않았습니다.",
                "COUNT_RESET_TIME",
            )

    return False, None, None


def _parse_hhmm_to_minutes(value: str) -> int | None:
    text = _clean_text(value)
    match = re.match(r"^(\d{1,2}):(\d{2})$", text)
    if not match:
        return None
    hours = int(match.group(1))
    minutes = int(match.group(2))
    if hours < 0 or hours > 23 or minutes < 0 or minutes > 59:
        return None
    return hours * 60 + minutes


def _format_kiosk_elapsed_minutes_ko(total_minutes: int) -> str:
    minutes = max(0, int(total_minutes))
    hours = minutes // 60
    remain = minutes % 60
    if hours <= 0:
        return f"{remain}분 경과"
    if remain <= 0:
        return f"{hours}시간 경과"
    return f"{hours}시간 {remain}분 경과"


def _format_kiosk_hhmm_label_ko(value: str) -> str:
    text = _clean_text(value)
    minutes = _parse_hhmm_to_minutes(text)
    if minutes is None:
        return text
    hours = minutes // 60
    remain = minutes % 60
    meridiem = "오전" if hours < 12 else "오후"
    display_hour = hours % 12
    if display_hour == 0:
        display_hour = 12
    if remain <= 0:
        return f"{meridiem} {display_hour}시"
    return f"{meridiem} {display_hour}:{remain:02d}"


def _resolve_kiosk_display_shift_elapsed_label(
    *,
    now_ms: int,
    shift_start_hhmm: str,
    shift_end_hhmm: str,
    planned_break_min: int,
    break_start_hhmm: str = "",
) -> str:
    start_text = _clean_text(shift_start_hhmm)
    end_text = _clean_text(shift_end_hhmm)
    start_min = _parse_hhmm_to_minutes(start_text)
    if start_min is None:
        return "생산시간 미설정"
    start_label = _format_kiosk_hhmm_label_ko(start_text)
    tz = ZoneInfo(KIOSK_PANEL_TIMEZONE)
    now_dt = datetime.fromtimestamp(now_ms / 1000, tz)
    current_min = now_dt.hour * 60 + now_dt.minute
    end_min = _parse_hhmm_to_minutes(end_text)
    if end_min is not None and end_min > start_min:
        elapsed_min = max(0, min(current_min, end_min) - start_min)
    else:
        elapsed_min = max(0, current_min - start_min)
    effective_elapsed_min = _compute_kiosk_effective_elapsed_minutes(
        now_ms=now_ms,
        shift_start_hhmm=shift_start_hhmm,
        shift_end_hhmm=shift_end_hhmm,
        planned_break_min=planned_break_min,
        break_start_hhmm=break_start_hhmm,
    )
    elapsed_label = _format_kiosk_elapsed_minutes_ko(effective_elapsed_min).replace(" 경과", "")
    return f"{start_label} 시작 · {elapsed_label}"


def _resolve_kiosk_recent_count_running(
    *,
    now_ms: int,
    last_count_at_ms: int,
    period_ms: int,
    health_state: str,
    runtime_state: str,
    rate_per_sec: float,
    current_qty_source: str,
    current_qty: int,
) -> bool:
    if str(health_state or "").strip().upper() != "LIVE":
        return False
    source_key = str(current_qty_source or "").strip().upper()
    if source_key == "NONE" or "SENSOR" not in source_key:
        return False
    if int(current_qty or 0) <= 0:
        return False
    if int(last_count_at_ms or 0) <= 0:
        return False
    runtime_key = str(runtime_state or "").strip().upper()
    if float(rate_per_sec or 0.0) <= 0.0 and runtime_key != "RUNNING":
        return False
    age_ms = max(0, int(now_ms) - int(last_count_at_ms))
    running_threshold_ms = max(int(period_ms or 0) * 2, KIOSK_TRANSIENT_STOP_SEC * 1000)
    return age_ms <= running_threshold_ms


def _is_kiosk_break_window_active(
    *,
    now_ms: int,
    shift_start_hhmm: str,
    shift_end_hhmm: str,
    planned_break_min: int,
    break_start_hhmm: str,
) -> bool:
    if int(planned_break_min or 0) <= 0:
        return False
    break_start_min = _parse_hhmm_to_minutes(_clean_text(break_start_hhmm))
    if break_start_min is None:
        return False
    tz = ZoneInfo(KIOSK_PANEL_TIMEZONE)
    now_dt = datetime.fromtimestamp(now_ms / 1000, tz)
    current_min = now_dt.hour * 60 + now_dt.minute
    shift_start_min = _parse_hhmm_to_minutes(_clean_text(shift_start_hhmm))
    shift_end_min = _parse_hhmm_to_minutes(_clean_text(shift_end_hhmm))
    break_end_min = break_start_min + max(0, int(planned_break_min or 0))
    if shift_start_min is not None and current_min < shift_start_min:
        return False
    if shift_end_min is not None and shift_end_min > 0 and current_min >= shift_end_min:
        return False
    return break_start_min <= current_min < break_end_min


def _compute_kiosk_effective_elapsed_minutes(
    *,
    now_ms: int,
    shift_start_hhmm: str,
    shift_end_hhmm: str,
    planned_break_min: int,
    break_start_hhmm: str = "",
) -> int:
    start_min = _parse_hhmm_to_minutes(_clean_text(shift_start_hhmm))
    if start_min is None:
        return 0
    tz = ZoneInfo(KIOSK_PANEL_TIMEZONE)
    now_dt = datetime.fromtimestamp(now_ms / 1000, tz)
    current_min = now_dt.hour * 60 + now_dt.minute
    end_min = _parse_hhmm_to_minutes(_clean_text(shift_end_hhmm))
    if end_min is not None and end_min > start_min:
        elapsed_min = max(0, min(current_min, end_min) - start_min)
    else:
        elapsed_min = max(0, current_min - start_min)
    break_start_min = _parse_hhmm_to_minutes(_clean_text(break_start_hhmm))
    consumed_break_min = 0
    if break_start_min is not None and planned_break_min > 0:
        effective_break_start = max(start_min, break_start_min)
        effective_current_min = min(current_min, end_min) if end_min is not None and end_min > start_min else current_min
        if effective_current_min > effective_break_start:
            consumed_break_min = min(max(0, planned_break_min), max(0, effective_current_min - effective_break_start))
    return max(0, elapsed_min - min(consumed_break_min, elapsed_min))


def _normalize_kiosk_reason_code(value: object) -> str:
    normalized = str(value or "").strip().upper()
    if normalized in ALLOWED_KIOSK_STATUS_REASON_CODES:
        return normalized
    return ""


def _resolve_kiosk_count_reset_hhmm(cfg: Dict[str, Any] | None, viewer_profile_json: Dict[str, Any]) -> str:
    candidate = _clean_text(viewer_profile_json.get("count_reset_hhmm"))
    if candidate:
        return candidate
    candidate = _clean_text((cfg or {}).get("shift_start_hhmm"))
    if candidate:
        return candidate
    return KIOSK_DEFAULT_COUNT_RESET_HHMM


def _resolve_kiosk_shift_anchor_ts_ms(now_ms: int, start_hhmm: str) -> int:
    start_min = _parse_hhmm_to_minutes(start_hhmm)
    if start_min is None:
        return 0
    tz = ZoneInfo(KIOSK_PANEL_TIMEZONE)
    now_dt = datetime.fromtimestamp(now_ms / 1000, tz)
    anchor_dt = now_dt.replace(
        hour=start_min // 60,
        minute=start_min % 60,
        second=0,
        microsecond=0,
    )
    return int(anchor_dt.timestamp() * 1000)


def _resolve_kiosk_shift_counter_bundle(
    registry: RunRegistry,
    *,
    telem: Dict[str, Any] | None,
    cfg: Dict[str, Any] | None,
    viewer_profile_json: Dict[str, Any],
    now_ms: int,
) -> Dict[str, Any]:
    sensor_total_qty = max(0, int((telem or {}).get("current_qty") or 0)) if telem else 0
    count_reset_hhmm = _resolve_kiosk_count_reset_hhmm(cfg, viewer_profile_json)
    anchor_ts_ms = _resolve_kiosk_shift_anchor_ts_ms(now_ms, count_reset_hhmm)
    device_id = _clean_text((telem or {}).get("counter_device_id")) or _clean_text((telem or {}).get("latest_device_id"))
    baseline_total_qty = 0
    baseline_ts_ms = 0
    baseline_strategy = ""
    if device_id and anchor_ts_ms > 0:
        baseline_row = registry.fetch_counter_baseline_total(device_id=device_id, anchor_ts_ms=anchor_ts_ms)
        if baseline_row:
            baseline_total_qty = max(0, int(baseline_row.get("total_count") or 0))
            baseline_ts_ms = max(0, int(baseline_row.get("ts_ms") or 0))
            baseline_strategy = str(baseline_row.get("strategy") or "")
    shift_current_qty = max(0, sensor_total_qty - baseline_total_qty) if sensor_total_qty > 0 else 0
    if sensor_total_qty > 0:
        # If the first observed frame after the shift anchor is also the latest frame,
        # fail-open to the sensor total instead of showing 0 until the next publish arrives.
        if baseline_strategy == "AT_OR_AFTER" and shift_current_qty <= 0:
            shift_current_qty = sensor_total_qty
            baseline_strategy = "AT_OR_AFTER_FIRST_SAMPLE_FALLBACK"
        # If the counter rebooted or reset mid-shift, the raw total becomes smaller than the
        # pre-shift baseline. Showing 0 in that case makes the kiosk look dead, so surface the
        # fresh raw total while preserving the baseline metadata for audit/debug.
        elif baseline_total_qty > sensor_total_qty:
            shift_current_qty = sensor_total_qty
            baseline_strategy = f"{baseline_strategy}|COUNTER_RESET_FALLBACK" if baseline_strategy else "COUNTER_RESET_FALLBACK"
    return {
        "sensor_total_qty": sensor_total_qty,
        "shift_current_qty": shift_current_qty,
        "shift_baseline_qty": baseline_total_qty,
        "shift_baseline_ts_ms": baseline_ts_ms,
        "shift_baseline_strategy": baseline_strategy,
        "count_reset_hhmm": count_reset_hhmm,
        "anchor_ts_ms": anchor_ts_ms,
    }


def _normalize_kiosk_day_plan_segment(segment: Dict[str, Any], *, fallback_index: int) -> Dict[str, Any]:
    status = str(segment.get("status") or "PLANNED").strip().upper() or "PLANNED"
    if status not in {"PLANNED", "RUNNING", "PAUSED", "CHANGEOVER", "COMPLETED", "ENDED"}:
        status = "PLANNED"
    return {
        "segment_id": _clean_text(segment.get("segment_id")) or f"segment_{fallback_index}",
        "order_index": max(1, int(segment.get("order_index") or fallback_index)),
        "display_product_name": _clean_text(segment.get("display_product_name")) or _clean_text(segment.get("product_name")),
        "target_qty": max(0, int(segment.get("target_qty") or 0)),
        "bpm_target": max(0, int(segment.get("bpm_target") or 0)),
        "status": status,
        "reason_code": _normalize_kiosk_reason_code(segment.get("reason_code")),
        "reason_detail": _clean_text(segment.get("reason_detail")) or None,
        "started_at": _coerce_kiosk_datetime(segment.get("started_at")),
        "ended_at": _coerce_kiosk_datetime(segment.get("ended_at")),
        "started_counter_qty": max(0, int(segment.get("started_counter_qty") or 0)),
        "ended_counter_qty": max(0, int(segment.get("ended_counter_qty") or 0)) if segment.get("ended_counter_qty") is not None else None,
    }


def _normalize_kiosk_day_plan(viewer_profile_json: Dict[str, Any], *, shift_current_qty: int) -> KioskLineDayPlanRecord | None:
    day_plan_raw = viewer_profile_json.get("day_plan")
    if not isinstance(day_plan_raw, dict):
        return None
    segments_raw = day_plan_raw.get("segments")
    if not isinstance(segments_raw, list):
        return None
    normalized_segments = [
        _normalize_kiosk_day_plan_segment(segment if isinstance(segment, dict) else {}, fallback_index=index + 1)
        for index, segment in enumerate(segments_raw)
    ]
    normalized_segments.sort(key=lambda row: (int(row.get("order_index") or 0), str(row.get("segment_id") or "")))
    active_segment_id = _clean_text(day_plan_raw.get("active_segment_id"))
    if not active_segment_id:
        for row in normalized_segments:
            if str(row.get("status") or "").upper() in {"RUNNING", "PAUSED", "CHANGEOVER"}:
                active_segment_id = str(row.get("segment_id") or "")
                break
        if not active_segment_id and normalized_segments:
            active_segment_id = str(normalized_segments[0].get("segment_id") or "")
    records: List[KioskLineDaySegmentRecord] = []
    for row in normalized_segments:
        started_counter_qty = max(0, int(row.get("started_counter_qty") or 0))
        ended_counter_qty = row.get("ended_counter_qty")
        actual_qty = 0
        if ended_counter_qty is not None:
            actual_qty = max(0, int(ended_counter_qty) - started_counter_qty)
        elif str(row.get("segment_id") or "") == active_segment_id:
            actual_qty = max(0, int(shift_current_qty) - started_counter_qty)
        records.append(
            KioskLineDaySegmentRecord(
                segment_id=str(row.get("segment_id") or ""),
                order_index=max(1, int(row.get("order_index") or 0)),
                display_product_name=str(row.get("display_product_name") or ""),
                target_qty=max(0, int(row.get("target_qty") or 0)),
                bpm_target=max(0, int(row.get("bpm_target") or 0)),
                status=str(row.get("status") or "PLANNED"),
                reason_code=str(row.get("reason_code") or ""),
                reason_detail=row.get("reason_detail"),
                started_at=row.get("started_at"),
                ended_at=row.get("ended_at"),
                started_counter_qty=started_counter_qty,
                ended_counter_qty=ended_counter_qty,
                actual_qty=actual_qty,
            )
        )
    return KioskLineDayPlanRecord(
        plan_date=_clean_text(day_plan_raw.get("plan_date")),
        count_reset_hhmm=_clean_text(day_plan_raw.get("count_reset_hhmm")) or KIOSK_DEFAULT_COUNT_RESET_HHMM,
        active_segment_id=active_segment_id,
        segments=records,
    )


def _validate_kiosk_device_assignment_or_400(
    registry: RunRegistry,
    *,
    layout_mode: str,
    line_ids: List[str],
) -> Tuple[str, List[str]]:
    normalized_layout_mode = _normalize_kiosk_layout_mode_or_400(layout_mode)
    cleaned_line_ids = _normalize_kiosk_device_line_ids(line_ids)
    raw_line_ids = [str(value or "").strip() for value in (line_ids or []) if str(value or "").strip()]
    if not cleaned_line_ids:
        raise HTTPException(status_code=400, detail="line_ids must contain at least one line")
    if len(cleaned_line_ids) != len(raw_line_ids):
        raise HTTPException(status_code=400, detail="line_ids must not contain duplicates or blanks")
    capacity = _kiosk_layout_capacity(normalized_layout_mode)
    if capacity > 0 and len(cleaned_line_ids) > capacity:
        raise HTTPException(
            status_code=400,
            detail=f"layout_mode={normalized_layout_mode} supports at most {capacity} lines",
        )
    existing_line_ids = set(registry.list_existing_kiosk_line_ids(cleaned_line_ids))
    invalid_line_ids = [line_id for line_id in cleaned_line_ids if line_id not in existing_line_ids]
    if invalid_line_ids:
        raise HTTPException(
            status_code=400,
            detail=f"unknown kiosk line ids: {', '.join(sorted(invalid_line_ids))}",
        )
    return normalized_layout_mode, cleaned_line_ids


def _summarize_kiosk_panel_tiles(
    tiles: List[KioskDeviceTileRecord],
    *,
    now_ms: int,
) -> Dict[str, Any]:
    source_values = [int(getattr(tile, "source_ts_ms", 0) or 0) for tile in tiles if int(getattr(tile, "source_ts_ms", 0) or 0) > 0]
    last_count_values = [
        int(getattr(tile, "last_count_at_ms", 0) or 0)
        for tile in tiles
        if int(getattr(tile, "last_count_at_ms", 0) or 0) > 0
    ]
    current_values = [
        int(getattr(tile, "current_qty", 0) or 0)
        for tile in tiles
        if str(getattr(tile, "current_qty_source", "NONE") or "NONE").upper() != "NONE"
    ]
    target_values = [
        int(getattr(tile, "target_qty", 0) or 0)
        for tile in tiles
        if int(getattr(tile, "target_qty", 0) or 0) > 0
    ]
    source_max_ts_ms = max(source_values) if source_values else 0
    source_min_ts_ms = min(source_values) if source_values else 0
    panel_age_ms = max(0, now_ms - source_max_ts_ms) if source_max_ts_ms > 0 else 0
    last_count_at_ms = max(last_count_values) if last_count_values else 0
    total_current_qty = sum(current_values) if current_values else None
    total_target_qty = sum(target_values) if target_values else None
    overall_progress_pct: int | None = None
    if total_current_qty is not None and total_target_qty and total_target_qty > 0:
        overall_progress_pct = max(0, int(round((total_current_qty / total_target_qty) * 100)))
    health_states = [str(getattr(tile, "health_state", "UNKNOWN") or "UNKNOWN").upper() for tile in tiles]
    production_states = [
        str(getattr(tile, "production_state", "UNKNOWN") or "UNKNOWN").upper()
        for tile in tiles
        if str(getattr(tile, "health_state", "UNKNOWN") or "UNKNOWN").upper() == "LIVE"
    ]
    live_count = sum(1 for state in health_states if state == "LIVE")
    stale_count = sum(1 for state in health_states if state == "STALE")
    no_data_count = sum(1 for state in health_states if state == "NO_DATA")
    if live_count == len(tiles) and tiles:
        health_state = "LIVE"
    elif no_data_count == len(tiles) and tiles:
        health_state = "NO_DATA"
    elif live_count == 0 and stale_count > 0:
        health_state = "STALE"
    else:
        health_state = "PARTIAL"
    production_state = "UNKNOWN"
    if production_states:
        unique_production_states = sorted(set(production_states))
        production_state = unique_production_states[0] if len(unique_production_states) == 1 else "MIXED"
    return {
        "health_state": health_state,
        "production_state": production_state,
        "source_max_ts_ms": source_max_ts_ms,
        "source_min_ts_ms": source_min_ts_ms,
        "panel_age_ms": panel_age_ms,
        "summary": KioskPanelSummaryRecord(
            total_current_qty=total_current_qty,
            total_target_qty=total_target_qty,
            overall_progress_pct=overall_progress_pct,
            last_count_at=_timestamp_ms_to_datetime(last_count_at_ms),
            last_count_at_ms=last_count_at_ms,
        ),
        "live_count": live_count,
        "stale_count": stale_count,
        "no_data_count": no_data_count,
    }


def _build_kiosk_line_product_suggestions_map(
    registry: RunRegistry,
    *,
    line_ids: List[str],
    cfg_by_line: Dict[str, Dict[str, Any]],
    approved_run_plan_by_line: Dict[str, Dict[str, Any]],
) -> Dict[str, List[str]]:
    normalized_line_ids = _normalize_kiosk_device_line_ids(line_ids)
    history_map = registry.list_kiosk_line_product_history(line_ids=normalized_line_ids, limit_per_line=12)
    out: Dict[str, List[str]] = {}
    for line_id in normalized_line_ids:
        values: List[str] = []
        seen: set[str] = set()
        for candidate in (
            _clean_text(cfg_by_line.get(line_id, {}).get("product_name")),
            _clean_text(approved_run_plan_by_line.get(line_id, {}).get("product_name")),
        ):
            if candidate and candidate not in seen:
                values.append(candidate)
                seen.add(candidate)
        for candidate in history_map.get(line_id, []):
            if candidate and candidate not in seen:
                values.append(candidate)
                seen.add(candidate)
        out[line_id] = _filter_kiosk_product_suggestions(
            values,
            seed_candidates=[
                _clean_text(cfg_by_line.get(line_id, {}).get("product_name")),
                _clean_text(approved_run_plan_by_line.get(line_id, {}).get("product_name")),
            ],
        )
    return out


def _tokenize_kiosk_product_suggestion(value: object) -> List[str]:
    text = _clean_text(value)
    if not text:
        return []
    tokens = re.findall(r"[가-힣]+|[A-Za-z]+|\d+", text)
    blocked = {"ML", "L", "%", "병", "본", "개"}
    out: List[str] = []
    for token in tokens:
        normalized = token.strip().upper()
        if not normalized or normalized in blocked:
            continue
        if normalized.isdigit():
            continue
        out.append(normalized)
    return out


def _filter_kiosk_product_suggestions(
    values: List[str],
    *,
    seed_candidates: List[str],
) -> List[str]:
    cleaned_values = [candidate for candidate in values if _is_valid_kiosk_product_suggestion(candidate)]
    if not cleaned_values:
        return []
    cleaned_seeds = [candidate for candidate in seed_candidates if _is_valid_kiosk_product_suggestion(candidate)]
    if not cleaned_seeds:
        return cleaned_values
    seed_token_set = {
        token
        for candidate in cleaned_seeds
        for token in _tokenize_kiosk_product_suggestion(candidate)
    }
    if not seed_token_set:
        return cleaned_values

    filtered: List[str] = []
    seen: set[str] = set()
    for candidate in cleaned_values:
        candidate_tokens = set(_tokenize_kiosk_product_suggestion(candidate))
        keep = candidate in cleaned_seeds or bool(candidate_tokens & seed_token_set)
        if not keep or candidate in seen:
            continue
        filtered.append(candidate)
        seen.add(candidate)
    return filtered or cleaned_seeds or cleaned_values


def _is_valid_kiosk_product_suggestion(candidate: object) -> bool:
    text = _clean_text(candidate)
    if not text:
        return False
    normalized = text.upper()
    if re.fullmatch(r"작업\s*\d+", text) or re.fullmatch(r"STEP\s*\d+", normalized):
        return False
    if normalized in {"품목명 미입력", "미설정", "라인 미설정"}:
        return False
    if normalized.startswith("PRD_") or normalized.startswith("PRD-"):
        return False
    if "다품목" in text and "집계" in text:
        return False
    if "PROOF" in normalized or "TEST" in normalized:
        return False
    if "TMP" in normalized or "SMOKE" in normalized:
        return False
    if "롤백" in text or "스모크" in text or "임시" in text:
        return False
    if normalized.startswith("RUN_"):
        return False
    return True


def _sanitize_kiosk_viewer_product_name(candidate: object) -> str:
    text = _clean_text(candidate)
    return text if _is_valid_kiosk_product_suggestion(text) else ""


def _list_kiosk_line_product_suggestions(
    registry: RunRegistry,
    *,
    line_id: str,
    q: str = "",
) -> List[str]:
    cleaned_line_id = _clean_text(line_id)
    if not cleaned_line_id:
        return []
    cfg_rows = registry.list_kiosk_line_configs_by_line_ids(line_ids=[cleaned_line_id]) if registry.kiosk_line_config_enabled else []
    cfg_by_line = {str(row.get("line_id") or "").strip(): row for row in cfg_rows if str(row.get("line_id") or "").strip()}
    approved_run_plan_by_line = _load_kiosk_run_plan_metrics_by_line(registry, cfg_rows)
    values = _build_kiosk_line_product_suggestions_map(
        registry,
        line_ids=[cleaned_line_id],
        cfg_by_line=cfg_by_line,
        approved_run_plan_by_line=approved_run_plan_by_line,
    ).get(cleaned_line_id, [])
    values = [candidate for candidate in values if _is_valid_kiosk_product_suggestion(candidate)]
    query = _clean_text(q).lower()
    if not query:
        return values
    return [candidate for candidate in values if query in candidate.lower()]


def _compose_kiosk_line_view_from_inputs(
    *,
    registry: RunRegistry,
    line_id: str,
    cfg: Dict[str, Any] | None,
    telem: Dict[str, Any] | None,
    approved_run_plan: Dict[str, Any] | None,
    production: Dict[str, Any] | None,
    open_event: Dict[str, Any] | None,
    announcements: List[KioskAnnouncementRecord],
    product_name_suggestions: List[str] | None = None,
    now_ms: int,
) -> KioskLineViewRecord:
    viewer_profile_json = dict(cfg.get("viewer_profile_json") or {}) if cfg and isinstance(cfg.get("viewer_profile_json"), dict) else {}
    line_label_ko = _clean_text(cfg.get("line_label_ko")) if cfg else ""
    if not line_label_ko:
        line_label_ko = _resolve_kiosk_line_label_ko(line_id)
    display_line_label_ko = (
        _clean_text(line_label_ko)
        if bool(viewer_profile_json.get("manual_line_label_enabled"))
        else _normalize_kiosk_display_label(_resolve_kiosk_line_label_ko(line_id), line_id)
    )
    config_source = _resolve_kiosk_config_source(cfg, telem)
    config_status = _resolve_kiosk_config_status(config_source=config_source)
    config_source_ref = _resolve_kiosk_config_source_ref(
        config_source=config_source,
        cfg=cfg,
        telem=telem,
        line_id=line_id,
    )
    config_lock = bool(cfg.get("config_lock")) if cfg else False
    config_updated_by = str(cfg.get("updated_by") or "") if cfg and config_source in {"MANUAL", "APPROVED_RUN"} else ""
    config_updated_at = _resolve_kiosk_config_updated_at(
        config_source=config_source,
        cfg=cfg,
        telem=telem,
    )
    config_note = str(cfg.get("note")) if cfg and cfg.get("note") is not None else None

    approved_run_plan = dict(approved_run_plan or {})
    production = dict(production or {})
    product_name = (
        _clean_text(approved_run_plan.get("product_name"))
        if config_source == "APPROVED_RUN"
        else ""
    ) or (_clean_text(cfg.get("product_name")) if cfg else "")
    product_name_detail = (
        _clean_text(approved_run_plan.get("product_name_detail"))
        if config_source == "APPROVED_RUN"
        else ""
    ) or (_clean_text(cfg.get("product_name_detail")) if cfg else "")
    product_count = max(
        0,
        int(
            (approved_run_plan.get("product_count") if config_source == "APPROVED_RUN" else None)
            or (cfg.get("product_count") if cfg else 0)
            or 0
        ),
    )
    product_semantics = (
        str(approved_run_plan.get("product_semantics") or "").strip()
        if config_source == "APPROVED_RUN"
        else ""
    ) or (str(cfg.get("product_semantics") or "").strip() if cfg else "")
    if not product_name:
        product_count = 0
        product_semantics = "UNKNOWN"
        product_name_detail = ""
    elif product_count <= 0:
        product_count = 1
    if not product_semantics:
        product_semantics = "MULTI_PRODUCT_AGGREGATED" if product_count > 1 else "SINGLE_PRODUCT"
    display_product_name = _clean_text(cfg.get("product_name")) if cfg else ""
    if not bool(viewer_profile_json.get("manual_product_name_enabled")):
        display_product_name = ""

    production_product_count = int(production.get("product_count") or 0)
    if production_product_count > max(product_count, 1):
        product_count = production_product_count
        product_semantics = "MULTI_PRODUCT_AGGREGATED"
        product_name = f"다품목 {product_count}건 집계"
        if not product_name_detail:
            product_name_detail = _clean_text(production.get("product_name_detail")) or None
    viewer_product_name = _sanitize_kiosk_viewer_product_name(product_name)
    viewer_product_name_detail = product_name_detail if viewer_product_name else ""
    unit_label = _clean_text(cfg.get("unit_label")) if cfg else ""
    if not unit_label:
        unit_label = str(os.getenv("BOHAE_KIOSK_DEFAULT_UNIT_LABEL") or "병").strip() or "병"

    shift_counter_bundle = _resolve_kiosk_shift_counter_bundle(
        registry,
        telem=telem,
        cfg=cfg,
        viewer_profile_json=viewer_profile_json,
        now_ms=now_ms,
    )
    sensor_total_qty = int(shift_counter_bundle["sensor_total_qty"])
    shift_current_qty = int(shift_counter_bundle["shift_current_qty"])
    shift_baseline_qty = int(shift_counter_bundle["shift_baseline_qty"])
    shift_baseline_ts_ms = int(shift_counter_bundle["shift_baseline_ts_ms"])
    shift_baseline_strategy = str(shift_counter_bundle["shift_baseline_strategy"] or "")
    count_reset_hhmm = str(shift_counter_bundle["count_reset_hhmm"] or "")
    shift_start_hhmm = _clean_text(cfg.get("shift_start_hhmm")) if cfg else ""
    shift_end_hhmm = _clean_text(cfg.get("shift_end_hhmm")) if cfg else ""
    planned_break_min = max(0, int(cfg.get("planned_break_min") or 0)) if cfg else 0
    break_start_hhmm = _clean_text(viewer_profile_json.get("break_start_hhmm")) or "13:30"
    reset_min = _parse_hhmm_to_minutes(count_reset_hhmm)
    start_min = _parse_hhmm_to_minutes(shift_start_hhmm)
    if not shift_start_hhmm and count_reset_hhmm:
        shift_start_hhmm = count_reset_hhmm
        start_min = reset_min
    elif not shift_end_hhmm and count_reset_hhmm and start_min is not None and reset_min is not None and reset_min < start_min:
        # Viewer should not show a display shift start later than the counter reset baseline.
        shift_start_hhmm = count_reset_hhmm
        start_min = reset_min
    day_plan = _normalize_kiosk_day_plan(viewer_profile_json, shift_current_qty=shift_current_qty)
    active_segment = None
    if day_plan:
        active_segment = next((segment for segment in day_plan.segments if segment.segment_id == day_plan.active_segment_id), None)
        if active_segment and active_segment.display_product_name:
            display_product_name = active_segment.display_product_name
            viewer_product_name = active_segment.display_product_name
            product_name = active_segment.display_product_name
    display_plan_ready = bool(display_product_name) or active_segment is not None
    target_qty = 0
    target_qty_source = "NONE"
    target_qty_authoritative = False
    if config_source == "APPROVED_RUN" and int(approved_run_plan.get("target_qty") or 0) > 0:
        target_qty = int(approved_run_plan.get("target_qty") or 0)
        target_qty_source = str(approved_run_plan.get("target_qty_source") or approved_run_plan.get("source") or "APPROVED_RUN_PLAN_SNAPSHOT")
        target_qty_authoritative = True
    elif cfg and int(cfg.get("target_qty") or 0) > 0:
        target_qty = int(cfg.get("target_qty") or 0)
        target_qty_source = "MANUAL_CONFIG" if config_source == "MANUAL" else "APPROVED_RUN_CONFIG_FALLBACK"
        target_qty_authoritative = config_source == "MANUAL"
    elif telem:
        target_qty = int(telem.get("target_qty") or 0)
        if target_qty > 0:
            target_qty_source = "SENSOR_FALLBACK"

    bpm_target = 0
    bpm_target_source = "NONE"
    bpm_target_authoritative = False
    if config_source == "APPROVED_RUN" and int(approved_run_plan.get("bpm_target") or 0) > 0:
        bpm_target = int(approved_run_plan.get("bpm_target") or 0)
        bpm_target_source = str(approved_run_plan.get("bpm_target_source") or approved_run_plan.get("source") or "APPROVED_RUN_PLAN_SNAPSHOT")
        bpm_target_authoritative = True
    elif cfg and int(cfg.get("bpm_target") or 0) > 0:
        bpm_target = int(cfg.get("bpm_target") or 0)
        bpm_target_source = "MANUAL_CONFIG" if config_source == "MANUAL" else "APPROVED_RUN_CONFIG_FALLBACK"
        bpm_target_authoritative = config_source == "MANUAL"
    if active_segment and int(active_segment.target_qty or 0) > 0:
        target_qty = int(active_segment.target_qty)
        target_qty_source = "DAY_PLAN_SEGMENT"
        target_qty_authoritative = True
    if active_segment and int(active_segment.bpm_target or 0) > 0:
        bpm_target = int(active_segment.bpm_target)
        bpm_target_source = "DAY_PLAN_SEGMENT"
        bpm_target_authoritative = True

    status = str(telem.get("status") or "NO_DATA") if telem else "NO_DATA"
    ts_ms = int(telem.get("ts_ms") or 0) if telem else 0
    period_ms = int(telem.get("period_ms") or KIOSK_VIEW_PERIOD_FLOOR_MS) if telem else KIOSK_VIEW_PERIOD_FLOOR_MS
    if period_ms <= 0:
        period_ms = KIOSK_VIEW_PERIOD_FLOOR_MS
    period_ms = max(KIOSK_VIEW_PERIOD_FLOOR_MS, period_ms)

    rate_per_sec = 0.0
    if telem is not None:
        try:
            rate_per_sec = float(telem.get("rate_per_sec") or 0.0)
        except Exception:
            rate_per_sec = 0.0

    if bpm_target <= 0 and rate_per_sec > 0.0:
        bpm_target = int(round(rate_per_sec * 60.0))
        if bpm_target > 0:
            bpm_target_source = "SENSOR_RATE_FALLBACK"
    bpm = int(round(rate_per_sec * 60.0)) if rate_per_sec > 0 else 0

    # ts_ms 의미:
    # - source: ontology.state_sensor.ts_ms (DB 수집 타임스탬프, epoch ms)
    # - 0 이하 값은 "유효 소스 타임스탬프 없음"으로 취급한다.
    source_ts_ms = ts_ms if ts_ms > 0 else 0
    counter_ts_ms = int(telem.get("counter_ts_ms") or 0) if telem else 0
    last_count_at_ms = counter_ts_ms if counter_ts_ms > 0 else source_ts_ms
    last_count_at = _timestamp_ms_to_datetime(last_count_at_ms)
    stale_ms = max(0, now_ms - source_ts_ms) if source_ts_ms > 0 else now_ms
    # stale 임계치(ms):
    # - 기본 하한: KIOSK_STALE_MIN_THRESHOLD_MS(1000ms)
    # - 센서 주기 기반: period_ms * KIOSK_STALE_MULTIPLIER(2배)
    # - 최종: max(1000, period_ms*2)
    stale_threshold_ms = max(KIOSK_STALE_MIN_THRESHOLD_MS, period_ms * KIOSK_STALE_MULTIPLIER)
    # stale 판정식:
    # - stale=true  : source_ts_ms <= 0 또는 stale_ms > stale_threshold_ms
    # - stale=false : source_ts_ms > 0 이고 stale_ms <= stale_threshold_ms
    # 근거:
    # - 1초 미만 임계치는 네트워크/스케줄링 지터에 민감하여 오탐이 늘어남.
    # - period의 2배를 허용해 일시적 수집 지연은 흡수하고, 실제 지연만 stale로 본다.
    stale = source_ts_ms <= 0 or stale_ms > stale_threshold_ms
    stale_reason = "NONE"
    if source_ts_ms <= 0:
        stale_reason = "NO_SOURCE_TS"
    elif stale:
        stale_reason = "SOURCE_TS_EXPIRED"

    runtime_state = _normalize_kiosk_runtime_state(telem, status)
    health_state = _resolve_kiosk_health_state(
        status=status,
        runtime_state=runtime_state,
        source_ts_ms=source_ts_ms,
        stale=stale,
    )
    current_qty = 0
    current_qty_source = "NONE"
    current_qty_authoritative = False
    current_qty_semantics = "NONE"
    current_qty_hidden_reason: str | None = None
    current_qty_adjustment_delta = _coerce_kiosk_int(viewer_profile_json.get("current_qty_adjustment_delta"), 0)
    manual_current_qty = max(0, int(cfg.get("manual_current_qty") or 0)) if cfg else 0
    manual_current_qty_enabled = bool(cfg.get("manual_current_qty_enabled")) if cfg else False
    work_order_count = int(production.get("work_order_count") or 0)
    lot_count = int(production.get("lot_count") or 0)
    current_run_label = _clean_text(production.get("current_run_label")) or None
    sensor_current_qty = sensor_total_qty
    active_segment_current_qty = shift_current_qty
    shift_counter_reset_fallback = "COUNTER_RESET_FALLBACK" in shift_baseline_strategy
    shift_counter_first_sample_fallback = shift_baseline_strategy == "AT_OR_AFTER_FIRST_SAMPLE_FALLBACK"
    if active_segment is not None:
        started_counter_qty = max(0, int(active_segment.started_counter_qty or 0))
        active_segment_current_qty = max(0, shift_current_qty - started_counter_qty)
        if (shift_counter_reset_fallback or shift_counter_first_sample_fallback) and started_counter_qty > shift_current_qty:
            active_segment_current_qty = shift_current_qty
    if shift_counter_reset_fallback:
        sensor_shift_semantics = "COUNTER_RESET_FALLBACK_SENSOR_CURRENT_QTY"
    elif shift_counter_first_sample_fallback:
        sensor_shift_semantics = "FIRST_SAMPLE_SENSOR_CURRENT_QTY"
    else:
        sensor_shift_semantics = "SHIFT_BASELINED_SENSOR_CURRENT_QTY"
    if manual_current_qty_enabled:
        current_qty = manual_current_qty
        current_qty_source = "MANUAL_INPUT_CURRENT_QTY"
        current_qty_authoritative = True
        current_qty_semantics = "MANUAL_INPUT_CURRENT_QTY"
    elif work_order_count > 0:
        current_qty = max(0, int(production.get("current_qty") or 0))
        current_qty_source = "WORK_ORDER_ACTUAL" if work_order_count == 1 else "WORK_ORDER_ACTUAL_AGGREGATED"
        current_qty_authoritative = True
        current_qty_semantics = "SINGLE_ACTIVE_WORK_ORDER" if work_order_count == 1 else "MULTI_ACTIVE_WORK_ORDER_AGGREGATED"
        # If ops actual is still zero but the fresh counter has already started moving,
        # surface the sensor count so the kiosk does not look dead during writeback lag.
        if sensor_current_qty > 0 and current_qty <= 0:
            current_qty = active_segment_current_qty if active_segment is not None else shift_current_qty
            current_qty_source = "LIVE_SENSOR_SHIFT_CURRENT_QTY" if health_state == "LIVE" else "LAST_SENSOR_SHIFT_CURRENT_QTY"
            current_qty_authoritative = False
            current_qty_semantics = f"{sensor_shift_semantics}_WORK_ORDER_ZERO_FALLBACK"
    elif telem is not None and sensor_current_qty > 0:
        current_qty = active_segment_current_qty if active_segment is not None else shift_current_qty
        current_qty_source = "LIVE_SENSOR_SHIFT_CURRENT_QTY" if health_state == "LIVE" else "LAST_SENSOR_SHIFT_CURRENT_QTY"
        current_qty_authoritative = False
        current_qty_semantics = "SEGMENT_BASELINED_SENSOR_CURRENT_QTY" if active_segment is not None else sensor_shift_semantics
    elif health_state == "NO_DATA":
        current_qty_hidden_reason = "STALE_OR_NO_DATA"
        current_qty_semantics = "HIDDEN_STALE_OR_NO_DATA"
    else:
        current_qty_hidden_reason = "NO_CURRENT_COUNT_SOURCE"
        current_qty_semantics = "NO_CURRENT_COUNT_SOURCE"

    if not display_plan_ready and not manual_current_qty_enabled:
        current_qty = 0
        current_qty_source = "NONE"
        current_qty_authoritative = False
        current_qty_semantics = "DISPLAY_PLAN_MISSING_HIDDEN"
        current_qty_hidden_reason = "DISPLAY_PLAN_MISSING"
        target_qty = 0
        target_qty_source = "NONE"
        target_qty_authoritative = False
        bpm_target = 0
        bpm_target_source = "NONE"
        bpm_target_authoritative = False
        display_product_name = ""
        viewer_product_name = ""
        product_name = ""
        product_name_detail = ""
        viewer_product_name_detail = ""

    if current_qty_source != "NONE" and not manual_current_qty_enabled and current_qty_adjustment_delta != 0:
        current_qty = max(0, int(current_qty) + int(current_qty_adjustment_delta))
        active_segment_current_qty = max(0, int(active_segment_current_qty) + int(current_qty_adjustment_delta))
        if current_qty_semantics and current_qty_semantics != "NONE":
            current_qty_semantics = f"{current_qty_semantics}|OPS_DELTA_ADJUSTED"
        else:
            current_qty_semantics = "OPS_DELTA_ADJUSTED"

    if current_qty_source == "NONE":
        progress_pct = 0
        progress_label = "집계 대기" if target_qty > 0 else "0%"
    else:
        progress_pct = int(round((current_qty / target_qty) * 100)) if target_qty > 0 else 0
        progress_label = f"목표 달성 ({progress_pct}%)" if target_qty > 0 and progress_pct >= 100 else f"{progress_pct}%"
    runtime_state_since_ts_ms, stop_started_at, stop_duration_sec, stop_timer_visible, stop_hidden_reason = _resolve_stop_window(
        telem=telem,
        runtime_state=runtime_state,
        stale=stale,
        now_ms=now_ms,
        last_count_at_ms=last_count_at_ms,
        open_event=open_event,
    )
    production_state = _resolve_kiosk_production_state(
        health_state=health_state,
        status=status,
        runtime_state=runtime_state,
        stop_duration_sec=stop_duration_sec,
    )
    count_running_recent = _resolve_kiosk_recent_count_running(
        now_ms=now_ms,
        last_count_at_ms=last_count_at_ms,
        period_ms=period_ms,
        health_state=health_state,
        runtime_state=runtime_state,
        rate_per_sec=rate_per_sec,
        current_qty_source=current_qty_source,
        current_qty=current_qty,
    )
    if count_running_recent and production_state in {"STOPPED", "TRANSIENT_STOP", "UNKNOWN"}:
        production_state = "RUNNING"
    status_override = _normalize_kiosk_status_override(viewer_profile_json.get("status_override"), default="AUTO")
    status_reason_code = _normalize_kiosk_reason_code(viewer_profile_json.get("status_reason_code"))
    status_reason_detail = _clean_text(viewer_profile_json.get("status_reason_detail")) or None
    if status_override == "CHANGEOVER" or status_reason_code == "CHANGEOVER":
        production_state = "CHANGEOVER"
    elif status_override == "BREAK":
        production_state = "BREAK"
    elif status_override == "ENDED":
        production_state = "ENDED"
    elif status_override == "RUNNING" and health_state not in {"STALE", "NO_DATA"} and production_state in {"RUNNING", "TRANSIENT_STOP"}:
        production_state = "RUNNING"
    elif status_override == "STOPPED":
        production_state = "STOPPED"
    auto_break_active = (
        status_override == "AUTO"
        and display_plan_ready
        and _is_kiosk_break_window_active(
            now_ms=now_ms,
            shift_start_hhmm=shift_start_hhmm,
            shift_end_hhmm=shift_end_hhmm,
            planned_break_min=planned_break_min,
            break_start_hhmm=break_start_hhmm,
        )
    )
    if auto_break_active and production_state in {"RUNNING", "TRANSIENT_STOP", "STOPPED", "UNKNOWN"}:
        production_state = "BREAK"
        if not status_reason_code:
            status_reason_code = "BREAK"
    if not display_plan_ready:
        production_state = "ENDED"
    display_status_code, display_status_label_ko, display_status_tone = _resolve_kiosk_display_status(
        production_state=production_state,
        health_state=health_state,
        status_override=status_override,
        status_reason_code=status_reason_code,
    )
    display_state = _resolve_kiosk_display_state(
        health_state=health_state,
        production_state=production_state,
    )
    display_state_reason = _resolve_kiosk_display_state_reason(
        health_state=health_state,
        production_state=production_state,
        stop_duration_sec=stop_duration_sec,
    )
    stop_label_ko = _resolve_kiosk_stop_label_ko(display_state) if stop_timer_visible else None
    operator_message_ko, action_hint_ko = _resolve_kiosk_operator_message_and_hint(
        config_status=config_status,
        health_state=health_state,
        production_state=production_state,
        status_override=status_override,
        status_reason_code=status_reason_code,
    )
    shift_duration_min = 0
    expected_qty_by_now = 0
    achievement_rate_pct = 0
    progress_rate_pct = progress_pct
    end_min = _parse_hhmm_to_minutes(shift_end_hhmm)
    effective_elapsed_min = _compute_kiosk_effective_elapsed_minutes(
        now_ms=now_ms,
        shift_start_hhmm=shift_start_hhmm,
        shift_end_hhmm=shift_end_hhmm,
        planned_break_min=planned_break_min,
        break_start_hhmm=break_start_hhmm,
    )
    if start_min is not None and end_min is not None and end_min > start_min:
        shift_duration_min = max(0, end_min - start_min - planned_break_min)
        if target_qty > 0 and shift_duration_min > 0:
            expected_qty_by_now = max(0, int(round(target_qty * (effective_elapsed_min / shift_duration_min))))
    elif start_min is not None and bpm_target > 0:
        expected_qty_by_now = max(0, int(bpm_target) * effective_elapsed_min)
        if target_qty > 0:
            expected_qty_by_now = min(expected_qty_by_now, int(target_qty))
    if (
        expected_qty_by_now <= 0
        and active_segment is not None
        and active_segment.started_at is not None
        and int(active_segment.bpm_target or 0) > 0
    ):
        segment_elapsed_min = max(0, int((now_ms - int(active_segment.started_at.timestamp() * 1000)) // 60000))
        expected_qty_by_now = max(0, int(active_segment.bpm_target) * segment_elapsed_min)
    if expected_qty_by_now > 0 and current_qty > 0:
        achievement_rate_pct = max(0, int(round((current_qty / expected_qty_by_now) * 100)))
    if active_segment is not None and int(active_segment.target_qty or 0) > 0 and current_qty >= int(active_segment.target_qty or 0):
        action_hint_ko = "현재 품목 목표에 도달했습니다. 종료 후 다음 품목을 시작하세요."
    display_shift_elapsed_label = _resolve_kiosk_display_shift_elapsed_label(
        now_ms=now_ms,
        shift_start_hhmm=shift_start_hhmm,
        shift_end_hhmm=shift_end_hhmm,
        planned_break_min=planned_break_min,
        break_start_hhmm=break_start_hhmm,
    )
    reset_required, reset_reason, reset_rule = _evaluate_kiosk_reset_required(
        current_qty=int(current_qty or 0),
        active_segment_label=_clean_text(active_segment.display_product_name if active_segment is not None else ""),
        viewer_profile_json=viewer_profile_json,
        now_ms=now_ms,
    )

    return KioskLineViewRecord(
        line_id=line_id,
        line_label_ko=line_label_ko,
        display_line_label_ko=display_line_label_ko or _normalize_kiosk_display_label(line_label_ko, line_id),
        product_name=viewer_product_name,
        product_name_ko=viewer_product_name,
        display_product_name=display_product_name,
        product_name_suggestions=[
            candidate
            for candidate in (product_name_suggestions or [])
            if _is_valid_kiosk_product_suggestion(candidate)
        ],
        product_name_detail=viewer_product_name_detail or None,
        product_count=product_count,
        product_semantics=product_semantics,
        target_qty=target_qty,
        target_qty_total=target_qty,
        target_qty_source=target_qty_source,
        target_qty_authoritative=target_qty_authoritative,
        manual_current_qty=manual_current_qty,
        manual_current_qty_enabled=manual_current_qty_enabled,
        unit_label=unit_label,
        bpm_target=bpm_target,
        bpm_target_source=bpm_target_source,
        bpm_target_authoritative=bpm_target_authoritative,
        config_source=config_source,
        config_source_ref=config_source_ref,
        config_lock=config_lock,
        config_status=config_status,
        config_updated_by=config_updated_by,
        config_updated_at=config_updated_at,
        config_note=config_note,
        current_qty=current_qty,
        sensor_total_qty=sensor_total_qty,
        shift_current_qty=shift_current_qty,
        shift_baseline_qty=shift_baseline_qty,
        shift_baseline_ts_ms=shift_baseline_ts_ms,
        shift_baseline_strategy=shift_baseline_strategy,
        count_reset_hhmm=count_reset_hhmm,
        current_qty_source=current_qty_source,
        current_qty_authoritative=current_qty_authoritative,
        current_qty_semantics=current_qty_semantics,
        current_qty_hidden_reason=current_qty_hidden_reason,
        work_order_count=work_order_count,
        lot_count=lot_count,
        current_run_label=current_run_label,
        bpm=bpm,
        progress_pct=progress_pct,
        progress_label=progress_label,
        expected_qty_by_now=expected_qty_by_now,
        achievement_rate_pct=achievement_rate_pct,
        progress_rate_pct=progress_rate_pct,
        active_segment_id=active_segment.segment_id if active_segment is not None else "",
        active_segment_label=active_segment.display_product_name if active_segment is not None else "",
        active_segment_status=active_segment.status if active_segment is not None else "",
        active_segment_target_qty=int(active_segment.target_qty or 0) if active_segment is not None else 0,
        active_segment_current_qty=active_segment_current_qty if active_segment is not None else 0,
        day_plan=day_plan,
        status=status,
        health_state=health_state,
        production_state=production_state,
        runtime_state=runtime_state,
        display_state=display_state,
        display_status_code=display_status_code,
        display_status_label_ko=display_status_label_ko,
        display_status_tone=display_status_tone,
        status_reason_code=status_reason_code,
        status_reason_detail=status_reason_detail,
        theme=_normalize_kiosk_theme(_clean_text(viewer_profile_json.get("theme")) or "", default="light"),
        display_state_reason=display_state_reason,
        runtime_state_since_ts_ms=runtime_state_since_ts_ms,
        stop_started_at=stop_started_at,
        stop_duration_sec=stop_duration_sec,
        stop_timer_visible=stop_timer_visible,
        stop_hidden_reason=stop_hidden_reason,
        stop_label_ko=stop_label_ko,
        temp_c=float(telem["temp_c"]) if telem and telem.get("temp_c") is not None else None,
        vibration_mm_s=float(telem["vibration_mm_s"]) if telem and telem.get("vibration_mm_s") is not None else None,
        power_kw=float(telem["power_kw"]) if telem and telem.get("power_kw") is not None else None,
        latest_device_id=str(telem.get("latest_device_id") or "") if telem else None,
        counter_device_id=str(telem.get("counter_device_id") or "") if telem else None,
        temp_device_id=str(telem.get("temp_device_id") or "") if telem else None,
        vibration_device_id=str(telem.get("vibration_device_id") or "") if telem else None,
        power_device_id=str(telem.get("power_device_id") or "") if telem else None,
        last_count_at=last_count_at,
        last_count_at_ms=last_count_at_ms,
        source_ts_ms=source_ts_ms,
        server_now_ms=now_ms,
        age_ms=int(stale_ms),
        ts_ms=ts_ms,
        period_ms=period_ms,
        stale_threshold_ms=int(stale_threshold_ms),
        stale_reason=stale_reason,
        operator_message_ko=operator_message_ko,
        action_hint_ko=action_hint_ko,
        message_ko=operator_message_ko,
        stale_ms=int(stale_ms),
        stale=bool(stale),
        reset_required=reset_required,
        reset_reason=reset_reason,
        reset_rule=reset_rule,
        shift_start_hhmm=shift_start_hhmm,
        shift_end_hhmm=shift_end_hhmm,
        planned_break_min=planned_break_min,
        display_shift_elapsed_label=display_shift_elapsed_label,
        viewer_profile_json=viewer_profile_json,
        announcements=announcements,
    )


def _build_kiosk_line_view_bundle(
    registry: RunRegistry,
    *,
    line_ids: List[str],
    now_ms: int,
) -> Tuple[Dict[str, KioskLineViewRecord], List[KioskAnnouncementRecord]]:
    normalized_line_ids = _normalize_kiosk_device_line_ids(line_ids)
    cfg_rows = registry.list_kiosk_line_configs_by_line_ids(line_ids=normalized_line_ids) if registry.kiosk_line_config_enabled else []
    telem_rows = registry.list_state_sensor_rows(line_ids=normalized_line_ids) if registry.state_sensor_enabled else []
    open_event_rows = registry.list_open_downtime_events(line_ids=normalized_line_ids) if registry.conn else []
    production_rows = registry.list_active_work_order_rows(
        line_ids=normalized_line_ids,
        as_of=datetime.fromtimestamp(now_ms / 1000, timezone.utc),
    ) if registry.work_order_enabled else []
    panel_announcements, line_announcement_map = _load_kiosk_announcement_bundle(registry, normalized_line_ids)

    cfg_by_line = {str(row.get("line_id") or "").strip(): row for row in cfg_rows if str(row.get("line_id") or "").strip()}
    telem_by_line = {str(row.get("line_id") or "").strip(): row for row in telem_rows if str(row.get("line_id") or "").strip()}
    open_event_by_line = {
        str(row.get("line_id") or "").strip(): row for row in open_event_rows if str(row.get("line_id") or "").strip()
    }
    approved_run_plan_by_line = _load_kiosk_run_plan_metrics_by_line(registry, cfg_rows)
    production_by_line = _aggregate_kiosk_live_production_by_line(production_rows)
    product_suggestion_by_line = _build_kiosk_line_product_suggestions_map(
        registry,
        line_ids=normalized_line_ids,
        cfg_by_line=cfg_by_line,
        approved_run_plan_by_line=approved_run_plan_by_line,
    )

    out: Dict[str, KioskLineViewRecord] = {}
    for line_id in normalized_line_ids:
        out[line_id] = _compose_kiosk_line_view_from_inputs(
            registry=registry,
            line_id=line_id,
            cfg=cfg_by_line.get(line_id),
            telem=telem_by_line.get(line_id),
            approved_run_plan=approved_run_plan_by_line.get(line_id),
            production=production_by_line.get(line_id),
            open_event=open_event_by_line.get(line_id),
            announcements=line_announcement_map.get(line_id, []),
            product_name_suggestions=product_suggestion_by_line.get(line_id, []),
            now_ms=now_ms,
        )
    return out, panel_announcements


def _compose_kiosk_line_view(registry: RunRegistry, line_id: str) -> KioskLineViewRecord:
    views_by_line, _ = _build_kiosk_line_view_bundle(registry, line_ids=[line_id], now_ms=_now_ms())
    return views_by_line.get(line_id) or KioskLineViewRecord(line_id=line_id, line_label_ko=_resolve_kiosk_line_label_ko(line_id))


def _compose_kiosk_panel_bundle(
    registry: RunRegistry,
    device_id: str,
    *,
    assignment_override: Dict[str, Any] | None = None,
) -> Dict[str, Any]:
    assignment = dict(assignment_override) if assignment_override is not None else registry.fetch_kiosk_device_assignment(device_id.strip())
    if assignment is None:
        raise HTTPException(status_code=404, detail="device_id not found")
    theme = _normalize_kiosk_theme(assignment.get("theme") or "", default="")
    try:
        layout_mode, line_ids = _validate_kiosk_device_assignment_or_400(
            registry,
            layout_mode=str(assignment.get("layout_mode") or "grid_2x2"),
            line_ids=list(assignment.get("line_ids") or []),
        )
    except HTTPException as exc:
        raise HTTPException(
            status_code=503,
            detail=f"kiosk_device_assignment misconfigured: {exc.detail}",
        ) from exc

    now_ms = _now_ms()
    views_by_line, panel_announcements = _build_kiosk_line_view_bundle(registry, line_ids=line_ids, now_ms=now_ms)
    tiles: List[KioskDeviceTileRecord] = []
    ordered_groups: List[str] = []
    selected_by_group: Dict[str, Tuple[int, KioskLineViewRecord]] = {}
    for idx, line_id in enumerate(line_ids):
        base = views_by_line[line_id]
        display_group_id = _resolve_kiosk_display_group_id(line_id)
        current = selected_by_group.get(display_group_id)
        candidate_rank = (
            1 if str(base.config_status or "").upper() == "CONFIGURED" else 0,
            1 if str(base.display_status_code or "").upper() != "ENDED" else 0,
            int(base.last_count_at_ms or 0),
        )
        current_rank = (
            1 if str(current[1].config_status or "").upper() == "CONFIGURED" else 0,
            1 if str(current[1].display_status_code or "").upper() != "ENDED" else 0,
            int(current[1].last_count_at_ms or 0),
        ) if current else (-1, -1, -1)
        candidate_last_count = int(base.last_count_at_ms or 0)
        current_last_count = int(current[1].last_count_at_ms or 0) if current else -1
        if display_group_id not in ordered_groups:
            ordered_groups.append(display_group_id)
        if current is None or candidate_rank > current_rank or (candidate_rank == current_rank and candidate_last_count >= current_last_count):
            selected_by_group[display_group_id] = (idx, base)

    for slot, display_group_id in enumerate(ordered_groups, start=1):
        _, base = selected_by_group[display_group_id]
        base_dict = base.model_dump() if hasattr(base, "model_dump") else base.dict()
        group_label = _resolve_kiosk_display_group_label(display_group_id, base)
        if group_label:
            base_dict["display_line_label_ko"] = group_label
        tiles.append(KioskDeviceTileRecord(slot=slot, **base_dict))

    return {
        "assignment": assignment,
        "layout_mode": layout_mode,
        "line_ids": line_ids,
        "theme": theme,
        "tiles": tiles,
        "announcements": panel_announcements,
        "generated_ts_ms": now_ms,
    }


def _build_public_kiosk_index(registry: RunRegistry) -> PublicKioskIndexResponse:
    now_ms = _now_ms()
    assignments: List[Dict[str, Any]] = []
    for row in registry.list_kiosk_device_assignments(limit=1000):
        resolved = _resolve_published_kiosk_device_assignment(registry, row)
        if resolved is None:
            continue
        device_id = _clean_text(resolved.get("device_id"))
        if not device_id:
            continue
        resolved["device_id"] = device_id
        resolved["line_ids"] = _normalize_kiosk_device_line_ids(list(resolved.get("line_ids") or []))
        assignments.append(resolved)

    all_line_ids = _normalize_kiosk_device_line_ids(
        [line_id for assignment in assignments for line_id in list(assignment.get("line_ids") or [])]
    )
    views_by_line, _ = _build_kiosk_line_view_bundle(registry, line_ids=all_line_ids, now_ms=now_ms)

    devices_out: List[PublicKioskIndexDeviceRecord] = []
    for assignment in assignments:
        device_id = _clean_text(assignment.get("device_id"))
        line_ids = _normalize_kiosk_device_line_ids(list(assignment.get("line_ids") or []))
        line_labels = [
            _clean_text(getattr(views_by_line.get(line_id), "display_line_label_ko", ""))
            or _clean_text(getattr(views_by_line.get(line_id), "line_label_ko", ""))
            or _resolve_kiosk_line_label_ko(line_id)
            for line_id in line_ids
        ]
        public_meta = _normalize_kiosk_public_surface_meta(
            assignment=assignment,
            line_labels=line_labels,
        )

        lines: List[PublicKioskIndexLineRecord] = []
        for line_id in line_ids:
            base_view = views_by_line.get(line_id) or _compose_kiosk_line_view(registry, line_id)
            reset_required, reset_reason, reset_rule = _evaluate_kiosk_reset_required(
                current_qty=int(base_view.current_qty or 0),
                active_segment_label=_clean_text(base_view.active_segment_label),
                viewer_profile_json=base_view.viewer_profile_json,
                now_ms=now_ms,
            )
            lines.append(
                PublicKioskIndexLineRecord(
                    line_id=line_id,
                    line_label_ko=_clean_text(base_view.display_line_label_ko) or base_view.line_label_ko or line_id,
                    product_name=_clean_text(base_view.product_name),
                    current_qty=int(base_view.current_qty) if base_view.current_qty is not None else None,
                    target_qty=int(base_view.target_qty) if base_view.target_qty is not None else None,
                    bpm=int(base_view.bpm) if base_view.bpm is not None else None,
                    status=_clean_text(base_view.runtime_state) or _clean_text(base_view.display_state) or _clean_text(base_view.status) or "NO_DATA",
                    stale=bool(base_view.stale),
                    reset_required=reset_required,
                    reset_reason=reset_reason,
                    reset_rule=reset_rule,
                    public_path=f"/line/{urlparse.quote(line_id)}",
                )
            )

        lines.sort(
            key=lambda item: (
                -(3 if item.reset_required else 2 if item.stale else 1 if item.status == "NO_DATA" else 0),
                -(int(item.current_qty or 0)),
                item.line_label_ko,
            )
        )

        latest_heartbeat_at = max(
            [
                int(getattr(views_by_line.get(line.line_id), "ts_ms", 0) or 0)
                or int(getattr(views_by_line.get(line.line_id), "source_ts_ms", 0) or 0)
                for line in lines
            ]
            or [0]
        )
        has_fresh_line = any(not line.stale for line in lines)
        reset_required = any(line.reset_required for line in lines)
        stale = any(line.stale for line in lines)
        issue_count = sum(1 for line in lines if line.reset_required or line.stale)
        device_status = "ONLINE" if has_fresh_line else "OFFLINE"

        devices_out.append(
            PublicKioskIndexDeviceRecord(
                device_id=device_id,
                public_label=str(public_meta["public_label"]),
                zone_label=str(public_meta["zone_label"]),
                sort_order=int(public_meta["sort_order"]),
                is_public_visible=bool(public_meta["is_public_visible"]),
                default_target_type=str(public_meta["default_target_type"]),
                default_target_id=str(public_meta["default_target_id"]),
                public_path=_build_kiosk_public_target_path(
                    device_id=device_id,
                    target_type=str(public_meta["default_target_type"]),
                    target_id=str(public_meta["default_target_id"]),
                ),
                layout_mode=_normalize_kiosk_layout_mode(_clean_text(assignment.get("layout_mode")) or "grid_2x2"),
                theme=_normalize_kiosk_theme(assignment.get("theme") or "light", default="light"),
                viewer_mode=_clean_text(assignment.get("viewer_mode")) or "ACTIVE_LINES_BOARD",
                active_lines_only=bool(assignment.get("active_lines_only")),
                line_ids=line_ids,
                lines=lines,
                status=device_status,
                reset_required=reset_required,
                stale=stale,
                issue_count=issue_count,
                last_heartbeat_at=_timestamp_ms_to_datetime(latest_heartbeat_at) if latest_heartbeat_at > 0 else None,
            )
        )

    visible_devices = [device for device in devices_out if device.is_public_visible]
    visible_devices.sort(
        key=lambda item: (
            -(4 if item.reset_required else 3 if item.status == "OFFLINE" else 2 if item.stale else 1 if item.issue_count > 0 else 0),
            -item.issue_count,
            item.sort_order,
            item.public_label,
        )
    )

    return PublicKioskIndexResponse(
        devices=visible_devices,
        generated_ts_ms=now_ms,
        source="public-kiosk-index-v1",
        meta={"ok": True},
    )


@app.get("/v1/kiosk/index", response_model=PublicKioskIndexResponse)
def get_public_kiosk_index(
    x_kiosk_token: str | None = Header(default=None, alias=KIOSK_READ_TOKEN_HEADER),
) -> PublicKioskIndexResponse:
    try:
        registry = RunRegistry(Config())
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc
    try:
        _ensure_kiosk_panel_backend_ready(registry)
        _require_kiosk_read_access(x_kiosk_token)
        return _build_public_kiosk_index(registry)
    finally:
        registry.close()


def _encode_sse_event(event: str, payload: Any) -> str:
    return f"event: {event}\ndata: {json.dumps(payload, ensure_ascii=False)}\n\n"


_KIOSK_STREAM_HUB = SharedPollingStreamHub()
_KIOSK_SSE_RETRY_MS = 1_000
_KIOSK_SSE_MAX_LIFETIME_SEC = 30


def _build_shared_sse_response(
    *,
    topic_key: str,
    connected_payload: Dict[str, Any],
    build_snapshot: Any,
    interval_sec: int,
    heartbeat_sec: int = 15,
    max_lifetime_sec: int = _KIOSK_SSE_MAX_LIFETIME_SEC,
) -> StreamingResponse:
    subscription = _KIOSK_STREAM_HUB.subscribe(
        topic_key=topic_key,
        build_snapshot=build_snapshot,
        interval_sec=interval_sec,
        heartbeat_sec=heartbeat_sec,
    )

    def event_stream() -> Any:
        try:
            yield f"retry: {int(_KIOSK_SSE_RETRY_MS)}\n\n"
            yield _encode_sse_event("connected", connected_payload)
            for event_name, payload in subscription.iter_events(max_lifetime_sec=float(max_lifetime_sec)):
                yield _encode_sse_event(event_name, payload)
        finally:
            subscription.close()

    return StreamingResponse(
        event_stream(),
        media_type="text/event-stream",
        headers={
            "Cache-Control": "no-cache, no-transform",
            "Connection": "keep-alive",
            "X-Accel-Buffering": "no",
        },
    )


@app.get("/v1/kiosk/index/stream")
def stream_public_kiosk_index(
    x_kiosk_token: str | None = Header(default=None, alias=KIOSK_READ_TOKEN_HEADER),
) -> StreamingResponse:
    _require_kiosk_read_access(x_kiosk_token)
    return _build_shared_sse_response(
        topic_key="public-kiosk-index",
        connected_payload={
            "ts": _now_ms(),
            "message": "kiosk-public-stream-connected",
        },
        build_snapshot=lambda: get_public_kiosk_index(x_kiosk_token=x_kiosk_token),
        interval_sec=5,
        heartbeat_sec=15,
    )


@app.get("/v1/kiosk/line/{line_id}/view", response_model=KioskLineViewRecord)
def get_kiosk_line_view(
    line_id: str,
    response: Response,
    x_kiosk_token: str | None = Header(default=None, alias=KIOSK_READ_TOKEN_HEADER),
) -> KioskLineViewRecord:
    if not line_id.strip():
        raise HTTPException(status_code=400, detail="line_id is required")
    try:
        registry = RunRegistry(Config())
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc
    try:
        _ensure_kiosk_panel_backend_ready(registry)
        _require_kiosk_read_access(x_kiosk_token)
        normalized_line_id = line_id.strip()
        view = _compose_kiosk_line_view(registry, normalized_line_id)
        if (
            not registry.kiosk_line_exists(normalized_line_id)
            and view.status == "NO_DATA"
            and not view.product_name
            and view.target_qty == 0
        ):
            raise HTTPException(status_code=404, detail="line_id not found")
        _apply_source_headers(response, int(view.source_ts_ms))
        return view
    finally:
        registry.close()


