@app.get("/v1/kiosk/device/{device_id}/view", response_model=KioskDeviceViewRecord)
def get_kiosk_device_view(
    device_id: str,
    response: Response,
    x_kiosk_token: str | None = Header(default=None, alias=KIOSK_READ_TOKEN_HEADER),
) -> KioskDeviceViewRecord:
    if not device_id.strip():
        raise HTTPException(status_code=400, detail="device_id is required")
    try:
        registry = RunRegistry(Config())
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc
    try:
        _ensure_kiosk_panel_backend_ready(registry)
        _require_kiosk_read_access(x_kiosk_token)
        assignment_row = registry.fetch_kiosk_device_assignment(device_id.strip())
        assignment_override = _resolve_published_kiosk_device_assignment(registry, assignment_row)
        bundle = _compose_kiosk_panel_bundle(
            registry,
            device_id.strip(),
            assignment_override=assignment_override,
        )
        assignment = dict(bundle["assignment"])
        layout_mode = str(bundle["layout_mode"])
        line_ids = [str(x) for x in bundle["line_ids"]]
        theme = _normalize_kiosk_theme(bundle.get("theme") or assignment.get("theme") or "", default="")
        viewer_mode = str(assignment.get("viewer_mode") or "ACTIVE_LINES_BOARD").strip().upper() or "ACTIVE_LINES_BOARD"
        active_lines_only = bool(assignment.get("active_lines_only"))
        viewer_profile_json = dict(assignment.get("viewer_profile_json") or {}) if isinstance(assignment.get("viewer_profile_json"), dict) else {}
        tiles = list(bundle["tiles"])
        now_ms = int(bundle["generated_ts_ms"])
        tile_summary = _summarize_kiosk_panel_tiles(tiles, now_ms=now_ms)
        payload = KioskDeviceViewRecord(
            device_id=device_id.strip(),
            layout_mode=layout_mode,
            line_ids=line_ids,
            tiles=tiles,
            summary=tile_summary["summary"],
            announcements=list(bundle["announcements"]),
            health_state=str(tile_summary["health_state"]),
            production_state=str(tile_summary["production_state"]),
            server_now_ms=now_ms,
            source_max_ts_ms=int(tile_summary["source_max_ts_ms"]),
            source_min_ts_ms=int(tile_summary["source_min_ts_ms"]),
            generated_ts_ms=now_ms,
            panel_age_ms=int(tile_summary["panel_age_ms"]),
            timezone=KIOSK_PANEL_TIMEZONE,
            meta=KioskPanelMetaRecord(
                access_policy=_resolve_kiosk_read_access_policy(),
                server_now_ms=now_ms,
                generated_ts_ms=now_ms,
                source_max_ts_ms=int(tile_summary["source_max_ts_ms"]),
                source_min_ts_ms=int(tile_summary["source_min_ts_ms"]),
                panel_age_ms=int(tile_summary["panel_age_ms"]),
                timezone=KIOSK_PANEL_TIMEZONE,
                device_assignment_updated_at=_coerce_kiosk_datetime(assignment.get("updated_at")),
                theme=theme,
                viewer_mode=viewer_mode,
                active_lines_only=active_lines_only,
                viewer_profile_json=viewer_profile_json,
                panel_version=KIOSK_PANEL_VERSION,
                line_count=len(tiles),
                live_line_count=int(tile_summary["live_count"]),
                stale_line_count=int(tile_summary["stale_count"]),
                no_data_line_count=int(tile_summary["no_data_count"]),
                layout_capacity=_kiosk_layout_capacity(layout_mode),
            ),
        )
        source_ts_ms = 0
        if payload.tiles:
            source_ts_ms = max(int(getattr(tile, "source_ts_ms", 0) or 0) for tile in payload.tiles)
        _apply_source_headers(response, int(source_ts_ms))
        return payload
    finally:
        registry.close()


