@app.post("/v1/kiosk/line/{line_id}/ack")
def post_kiosk_line_ack(
    line_id: str,
    x_kiosk_action_token: str | None = Header(default=None, alias=KIOSK_ACTION_TOKEN_HEADER),
    actor_claims: Dict[str, Any] = Depends(get_optional_current_actor),
) -> Dict[str, Any]:
    if not line_id.strip():
        raise HTTPException(status_code=400, detail="line_id is required")
    try:
        registry = RunRegistry(Config())
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc
    try:
        if not registry.decision_log_enabled:
            raise HTTPException(
                status_code=503,
                detail="decision_log 테이블이 없습니다. bohae_aps_v20/sql/20_app_ops_foundation_v1.sql을 먼저 적용하세요.",
            )
        actor = _require_kiosk_action_actor(
            registry,
            actor_claims,
            x_kiosk_action_token=x_kiosk_action_token,
            line_id=line_id,
        )
        registry.insert_decision_log(
            scenario_id="OPS_KIOSK",
            event_type="KIOSK_ACK",
            payload_json={
                "ENTITY_TYPE": "KIOSK_ACK",
                "ENTITY_ID": line_id.strip(),
                "ACTOR_ID": actor.get("actor_id"),
                "ACTOR_EMAIL": actor.get("actor_email"),
                "ACTOR_ROLE": actor.get("actor_role"),
                "AUTH_SOURCE": actor.get("auth_source"),
                "SOURCE": "kiosk_hmi",
            },
        )
        return {"status": "ok", "ack": True}
    finally:
        registry.close()


