@app.get("/v1/kiosk/notices", response_model=List[KioskAnnouncementRecord])
def get_kiosk_notices(
    device_id: str | None = Query(default=None),
    line_id: str | None = Query(default=None),
    line_ids: str | None = Query(default=None),
    x_kiosk_token: str | None = Header(default=None, alias=KIOSK_READ_TOKEN_HEADER),
) -> List[KioskAnnouncementRecord]:
    try:
        registry = RunRegistry(Config())
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc
    try:
        _ensure_kiosk_notice_backend_ready(registry)
        _require_kiosk_read_access(x_kiosk_token)
        requested_line_ids = [value.strip() for value in str(line_ids or "").split(",") if value.strip()]
        if line_id and line_id.strip():
            requested_line_ids.append(line_id.strip())
        if not requested_line_ids and not (device_id and device_id.strip()):
            raise HTTPException(status_code=400, detail="device_id or line_id or line_ids is required")
        if device_id and device_id.strip():
            if not registry.kiosk_device_assignment_enabled:
                raise HTTPException(
                    status_code=503,
                    detail="kiosk_device_assignment 테이블이 없습니다. bohae_aps_v20/sql/22_kiosk_control_plane_v1.sql을 먼저 적용하세요.",
                )
            assignment = _resolve_published_kiosk_device_assignment(
                registry,
                registry.fetch_kiosk_device_assignment(device_id.strip()),
            )
            if assignment:
                requested_line_ids.extend(
                    [str(value).strip() for value in (assignment.get("line_ids") or []) if str(value).strip()]
                )
        deduped_line_ids = sorted({value for value in requested_line_ids if value})
        panel_announcements, _ = _load_kiosk_announcement_bundle(registry, deduped_line_ids)
        return panel_announcements
    finally:
        registry.close()


@app.get("/v1/ops/kiosk/index", response_model=OpsKioskIndexResponse)
def get_ops_kiosk_index(
    actor_claims: Dict[str, Any] = Depends(get_current_actor),
) -> OpsKioskIndexResponse:
    try:
        registry = RunRegistry(Config())
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc
    try:
        _require_authenticated_user(registry, actor_claims)

        line_map: Dict[str, str] = dict(_build_display_names_response().lines)
        lines_out: Dict[str, OpsKioskIndexLineRecord] = {}

        for line_id, label in line_map.items():
            cleaned = _clean_text(line_id)
            if not cleaned:
                continue
            lines_out[cleaned] = OpsKioskIndexLineRecord(
                line_id=cleaned,
                line_label_ko=_clean_text(label) or _resolve_kiosk_line_label_ko(cleaned),
            )

        if registry.kiosk_line_config_enabled:
            for row in registry.list_kiosk_line_configs(limit=2000):
                line_id = _clean_text(row.get("line_id"))
                if not line_id:
                    continue
                current = lines_out.get(
                    line_id,
                    OpsKioskIndexLineRecord(
                        line_id=line_id,
                        line_label_ko=_resolve_kiosk_line_label_ko(line_id),
                    ),
                )
                row_label = _clean_text(row.get("line_label_ko"))
                lines_out[line_id] = OpsKioskIndexLineRecord(
                    line_id=line_id,
                    line_label_ko=row_label or current.line_label_ko or _resolve_kiosk_line_label_ko(line_id),
                    product_name=_clean_text(row.get("product_name")),
                    target_qty=int(row.get("target_qty") or 0),
                    manual_current_qty=int(row.get("manual_current_qty") or 0),
                    manual_current_qty_enabled=bool(row.get("manual_current_qty_enabled")),
                    unit_label=_clean_text(row.get("unit_label")) or "병",
                    bpm_target=int(row.get("bpm_target") or 0),
                    shift_start_hhmm=_clean_text(row.get("shift_start_hhmm")),
                    shift_end_hhmm=_clean_text(row.get("shift_end_hhmm")),
                    planned_break_min=int(row.get("planned_break_min") or 0),
                    viewer_profile_json=dict(row.get("viewer_profile_json") or {}) if isinstance(row.get("viewer_profile_json"), dict) else {},
                    config_source=_resolve_kiosk_config_source(row, None),
                    config_status=_resolve_kiosk_config_status(config_source=_resolve_kiosk_config_source(row, None)),
                    config_lock=bool(row.get("config_lock")),
                )

        now_ms = _now_ms()
        bundled_views, _ = _build_kiosk_line_view_bundle(
            registry,
            line_ids=list(lines_out.keys()),
            now_ms=now_ms,
        )
        for line_id, current in list(lines_out.items()):
            base_view = bundled_views.get(line_id) or _compose_kiosk_line_view(registry, line_id)
            reset_required, reset_reason, reset_rule = _evaluate_kiosk_reset_required(
                current_qty=int(base_view.current_qty or 0),
                active_segment_label=_clean_text(base_view.active_segment_label),
                viewer_profile_json=base_view.viewer_profile_json,
                now_ms=now_ms,
            )
            lines_out[line_id] = OpsKioskIndexLineRecord(
                line_id=line_id,
                line_label_ko=base_view.line_label_ko or current.line_label_ko,
                display_line_label_ko=base_view.display_line_label_ko,
                product_name=base_view.product_name,
                display_product_name=base_view.display_product_name,
                product_name_suggestions=base_view.product_name_suggestions,
                product_name_detail=base_view.product_name_detail,
                product_count=int(base_view.product_count or 0),
                product_semantics=base_view.product_semantics,
                target_qty=int(base_view.target_qty or 0),
                target_qty_source=str(base_view.target_qty_source or ""),
                target_qty_authoritative=bool(base_view.target_qty_authoritative),
                manual_current_qty=int(base_view.manual_current_qty or 0),
                manual_current_qty_enabled=bool(base_view.manual_current_qty_enabled),
                current_qty=int(base_view.current_qty or 0),
                current_qty_source=str(base_view.current_qty_source or ""),
                current_qty_authoritative=bool(base_view.current_qty_authoritative),
                current_qty_semantics=base_view.current_qty_semantics,
                current_qty_hidden_reason=base_view.current_qty_hidden_reason,
                work_order_count=int(base_view.work_order_count or 0),
                lot_count=int(base_view.lot_count or 0),
                current_run_label=base_view.current_run_label,
                unit_label=base_view.unit_label or "병",
                bpm_target=int(base_view.bpm_target or 0),
                bpm_target_source=str(base_view.bpm_target_source or ""),
                bpm_target_authoritative=bool(base_view.bpm_target_authoritative),
                shift_start_hhmm=base_view.shift_start_hhmm,
                shift_end_hhmm=base_view.shift_end_hhmm,
                planned_break_min=int(base_view.planned_break_min or 0),
                viewer_profile_json=base_view.viewer_profile_json,
                config_source=base_view.config_source,
                config_status=base_view.config_status,
                config_lock=bool(base_view.config_lock),
                health_state=base_view.health_state,
                production_state=base_view.production_state,
                bpm=int(base_view.bpm or 0),
                runtime_state=base_view.runtime_state,
                display_state=base_view.display_state,
                display_status_code=base_view.display_status_code,
                display_status_label_ko=base_view.display_status_label_ko,
                display_status_tone=base_view.display_status_tone,
                stop_duration_sec=base_view.stop_duration_sec,
                stale=bool(base_view.stale),
                temp_c=base_view.temp_c,
                vibration_mm_s=base_view.vibration_mm_s,
                power_kw=base_view.power_kw,
                source_ts_ms=int(base_view.source_ts_ms or 0),
                reset_required=reset_required,
                reset_reason=reset_reason,
                reset_rule=reset_rule,
            )

        devices: list[OpsKioskIndexDeviceRecord] = []
        if registry.kiosk_device_assignment_enabled:
            for row in registry.list_kiosk_device_assignments(limit=1000):
                device_id = _clean_text(row.get("device_id"))
                if not device_id:
                    continue
                line_ids = [str(x).strip() for x in (row.get("line_ids") or []) if str(x).strip()]
                for line_id in line_ids:
                    if line_id not in lines_out:
                        lines_out[line_id] = OpsKioskIndexLineRecord(
                            line_id=line_id,
                            line_label_ko=_resolve_kiosk_line_label_ko(line_id),
                        )
                devices.append(
                    OpsKioskIndexDeviceRecord(
                        device_id=device_id,
                        layout_mode=_normalize_kiosk_layout_mode(row.get("layout_mode") or "grid_2x2"),
                        line_ids=line_ids,
                        theme=_normalize_kiosk_theme(row.get("theme") or "light"),
                        viewer_mode=str(row.get("viewer_mode") or "ACTIVE_LINES_BOARD").strip().upper() or "ACTIVE_LINES_BOARD",
                        active_lines_only=bool(row.get("active_lines_only")),
                        viewer_profile_json=dict(row.get("viewer_profile_json") or {}) if isinstance(row.get("viewer_profile_json"), dict) else {},
                    )
                )

        lines_sorted = sorted(lines_out.values(), key=lambda item: item.line_id)
        devices_sorted = sorted(devices, key=lambda item: item.device_id)
        return OpsKioskIndexResponse(
            lines=lines_sorted,
            devices=devices_sorted,
            generated_ts_ms=_now_ms(),
        )
    finally:
        registry.close()


@app.get("/v1/ops/kiosk/index/stream")
def stream_ops_kiosk_index(
    actor_claims: Dict[str, Any] = Depends(get_current_actor),
) -> StreamingResponse:
    actor_key = hashlib.sha1(
        json.dumps(actor_claims, ensure_ascii=False, sort_keys=True, default=str).encode("utf-8")
    ).hexdigest()
    return _build_shared_sse_response(
        topic_key=f"ops-kiosk-index:{actor_key}",
        connected_payload={
            "ts": _now_ms(),
            "message": "ops-kiosk-index-stream-connected",
        },
        build_snapshot=lambda: get_ops_kiosk_index(actor_claims=actor_claims),
        interval_sec=8,
        heartbeat_sec=15,
    )


