@app.get("/v1/ops/kiosk/edge-health", response_model=KioskEdgeHealthResponse)
def get_ops_kiosk_edge_health(
    limit: int = Query(default=500, ge=1, le=5000),
    actor_claims: Dict[str, Any] = Depends(get_current_actor),
) -> KioskEdgeHealthResponse:
    try:
        registry = RunRegistry(Config())
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc
    try:
        _require_authenticated_user(registry, actor_claims)
        now_ms = _now_ms()
        rows = registry.list_state_sensors(limit=limit)
        stale_sensors: List[KioskEdgeHealthSensorRecord] = []
        total_sensors = 0
        online_count = 0

        for row in rows:
            line_id = _clean_text(row.get("line_id"))
            if not line_id:
                continue
            total_sensors += 1
            source_ts_ms = int(
                row.get("counter_ts_ms")
                or row.get("runtime_ts_ms")
                or row.get("ts_ms")
                or 0
            )
            period_ms = int(row.get("period_ms") or KIOSK_VIEW_PERIOD_FLOOR_MS or 0)
            stale_threshold_ms = max(
                KIOSK_STALE_MIN_THRESHOLD_MS,
                period_ms * KIOSK_STALE_MULTIPLIER,
            )
            age_ms = max(0, now_ms - source_ts_ms) if source_ts_ms > 0 else stale_threshold_ms + 1
            if age_ms <= stale_threshold_ms:
                online_count += 1
                continue

            stale_sensors.append(
                KioskEdgeHealthSensorRecord(
                    line_id=line_id,
                    device_id=_clean_text(row.get("counter_device_id") or row.get("latest_device_id")),
                    downtime_seconds=int(age_ms // 1000),
                    age_ms=age_ms,
                    stale_threshold_ms=stale_threshold_ms,
                    last_count_at_ms=source_ts_ms,
                    runtime_state=_clean_text(row.get("runtime_state")) or None,
                    status=_clean_text(row.get("status")) or None,
                )
            )

        stale_sensors.sort(
            key=lambda item: (item.downtime_seconds, item.line_id),
            reverse=True,
        )
        return KioskEdgeHealthResponse(
            total_sensors=total_sensors,
            online_count=online_count,
            stale_count=len(stale_sensors),
            stale_sensors=stale_sensors,
            generated_ts_ms=now_ms,
        )
    finally:
        registry.close()


