@app.put("/v1/ops/kiosk/profiles/{profile_id}", response_model=KioskViewProfileRecord)
def upsert_ops_kiosk_profile(
    profile_id: str,
    request: OpsKioskProfileUpsertRequest,
    actor_claims: Dict[str, Any] = Depends(get_current_actor),
) -> KioskViewProfileRecord:
    if not profile_id.strip():
        raise HTTPException(status_code=400, detail="profile_id is required")
    try:
        registry = RunRegistry(Config())
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc
    try:
        actor = _require_authenticated_user(registry, actor_claims)
        if not registry.kiosk_view_profile_enabled:
            raise HTTPException(
                status_code=503,
                detail="kiosk_view_profile 테이블이 없습니다. bohae_aps_v20/sql/94_kiosk_view_profile_v1.sql을 먼저 적용하세요.",
            )
        existing = registry.fetch_kiosk_view_profile(profile_id.strip())
        if existing and not _actor_can_edit_kiosk_profile(actor, existing):
            raise HTTPException(status_code=403, detail="이 프로필을 수정할 권한이 없습니다.")
        normalized_scope = _normalize_kiosk_profile_scope(request.profile_scope)
        role = str(actor.get("actor_role") or "VIEWER").upper().strip()
        if normalized_scope == "SHARED" and role not in {"ADMIN", "MANAGER"}:
            raise HTTPException(status_code=403, detail="공용 프로필은 매니저/관리자만 저장할 수 있습니다.")
        normalized_kind = _normalize_kiosk_profile_kind(request.profile_kind)
        target_device_id = _clean_text(request.target_device_id)
        target_line_id = _clean_text(request.target_line_id)
        if normalized_kind == "LINE_FOCUS" and not target_line_id:
            raise HTTPException(status_code=400, detail="LINE_FOCUS profile requires target_line_id")
        if normalized_kind == "DEVICE_BOARD" and not target_device_id:
            raise HTTPException(status_code=400, detail="DEVICE_BOARD profile requires target_device_id")
        normalized_line_ids = _normalize_kiosk_profile_line_ids_or_400(registry, [str(value) for value in request.line_ids])
        if normalized_kind == "LINE_FOCUS":
            normalized_line_ids = [target_line_id] if target_line_id else []
        after = registry.upsert_kiosk_view_profile(
            profile_id=profile_id.strip(),
            title=request.title.strip(),
            profile_kind=normalized_kind,
            profile_scope=normalized_scope,
            owner_user_id=_clean_text(existing.get("owner_user_id")) if existing and _clean_text(existing.get("owner_user_id")) else str(actor.get("actor_id") or ""),
            owner_employee_no=_clean_text(existing.get("owner_employee_no")) if existing and _clean_text(existing.get("owner_employee_no")) else str(actor.get("actor_employee_no") or ""),
            target_device_id=target_device_id or None,
            target_line_id=target_line_id or None,
            layout_mode=_normalize_kiosk_layout_mode(request.layout_mode),
            theme=_normalize_kiosk_theme_or_400(request.theme.strip()),
            viewer_mode=str(request.viewer_mode or "ACTIVE_LINES_BOARD").strip().upper() or "ACTIVE_LINES_BOARD",
            active_lines_only=bool(request.active_lines_only),
            area_filter=_normalize_kiosk_area_filter(request.area_filter),
            line_ids=normalized_line_ids,
            viewer_profile_json=dict(request.viewer_profile_json or {}),
            note=request.note.strip(),
            updated_by=str(actor.get("actor_id") or actor.get("actor_email") or "ops"),
        )
        if after is None:
            raise HTTPException(status_code=500, detail="kiosk profile upsert failed")
        if registry.decision_log_enabled:
            registry.insert_decision_log(
                scenario_id="OPS_KIOSK",
                event_type="KIOSK_VIEW_PROFILE_UPSERT",
                payload_json={
                    "ENTITY_TYPE": "KIOSK_VIEW_PROFILE",
                    "ENTITY_ID": profile_id.strip(),
                    "ACTOR_EMAIL": actor.get("actor_email"),
                    "ACTOR_ROLE": actor.get("actor_role"),
                    "NOTE": request.note.strip(),
                    "AFTER": _json_safe(after),
                },
            )
        return _to_kiosk_view_profile_record(actor, after)
    finally:
        registry.close()


@app.delete("/v1/ops/kiosk/profiles/{profile_id}")
def delete_ops_kiosk_profile(
    profile_id: str,
    actor_claims: Dict[str, Any] = Depends(get_current_actor),
) -> Dict[str, Any]:
    if not profile_id.strip():
        raise HTTPException(status_code=400, detail="profile_id is required")
    try:
        registry = RunRegistry(Config())
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc
    try:
        actor = _require_authenticated_user(registry, actor_claims)
        if not registry.kiosk_view_profile_enabled:
            raise HTTPException(
                status_code=503,
                detail="kiosk_view_profile 테이블이 없습니다. bohae_aps_v20/sql/94_kiosk_view_profile_v1.sql을 먼저 적용하세요.",
            )
        existing = registry.fetch_kiosk_view_profile(profile_id.strip())
        if existing is None:
            raise HTTPException(status_code=404, detail="profile_id not found")
        if not _actor_can_edit_kiosk_profile(actor, existing):
            raise HTTPException(status_code=403, detail="이 프로필을 삭제할 권한이 없습니다.")
        removed = registry.delete_kiosk_view_profile(profile_id.strip())
        if not removed:
            raise HTTPException(status_code=500, detail="kiosk profile delete failed")
        if registry.decision_log_enabled:
            registry.insert_decision_log(
                scenario_id="OPS_KIOSK",
                event_type="KIOSK_VIEW_PROFILE_DELETE",
                payload_json={
                    "ENTITY_TYPE": "KIOSK_VIEW_PROFILE",
                    "ENTITY_ID": profile_id.strip(),
                    "ACTOR_EMAIL": actor.get("actor_email"),
                    "ACTOR_ROLE": actor.get("actor_role"),
                    "BEFORE": _json_safe(existing),
                },
            )
        return {"profile_id": profile_id.strip(), "status": "DELETED"}
    finally:
        registry.close()


@app.post("/v1/ops/kiosk/sync-approved-run/{run_id}")
def post_ops_kiosk_sync_approved_run(
    run_id: str,
    actor_claims: Dict[str, Any] = Depends(get_current_actor),
) -> Dict[str, Any]:
    if not run_id.strip():
        raise HTTPException(status_code=400, detail="run_id is required")
    try:
        registry = RunRegistry(Config())
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc
    try:
        actor = _require_manager_or_admin(registry, actor_claims)
        if not registry.kiosk_line_config_enabled:
            raise HTTPException(
                status_code=503,
                detail="kiosk_line_config 테이블이 없습니다. bohae_aps_v20/sql/22_kiosk_control_plane_v1.sql을 먼저 적용하세요.",
            )
        approval_row = registry.fetch_approval(run_id.strip()) if registry.approval_enabled else None
        if approval_row is None:
            run_row = registry.fetch_run(run_id.strip())
            if run_row is None:
                raise HTTPException(status_code=404, detail="run_id not found")
            raise HTTPException(status_code=409, detail="run is not approved")
        if str(approval_row.get("approval_status") or "").strip().upper() != "APPROVED":
            raise HTTPException(status_code=409, detail="run is not approved")
        executed_run_id = registry.check_already_executed(run_id.strip())
        if not executed_run_id:
            raise HTTPException(status_code=409, detail="run is approved but not executed")
        executed_run_row = registry.fetch_run(executed_run_id)
        if executed_run_row is None:
            raise HTTPException(status_code=409, detail="executed run metadata is missing")
        summary = _auto_sync_kiosk_config_from_approved_run(
            registry,
            executed_run_row,
            actor,
            source_event="RUN_EXECUTED",
        )
        return {
            "status": "ok",
            "run_id": run_id.strip(),
            "executed_run_id": executed_run_id,
            "matched_lines": list(summary.get("matched_lines") or []),
            "updated_lines": list(summary.get("updated_lines") or []),
            "skipped_locked_lines": list(summary.get("skipped_locked_lines") or []),
            "missing_mapping_lines": list(summary.get("missing_mapping_lines") or []),
            "warnings": list(summary.get("warnings") or []),
            "updated_count": int(summary.get("updated_count") or 0),
            "skipped_locked_count": int(summary.get("skipped_locked_count") or 0),
            "missing_mapping_count": int(summary.get("missing_mapping_count") or 0),
        }
    finally:
        registry.close()


