def _execute_ops_kiosk_line_status_action(
    *,
    line_id: str,
    action: str,
    note: str,
    reason_code: str = "",
    reason_detail: str | None = None,
    actor_claims: Dict[str, Any],
) -> KioskLineConfigRecord:
    if not line_id.strip():
        raise HTTPException(status_code=400, detail="line_id is required")
    try:
        registry = RunRegistry(Config())
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc
    try:
        if not registry.kiosk_line_config_enabled:
            raise HTTPException(
                status_code=503,
                detail="kiosk_line_config 테이블이 없습니다. bohae_aps_v20/sql/22_kiosk_control_plane_v1.sql을 먼저 적용하세요.",
            )
        actor = _require_kiosk_line_editor(registry, actor_claims, line_id=line_id.strip())
        before = registry.fetch_kiosk_line_config(line_id.strip()) or {}
        before_viewer_profile_json = (
            dict(before.get("viewer_profile_json") or {})
            if isinstance(before.get("viewer_profile_json"), dict)
            else {}
        )
        next_status_override = _resolve_kiosk_status_action_override(action)
        next_reason_code = _normalize_kiosk_reason_code(reason_code)
        next_reason_detail = _clean_text(reason_detail)
        action_key = str(action or "").strip().upper()
        if action_key == "CHANGEOVER_START":
            next_reason_code = "CHANGEOVER"
        elif action_key == "BREAK_START":
            next_reason_code = "BREAK"
        elif action_key == "STOP" and not next_reason_code:
            next_reason_code = "MANUAL_STOP"
        elif action_key in {"START", "AUTO", "BREAK_END", "CHANGEOVER_END"}:
            next_reason_code = ""
            next_reason_detail = None
        after_viewer_profile_json = dict(before_viewer_profile_json)
        after_viewer_profile_json["status_override"] = next_status_override
        if next_reason_code:
            after_viewer_profile_json["status_reason_code"] = next_reason_code
        else:
            after_viewer_profile_json.pop("status_reason_code", None)
        if next_reason_detail:
            after_viewer_profile_json["status_reason_detail"] = next_reason_detail
        else:
            after_viewer_profile_json.pop("status_reason_detail", None)

        after = registry.upsert_kiosk_line_config(
            line_id=line_id.strip(),
            line_label_ko=_clean_text(before.get("line_label_ko")) or _resolve_kiosk_line_label_ko(line_id.strip()),
            product_name=_clean_text(before.get("product_name")) or "품목명 미입력",
            target_qty=int(before.get("target_qty") or 0),
            manual_current_qty=max(0, int(before.get("manual_current_qty") or 0)),
            manual_current_qty_enabled=bool(before.get("manual_current_qty_enabled")),
            unit_label=_clean_text(before.get("unit_label")) or "병",
            bpm_target=max(0, int(before.get("bpm_target") or 0)),
            shift_start_hhmm=_clean_text(before.get("shift_start_hhmm")),
            shift_end_hhmm=_clean_text(before.get("shift_end_hhmm")),
            planned_break_min=max(0, int(before.get("planned_break_min") or 0)),
            viewer_profile_json=after_viewer_profile_json,
            source=_clean_text(before.get("source")) or "MANUAL",
            source_ref=_clean_text(before.get("source_ref")) or None,
            config_lock=bool(before.get("config_lock")),
            note=note.strip(),
            updated_by=str(actor.get("actor_id") or actor.get("actor_email") or "ops"),
        )
        if after is None:
            raise HTTPException(status_code=500, detail="status action upsert failed")

        registry.insert_decision_log(
            scenario_id="OPS_KIOSK",
            event_type="KIOSK_LINE_STATUS_ACTION",
            payload_json={
                "ENTITY_TYPE": "KIOSK_LINE_CONFIG",
                "ENTITY_ID": line_id.strip(),
                "ACTOR_EMAIL": actor.get("actor_email"),
                "ACTOR_ROLE": actor.get("actor_role"),
                "ACTION": action.strip().upper(),
                "NOTE": note.strip(),
                "BEFORE_STATUS_OVERRIDE": _normalize_kiosk_status_override(before_viewer_profile_json.get("status_override"), default="AUTO"),
                "AFTER_STATUS_OVERRIDE": next_status_override,
                "AFTER_STATUS_REASON_CODE": next_reason_code,
                "AFTER_STATUS_REASON_DETAIL": next_reason_detail,
                "AFTER": _json_safe(after),
            },
        )
        return KioskLineConfigRecord(**after)
    finally:
        registry.close()


